INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('1', '33', 'One Platform, All Solutions', 'one-platform-all-solutions-1782972638', '<div style="display: flex; flex-wrap: wrap; align-items: center; justify-content: space-between; padding: 1rem 0; margin-bottom: 2rem; font-family: sans-serif;"><!-- Kiri: Teks & Info -->\r\n<div style="flex: 1 1 50%; min-width: 300px; padding-right: 2rem;"><span style="color: #1885c4; font-weight: bold; font-size: 1.25rem; display: block; margin-bottom: 0.5rem;">#OnePlatformAllSolutions</span>\r\n<h2 style="font-size: 2.75rem; font-weight: 800; margin-top: 0; margin-bottom: 1.5rem; line-height: 1.2; color: #0f172a;">Semua Kebutuhan Sekolah<br><span style="color: #1885c4;">dalam Satu Aplikasi</span></h2>\r\n<p style="font-size: 1.125rem; color: #475569; margin-bottom: 1.5rem; line-height: 1.6;">Pantau perkembangan anak, cek tagihan sekolah, menerima pengumuman, melihat jadwal pelajaran, hingga berkomunikasi dengan sekolah langsung dari smartphone Anda.</p>\r\n<p style="font-size: 1.125rem; color: #475569; margin-bottom: 2.5rem; line-height: 1.6; font-weight: 500;">Download sekarang dan nikmati kemudahan layanan sekolah dalam genggaman.</p>\r\n<div style="display: flex; gap: 1.5rem; align-items: center;"><!-- Tempat QR Code -->\r\n<div style="width: 120px; height: 120px; background: white; border: 2px solid #e2e8f0; display: flex; align-items: center; justify-content: center; border-radius: 1rem; color: #94a3b8; font-size: 0.875rem; text-align: center; box-shadow: inset 0 2px 4px 0 rgba(0,0,0,0.06);"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782972626_qr-code.webp" alt="" width="152" height="152"></div>\r\n<div style="display: flex; flex-direction: column; gap: 0.75rem;">\r\n<div style="background: black; color: white; padding: 0.75rem 1.5rem; border-radius: 0.5rem; text-align: center; font-weight: bold; font-size: 0.875rem;">Google Play</div>\r\n<div style="background: black; color: white; padding: 0.75rem 1.5rem; border-radius: 0.5rem; text-align: center; font-weight: bold; font-size: 0.875rem;">App Store</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Kanan: Hero Image Placeholder -->\r\n<div style="flex: 1 1 40%; min-width: 300px; display: flex; justify-content: flex-end; margin-top: 2rem;">\r\n<div style="width: 100%; max-width: 350px; background: #e0f2fe; border-radius: 1.5rem; overflow: hidden; border: 8px solid white; box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04); display: flex; align-items: center; justify-content: center;">\r\n<p style="padding: 2rem; text-align: center; color: #64748b; font-size: 0.875rem; margin: 0;"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782972608_phone-mockup.webp" alt="" width="375" height="364"></p>\r\n</div>\r\n</div>\r\n</div>', '1', NULL, '72', '2026-07-02 06:07:41', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('2', '33', 'Evolusi Arsitektur Sistem: Monolitik ke Microservices', 'evolusi-arsitektur-sistem-monolitik-ke-microservices-1782972892', '<h2>Latar Belakang Transformasi</h2>\r\n<p>Seiring dengan berkembangnya ekosistem digital Yayasan Pesantren Islam Al-Azhar, kompleksitas aplikasi dan volume data terus meningkat secara eksponensial. Hal ini menuntut adanya pembaharuan fundamental pada arsitektur sistem agar tetap tangguh, responsif, dan mudah dikembangkan. Gambar arsitektur di atas memvisualisasikan lompatan strategis dari arsitektur <strong>Monolitik</strong> (Sistem Salam Lama) menuju arsitektur <strong>Microservices</strong> (Al-Azhar Apps modern).</p>\r\n<h2>Analisis Arsitektur Lama: SALAM Architecture (Monolitik)</h2>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782972869_13.png" alt="" width="342" height="393"></p>\r\n<p>Pada arsitektur sistem Salam yang lama, aplikasi dibangun menggunakan pendekatan monolitik klasik. Seperti yang terlihat pada diagram sebelah kiri, komponen <strong>User Interface</strong>, <strong>Business Logic</strong>, dan <strong>Data Access Layer</strong> tergabung secara erat <em>(tightly coupled)</em> dalam satu kesatuan sistem besar.</p>\r\n<ul>\r\n<li><strong>Satu Database Terpusat:</strong> Seluruh modul dan fungsi berbagi satu <em>database</em> yang sama. Beban komputasi menjadi sangat berat ketika terjadi lonjakan pengguna.</li>\r\n<li><strong>Ketergantungan Modul:</strong> Perubahan kecil pada satu bagian <em>business logic</em> mengharuskan seluruh sistem di-<em>deploy</em> ulang, meningkatkan risiko <em>downtime</em>.</li>\r\n<li><strong>Hambatan Skalabilitas:</strong> Sulit untuk meningkatkan performa pada satu fitur spesifik saja tanpa harus memperbesar kapasitas <em>server</em> untuk seluruh aplikasi.</li>\r\n</ul>\r\n<h2>Paradigma Baru: AL-AZHAR APPS Architecture (Microservices)</h2>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782972887_16.png" alt="" width="471" height="397"></p>\r\n<p>Diagram sebelah kanan menunjukkan bagaimana Al-Azhar Apps didesain ulang secara radikal menggunakan arsitektur <strong>Microservices</strong>. Sistem besar dipecah menjadi layanan-layanan kecil (<em>microservices</em>) yang berdiri sendiri dan berpusat di sekitar <strong>User Interface</strong> terpadu.</p>\r\n<ul>\r\n<li><strong>Desentralisasi Database:</strong> Setiap <em>microservice</em> kini memiliki <em>database</em> independennya masing-masing. Isolasi data ini mencegah fenomena <em>single point of failure</em>. Jika satu database layanan bermasalah, layanan lain tetap beroperasi normal.</li>\r\n<li><strong>Independensi Deployment:</strong> Tim pengembang dapat melakukan <em>update</em>, <em>maintenance</em>, atau penambahan fitur pada satu layanan tanpa mengganggu sistem yang lain. Rilis pembaruan menjadi jauh lebih cepat dan aman.</li>\r\n<li><strong>Skalabilitas Presisi:</strong> Jika layanan Pembayaran (contohnya) sedang mengalami lonjakan akses pada masa pendaftaran, kita cukup melakukan <em>scaling up</em> khusus pada <em>microservice</em> tersebut, tanpa membebani layanan akademik lainnya.</li>\r\n</ul>\r\n<blockquote><strong>Kesimpulan Strategis:</strong> Transisi dari Monolitik ke Microservices ini bukan sekadar pembaruan teknis, melainkan investasi strategis jangka panjang. Infrastruktur baru Al-Azhar Apps memastikan bahwa sistem akan selalu siap beradaptasi dengan inovasi teknologi baru dan melayani komunitas Al-Azhar tanpa kompromi pada performa dan keandalan.</blockquote>', '1', NULL, '74', '2026-07-02 06:07:41', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('3', '33', 'Release Notes', 'release-notes-1782972659', '<p>Al Azhar Apps merupakan platform digital resmi dari Yayasan Pesantren Islam Al-Azhar yang dirancang untuk mengintegrasikan seluruh ekosistem pendidikan ke dalam satu genggaman. Mengusung semangat #OnePlatformAllSolutions, kami menghadirkan kemudahan mulai dari proses Penerimaan Murid Baru (PMB) yang cepat, hingga pemenuhan semua kebutuhan sekolah dalam satu aplikasi. Kini, Anda dapat memantau perkembangan anak, mengecek tagihan pendidikan, menerima pengumuman, melihat jadwal pelajaran, hingga berkomunikasi dengan sekolah secara mulus langsung dari smartphone Anda. Layanan terbaik, khusus untuk komunitas Al Azhar.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782972654_phone-mockup.webp" alt="" width="449" height="436"></p>', '1', NULL, '73', '2026-07-02 06:07:41', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('4', '33', 'Topologi Infrastruktur Cloud-Native: Skalabilitas, Keamanan, & High Availability', 'topologi-infrastruktur-cloud-native-skalabilitas-keamanan-high-availability', '<p>Di balik antarmuka aplikasi yang cepat dan responsif, Al-Azhar Apps ditopang oleh arsitektur infrastruktur <em>Cloud-Native</em> yang sangat tangguh. Diagram topologi di atas menjabarkan bagaimana sistem dirancang untuk mencapai tingkat ketersediaan tinggi (<em>High Availability</em>), keamanan berlapis, dan siklus pengembangan yang otomatis. Berikut adalah bedah mendalam dari setiap lapisan arsitektur tersebut:<img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782973781_Untitled design.jpg" alt="" width="752" height="423"></p>\r\n<h2>1. Traffic Gateway &amp; Proxy Layer (Lapisan Jaringan Publik)</h2>\r\n<p>Setiap permintaan (<em>request</em>) yang datang dari <strong>Internet</strong> tidak langsung menyentuh <em>server</em> aplikasi. Lalu lintas ini diatur dan disaring terlebih dahulu oleh node <strong>STG-PROXY</strong> dan <strong>PROXY1/UTILITY</strong>. Lapisan ini bertindak sebagai pintu gerbang utama yang melakukan <em>load balancing</em>, terminasi SSL, serta perlindungan awal terhadap serangan siber sebelum meneruskan rute trafik ke klaster aplikasi di belakangnya.</p>\r\n<h2>2. Kubernetes Orchestration Layer (Lapisan Orkestrasi)</h2>\r\n<p>Jantung dari ekosistem Al-Azhar Apps adalah teknologi kontainerisasi yang diorkestrasi oleh <strong>Kubernetes</strong>. Diagram menunjukkan adanya infrastruktur <em>cluster</em> yang sangat matang:</p>\r\n<ul>\r\n<li><strong>High Availability (HA) Cluster:</strong> Klaster utama (di sisi kanan) menggunakan arsitektur <em>Multi-Master</em> (<strong>STG-MASTER 1, 2, 3</strong>) beserta jajaran <em>Worker Node</em> (<strong>STG-WORKER 1, 2, 3</strong>). Jika salah satu <em>server master</em> mengalami kegagalan <em>(downtime)</em>, sistem akan tetap berjalan tanpa henti karena <em>master</em> lainnya akan mengambil alih kendali secara instan.</li>\r\n<li><strong>Utility Cluster:</strong> Terdapat klaster terpisah di sisi kiri yang didedikasikan untuk menjalankan beban kerja utilitas dan manajemen, guna memastikan proses internal tidak mengganggu performa aplikasi publik.</li>\r\n</ul>\r\n<h2>3. CI/CD Pipeline (Pipa Integrasi &amp; Pengiriman Berkelanjutan)</h2>\r\n<p>Perjalanan kode dari <strong>Developer</strong> hingga menjadi fitur yang siap pakai sangat terotomatisasi:</p>\r\n<ol>\r\n<li>Pengembang menyimpan kode pada repositori <strong>GITLAB</strong>.</li>\r\n<li>Perubahan kode akan memicu <strong>RUNNER 1</strong> dan <strong>RUNNER 2</strong> untuk melakukan <em>build</em> dan pengujian secara otomatis.</li>\r\n<li>Hasil <em>build</em> (berupa <em>image container</em>) akan didorong ke <strong>STG-REGISTRY</strong> (repositori privat).</li>\r\n<li>Dari <em>registry</em> ini, aplikasi didistribusikan secara otomatis ke dalam klaster Kubernetes. Rantai pasok <em>software</em> ini menjamin bahwa peluncuran fitur baru berlangsung cepat, aman, dan tanpa mengorbankan stabilitas sistem.</li>\r\n</ol>\r\n<h2>4. Data &amp; Storage Layer (Lapisan Basis Data &amp; Penyimpanan)</h2>\r\n<p>Keamanan dan keutuhan data adalah prioritas absolut. Sistem penyimpanan dibagi menjadi dua tulang punggung utama:</p>\r\n<ul>\r\n<li><strong>Relational Database:</strong> Menggunakan klaster <strong>PostgreSQL (STG-DB 1 &amp; STG-DB 2)</strong> yang saling bereplikasi (ditunjukkan oleh tanda panah dua arah). Hal ini menjamin bahwa jika satu <em>server database</em> mati, data tidak akan hilang dan <em>server database</em> cadangan akan langsung menggantikannya.</li>\r\n<li><strong>Object Storage:</strong> Untuk file tak terstruktur (dokumen, gambar, media), sistem menggunakan penyimpanan berstandar S3 (<strong>STG-S3</strong>) di atas infrastruktur <strong>RUSTFS</strong> yang dirancang secara terdistribusi untuk melayani file dalam skala masif.</li>\r\n</ul>\r\n<h2>5. Observability &amp; Security (Pemantauan &amp; SOC)</h2>\r\n<p>Infrastruktur hebat membutuhkan pengawasan yang sama hebatnya. Di sudut kiri bawah, terdapat tim <strong>SOC (Security Operations Center) dan DevOps</strong> yang didukung oleh tumpukan (<em>stack</em>) visibilitas penuh:</p>\r\n<ul>\r\n<li><strong>STG-MONIT &amp; STG-LOKI:</strong> Seluruh log sistem, metrik <em>server</em>, dan telemetri ditarik secara <em>real-time</em> ke dalam sistem pemantauan terpusat. Hal ini memungkinkan tim DevOps mendeteksi anomali <em>hardware</em> atau potensi serangan keamanan sebelum berdampak pada pengguna.</li>\r\n</ul>\r\n<blockquote><strong>Catatan Penting:</strong> Desain infrastruktur ini mencerminkan arsitektur berskala Enterprise (<em>Enterprise-grade</em>). Dengan menggabungkan Kubernetes HA, CI/CD otomatis, database tereplikasi, serta pemantauan proaktif, Al-Azhar Apps dibangun untuk menjawab tantangan masa depan dengan slogan yang terbukti benar: <em>"One Platform, Endless Possibilities."</em></blockquote>', '1', NULL, '75', '2026-07-02 06:07:41', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('5', '33', 'Roadmap Upgrading Al Azhar Apps: Resolusi Teknologi & Ekosistem Terpadu', 'roadmap-upgrading-al-azhar-apps-resolusi-teknologi-ekosistem-terpadu', '<p>Berdasarkan cetak biru "Tabel Upgrading Al Azhar Apps" yang diterbitkan pada tanggal 12 Mei 2026, Yayasan Pesantren Islam Al-Azhar (YPIA) secara resmi melakukan lompatan kuantum di sisi teknologi dan layanan. Pembaruan ini bukan sekadar penambahan fitur, melainkan revolusi arsitektur dan operasional demi menyajikan aplikasi yang super cepat, aman, dan dapat dikontrol secara mandiri.</p>\r\n<p>Berikut adalah tafsir komprehensif dari poin-poin utama pembaruan (<em>upgrading</em>) yang diimplementasikan:</p>\r\n<h2>1. Lompatan Pondasi Teknologi: Dari Monolitik ke Microservices</h2>\r\n<p>Pembaruan terbesar terjadi pada jantung aplikasi, di mana YPIA secara total memisahkan antarmuka (<em>Frontend</em>) dan logika bisnis (<em>Backend</em>):</p>\r\n<ul>\r\n<li><strong>Bahasa Pemrograman Modern:</strong> Meninggalkan arsitektur <em>fullstack</em> tradisional (seperti Laravel), kini <em>Frontend</em> dibangun dengan <strong>Next.js</strong> (memastikan <em>render</em> halaman yang sangat cepat dan ramah SEO), sedangkan <em>Backend</em> ditenagai oleh <strong>Go-Lang</strong>. Go-Lang dipilih karena performa <em>concurrency</em>-nya yang luar biasa tinggi dan sangat efisien dalam penggunaan sumber daya server.</li>\r\n<li><strong>Auto-Healing &amp; High Availability:</strong> Sistem tidak lagi bergantung pada perbaikan manual saat *down*. Mekanisme <em>Auto-healing</em> akan secara otomatis memindahkan *traffic* dari komponen yang gagal ke komponen cadangan yang sehat, memastikan *downtime* nyaris nol.</li>\r\n<li><strong>Pemisahan Jalur Read/Write:</strong> Operasi membaca (melihat dashboard/rapor) dan operasi menulis (menyimpan data pembayaran) kini dilayani oleh *database* yang berbeda secara independen. Pendekatan ini memecahkan masalah *bottleneck* saat lalu lintas padat.</li>\r\n</ul>\r\n<h2>2. Kedaulatan Data &amp; Jaringan Server (Cloud Multi-Region)</h2>\r\n<p>Dalam hal pengelolaan *server*, YPIA mengambil langkah tegas untuk melindungi kedaulatan data umat:</p>\r\n<ul>\r\n<li><strong>Multi-Region 100% Indonesia:</strong> Seluruh pusat data ditempatkan di berbagai wilayah dalam yurisdiksi Indonesia. Selain mematuhi regulasi lokal, hal ini menekan nilai <em>latency</em> hingga ke titik terendah.</li>\r\n<li><strong>Zero Network Cost:</strong> Penggunaan *cloud* dikonfigurasi sedemikian rupa agar tidak membebankan biaya *inbound/outbound network* tambahan saat *microservices* saling bertukar data atau melakukan proses <em>backup &amp; recovery</em> masif.</li>\r\n</ul>\r\n<h2>3. Fitur Mutakhir, Keamanan, &amp; Sentuhan Religius</h2>\r\n<p>Aplikasi ini dirancang bukan hanya untuk menjadi alat administratif, melainkan pendamping harian yang aman bagi ekosistem keluarga Al-Azhar:</p>\r\n<ul>\r\n<li><strong>Pengamanan Biometrik:</strong> Otentikasi ganda (2FA) diperkuat dengan perlindungan <em>Face Recognition</em> (Pengenalan Wajah) dan Sidik Jari (<em>Fingerprint</em>) ditambah enkripsi data di setiap API.</li>\r\n<li><strong>Integrasi Layanan Islami:</strong> Aplikasi menyediakan jadwal sholat otomatis dan notifikasi Adzan yang cerdas menyesuaikan secara dinamis dengan lokasi GPS pengguna saat bepergian.</li>\r\n<li><strong>UI/UX Tematik &amp; Pemantauan Anak:</strong> Tampilan aplikasi (UI/UX) kini bersifat dinamis dan akan otomatis berubah merespons momen keagamaan atau nasional (misal: nuansa Idul Fitri). Selain itu, Orang Tua Murid (OTM) kini bisa memantau kehadiran anak, jadwal, serta nilai rapor secara *real-time* dari genggaman.</li>\r\n</ul>\r\n<h2>4. Manajemen Data: Single Source of Truth &amp; Integrasi Pembayaran</h2>\r\n<p>YPIA menghilangkan kultur data yang terkotak-kotak (<em>Silo</em>) antara divisi keuangan dan sekolah:</p>\r\n<ul>\r\n<li><strong>Integritas Data Terpadu:</strong> Perubahan status di satu sistem (misal: pembayaran spp) akan seketika (<em>real-time</em>) ter-<em>update</em> di sistem absensi dan akademik karena seluruh <em>microservice</em> mengakses repositori data terpadu.</li>\r\n<li><strong>Payment Aggregator:</strong> Alih-alih membangun koneksi rumit satu-per-satu ke bank (<em>host-to-host</em>), aplikasi menggunakan kanal Agregator Pembayaran. Ini membuat opsi metode bayar (Virtual Account, QRIS, Kartu Kredit) menjadi tak terbatas dan biaya pemeliharaannya sangat rendah.</li>\r\n<li><strong>Analytics Dashboard:</strong> Laporan operasional tak lagi dibuat manual. Terdapat dasbor <em>Descriptive Analytic</em> PDF/Excel yang dapat dikembangkan menuju <em>Predictive Analytics</em> untuk memprediksi pola pembayaran atau tren keuangan di masa mendatang.</li>\r\n</ul>\r\n<h2>5. Performa Super Maksimal &amp; Business Continuity</h2>\r\n<p>Hasil uji beban (<em>Load Test</em>) yang dicantumkan dalam dokumen memberikan fakta angka yang impresif atas infrastruktur baru ini:</p>\r\n<ul>\r\n<li><strong>Performa Fantastis:</strong> Mampu menangani hingga <strong>3.700 pengguna per detik</strong> secara bersamaan. Kecepatan respon (<em>Latency Response</em>) tercatat hanya <strong>0,092 detik</strong> (dibawah 0,1 detik!), dengan tingkat kegagalan (*error rate*) di bawah 1%.</li>\r\n<li><strong>Monitoring Terpusat:</strong> Seluruh ekosistem diawasi melalui <em>Control Tower</em> berbasis <strong>SigNoz dan Grafana</strong>, lengkap dengan peringatan dini langsung ke Telegram tim IT jika ada anomali.</li>\r\n</ul>\r\n<blockquote><strong>Ownership Source Code 100%:</strong> Yang paling fundamental dari transformasi ini adalah kepastian kelangsungan bisnis (<em>Business Continuity</em>). Baik <em>Database</em> maupun <em>Source Code</em> aplikasi sepenuhnya (100%) menjadi hak milik YPIA, memastikan kebebasan untuk pengembangan mandiri yang berkesinambungan di masa depan tanpa keterikatan mutlak pada pihak ketiga.</blockquote>', '1', NULL, '76', '2026-07-02 06:07:41', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('6', '25', 'Registrasi Akun Al Azhar Apps', 'registrasi-akun-al-azhar-apps', '<h2>Panduan Cara Proses Registrasi Nomor Handphone</h2>\r\n<p>Tutorial ini ditujukan untuk Orang Tua Calon/Murid yang ingin mendaftarkan akun baru pada Al Azhar Apps. Berikut adalah langkah-langkah pendaftarannya:</p>\r\n<ol>\r\n<li><strong>Masukkan Nomor Handphone:</strong> Setelah membuka aplikasi Al Azhar Apps, masukkan nomor handphone orang tua pada kolom yang tersedia. Pastikan nomor yang digunakan adalah nomor <strong>WhatsApp aktif</strong>. <br><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782975265_1.jpg" alt="" width="245" height="499"></li>\r\n<li><strong>Lanjutkan Pendaftaran:</strong> Apabila nomor handphone Anda belum terdaftar, maka akan muncul <em>Pop Up</em> pemberitahuan "Nomor Belum Terdaftar". Tekan tombol <strong>Lanjutkan</strong> untuk melanjutkan proses pendaftaran. <br><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782975294_2.jpg" alt="" width="244" height="489"></li>\r\n<li><strong>Lengkapi Data Diri:</strong> Masukkan <strong>Nama Lengkap</strong> orang tua murid dan alamat <strong>Email</strong> pada form pendaftaran yang disediakan. <br><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782975315_3.jpg" alt="" width="240" height="506"></li>\r\n<li><strong>Minta dan Masukkan Kode OTP:</strong> Tekan tombol <strong>Selanjutnya</strong>. Sistem akan mengirimkan kode OTP via WhatsApp. Cek pesan WhatsApp Anda, lalu masukkan kode OTP tersebut pada kotak <em>field</em> yang disediakan, lalu tekan <strong>Selanjutnya</strong>. <br><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782975335_4.jpg" alt="" width="237" height="499"></li>\r\n<li><strong>Buat dan Konfirmasi PIN:</strong> Buat 6 digit PIN untuk keamanan akun Anda, lalu tekan tombol <strong>Selanjutnya</strong>. Masukkan kembali PIN tersebut di halaman berikutnya untuk proses konfirmasi. <br><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1782975361_6.jpg" alt="" width="238" height="499"></li>\r\n<li><strong>Registrasi Berhasil:</strong> Akun Anda telah berhasil dibuat! Silakan kembali ke halaman <em>Login</em> untuk masuk ke aplikasi. <br><br></li>\r\n</ol>', '1', NULL, '23', '2026-07-02 06:07:41', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('9', '25', 'Instalasi Mobile App', 'instalasi-mobile-app', '<p>Aplikasi Al Azhar Apps dirancang untuk memudahkan seluruh civitas akademika dalam mengakses informasi dan layanan sekolah secara praktis dari genggaman Anda.</p>\n\n<h3>Cara Mengunduh Aplikasi</h3>\n<p>Anda dapat mengunduh aplikasi Al Azhar Apps secara gratis melalui toko aplikasi resmi sesuai dengan perangkat yang Anda gunakan:</p>\n\n<ul>\n    <li><strong>Untuk Pengguna Android:</strong><br>\n    Silakan kunjungi Google Play Store atau klik tautan berikut:<br>\n    <a href="https://play.google.com/store/apps/details?id=com.alazhar.alazharapps" target="_blank">Unduh Al Azhar Apps di Google Play Store</a>\n    </li>\n    <li><strong>Untuk Pengguna iOS (iPhone/iPad):</strong><br>\n    Silakan kunjungi Apple App Store dan cari "Al Azhar Apps" (atau klik tautan yang tersedia di portal resmi kami).\n    </li>\n</ul>\n\n<h3>Spesifikasi Minimal Perangkat (HP)</h3>\n<p>Agar aplikasi Al Azhar Apps dapat berjalan dengan lancar dan optimal, pastikan perangkat Anda memenuhi spesifikasi minimal berikut:</p>\n\n<ul>\n    <li><strong>Sistem Operasi Android:</strong> Minimal Android 8.0 (Oreo) atau yang lebih baru.</li>\n    <li><strong>Sistem Operasi iOS:</strong> Minimal iOS 12.0 atau yang lebih baru.</li>\n    <li><strong>RAM:</strong> Minimal 2 GB (Disarankan 3 GB atau lebih untuk performa terbaik).</li>\n    <li><strong>Penyimpanan Internal:</strong> Ruang kosong minimal 100 MB.</li>\n    <li><strong>Koneksi Internet:</strong> Stabil (3G/4G/5G atau Wi-Fi) untuk sinkronisasi data yang realtime.</li>\n</ul>\n\n<p>Jika perangkat Anda memenuhi persyaratan di atas, Anda siap untuk menginstal dan menggunakan aplikasi Al Azhar Apps tanpa hambatan.</p>', '1', '2', '24', '2026-07-03 06:13:35', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('10', '25', 'Login', 'halaman-selamat-datang-login', '<p>Halaman <strong>Selamat Datang</strong> adalah antarmuka pertama yang akan Anda (Orang Tua Murid) temui ketika membuka aplikasi Al Azhar Apps. Halaman ini dirancang dengan antarmuka yang bersih dan mudah dipahami, menggabungkan proses masuk (login) dan pendaftaran (registrasi) ke dalam satu alur yang praktis.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783061305_WhatsApp Image 2026-07-03 at 13.20.15.jpeg" alt="" width="252" height="547"></p>\r\n<h3>Fitur dan Komponen Halaman</h3>\r\n<p>Berikut adalah penjelasan detail mengenai elemen-elemen yang ada pada halaman ini:</p>\r\n<ul>\r\n<li><strong>Kolom Input Nomor Handphone:</strong><br>Anda diminta untuk memasukkan nomor handphone dengan kode negara (+62 untuk Indonesia). Sangat penting untuk memastikan bahwa nomor yang dimasukkan adalah <strong>nomor WhatsApp yang aktif</strong>. Sistem akan menggunakan nomor ini untuk mengirimkan kode verifikasi (OTP) baik untuk login maupun pendaftaran akun baru.</li>\r\n<li><strong>Tombol "Masuk":</strong><br>Setelah memasukkan nomor handphone, tekan tombol biru "Masuk" untuk melanjutkan. Sistem akan secara otomatis mendeteksi apakah nomor Anda sudah terdaftar atau belum, dan mengarahkan Anda ke langkah verifikasi selanjutnya.</li>\r\n<li><strong>Ikon Sidik Jari (Biometrik):</strong><br>Di sebelah kanan tombol Masuk, terdapat ikon sidik jari. Fitur ini memungkinkan Anda untuk masuk dengan cepat menggunakan sensor biometrik (sidik jari atau pengenalan wajah) di HP Anda, asalkan Anda sudah pernah berhasil login sebelumnya dan mengaktifkan fitur biometrik ini.</li>\r\n<li><strong>Tautan Kebijakan Privasi:</strong><br>Di bagian bawah layar, terdapat tautan menuju <em>Kebijakan Privasi</em>. Dengan menekan tombol Masuk, Anda dianggap menyetujui kebijakan pengelolaan data dan privasi dari Yayasan Pesantren Islam Al Azhar.</li>\r\n</ul>\r\n<h3>Langkah Penggunaan Singkat</h3>\r\n<ol>\r\n<li>Buka aplikasi Al Azhar Apps.</li>\r\n<li>Ketik nomor WhatsApp aktif Anda pada kolom yang disediakan (tidak perlu mengetik angka 0 di depan jika kode negara +62 sudah terpilih).</li>\r\n<li>Ketuk tombol <strong>Masuk</strong>.</li>\r\n<li>Tunggu pesan WhatsApp masuk yang berisi kode verifikasi OTP, lalu masukkan kode tersebut di layar berikutnya.</li>\r\n</ol>', '1', NULL, '25', '2026-07-03 06:25:07', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('11', '25', 'Verifikasi PIN', 'halaman-masukkan-pin', '<p>Setelah Anda memasukkan nomor handphone atau melewati tahap awal login, langkah pengamanan selanjutnya adalah halaman <strong>Masukkan PIN</strong>. Halaman ini berfungsi sebagai lapisan keamanan untuk melindungi data pribadi dan aktivitas Anda di dalam aplikasi Al Azhar Apps.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783061337_WhatsApp Image 2026-07-03 at 13.28.22.jpeg" alt="" width="256" height="555"></p>\r\n<h3>Fitur dan Komponen Halaman</h3>\r\n<p>Berikut adalah komponen utama pada antarmuka ini:</p>\r\n<ul>\r\n<li><strong>Tombol Kembali (Panah Kiri):</strong> Berada di pojok kiri atas, berfungsi untuk membatalkan proses dan kembali ke halaman Selamat Datang.</li>\r\n<li><strong>Indikator PIN (6 Digit):</strong> Terdapat enam buah titik yang akan berubah warna ketika Anda mengetikkan angka. Aplikasi ini mewajibkan penggunaan PIN sepanjang 6 digit untuk keamanan maksimal.</li>\r\n<li><strong>Tautan Reset PIN:</strong> Jika Anda melupakan PIN Anda, Anda dapat menekan tautan <em>"Lupa PIN? klik Reset PIN"</em>. Sistem akan memandu Anda melakukan prosedur pemulihan (umumnya dengan mengirimkan kode OTP ke WhatsApp Anda).</li>\r\n<li><strong>Keypad Angka Virtual:</strong> Terdapat tombol angka 0 hingga 9 yang didesain ergonomis, besar, dan jelas agar mudah ditekan di layar ponsel.</li>\r\n<li><strong>Ikon Mata (Sembunyikan/Tampilkan PIN):</strong> Terletak di pojok kiri bawah keypad, fitur ini sangat berguna jika Anda ingin mengintip/memastikan angka PIN yang Anda tekan sudah benar.</li>\r\n<li><strong>Ikon Hapus (Backspace):</strong> Terletak di pojok kanan bawah keypad, digunakan untuk menghapus angka terakhir yang Anda masukkan jika terjadi kesalahan ketik.</li>\r\n<li><strong>Tombol Masuk:</strong> Tombol biru di bagian bawah layar yang digunakan untuk memproses login Anda setelah seluruh digit PIN dimasukkan.</li>\r\n</ul>\r\n<h3>Panduan Penggunaan Singkat</h3>\r\n<ol>\r\n<li>Perhatikan 6 titik indikator di atas keypad. Gunakan keypad angka yang tersedia di layar untuk memasukkan 6 digit PIN rahasia akun Anda.</li>\r\n<li>Jika ragu, Anda bisa menekan tombol <strong>ikon mata</strong> untuk melihat angka yang Anda ketik.</li>\r\n<li>Jika salah ketik, tekan ikon <strong>Hapus (Backspace)</strong>.</li>\r\n<li>Jika Anda benar-benar lupa PIN, langsung klik tulisan <strong>Reset PIN</strong>.</li>\r\n<li>Setelah 6 digit terisi penuh, ketuk tombol <strong>Masuk</strong> untuk memverifikasi. Jika PIN benar, Anda akan diarahkan ke dasbor utama aplikasi.</li>\r\n</ol>', '1', NULL, '26', '2026-07-03 06:30:14', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('12', '31', 'Akses Halaman Backoffice', 'akses-halaman-backoffice', '<p>Sistem Back Office Al Azhar Apps (One Platform, All Solutions) digunakan oleh pengelola, guru, dan staf administrasi untuk mengelola data sekolah secara terpusat.</p>\n\n<h3>Cara Mengakses dan Login ke Backoffice</h3>\n<ol>\n    <li>\n        <strong>Buka Tautan:</strong><br>\n        Silakan buka peramban (browser) Anda seperti Google Chrome, Safari, atau Firefox, kemudian akses tautan berikut:<br>\n        <a href="https://apps.alazhar.or.id/" target="_blank"><strong>https://apps.alazhar.or.id/</strong></a>\n    </li>\n    <li>\n        <strong>Masukkan Kredensial:</strong><br>\n        Pada halaman login utama, silakan masukkan <strong>Username</strong> atau <strong>Email</strong> yang telah didaftarkan pada kolom pertama.\n    </li>\n    <li>\n        <strong>Masukkan Kata Sandi:</strong><br>\n        Masukkan <strong>Password</strong> Anda pada kolom kedua. Pastikan kombinasi huruf besar, kecil, dan angka sudah benar.\n    </li>\n    <li>\n        <strong>Verifikasi Keamanan (reCAPTCHA):</strong><br>\n        Centang kotak yang bertuliskan <em>"I\'m not a robot"</em> untuk verifikasi keamanan.\n    </li>\n    <li>\n        <strong>Masuk ke Sistem:</strong><br>\n        Klik tombol biru <strong>Login</strong> untuk masuk ke dalam dasbor sistem Back Office.\n    </li>\n</ol>\n\n<p><em>Catatan: Jika Anda melupakan kata sandi Anda, klik tautan "Lupa password?" di bawah tombol Login untuk melakukan pengaturan ulang kata sandi.</em></p>', '1', '2', '77', '2026-07-03 06:33:14', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('13', '25', 'Dasbor Beranda', 'halaman-beranda-utama', '<p>Setelah berhasil melewati verifikasi PIN, Anda akan diarahkan ke <strong>Halaman Beranda</strong>. Halaman ini adalah pusat kendali utama (dasbor) dari aplikasi Al Azhar Apps yang didesain agar Anda dapat mengakses semua fitur dan informasi penting dengan cepat.</p>\r\n<table style="border-collapse: collapse; width: 82.87%; height: 490.391px;" border="1"><colgroup><col style="width: 50.1656%;"><col style="width: 49.8344%;"></colgroup>\r\n<tbody>\r\n<tr style="height: 490.391px;">\r\n<td style="height: 490.391px;"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783061450_WhatsApp Image 2026-07-03 at 13.41.07.jpeg" alt="" width="240" height="519"></td>\r\n<td style="height: 490.391px;"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783061472_WhatsApp Image 2026-07-03 at 13.43.48.jpeg" alt="" width="249" height="540"></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<h3>Komponen Utama Halaman Beranda</h3>\r\n<p>Berikut adalah rincian elemen dan fitur yang tersedia di halaman ini:</p>\r\n<ul>\r\n<li><strong>Sapaan Pengguna:</strong><br>Di bagian atas halaman, Anda akan melihat sapaan "Assalamualaikum" diikuti dengan nama Anda, memberikan sentuhan personal pada aplikasi.</li>\r\n<li><strong>Menu Akses Cepat (Grid Ikon):</strong><br>Kumpulan ikon menu utama yang paling sering digunakan, meliputi:\r\n<ul>\r\n<li><strong>PMB:</strong> Informasi Penerimaan Murid Baru.</li>\r\n<li><strong>Tagihan:</strong> Pengecekan tagihan sekolah (titik merah menandakan adanya notifikasi atau tagihan yang perlu diperhatikan).</li>\r\n<li><strong>Lokasi:</strong> Informasi dan peta sekolah.</li>\r\n<li><strong>Aktifitas:</strong> Laporan kegiatan dan aktivitas.</li>\r\n<li><strong>Layanan Islami:</strong> Fitur penunjang ibadah harian seperti panduan Sholat, arah Qiblah, kumpulan Doa, dan Al Quran digital.</li>\r\n</ul>\r\nTerdapat juga tombol <strong>Menu Lainnya</strong> untuk menampilkan menu-menu tambahan.</li>\r\n<li><strong>Banner Informasi (Carousel):</strong><br>Sebuah <em>slider</em> gambar dinamis yang menampilkan informasi terkini, pengumuman sekolah, kegiatan, atau peringatan hari besar (seperti Hari Anak Nasional). Anda dapat menggesernya ke samping untuk melihat gambar lainnya.</li>\r\n<li><strong>Widget Infaq:</strong><br>Panel informasi khusus untuk transparansi donasi, menampilkan Total Keseluruhan Infaq Sekolah. Anda dapat menekan tombol <strong>Infaq</strong> untuk berpartisipasi atau <strong>Detail</strong> untuk melihat riwayat secara lengkap.</li>\r\n<li><strong>Jadwal Shalat:</strong><br>Menampilkan jadwal shalat lima waktu (Subuh, Dzuhur, Ashar, Maghrib, Isya) secara <em>real-time</em> yang menyesuaikan dengan lokasi Anda saat ini (contoh: Kota Adm. Jakarta Selatan). Terdapat juga ikon ilustrasi waktu pada masing-masing jadwal dan ikon perbarui (refresh) di sudut kanan.</li>\r\n<li><strong>Majalah Digital:</strong><br>Di bagian bawah layar, terdapat rak virtual untuk <em>Majalah Al Azhar</em>. Anda dapat menggesernya ke samping (horizontal) untuk melihat edisi-edisi majalah (ditandai dengan label "NEW" untuk edisi terbaru). Tersedia pula tautan <strong>Lihat Semua</strong> untuk menjelajahi koleksi majalah secara lengkap.</li>\r\n<li><strong>Bilah Navigasi Bawah (Bottom Navigation):</strong><br>Menu utama aplikasi yang selalu tampil di bagian bawah layar:\r\n<ul>\r\n<li><strong>Beranda:</strong> Kembali ke halaman dasbor utama ini.</li>\r\n<li><strong>Anak:</strong> Menu khusus untuk memantau profil, nilai, dan perkembangan anak Anda di sekolah.</li>\r\n<li><strong>Chat:</strong> Fitur pesan untuk berkomunikasi langsung dengan pihak sekolah atau guru.</li>\r\n<li><strong>Akun:</strong> Menu untuk mengatur profil, pengaturan privasi, dan keamanan.</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p>Semua informasi dirancang dalam tata letak yang bersih dan modern agar Anda merasa nyaman menggunakan Al Azhar Apps sebagai solusi pendidikan terpadu.</p>', '1', NULL, '27', '2026-07-03 06:46:26', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('15', '25', 'Bottom Menu Anak', 'menu-anak-dan-pmb', '<p>Menu <strong>Anak</strong> (dapat diakses dari panel navigasi bawah) merupakan ruang dasbor utama tempat orang tua dapat memantau seluruh aktivitas, perkembangan akademik, dan administrasi putra-putrinya secara terpusat.</p>\r\n<h3>1. Skenario Pengguna Baru (Belum Memiliki Anak Terdaftar)</h3>\r\n<p>Bagi orang tua yang baru pertama kali menggunakan aplikasi dan belum pernah mendaftarkan anaknya ke sekolah Al Azhar, halaman Menu Anak ini akan terlihat kosong. Layar akan menampilkan ilustrasi keluarga dengan pesan <em>"Belum Ada Anak yang Terdaftar"</em>.</p>\r\n<p>Pada kondisi ini, Menu Anak bertindak sebagai jalan pintas. Anda cukup menekan tombol biru <strong>Daftar Sekarang</strong>, dan sistem akan langsung mengarahkan Anda ke halaman formulir <strong>Pendaftaran Murid Baru (PMB)</strong>.</p>\r\n<h3>2. Skenario Pengguna Lama (Anak Sudah Terdaftar)</h3>\r\n<p>Setelah proses pendaftaran (PMB) berhasil diselesaikan dan status anak sudah resmi diterima, halaman Menu Anak ini akan berubah fungsinya menjadi "Ruang Pantau Utama". Di halaman ini nantinya Anda akan dapat melihat:</p>\r\n<ul>\r\n<li>Profil Siswa dan detail akademik anak.</li>\r\n<li>Pemantauan nilai, kehadiran, dan aktivitas harian di sekolah.</li>\r\n<li>Riwayat tagihan dan jadwal yang spesifik untuk anak tersebut.</li>\r\n</ul>\r\n<p><em>(Catatan: Apabila Anda ingin mendaftarkan anak kedua/adiknya, Anda bisa langsung menggunakan menu ikon <strong>PMB</strong> yang ada di halaman Beranda Utama).</em></p>', '1', '2', '28', '2026-07-03 07:22:16', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('16', '25', 'Fitur Menu Tagihan', 'menu-tagihan-dan-pembayaran', '<p>Menu <strong>Tagihan</strong> dirancang untuk memudahkan orang tua murid dalam memeriksa dan melakukan pembayaran administrasi sekolah (seperti Formulir PMB, SPP bulanan, atau kegiatan lainnya) secara langsung dari aplikasi.</p>\r\n<table style="border-collapse: collapse; width: 98.3857%; height: 743.391px;" border="1"><colgroup><col style="width: 49.5726%;"><col style="width: 50.4274%;"></colgroup>\r\n<tbody>\r\n<tr style="height: 743.391px;">\r\n<td style="height: 743.391px;"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783129735_1.jpeg" alt="" width="328" height="712"></td>\r\n<td style="height: 743.391px;"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783129747_2.jpeg" alt="" width="328" height="712"></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<h3>1. Halaman Daftar Tagihan &amp; Infaq</h3>\r\n<p>Saat Anda masuk ke menu Tagihan, Anda akan melihat kartu identitas anak (Nama dan Asal Sekolah) di bagian atas.</p>\r\n<ul>\r\n<li><strong>Memilih Tagihan:</strong> Sistem akan menampilkan daftar tagihan yang belum dibayar. Anda dapat mencentang kotak di sebelah kanan nominal untuk memilih tagihan mana yang ingin dibayar saat ini.</li>\r\n<li><strong>Fitur Infaq (Donasi):</strong> Tersedia juga kolom khusus untuk berinfaq. Jika Anda mengetuk tombol <strong>Infaq</strong>, akan muncul <em>pop-up</em> yang berisi kutipan ayat Al-Qur\'an dan kolom untuk memasukkan nominal infaq secara sukarela. Nominal infaq ini nantinya akan ditambahkan ke dalam total tagihan Anda.</li>\r\n<li><strong>Proses Pembayaran:</strong> Setelah memilih tagihan (dan/atau memasukkan infaq), total yang harus dibayar akan tertera di bagian bawah layar. Ketuk tombol biru <strong>Bayar</strong> untuk melanjutkan.</li>\r\n</ul>\r\n<table style="border-collapse: collapse; width: 98.3857%; height: 729.391px;" border="1"><colgroup><col style="width: 49.5382%;"><col style="width: 50.5234%;"></colgroup>\r\n<tbody>\r\n<tr style="height: 729.391px;">\r\n<td style="height: 729.391px;"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783129829_3.jpeg" alt="" width="328" height="712"></td>\r\n<td style="height: 729.391px;"><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783129839_4.jpeg" alt="" width="328" height="711"></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<h3>2. Konfirmasi Pembayaran</h3>\r\n<p>Sebelum masuk ke pemilihan bank, sistem akan memunculkan <em>pop-up</em> <strong>Konfirmasi Pembayaran</strong>. Jendela ini berfungsi agar Anda dapat memastikan kembali bahwa total nominal dan jumlah item tagihan yang Anda pilih sudah benar. Jika sudah sesuai, ketuk tombol <strong>Lanjutkan</strong>.</p>\r\n<h3>3. Ringkasan &amp; Pemilihan Metode Pembayaran</h3>\r\n<p>Pada layar berikutnya, Anda akan melihat rincian akhir dari transaksi Anda:</p>\r\n<ul>\r\n<li><strong>Ringkasan Pembayaran:</strong> Menampilkan detail <em>item</em> yang dibayar (misalnya: Formulir Pendaftaran PMB sebesar Rp 550.000).</li>\r\n<li><strong>Pilih Metode Pembayaran:</strong> Anda dapat memilih berbagai saluran pembayaran yang didukung, seperti transfer bank via <em>Virtual Account</em> (Bank BCA, CIMB Niaga, Bank Mandiri, dan lainnya).</li>\r\n</ul>\r\n<table style="border-collapse: collapse; width: 100%;" border="1"><colgroup><col style="width: 33.2735%;"><col style="width: 33.2735%;"><col style="width: 33.2735%;"></colgroup>\r\n<tbody>\r\n<tr>\r\n<td><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783130128_5.jpeg" alt="" width="328" height="711"></td>\r\n<td><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783130138_6.jpeg" alt="" width="329" height="713"></td>\r\n<td><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783130164_7.jpeg" alt="" width="329" height="713"></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Pilih metode bank yang paling memudahkan Anda dengan mengetuk tombol radio di sebelahnya, lalu ketuk tombol <strong>Lanjutkan</strong> (atau <strong>Bayar Sekarang</strong>). Sistem akan memproses permintaan Anda dan menampilkan instruksi transfer beserta nomor rekening/Virtual Account yang harus dituju.</p>', '1', '2', '29', '2026-07-04 01:48:17', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('17', '25', 'Fitur Menu PMB', 'panduan-pmb', '<p>Menu <strong>PMB (Penerimaan Murid Baru)</strong> adalah pintu masuk utama bagi orang tua yang ingin mendaftarkan putra-putrinya ke sekolah Al Azhar. Menu ini dapat diakses langsung melalui ikon PMB di halaman Dasbor Utama (Beranda).</p>\r\n<h3>1. Mengisi Formulir PMB</h3>\r\n<p>Formulir pendaftaran dirancang agar praktis diisi melalui <em>smartphone</em> Anda. Pastikan untuk mengisi semua kolom yang memiliki tanda bintang merah (*), yang menandakan bahwa kolom tersebut wajib diisi.</p>\r\n<h4>A. Data Sekolah Tujuan</h4>\r\n<ul>\r\n<li><strong>Tahun Ajaran &amp; Jenjang:</strong> Pilih tahun ajaran yang tersedia dan jenjang pendidikan (misalnya: TK, SD, SMP, SMA) melalui menu <em>dropdown</em>.</li>\r\n<li><strong>Tujuan Sekolah, Kelas, &amp; Program:</strong> Kolom-kolom ini pada awalnya akan terkunci (ditandai dengan ikon gembok). Anda baru bisa memilih data pada kolom ini <strong>setelah</strong> Anda menentukan Jenjang Pendidikan di bagian atas.</li>\r\n</ul>\r\n<h4>B. Data Pribadi Calon Murid</h4>\r\n<ul>\r\n<li><strong>Nama Calon Murid:</strong> Masukkan nama lengkap calon murid sesuai dengan dokumen resmi (Akte Kelahiran).</li>\r\n<li><strong>Jenis Kelamin:</strong> Pilih jenis kelamin dengan mengetuk pilihan tombol radio: Laki-laki atau Perempuan.</li>\r\n<li><strong>Tempat &amp; Tanggal Lahir:</strong> Ketik nama kota tempat lahir, lalu gunakan tombol ikon kalender di sebelah kanannya untuk memilih tanggal, bulan, dan tahun lahir dengan mudah tanpa harus mengetik manual.</li>\r\n<li><strong>Nama Ayah/Ibu:</strong> Masukkan nama lengkap orang tua atau wali murid.</li>\r\n<li><strong>Alamat:</strong> Masukkan alamat lengkap tempat tinggal saat ini (perhatikan batas maksimal 100 karakter).</li>\r\n</ul>\r\n<h4>C. Kontak &amp; Informasi Tambahan</h4>\r\n<ul>\r\n<li><strong>Nomor Handphone:</strong> Kolom ini secara otomatis akan terkunci dan terisi dengan nomor handphone/WhatsApp yang Anda gunakan saat mendaftar atau login pertama kali ke Al Azhar Apps.</li>\r\n<li><strong>Sumber Informasi:</strong> Beritahu kami dari mana Anda mengetahui informasi pendaftaran sekolah ini dengan mencentang satu atau beberapa kotak yang disediakan (seperti <em>Spanduk, Sosial Media, Website, Whatsapp Blast</em>, dll).</li>\r\n</ul>\r\n<h3>2. Tahap Akhir Pendaftaran</h3>\r\n<p>Setelah seluruh kolom formulir Anda pastikan terisi dengan data yang valid dan lengkap, ketuk tombol <strong>Daftar PMB</strong> berwarna biru di bagian bawah layar. Jika Anda ingin membatalkan atau kembali, tekan tombol <strong>Batalkan</strong>.</p>\r\n<p>Setelah pendaftaran berhasil dikirim, sistem akan memproses data Anda dan mengarahkan Anda ke tahap selanjutnya (misalnya proses pembayaran biaya formulir PMB yang akan muncul di menu Tagihan).</p>', '1', '2', '30', '2026-07-04 02:11:34', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('18', '25', 'Bottom Menu Chat', 'menu-chat', '<p>Menu <strong>Chat</strong> yang dapat diakses melalui deretan ikon menu di bagian bawah layar (<em>Bottom Navigation</em>) merupakan jalur komunikasi resmi yang menghubungkan orang tua murid dengan pihak sekolah atau pusat layanan (Admin/Customer Service) Al Azhar.</p>\r\n<p>Fasilitas ini telah terintegrasi dengan sistem penjadwalan cerdas (<em>smart routing</em>), sehingga antarmukanya akan beradaptasi secara otomatis berdasarkan hari dan jam operasional kerja.</p>\r\n<h3>1. Tampilan Hari Kerja (Senin - Jumat)</h3>\r\n<p>Pada saat jam dan hari operasional aktif, Menu Chat akan menampilkan antarmuka <strong>Ruang Obrolan Langsung (Live Chat Room)</strong>. Anda dapat saling bertukar pesan (mengirim teks, bertanya, atau mengajukan keluhan) dan akan direspons secara langsung (<em>real-time</em>) oleh tim Customer Service kami, mirip dengan aplikasi perpesanan instan pada umumnya.</p>\r\n<h3>2. Tampilan Akhir Pekan (Sabtu - Minggu)</h3>\r\n<p>Apabila Anda mengakses Menu Chat pada saat hari libur akhir pekan atau di luar jam kerja aktif, sistem secara cerdas akan mengganti tampilan Live Chat menjadi <strong>Formulir Tinggalkan Pesan (Offline Message Form)</strong>.</p>\r\n<p>Seperti yang terlihat pada layar, akan muncul instruksi berbunyi <em>"Silakan isi form di bawah ini dan kami akan segera menghubungi Anda"</em>. Anda cukup memastikan data pada kolom berikut:</p>\r\n<ul>\r\n<li><strong>Nama:</strong> Biasanya sudah terisi secara otomatis (<em>auto-filled</em>) dengan nama akun yang sedang Anda gunakan (contoh: Donar Azhar).</li>\r\n<li><strong>Email:</strong> Terisi otomatis dengan alamat email terdaftar (contoh: donarazhar@gmail.com).</li>\r\n<li><strong>Pesan:</strong> Pada kolom kosong ini, ketikkan secara rinci pertanyaan, kendala, atau permohonan informasi yang ingin Anda sampaikan.</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783131970_WhatsApp Image 2026-07-04 at 09.21.04.jpeg" alt="" width="327" height="709"></p>\r\n<h3>3. Mengirim Pesan</h3>\r\n<p>Setelah pesan dirasa cukup jelas, ketuk tombol <strong>Kirim</strong> (ikon pesawat kertas) berwarna biru di bagian bawah. Tiket pesan Anda akan langsung terekam dengan aman ke dalam sistem kami. Begitu jam operasional sekolah kembali aktif pada hari kerja berikutnya, tim Customer Service Al Azhar akan memprioritaskan untuk merespons pesan Anda.</p>', '1', '2', '31', '2026-07-04 02:25:36', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('19', '25', 'Botttom Menu Akun', 'menu-akun-dan-pengaturan', '<table style="border-collapse: collapse; width: 100%;" border="1"><colgroup><col style="width: 49.9405%;"><col style="width: 49.9405%;"></colgroup>\r\n<tbody>\r\n<tr>\r\n<td><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783141925_WhatsApp Image 2026-07-04 at 11.50.18.jpeg" alt="" width="738" height="1600"></td>\r\n<td><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783141935_WhatsApp Image 2026-07-04 at 11.50.19.jpeg" alt="" width="738" height="1600"></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Menu&nbsp;<strong>Akun</strong> merupakan pusat kontrol profil dan pengaturan preferensi pengguna pada aplikasi Al-Azhar Apps. Halaman ini didesain secara bersih dan terstruktur menjadi beberapa blok kartu (card) untuk memudahkan navigasi.</p>\r\n<hr>\r\n<h3>1. Kartu Profil Pengguna (Profile Card)</h3>\r\n<p>Bagian teratas halaman menampilkan kartu profil berwarna biru khas Al-Azhar. Di dalam kartu ini, terdapat informasi utama pengguna:</p>\r\n<ul>\r\n<li><strong>Nama Pengguna:</strong> Menampilkan nama lengkap pemilik akun (contoh: Donar Azhar).</li>\r\n<li><strong>Nomor Telepon:</strong> Menampilkan nomor HP yang terdaftar beserta kode negara (+62).</li>\r\n<li><strong>Alamat Email:</strong> Menampilkan email yang digunakan untuk mendaftar.</li>\r\n</ul>\r\n<h3>2. Bagian Pengaturan (Settings)</h3>\r\n<p>Blok ini berisi berbagai menu untuk memodifikasi pengaturan keamanan dan data akun:</p>\r\n<ul>\r\n<li><strong>Akun:</strong> Menu untuk memperbarui nomor telepon dan alamat email pengguna.</li>\r\n<li><strong>Ganti PIN:</strong> Menu untuk mengubah PIN (Personal Identification Number) guna menjaga keamanan transaksi dan akses aplikasi.</li>\r\n<li><strong>Login Biometrik:</strong> Sebuah tombol geser (<em>toggle</em>) yang memungkinkan pengguna untuk masuk (login) menggunakan sidik jari (<em>fingerprint</em>) atau pemindaian wajah (<em>Face ID</em>).</li>\r\n<li><strong>Auto Update:</strong> Tombol geser (<em>toggle</em>) untuk mengaktifkan pembaruan otomatis saat membuka aplikasi.</li>\r\n<li><strong>Notifikasi:</strong> Pengaturan untuk mengaktifkan atau menonaktifkan notifikasi (pemberitahuan) dari aplikasi.</li>\r\n<li><strong>Akses Lokasi:</strong> Pengaturan untuk memberikan izin akses pelacakan lokasi.</li>\r\n</ul>\r\n<h3>3. Bantuan &amp; Dukungan</h3>\r\n<p>Blok ini menyediakan akses ke informasi layanan pelanggan dan kebijakan legal:</p>\r\n<ul>\r\n<li><strong>Bantuan:</strong> Mengarahkan pengguna ke halaman FAQ (Tanya Jawab) atau layanan dukungan teknis jika mengalami kendala.</li>\r\n<li><strong>Kebijakan Privasi:</strong> Menampilkan halaman ketentuan penggunaan aplikasi dan kebijakan privasi data pengguna.</li>\r\n</ul>\r\n<h3>4. Informasi Aplikasi &amp; Tombol Keluar</h3>\r\n<p>Bagian paling bawah halaman memberikan informasi teknis serta opsi untuk mengakhiri sesi:</p>\r\n<ul>\r\n<li><strong>Informasi Aplikasi:</strong> Menampilkan versi aplikasi saat ini (contoh: Versi 3.15.40) dan nama Developer (YPI Al Azhar).</li>\r\n<li><strong>Tombol Keluar (Logout):</strong> Tombol berukuran besar berwarna merah pekat yang diletakkan di bawah (<em>sticky/bottom</em>). Warna merah digunakan sebagai peringatan visual bahwa ini adalah aksi destruktif (mengakhiri sesi dan keluar dari aplikasi).</li>\r\n</ul>', '1', '2', '32', '2026-07-04 05:06:44', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('20', '32', 'Analisa Modul-Modul', 'analisa-modul-backoffice', '<p><strong>Analisa Modul Backoffice</strong></p>\r\n<p>Dari seluruh halaman yang ada, sistem ini terbagi menjadi beberapa modul utama. Perlu dicatat di awal bahwa aplikasi ini dibangun dengan <strong>arsitektur multi-sekolah dalam satu Yayasan</strong> &mdash; sesuai tagline "<em>One Platform, All Solutions</em>" dan adanya filter "Cari Nama Sekolah" di berbagai laporan. Artinya, satu Yayasan bisa membina banyak sekolah (TK, SD, dst.) dalam satu platform yang sama, dan data antar-sekolah tersebut saling terhubung &mdash; bukan aplikasi yang berdiri sendiri per sekolah.</p>\r\n<hr>\r\n<h3>A. Modul Dashboard &amp; Laporan (Eksekutif &amp; Analitik)</h3>\r\n<ul>\r\n<li><strong>Dashboard Summary &amp; Keuangan</strong>: Menampilkan ringkasan penerimaan dana, piutang, diskon, serta grafik pencapaian uang sekolah dan uang pangkal.</li>\r\n<li><strong>Dashboard Murid</strong>: Berisi <strong>dua jenis statistik yang berbeda tujuan</strong>:\r\n<ul>\r\n<li><strong>Funnel PMB</strong> &mdash; corong pendaftaran murid <em>baru</em>: Animo (minat) &rarr; Tercatat &rarr; menjadi Calon Murid.</li>\r\n<li><strong>Siklus Murid Aktif</strong> &mdash; statistik murid <em>lama</em> yang sudah terdaftar: Total Aktif &rarr; Daftar Ulang &rarr; Lulus &rarr; Pindah/Keluar.</li>\r\n</ul>\r\nKeduanya sering tertampil berdampingan di dashboard, namun mewakili tahap yang berbeda dalam siklus hidup murid (murid baru vs murid yang sudah berjalan).</li>\r\n</ul>\r\n<hr>\r\n<h3>B. Modul Penerimaan Murid Baru (PMB)</h3>\r\n<ul>\r\n<li><strong>Master Gelombang PMB</strong>: Pengaturan gelombang pendaftaran (tanggal buka/tutup, jatuh tempo) per jenjang dan tahun ajaran.</li>\r\n<li><strong>Animo &amp; Pendaftaran</strong>: Pendaftaran awal (animo) yang merekam data dasar sebelum melengkapi formulir seutuhnya. Proses ini mensyaratkan <strong>pembayaran Uang Formulir</strong> sebagai gerbang pertama sebelum calon murid bisa lanjut ke tahap ujian.</li>\r\n<li><strong>Ujian &amp; Kelulusan PMB</strong>: Penjadwalan ujian, pendataan peserta ujian, input nilai, dan penentuan kelulusan calon murid. Setelah dinyatakan lulus, calon murid harus melunasi <strong>Uang Pangkal (DSP)</strong> sebagai gerbang kedua sebelum resmi menjadi murid aktif.</li>\r\n<li><strong>Data Calon Murid Lintas Sekolah</strong> <em>(temuan tambahan)</em>: Modul ini mencatat kolom <strong>Sekolah Asal</strong> dan <strong>Sekolah Tujuan</strong>, yang mengindikasikan sistem juga melacak <strong>perpindahan/kontinuitas murid antar-sekolah dalam satu Yayasan</strong> &mdash; misalnya murid yang lulus dari jenjang TK secara otomatis terdaftar sebagai calon murid di jenjang SD milik yayasan yang sama. Ini adalah jalur PMB internal yang berbeda dari pendaftaran murid baru dari luar.</li>\r\n</ul>\r\n<hr>\r\n<h3>C. Modul Akademik &amp; Master Data Sekolah</h3>\r\n<ul>\r\n<li><strong>Master Sekolah &amp; Profil</strong>: Menyimpan identitas resmi sekolah (NPSN, SK, Akreditasi, Lokasi) dan struktur kepegawaian pimpinan.</li>\r\n<li><strong>Rombongan Belajar (Rombel) &amp; Kelas</strong>: Pemetaan murid ke dalam kelas. Satu Rombel dibentuk dari kombinasi <strong>Tahun Ajaran, Tingkat Kelas, Ruangan, Program</strong>, dan satu <strong>Wali Kelas</strong> (dari data Pegawai).</li>\r\n<li><strong>Kurikulum &amp; Program</strong>: Pengaturan jadwal belajar, mata pelajaran, serta program pendidikan (Reguler, Bilingual, dsb).</li>\r\n<li><strong>Kenaikan Kelas &amp; Kelulusan</strong>: Proses di akhir tahun ajaran ini memiliki <strong>dua cabang</strong>: murid tingkat menengah dipindahkan (naik) ke rombel tingkat lebih tinggi di tahun ajaran baru, sedangkan murid tingkat akhir diproses menjadi status <strong>Lulus</strong>, yang datanya kemudian tersambung ke modul cetak Ijazah.</li>\r\n<li><strong>Kalender Akademik</strong> <em>(temuan tambahan)</em>: Terdapat menu Kalender di bagian Administrasi, kemungkinan untuk mengatur agenda dan hari libur akademik sekolah.</li>\r\n</ul>\r\n<hr>\r\n<h3>D. Modul Keuangan &amp; Pembayaran</h3>\r\n<ul>\r\n<li><strong>Komponen Biaya</strong>: Pengaturan Biaya SPP (Uang Sekolah), Uang Pangkal, dan Biaya Daftar Ulang &mdash; masing-masing punya master data terpisah per Tahun Ajaran, Tingkat Kelas, dan Program.</li>\r\n<li><strong>Tagihan Murid</strong>: Sistem memisahkan tagihan berdasarkan status keanggotaan siswa:\r\n<ul>\r\n<li><strong>Calon Murid</strong> ditagih Uang Formulir dan Uang Pangkal (DSP) selama proses PMB.</li>\r\n<li><strong>Murid aktif</strong> ditagih SPP bulanan dan Uang Daftar Ulang setiap awal tahun ajaran.</li>\r\n</ul>\r\nSetiap tagihan dilengkapi <strong>Virtual Account (VA)</strong> dan <strong>No. Reference</strong> untuk pelacakan status lunas atau piutang secara otomatis.</li>\r\n<li><strong>Sistem Diskon/Potongan</strong>: Pengajuan diskon biaya pendidikan untuk murid aktif, dengan 6 kategori: Prestasi Kejuaraan, Prestasi Rapot, Hafalan Al-Quran, Saudara Kandung, Anak Pegawai, dan Lulusan Yayasan (YPI). Setiap pengajuan mensyaratkan minimal satu dokumen bukti pendukung, dan nominalnya langsung mengurangi tagihan yang bersangkutan.</li>\r\n<li><strong>Fitur Angsuran</strong> <em>(temuan tambahan, belum terekspos detail)</em>: Terdapat menu "Angsuran" di bagian Master Data, kemungkinan untuk mendukung skema cicilan pembayaran Uang Pangkal atau Daftar Ulang, meski detail formnya belum terlihat dari screenshot yang tersedia.</li>\r\n</ul>\r\n<hr>\r\n<h3>E. Modul Pelengkap &amp; Kepegawaian</h3>\r\n<ul>\r\n<li><strong>Personnel / Kepegawaian</strong>: Data lengkap staf/guru (NIK, NIP, pangkat, jabatan, riwayat pendidikan, data keluarga).</li>\r\n<li><strong>Sarana Prasarana &amp; Ekstrakurikuler</strong>: Pendataan fasilitas sekolah (ukuran ruangan, kapasitas) dan kegiatan tambahan murid, termasuk biaya ekskul dan data pelatih.</li>\r\n<li><strong>Prestasi Murid</strong>: Pencatatan jejak prestasi murid di berbagai tingkatan (sekolah, kabupaten, nasional, dst). Modul ini berbeda tujuan dari kategori "Prestasi" di menu Diskon &mdash; yang satu adalah <strong>portofolio riwayat lomba</strong>, sedangkan yang lain adalah <strong>klaim potongan biaya</strong> berdasarkan prestasi tersebut. Kedua modul beririsan datanya, namun fungsinya terpisah.</li>\r\n<li><strong>Jurnal &amp; Cetak Dokumen</strong>: Sidebar menamai grup ini "Jurnal &amp; E-Rapot", yang mengindikasikan adanya modul <strong>Jurnal Mengajar</strong> (kemungkinan pencatatan aktivitas belajar harian guru) yang belum terekspos detail dari screenshot. Sub-modul yang sudah terlihat: generate/download <strong>E-Rapot</strong> dan <strong>Ijazah</strong>, difilter berdasarkan Kelas, Rombel, dan Tahun Ajaran.</li>\r\n<li><strong>Manajemen User</strong>: Pengaturan akun pengguna, role (peran), status, dan otorisasi akses LMS. Terdapat juga <strong>Log Activity</strong> &mdash; fitur audit trail yang mencatat setiap aktivitas user (siapa mengubah data apa, dan kapan) untuk kebutuhan keamanan dan akuntabilitas sistem.</li>\r\n</ul>\r\n<hr>\r\n<h3>Kesimpulan</h3>\r\n<p>Al Azhar Apps merupakan <strong>platform SIS (Sistem Informasi Sekolah) multi-tenant</strong> yang dirancang untuk satu Yayasan yang membina beberapa sekolah sekaligus. Lima modul utamanya &mdash; Dashboard/Laporan, PMB, Akademik, Keuangan, dan Pelengkap/Kepegawaian &mdash; saling terhubung melalui satu alur besar: <strong>calon murid masuk lewat funnel PMB (dengan dua gerbang pembayaran: formulir dan uang pangkal) &rarr; resmi menjadi murid dan ditempatkan ke Rombel &rarr; mengikuti siklus akademik tahunan (naik kelas atau lulus) &rarr; selama aktif, dikenai tagihan berkala (SPP, daftar ulang) yang bisa dipotong lewat sistem diskon dan dilacak otomatis via Virtual Account</strong>.</p>\r\n<p>Yang membuat sistem ini berbeda dari SIS generik adalah dua hal: <strong>jalur kontinuitas murid antar-sekolah dalam satu Yayasan</strong> (misalnya otomatis dari TK ke SD) dan <strong>pemisahan tegas antara tagihan Calon Murid vs Murid aktif</strong>, yang mencerminkan business logic khas institusi pendidikan berjenjang di bawah satu payung yayasan.</p>', '1', NULL, '86', '2026-07-06 01:07:11', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('21', '24', 'Analisa Gambaran ERD', 'analisa-gambaran-erd', '<p><strong>Gambaran ERD (Entity Relationship Diagram)</strong></p>\r\n<p>Berdasarkan analisa database relasional yang dibutuhkan untuk mengakomodasi layar-layar tersebut, berikut adalah gambaran utama ERD-nya. (Diagram ini berfokus pada entitas utama agar mudah dipahami)</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783392177_ERD.jpg" alt="" width="868" height="464"></p>\r\n<pre><code class="language-mermaid">\r\nerDiagram\r\n    YAYASAN ||--o{ SEKOLAH : membina\r\n    SEKOLAH ||--o{ PEGAWAI : mempekerjakan\r\n    PEGAWAI ||--o| USER : "punya akun"\r\n    SEKOLAH ||--o{ TAHUN_AJARAN : "beroperasi pada"\r\n    SEKOLAH ||--o{ PROGRAM : menawarkan\r\n    SEKOLAH ||--o{ ROMBEL : memiliki\r\n    SEKOLAH ||--o{ RUANGAN : memiliki\r\n    SEKOLAH ||--o{ KURIKULUM : menetapkan\r\n    SEKOLAH ||--o{ SARANA_PRASARANA : memiliki\r\n    SEKOLAH ||--o{ EKSTRAKURIKULER : menyediakan\r\n    SEKOLAH ||--o{ GELOMBANG_PENDAFTARAN : membuka\r\n\r\n    TAHUN_AJARAN ||--o{ ROMBEL : "berlaku utk"\r\n    TAHUN_AJARAN ||--o{ MURID : "mendaftar pada"\r\n    TAHUN_AJARAN ||--o{ UANG_SEKOLAH : "berlaku utk"\r\n    TAHUN_AJARAN ||--o{ UANG_PANGKAL : "berlaku utk"\r\n    TAHUN_AJARAN ||--o{ UANG_DAFTAR_ULANG : "berlaku utk"\r\n    TAHUN_AJARAN ||--o{ GELOMBANG_PENDAFTARAN : "berlaku utk"\r\n\r\n    PROGRAM ||--o{ ROMBEL : mengelompokkan\r\n    PROGRAM ||--o{ MURID : diikuti\r\n    RUANGAN ||--o{ ROMBEL : ditempati\r\n    PEGAWAI ||--o{ ROMBEL : "jadi wali kelas"\r\n    KURIKULUM ||--o{ MATA_PELAJARAN : terdiri\r\n\r\n    ROMBEL ||--o{ MURID : menampung\r\n    MURID ||--o{ TRANSAKSI : melakukan\r\n    MURID ||--o{ TAGIHAN : menerima\r\n    MURID ||--o{ DISKON : mengajukan\r\n    MURID ||--o{ PRESTASI : mencatat\r\n    MURID ||--o{ KENAIKAN_KELAS : mengalami\r\n    MURID ||--o{ E_RAPOT : memiliki\r\n    MURID ||--o| IJAZAH : menerima\r\n    MURID ||--o{ EKSTRAKURIKULER_MURID : mengikuti\r\n    EKSTRAKURIKULER ||--o{ EKSTRAKURIKULER_MURID : diikuti\r\n\r\n    GELOMBANG_PENDAFTARAN ||--o{ JADWAL_UJIAN : mencakup\r\n    GELOMBANG_PENDAFTARAN ||--o{ CALON_MURID : menaungi\r\n    JADWAL_UJIAN ||--o{ PESERTA_UJIAN : melibatkan\r\n    CALON_MURID ||--o{ PESERTA_UJIAN : "ikut ujian sbg"\r\n    CALON_MURID ||--o| KELULUSAN_PESERTA : dievaluasi\r\n    CALON_MURID ||--o| MURID : "menjadi (jika diterima)"\r\n    CALON_MURID ||--o{ TRANSAKSI : "bayar formulir/DSP"\r\n\r\n    USER ||--o{ LOG_ACTIVITY : menghasilkan\r\n\r\n    SEKOLAH {\r\n        id id\r\n        string npsn\r\n        string nama_sekolah\r\n        string alamat\r\n        int yayasan_id\r\n    }\r\n    MURID {\r\n        id id\r\n        string nis\r\n        string nisn\r\n        string nama\r\n        string status\r\n        int rombel_id\r\n        int program_id\r\n        int tahun_ajaran_id\r\n    }\r\n    CALON_MURID {\r\n        id id\r\n        string no_registrasi\r\n        string nama\r\n        string jenjang\r\n        string status_pendaftaran\r\n        int gelombang_id\r\n    }\r\n    GELOMBANG_PENDAFTARAN {\r\n        id id\r\n        string nama_gelombang\r\n        date tgl_buka\r\n        date tgl_tutup\r\n        date jatuh_tempo\r\n        int target\r\n    }\r\n    JADWAL_UJIAN {\r\n        id id\r\n        string nama_ujian\r\n        string tipe_ujian\r\n        int ruangan_id\r\n    }\r\n    PESERTA_UJIAN {\r\n        id id\r\n        int calon_murid_id\r\n        int jadwal_ujian_id\r\n        float nilai\r\n    }\r\n    KELULUSAN_PESERTA {\r\n        id id\r\n        int peserta_ujian_id\r\n        string status\r\n    }\r\n    UANG_SEKOLAH {\r\n        id id\r\n        int tahun_ajaran_id\r\n        string tingkat_kelas\r\n        int program_id\r\n        float nominal\r\n    }\r\n    UANG_PANGKAL {\r\n        id id\r\n        int tahun_ajaran_id\r\n        string komponen\r\n        float nominal\r\n    }\r\n    UANG_DAFTAR_ULANG {\r\n        id id\r\n        int tahun_ajaran_id\r\n        string komponen_biaya\r\n        float nominal\r\n        date jatuh_tempo\r\n    }\r\n    TAGIHAN {\r\n        id id\r\n        int murid_id\r\n        string jenis_biaya\r\n        float nominal\r\n        string status\r\n    }\r\n    TRANSAKSI {\r\n        id id\r\n        int murid_id\r\n        string no_reference\r\n        string va\r\n        float nominal\r\n        date tanggal\r\n    }\r\n    DISKON {\r\n        id id\r\n        int murid_id\r\n        string kategori\r\n        float besar_potongan\r\n        string status_approval\r\n    }\r\n    PRESTASI {\r\n        id id\r\n        int murid_id\r\n        string bidang\r\n        string jenis_lomba\r\n        string juara\r\n        string tingkat\r\n    }\r\n    KENAIKAN_KELAS {\r\n        id id\r\n        int murid_id\r\n        int rombel_asal\r\n        int rombel_tujuan\r\n        string status\r\n    }\r\n    E_RAPOT {\r\n        id id\r\n        int murid_id\r\n        string term\r\n        string kelengkapan\r\n    }\r\n    IJAZAH {\r\n        id id\r\n        int murid_id\r\n        date tgl_lulus\r\n    }\r\n    USER {\r\n        id id\r\n        int pegawai_id\r\n        string role\r\n        string username\r\n    }\r\n    LOG_ACTIVITY {\r\n        id id\r\n        int user_id\r\n        string aktivitas\r\n        datetime waktu\r\n    }\r\n</code></pre>', '1', NULL, '92', '2026-07-06 01:11:18', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('22', '29', 'Analisa Workflow Backoffice', 'panduan-membaca-alur-flow-utama-diagram', '<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783473445_workflow backoffice.png" alt="" width="512" height="768"></p>\r\n<p>Berikut alur yang sudah disesuaikan dengan tampilan UI yang sebenarnya, dijelaskan selangkah demi selangkah dengan bahasa sederhana.</p>\r\n<hr>\r\n<h3>A. Alur PMB (Penerimaan Murid Baru)</h3>\r\n<p>Bayangkan ini seperti <strong>funnel/corong</strong> &mdash; dari banyak pendaftar, hanya yang lolos &amp; bayar yang akhirnya jadi murid resmi. Ada dua kemungkinan jalur pembayaran: <strong>Tanpa Cicilan (Reguler)</strong> dan <strong>Dengan Cicilan</strong>. Kedua jalur ini sama persis di awal, dan baru bercabang setelah calon murid dinyatakan lulus ujian.</p>\r\n<h4>A.1 Tahap Persiapan (dilakukan Backoffice/Sekolah)</h4>\r\n<p><strong>1. Setting komponen biaya &amp; Gelombang Pendaftaran</strong><br>Sebelum pendaftaran dibuka, tim Backoffice sekolah menyiapkan dua hal di sistem:</p>\r\n<ul>\r\n<li>Komponen <strong>Uang Pangkal</strong> dan <strong>Uang Sekolah (SPP)</strong> beserta rinciannya.</li>\r\n<li><code>GELOMBANG_PMB</code> &mdash; periode pendaftaran (tanggal buka/tutup) per jenjang dan <code>TAHUN_AJARAN</code>.</li>\r\n</ul>\r\n<h4>A.2 Tahap Pendaftaran Awal (dilakukan Orang Tua/Murid &mdash; OTM)</h4>\r\n<p><strong>2. Calon murid daftar (status: Animo)</strong><br>Orang tua melakukan pendaftaran awal melalui aplikasi &rarr; data masuk ke tabel <code>CALON_MURID</code> dengan status awal <strong>Animo</strong>.</p>\r\n<p><strong>3. Bayar Uang Formulir (gerbang pertama)</strong><br>Sebelum lanjut ke tahap berikutnya, calon murid wajib membayar <strong>Uang Formulir</strong> melalui menu Tagihan di aplikasi (metode QRIS atau lainnya). Kalau belum bayar, status akan "macet" di sini dan tidak bisa lanjut.</p>\r\n<p><strong>4. Lengkapi Identitas</strong><br>Setelah formulir lunas, OTM melengkapi data <strong>Asal Sekolah</strong> dan <strong>Profil Murid</strong> secara menyeluruh, lalu mengajukan data tersebut untuk diverifikasi sekolah.</p>\r\n<h4 style="color: #1885c4;">A.3 Tahap Ujian Masuk</h4>\r\n<p><strong>5. Sekolah mengirimkan Kartu Ujian</strong><br>Setelah data disetujui, Backoffice mengirimkan <strong>Kartu Ujian</strong> ke akun OTM.</p>\r\n<p><strong>6. OTM mendapatkan kartu &amp; anak mengikuti ujian</strong><br>OTM mengunduh Kartu Peserta Ujian dari aplikasi (wajib ditunjukkan saat ujian berlangsung), lalu anak mengikuti tes sesuai jadwal.</p>\r\n<h4>A.4 Tahap Penilaian &amp; Pengumuman Kelulusan (dilakukan Backoffice)</h4>\r\n<p><strong>7. Input &amp; Upload Nilai</strong><br>Tim Backoffice men-download template nilai, mengisi hasil ujian sesuai format, lalu mengunggah (upload) nilai tersebut ke sistem.</p>\r\n<p><strong>8. Meluluskan &amp; Mengirim Notifikasi</strong><br>Calon murid yang memenuhi syarat diluluskan (submit kelulusan) di sistem, lalu notifikasi kelulusan otomatis dikirim ke OTM.</p>\r\n<blockquote>Di titik inilah alur mulai <strong>bercabang menjadi dua jalur</strong>, tergantung skema pembayaran Uang Pangkal yang dipilih OTM: <strong>Tanpa Cicilan</strong> atau <strong>Dengan Cicilan</strong>.</blockquote>\r\n<h4 style="color: #22c55e;">A.5.a Jalur Tanpa Cicilan &mdash; Pembayaran Uang Pangkal (Gerbang Kedua)</h4>\r\n<p><strong>9. Terima notifikasi &amp; syarat ketentuan UP</strong><br>OTM menerima notifikasi lulus ujian sekaligus notifikasi syarat &amp; ketentuan Uang Pangkal (UP). OTM membuka menu tersebut untuk melihat komponen biaya UP, lalu menekan <strong>Setuju</strong> dan menerima file PDF rincian biaya.</p>\r\n<p><strong>10. Bayar Uang Pangkal secara penuh</strong><br>Tagihan UP muncul di menu Tagihan aplikasi. OTM membayar komponen UP secara <strong>lunas sekaligus</strong>.</p>\r\n<p><strong>11. Status berubah menjadi Aktif</strong><br>Setelah pembayaran terkonfirmasi, sistem membuat record baru di tabel <code>MURID</code> dengan status <strong>Aktif</strong>, dan siswa resmi terdaftar.</p>\r\n<h4 style="color: #7c3aed;">A.5.b Jalur Dengan Cicilan &mdash; Pengajuan Angsuran Uang Pangkal</h4>\r\n<p><strong>9. Terima notifikasi, baca syarat, lalu ajukan cicilan langsung ke sekolah</strong><br>Sama seperti jalur reguler, OTM menerima notifikasi syarat &amp; ketentuan UP dan menekan Setuju. Namun jika OTM ingin mencicil, OTM harus <strong>datang langsung ke sekolah (Tata Usaha)</strong> untuk mengajukan permohonan skema angsuran &mdash; proses ini dilakukan secara luring/tatap muka, bukan melalui aplikasi.</p>\r\n<p><strong>10. Persetujuan angsuran</strong><br>Tim Backoffice sekolah memproses permohonan sesuai ketentuan jumlah angsuran yang ditetapkan Yayasan. <strong>Jika permohonan lebih dari 3 kali angsuran</strong>, permohonan diteruskan ke <strong>Direktorat Keuangan</strong> untuk mendapat persetujuan (approval) khusus sebelum skema cicilan berlaku.</p>\r\n<p><strong>11. Pembayaran bertahap (minimal 50% di termin pertama)</strong><br>Setelah disetujui, tagihan UP muncul di menu Tagihan sudah disesuaikan dengan jadwal cicilan.</p>\r\n<blockquote style="border-left-color: #eab308; background: #fef9c3;"><strong>Ketentuan penting:</strong> status anak baru diproses <strong>Aktif</strong> apabila pembayaran termin pertama sudah mencapai minimal <strong>50% dari total Uang Pangkal</strong>.</blockquote>\r\n<p>&nbsp;</p>\r\n<p><strong>12. Status Aktif &amp; penempatan Rombel</strong><br>Setelah syarat 50% terpenuhi, siswa berstatus Aktif dan Tata Usaha menempatkan siswa ke <code>ROMBEL</code> yang sesuai &mdash; sama seperti jalur reguler, hanya pelunasan sisa UP dilakukan bertahap sesuai akad yang disetujui.</p>\r\n<blockquote><strong>Intinya:</strong> Kedua jalur PMB sama-sama melewati 2 gerbang pembayaran &mdash; Uang Formulir (di awal) dan Uang Pangkal (setelah lulus ujian). Bedanya hanya pada <em>cara</em> membayar gerbang kedua: <strong>lunas sekaligus</strong> (jalur reguler, langsung via aplikasi) atau <strong>bertahap</strong> (jalur cicilan, butuh pengajuan tatap muka ke sekolah dan minimal 50% di termin pertama untuk aktivasi).</blockquote>\r\n<hr>\r\n<h3>B. Alur Akademik (Pengelolaan Kelas)</h3>\r\n<p><strong>1. Siapkan "ruang" dan "kelas" (Rombel)</strong><br>Sebelum tahun ajaran mulai, admin membuat <code>ROMBEL</code> (misal "TK B - Rombel A"). Satu Rombel butuh <strong>5 informasi</strong>, bukan cuma 3:<br>- <code>TAHUN_AJARAN</code> &mdash; Rombel ini untuk tahun ajaran berapa<br>- <code>TINGKAT_KELAS</code> &mdash; misal TK A, TK B<br>- <code>RUANGAN</code> &mdash; fisik ruang kelasnya di mana ⭐ <em>tambahan</em><br>- <code>PROGRAM</code> &mdash; Reguler/Bilingual dsb ⭐ <em>tambahan</em><br>- <code>PEGAWAI</code> &mdash; siapa Wali Kelasnya</p>\r\n<p><strong>2. Isi Rombel dengan murid</strong><br>Murid (baik yang baru lulus PMB &mdash; dari jalur reguler maupun cicilan, atau murid lama naik kelas) dimasukkan ke dalam Rombel tersebut sesuai program &amp; tingkat kelasnya.</p>\r\n<p><strong>3. Di akhir tahun ajaran &mdash; dua kemungkinan jalan</strong><br>Fitur "Kenaikan Kelas &amp; Kelulusan" punya <strong>dua cabang</strong>, bukan cuma satu:</p>\r\n<ul>\r\n<li><strong>Cabang Naik Kelas</strong> (untuk murid yang belum tingkat akhir):<br>Sistem update <code>rombel_id</code> murid ke Rombel di tingkat lebih tinggi, untuk <code>TAHUN_AJARAN</code> berikutnya.</li>\r\n<li><strong>Cabang Lulus</strong> ⭐ <em>tambahan yang sebelumnya belum masuk</em> (untuk murid tingkat akhir):<br>Murid tidak "naik kelas" lagi, tapi statusnya jadi <strong>Lulus</strong> &rarr; nanti datanya muncul di modul <code>IJAZAH</code> untuk dicetak.</li>\r\n</ul>\r\n<p>Ada juga tombol <strong>Batalkan</strong> &mdash; kalau admin salah proses, murid bisa dikembalikan dari status "Sudah Diproses" ke "Belum Diproses" sebelum ditekan <strong>Submit</strong> (final).</p>\r\n<blockquote><strong>Intinya:</strong> Rombel itu seperti "kotak" yang butuh 5 komponen (tahun ajaran, tingkat, ruangan, program, wali kelas). Dan di akhir tahun, murid punya 2 nasib: pindah ke rombel yang lebih tinggi, atau lulus dan keluar dari sistem akademik (tapi tetap punya data historis untuk ijazah).</blockquote>\r\n<hr>\r\n<h3>C. Alur Keuangan &amp; Diskon</h3>\r\n<p>Ini bagian yang paling penting dikoreksi: <strong>jangan campur tagihan Calon Murid dengan tagihan Murid aktif</strong> &mdash; keduanya beda level.</p>\r\n<p><strong>1. Dua sumber tagihan yang berbeda</strong></p>\r\n<table border="1" cellspacing="0" cellpadding="5">\r\n<thead>\r\n<tr>\r\n<th>Siapa yang ditagih</th>\r\n<th>Jenis Tagihan</th>\r\n<th>Kapan</th>\r\n</tr>\r\n</thead>\r\n<tbody>\r\n<tr>\r\n<td><code>CALON_MURID</code> (belum resmi murid)</td>\r\n<td>Uang Formulir, Uang Pangkal (DSP) &mdash; lunas sekaligus atau bertahap (cicilan)</td>\r\n<td>Selama proses PMB</td>\r\n</tr>\r\n<tr>\r\n<td><code>MURID</code> (sudah resmi &amp; aktif)</td>\r\n<td>SPP bulanan (Uang Sekolah), Uang Daftar Ulang</td>\r\n<td>Setiap bulan / setiap awal tahun ajaran</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Jadi alurnya: Calon Murid dulu ditagih formulir &amp; pangkal (baik lunas maupun cicilan) &rarr; begitu resmi jadi Murid Aktif &rarr; baru ditagih SPP bulanan dan (di tahun berikutnya) Uang Daftar Ulang.</p>\r\n<p><strong>2. Pengajuan Diskon (khusus untuk Murid aktif)</strong><br>Kalau seorang murid punya kriteria tertentu, admin ajukan diskon lewat 6 kategori:<br>- Prestasi Kejuaraan<br>- Prestasi Rapot<br>- Hafalan Al-Quran<br>- Saudara Kandung<br>- Anak Pegawai<br>- Lulusan YPIA</p>\r\n<p>Setiap pengajuan butuh minimal 1 dokumen bukti (sertifikat, KK, dll), dan tersimpan di tabel <code>DISKON</code> yang terhubung langsung ke <code>MURID</code>.</p>\r\n<p><strong>3. Kalkulasi tagihan akhir</strong><br>Saat tagihan (SPP/Daftar Ulang) mau ditampilkan ke orang tua:</p>\r\n<pre>Tagihan Akhir = Nominal Dasar - Potongan Diskon (jika ada)</pre>\r\n<p>Setiap tagihan dilengkapi <strong>Virtual Account (VA)</strong> dan <strong>No. Reference</strong>, supaya sistem otomatis tahu status: <strong>Lunas</strong> atau <strong>Piutang/Tunggakan</strong> &mdash; ini yang muncul di Dashboard Summary ("Total Piutang &amp; Tunggakan").</p>\r\n<blockquote><strong>Intinya:</strong> Ada 2 "kasir" berbeda dalam sistem &mdash; kasir untuk Calon Murid (formulir + pangkal, lunas atau cicilan) dan kasir untuk Murid aktif (SPP + daftar ulang). Diskon hanya berlaku untuk kasir Murid aktif, dan semua pembayaran dilacak otomatis lewat VA.</blockquote>\r\n<hr>\r\n<h3>Peta Besar: Bagaimana Ketiga Alur Ini Saling Terhubung</h3>\r\n<pre>[PMB] Calon Murid daftar\r\n   &rarr; bayar Formulir\r\n   &rarr; ikut Ujian\r\n   &rarr; Lulus, lalu pilih skema Uang Pangkal:\r\n        (a) Lunas sekaligus via aplikasi, ATAU\r\n        (b) Cicilan: ajukan ke sekolah &rarr; approval (+Direktorat Keuangan jika &gt;3x) &rarr; bayar min. 50% termin pertama\r\n   &rarr; jadi MURID resmi (Aktif) &amp; ditempatkan ke ROMBEL\r\n        &darr;\r\n[Akademik] Murid belajar 1 tahun ajaran\r\n   &rarr; akhir tahun: Naik Kelas (pindah rombel) ATAU Lulus (jadi Ijazah)\r\n        &darr;\r\n[Keuangan] Selama jadi Murid aktif:\r\n   &rarr; ditagih SPP bulanan + Daftar Ulang tahunan\r\n   &rarr; bisa dapat Diskon (potong tagihan)\r\n   &rarr; bayar via VA &rarr; status Lunas/Piutang terpantau di Dashboard\r\n</pre>\r\n<p>Dengan koreksi ini, workflow sudah mencakup detail penting yang sebelumnya belum terlihat: adanya <strong>2 skema pembayaran Uang Pangkal</strong> (lunas vs cicilan) yang menentukan kapan status calon murid resmi berubah menjadi Aktif, lengkap dengan mekanisme approval berjenjang untuk pengajuan cicilan lebih dari 3 kali angsuran.</p>', '1', NULL, '1', '2026-07-06 01:14:54', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('23', '26', 'Modul Dashboard Menu Summary', 'dashboard-menu-summary', '<p>Halaman <strong>Dashboard Summary</strong> merupakan pusat informasi eksekutif (Executive Dashboard) yang memberikan ringkasan data finansial dan status penerimaan murid secara real-time untuk tahun ajaran yang sedang aktif.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783301992_1-1 dashboard-summary.png" alt="" width="908" height="899"></p>\r\n<h3>Komponen Utama Halaman</h3>\r\n<h4>1. Navigasi dan Filter</h4>\r\n<ul>\r\n<li><strong>Sidebar Kiri:</strong> Memuat menu navigasi utama seperti Dashboard (Summary, Murid), Transaksi (PMB), Laporan, dan Master Data Sekolah (Data Murid, Profile, Rombel, Kurikulum, dll).</li>\r\n<li><strong>Top Bar:</strong> Menampilkan breadcrumb, notifikasi, dan profil pengguna aktif (contoh: Admin Sekolah).</li>\r\n<li><strong>Filter:</strong> Tombol filter di pojok kanan atas memungkinkan admin untuk menyesuaikan rentang data yang ditampilkan (misalnya memfilter berdasarkan tahun ajaran atau jenjang).</li>\r\n</ul>\r\n<h4>2. Kartu Indikator Utama (Key Performance Indicators)</h4>\r\n<p>Menyajikan 5 metrik finansial penting dalam bentuk kartu berwarna agar mudah dibaca dan dievaluasi dengan cepat:</p>\r\n<ul>\r\n<li><strong>Total Penerimaan:</strong> Total dana pendidikan yang telah masuk/diterima secara keseluruhan.</li>\r\n<li><strong>Total Penerimaan Titipan:</strong> Dana titipan yang diterima oleh pihak sekolah.</li>\r\n<li><strong>Total Piutang &amp; Tunggakan:</strong> Jumlah kewajiban pembayaran dari murid yang belum dilunasi.</li>\r\n<li><strong>Total Piutang Titipan:</strong> Jumlah piutang dari dana titipan.</li>\r\n<li><strong>Total Diskon:</strong> Total potongan biaya (diskon) yang telah diberikan kepada murid berdasarkan berbagai kriteria (prestasi, saudara kandung, dll).</li>\r\n</ul>\r\n<h4>3. Banner Total Penerimaan</h4>\r\n<p>Sebuah banner grafis menonjol berwarna hijau yang merinci Total Penerimaan ke dalam tiga rentang waktu:</p>\r\n<ul>\r\n<li>Penerimaan pada bulan berjalan (contoh: Juli 2026).</li>\r\n<li>Penerimaan akumulatif tahun berjalan (Juli s/d saat ini).</li>\r\n<li>Komparasi atau perbandingan dengan total penerimaan pada Tahun Ajaran yang lalu.</li>\r\n</ul>\r\n<h4>4. Grafik Analitik (Charts)</h4>\r\n<p>Menyediakan visualisasi data pergerakan tren sepanjang tahun ajaran:</p>\r\n<ul>\r\n<li><strong>Grafik Penerimaan PMB:</strong> Grafik garis (line chart) yang memantau tren pendaftaran murid baru dari bulan ke bulan.</li>\r\n<li><strong>Grafik Penerimaan - Tagihan Uang Sekolah:</strong> Grafik batang (bar chart) interaktif yang menyandingkan total Tagihan (warna hijau) dengan total Penerimaan aktual (warna biru) per bulannya (dari Juli hingga Juni).</li>\r\n</ul>\r\n<h4>5. Progress Penerimaan Uang Sekolah</h4>\r\n<p>Komponen ini menampilkan persentase rata-rata penerimaan (AVG) secara keseluruhan melalui sebuah <em>progress bar</em> horizontal. Dilengkapi juga dengan rincian persentase konversi atau progress penerimaan uang sekolah per bulan di bawahnya untuk melacak konsistensi pembayaran siswa.</p>\r\n<h4>6. Ringkasan Status Unit/Sekolah</h4>\r\n<p>Dua kartu di bagian bawah menyajikan data capaian yang lebih spesifik berdasarkan unit sekolah (misal: TK Islam Al Azhar 6 Sentra Primer):</p>\r\n<ul>\r\n<li><strong>Penerimaan Murid Baru (Jumlah Siswa):</strong> Menampilkan progres persentase jumlah siswa pendaftar dibandingkan dengan kuota/target siswa baru yang dicanangkan.</li>\r\n<li><strong>Penerimaan Sekolah Tahun Pembelajaran:</strong> Menampilkan ringkasan total uang masuk yang mencakup seluruh komponen biaya (Uang Formulir, Uang Pangkal, Uang Sekolah, Uang Kegiatan, Uang Seragam) beserta jumlah transaksinya.</li>\r\n</ul>', '1', NULL, '69', '2026-07-06 01:37:11', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('24', '26', 'Modul Dashboard Menu Murid', 'dashboard-menu-murid', '<p>Halaman <strong>Dashboard Murid</strong> merupakan pusat pemantauan analitik yang berfokus pada statistik kesiswaan, melingkupi proses Penerimaan Murid Baru (PMB) hingga status murid aktif pada tahun ajaran yang sedang berjalan.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783302149_1-2 dashboard murid.png" alt="" width="930" height="1232"></p>\r\n<h3>Komponen Utama Halaman</h3>\r\n<h4>1. Proses PMB (Penerimaan Murid Baru)</h4>\r\n<p>Bagian ini memberikan visibilitas penuh terhadap corong (funnel) pendaftaran siswa baru:</p>\r\n<ul>\r\n<li><strong>Progress Bar Capaian vs Target:</strong> Indikator visual progres jumlah perolehan siswa dibandingkan dengan target yang ditetapkan.</li>\r\n<li><strong>Kartu Total Animo:</strong> Melacak prospek awal (animo). Menampilkan total animo beserta rincian yang "Sudah Bayar" dan "Belum Bayar" biaya pendaftaran/formulir.</li>\r\n<li><strong>Kartu Total Pendaftar:</strong> Melacak pendaftar yang sedang berproses. Menampilkan rincian status seperti Belum Melengkapi PMB, Lulus, Tidak Lulus, dan Cadangan.</li>\r\n<li><strong>Kartu Calon Murid:</strong> Melacak kandidat yang sudah lolos seleksi awal. Menampilkan rincian pembayaran Uang Pangkal (UP) yang "Sudah Bayar UP" dan "Belum Bayar UP".</li>\r\n</ul>\r\n<h4>2. Jumlah Murid Tahun Berjalan</h4>\r\n<p>Menampilkan 4 metrik status murid pada tahun ajaran aktif melalui kartu indikator warna-warni:</p>\r\n<ul>\r\n<li><strong>Total Aktif:</strong> Jumlah keseluruhan murid yang aktif bersekolah.</li>\r\n<li><strong>Total Daftar Ulang:</strong> Jumlah murid yang sudah melakukan daftar ulang untuk tahun ajaran selanjutnya.</li>\r\n<li><strong>Total Lulus:</strong> Jumlah murid yang telah lulus dari jenjang tersebut.</li>\r\n<li><strong>Pindah Keluar:</strong> Jumlah murid yang mutasi atau pindah sekolah.</li>\r\n</ul>\r\n<h4>3. Grafik Total Murid (Distribusi Status)</h4>\r\n<p>Grafik batang interaktif yang memecah seluruh pergerakan status siswa (mulai dari Animo PMB hingga status akhir seperti Naik Kelas, Lulus, atau Pindah). Komponen ini memberikan gambaran komprehensif tentang distribusi populasi murid di semua tahapan administrasi.</p>\r\n<h4>4. Grafik Jumlah Murid Per Kelas</h4>\r\n<p>Grafik batang sekunder yang berfokus pada kepadatan rombongan belajar:</p>\r\n<ul>\r\n<li>Dilengkapi filter <strong>Semester</strong> (Ganjil/Genap) dan <strong>Tahun Ajaran</strong>.</li>\r\n<li>Menampilkan jumlah murid per tingkat kelas (misalnya: Playgroup, TK A, TK B, Toddler) sehingga admin dapat memantau rasio dan kapasitas kelas.</li>\r\n</ul>\r\n<h4>5. Ringkasan Jumlah PMB</h4>\r\n<p>Sebuah panel khusus yang memberikan kesimpulan cepat mengenai Target, Pendaftar, dan Perolehan akhir siswa baru untuk mempermudah evaluasi akhir panitia PMB.</p>\r\n<h4>6. Daftar Calon Siswa Belum Membayar Formulir</h4>\r\n<p>Tabel interaktif atau <em>actionable list</em> di bagian paling bawah yang menampilkan data calon siswa yang belum melunasi biaya formulir. Tabel ini mencakup detail seperti Nama Calon Siswa, Tujuan Sekolah, Program, Asal Sekolah, No HP, dan Status (contoh: "Belum Dikonfirmasi Ulang"). Fitur ini sangat penting untuk tim administrasi melakukan <em>follow-up</em> kepada orang tua/wali murid.</p>', '1', NULL, '70', '2026-07-06 01:41:46', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('25', '28', 'Modul Transaksi Menu PMB', 'transaksi-penerimaan-murid-baru-pmb', '<p>Halaman <strong>Penerimaan Murid Baru (Transaksi PMB)</strong> merupakan antarmuka krusial dalam siklus operasional pendaftaran siswa baru di sistem Al Azhar Apps. Halaman ini dirancang dengan pendekatan <em>tabbed navigation</em> (navigasi berbasis tab) untuk memecah alur kerja administrasi PMB menjadi tiga fase utama yang terstruktur, memastikan tim panitia dapat melacak status setiap pendaftar secara presisi.</p>\r\n<h3>Komponen Navigasi dan Pencarian</h3>\r\n<p>Di bagian atas antarmuka, terdapat elemen fungsional yang mendukung efisiensi operasional harian:</p>\r\n<ul>\r\n<li><strong>Tab Fase PMB:</strong> Terdiri dari tiga tab utama yaitu <em>Animo</em>, <em>Melengkapi Formulir</em>, dan <em>PMB</em> yang merepresentasikan perjalanan (<em>funnel</em>) calon murid.</li>\r\n<li><strong>Kolom Pencarian (Search):</strong> Memungkinkan pencarian data secara instan berdasarkan nama, nomor registrasi, atau nomor handphone tanpa memuat ulang halaman.</li>\r\n<li><strong>Tombol Filter:</strong> Menyediakan opsi penyaringan data lanjutan (seperti filter berdasarkan gelombang, jenjang, asal sekolah, atau status) untuk mempersempit tabel daftar pendaftar.</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783303143_2-1 transaksi-tab animo.png" alt="" width="782" height="714"></p>\r\n<h3>1. Tab "Animo" (Fase Inisiasi &amp; Pembayaran Formulir)</h3>\r\n<p>Tab <strong>Animo</strong> berfungsi sebagai kolam penampungan awal bagi seluruh prospek yang baru saja membuat akun dan meregistrasikan minat mereka.</p>\r\n<ul>\r\n<li><strong>Tujuan Utama:</strong> Memantau komitmen awal calon siswa melalui pelunasan biaya pendaftaran (Uang Formulir).</li>\r\n<li><strong>Karakteristik Tabel:</strong>\r\n<ul>\r\n<li><code>Uang Formulir</code>: Menampilkan nominal tagihan formulir pendaftaran.</li>\r\n<li><code>Status Pembayaran</code>: Menggunakan komponen label warna yang mencolok (contoh: tag merah muda untuk "Belum Bayar Formulir") untuk memudahkan identifikasi status finansial secara visual.</li>\r\n<li><code>Mengundurkan Diri?</code>: Disediakan <em>dropdown action</em> cepat berwarna hijau bagi admin untuk menandai prospek yang membatalkan pendaftaran, sehingga kebersihan data funnel PMB tetap terjaga.</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783303171_2-2 transaksi-tab melengkapi formulir.png" alt="" width="781" height="714"></p>\r\n<h3>2. Tab "Melengkapi Formulir" (Fase Pemberkasan)</h3>\r\n<p>Setelah calon murid melunasi biaya formulir (sehingga animo terverifikasi), data mereka akan otomatis bermigrasi ke tab <strong>Melengkapi Formulir</strong>.</p>\r\n<ul>\r\n<li><strong>Tujuan Utama:</strong> Memantau progres pengisian kelengkapan berkas fisik maupun digital, detail biodata calon murid, dan data orang tua/wali.</li>\r\n<li><strong>Karakteristik Tabel:</strong>\r\n<ul>\r\n<li>Tampilan tabel disesuaikan dengan menghilangkan kolom tagihan formulir dan menggantinya dengan kolom <code>Aksi</code>.</li>\r\n<li>Kolom <code>Aksi</code> memberikan keleluasaan bagi admin untuk menginspeksi kelengkapan dokumen, melakukan validasi/approval data, atau mengirimkan notifikasi pengingat (<em>reminder</em>) kepada orang tua yang dokumen pendaftarannya belum tuntas.</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783303208_2-3 transaksi-tab PMB.png" alt="" width="792" height="724"></p>\r\n<h3>3. Tab "PMB" (Fase Kewajiban Akhir &amp; Daftar Ulang)</h3>\r\n<p>Tab <strong>PMB</strong> merupakan fase pamungkas di mana calon murid yang berkasnya sudah divalidasi dan telah lolos tahapan seleksi diproses untuk menjadi murid resmi.</p>\r\n<ul>\r\n<li><strong>Tujuan Utama:</strong> Memantau penyelesaian kewajiban finansial akhir, yakni pelunasan Uang Pangkal atau keseluruhan biaya Daftar Ulang (dicantumkan sebagai <em>Uang PMB</em>).</li>\r\n<li><strong>Karakteristik Tabel:</strong>\r\n<ul>\r\n<li><code>Uang PMB</code>: Menampilkan rekapitulasi besaran biaya pendidikan yang harus dilunasi sebagai syarat daftar ulang.</li>\r\n<li>Fase ini menjadi <em>gate</em> terakhir sebelum data calon murid secara sistem dinyatakan valid, direlasikan ke dalam master data <strong>Murid</strong>, dan ditempatkan secara definitif ke dalam <strong>Rombongan Belajar (Rombel)</strong>.</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Pendekatan antarmuka dengan tiga tab ini sukses menciptakan <strong>Pipeline Pendaftaran yang transparan layaknya sistem Kanban</strong>. Petugas administrasi PMB tidak perlu berpindah-pindah modul atau halaman untuk mengelola pendaftar dengan status yang berbeda. Selain itu, penggunaan <em>empty state</em> yang rapi (ilustrasi "Data tidak ada") memberikan *feedback* visual yang menenangkan saat antrean di suatu tahapan telah berhasil diselesaikan (<em>zero-inbox approach</em>).</p>', '1', NULL, '53', '2026-07-06 01:49:07', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('26', '28', 'Modul Laporan Menu Keuangan Murid & Transaksi Murid', 'laporan-keuangan-keuangan-murid-transaksi-murid', '<p>Modul <strong>Laporan Keuangan</strong> pada sistem Al Azhar Apps merupakan pusat pelaporan finansial yang sangat vital bagi pihak manajemen sekolah dan yayasan. Modul ini dipecah menjadi dua sub-menu utama yang saling melengkapi, yakni <em>Keuangan Murid</em> dan <em>Transaksi Murid (Kode Biaya)</em>. Keduanya dirancang khusus untuk memberikan transparansi dan kemudahan <em>tracking</em> arus kas secara detail.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783305030_3-1 laporan-keuangan murid.png" alt="" width="799" height="751"></p>\r\n<h3>1. Sub-menu: Keuangan Murid</h3>\r\n<p>Halaman ini berfokus pada pencatatan <em>ledger</em> atau buku besar status finansial secara spesifik per individu murid. Antarmuka ini dirancang agar admin keuangan dapat dengan cepat menelusuri riwayat tagihan dan identitas pembayaran masing-masing siswa.</p>\r\n<h4>Komponen Pencarian &amp; Filter Lanjutan</h4>\r\n<ul>\r\n<li><strong>Filter Multi-Dimensi:</strong> Berada di dalam panel putih (card) teratas, admin dapat memfilter data dengan presisi menggunakan 5 parameter sekaligus: <code>Sekolah</code>, <code>Tahun Ajaran</code>, <code>Kelas</code>, <code>Program</code>, dan <code>Tipe</code> (misal: Penerimaan).</li>\r\n<li><strong>Tombol Aksi (Terapkan &amp; Reset):</strong> Memberikan kendali kapan kueri pencarian dieksekusi ke <em>database</em>, menghindari beban <em>loading</em> berlebih saat admin masih mengatur beberapa filter secara bersamaan.</li>\r\n<li><strong>Export Data:</strong> Terdapat tombol <code>Export</code> (biru) di pojok kanan atas yang sangat krusial untuk kebutuhan pelaporan eksternal atau audit, memungkinkan data diunduh langsung ke format <em>spreadsheet</em> (Excel/CSV).</li>\r\n</ul>\r\n<h4>Struktur Tabel Data</h4>\r\n<p>Tabel disajikan mendatar dengan menonjolkan kolom-kolom identifikasi finansial seperti: <code>NIS/No Registrasi</code>, <code>Nama Murid</code>, <code>No Reference</code>, dan <code>VA (Virtual Account)</code>. Ketersediaan nomor <em>Virtual Account</em> secara langsung di tabel mempermudah tim <em>finance</em> saat harus melakukan rekonsiliasi atau pencocokan silang secara manual dengan <em>dashboard bank</em>.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783305054_3-2 laporan-transaksi murid (kode biaya).png" alt="" width="809" height="794"></p>\r\n<h3>2. Sub-menu: Transaksi Murid (Kode Biaya)</h3>\r\n<p>Berbeda dengan halaman sebelumnya yang berbasis profil individu murid, halaman <strong>Transaksi Murid</strong> sepenuhnya berorientasi pada <em>cash-flow</em> (arus kas) masuk berdasarkan rentang waktu operasional dan pemisahan rekening bank.</p>\r\n<h4>Komponen Filter Berbasis Waktu &amp; Rekening</h4>\r\n<ul>\r\n<li><strong>Filter Rekening &amp; Tanggal:</strong> Halaman ini menggunakan komponen <em>dropdown</em> <code>Pilih Rekening</code> yang disandingkan dengan sepasang <em>Date Range Picker</em> (Pilih tanggal awal dan akhir). Desain filter ini adalah standar industri yang sangat ideal untuk rutinitas tutup buku harian (<em>daily closing</em>) atau bulanan (<em>month-end closing</em>).</li>\r\n</ul>\r\n<h4>Struktur Tabel Data Transaksional</h4>\r\n<p>Tabel membeberkan baris transaksi historis dengan penekanan pada detail sumber dan peruntukan dana. Kolom seperti <code>Sekolah</code>, <code>Asal Sekolah</code>, dan <code>Bulan</code> (misalnya rincian: "Uang Sekolah Jul 2026") memungkinkan akuntan untuk membedah secara akurat komponen pendapatan (kode biaya) apa saja yang telah berhasil dicairkan pada periode tertentu.</p>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Pendekatan desain antarmuka (UI/UX) pada modul Laporan Keuangan ini sangat mengedepankan prinsip <strong>Data Density &amp; Accessibility</strong> (Kepadatan &amp; Keteraksesan Data). Penempatan formulir filter yang membentang horizontal di atas (<em>top filter bar</em>) bertujuan untuk menyisakan ruang vertikal layar semaksimal mungkin bagi tabel data, sehingga mengurangi kelelahan akibat <em>scrolling</em> panjang. Hadirnya fitur pencarian cepat global dan fasilitas <em>Export</em> menjadikannya sebuah *tool* pelaporan keuangan yang tangguh dan memanjakan penggunanya.</p>', '1', NULL, '54', '2026-07-06 02:28:44', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('27', '27', 'Modul Sekolah Menu Data Murid', 'master-data-murid', '<p>Menu <strong>Data Murid</strong> yang berada di bawah modul "Sekolah" adalah antarmuka utama (<em>Master Data</em>) untuk mengelola seluruh profil siswa yang telah resmi terdaftar di institusi pendidikan terkait.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783307176_4-1 sekolah-data murid.png" alt="" width="922" height="867"></p>\r\n<h3>Fungsi dan Komponen Antarmuka</h3>\r\n<p>Halaman ini dirancang dengan elegan namun sarat akan fungsi esensial untuk memudahkan tim tata usaha (TU) atau admin sekolah dalam menginspeksi dan memutakhirkan profil setiap murid.</p>\r\n<h4>1. Pencarian dan Filter Cerdas</h4>\r\n<ul>\r\n<li><strong>Pencarian Global:</strong> Terdapat kolom pencarian (<em>Search bar</em>) berukuran besar di bagian paling atas untuk melacak data murid secara instan, cukup dengan mengetikkan nama atau NIS tanpa perlu mengatur parameter lainnya.</li>\r\n<li><strong>Panel Filter Ekstensif:</strong> Dengan menekan tombol hijau "Filter", sebuah panel putih interaktif akan muncul. Panel ini memuat empat opsi <em>dropdown</em> utama: <code>Tahun Ajaran</code>, <code>Kelas</code>, <code>Status</code> (semua, aktif, lulus, pindah, dll.), dan <code>Program</code>. Tersedia tombol "Terapkan" dan "Reset" agar kueri perpaduan filter dapat dieksekusi secara manual ke database, meminimalisir loading tak terduga.</li>\r\n</ul>\r\n<h4>2. Tabel Master Data</h4>\r\n<p>Tabel disajikan secara horizontal dan informatif, mengakomodasi rincian fundamental dari profil siswa:</p>\r\n<ul>\r\n<li><strong>Identitas Dasar:</strong> Menampilkan kolom <code>Nama Lengkap</code>, <code>NIS</code> (Nomor Induk Siswa), dan <code>Jenis Kelamin</code>.</li>\r\n<li><strong>Penempatan Akademis:</strong> Kolom <code>Tahun Ajaran</code>, <code>Kelas</code>, <code>Rombel</code> (Rombongan Belajar), dan <code>Program</code> memberikan kejelasan absolut mengenai penempatan siswa pada tahun ajaran yang sedang aktif.</li>\r\n<li><strong>Status:</strong> Diwakili oleh komponen <em>badge</em> atau label warna yang menonjol (contoh: label hijau pastel bertuliskan "Aktif"). Fitur visual ini mempercepat identifikasi apakah seorang murid masih aktif menempuh pendidikan, ataukah sudah berstatus alumni/mutasi.</li>\r\n</ul>\r\n<h4>3. Kolom Aksi (Action)</h4>\r\n<p>Kolom paling kanan (<code>Aksi</code>) disisihkan secara eksklusif untuk tindakan manajerial per baris data, dengan memanfaatkan desain ikonografi untuk menghemat ruang:</p>\r\n<ul>\r\n<li><strong>Icon Pensil (Edit):</strong> Berfungsi memicu formulir pembaruan atau koreksi biodata murid apabila terdapat perubahan informasi krusial (seperti pindah alamat, pergantian nomor handphone wali, dll).</li>\r\n<li><strong>Icon Kaca Pembesar (Detail):</strong> Berfungsi sebagai pintu masuk menuju halaman <em>Profil Detail Siswa</em> yang jauh lebih komprehensif, mencakup riwayat tagihan finansial, riwayat absensi, hingga catatan khusus lainnya.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Halaman Master Data Murid menjunjung tinggi prinsip <strong>Clarity and Efficiency</strong>. Penyusunan <em>layout</em> tabel yang berjarak lega, status berbentuk <em>badge</em> yang kontras, serta mekanisme penyembunyian <em>form filter</em> tingkat lanjut di balik opsi <em>collapse/expand</em> (tombol "Filter"), berhasil menciptakan pengalaman pengguna yang bersih (<em>clean look</em>). Hal ini terbukti mampu menjaga konsentrasi admin sekolah meski harus memproses ribuan baris data siswa setiap harinya.</p>', '1', NULL, '38', '2026-07-06 03:03:11', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('28', '27', 'Modul Sekolah Menu Profile Sekolah', 'profile-sekolah', '<p>Menu <strong>Profile Sekolah</strong> merupakan formulir <em>Master Data</em> terpusat yang menyimpan identitas resmi, lokasi geografis, dan struktur manajerial dari sebuah unit sekolah (misalnya: TK Islam Al Azhar 6 Sentra Primer). Akurasi data di halaman ini amat penting karena informasi di dalamnya seringkali dipanggil oleh sistem untuk mencetak <em>kop</em> surat resmi, kuitansi tagihan, maupun pelaporan kelembagaan.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783307457_4-2 sekolah-profile sekolah.png" alt="" width="850" height="1831"></p>\r\n<h3>Struktur Formulir (Form Sections)</h3>\r\n<p>Mengingat banyaknya data yang harus di-<em>input</em>, antarmuka ini mengelompokkan formulir ke dalam tiga bagian (<em>sections</em>) utama secara vertikal. Pendekatan ini (<em>Chunking</em>) bertujuan agar <em>cognitive load</em> atau beban pikiran pengguna tidak terlalu berat saat mengisi data.</p>\r\n<h4>1. Bagian "Profile" (Identitas &amp; Legalitas Instansi)</h4>\r\n<p>Area ini mengakomodir data-data administratif. <em>Field</em> disusun menggunakan <em>layout</em> dua kolom (<em>two-column grid</em>) untuk memaksimalkan ruang horizontal layar:</p>\r\n<ul>\r\n<li><strong>Data Pokok &amp; Izin:</strong> Memuat <code>NPSN</code>, <code>NIS</code>, <code>Nomor SK IJOP (Ijin Operasional)</code>, dan <code>NPWP</code>.</li>\r\n<li><strong>Informasi Dasar:</strong> Memuat <code>Jenjang</code> (misal: TKA), <code>Nama Sekolah</code>, <code>Tahun Berdiri</code>, <code>Tahun Akreditasi</code>, dan <code>Nilai Akreditasi</code>.</li>\r\n<li><strong>Afiliasi:</strong> Memuat <code>Kategori</code> status sekolah (misal: Cabang Langsung), <code>Nama Yayasan</code>, serta media kontak <code>Email</code> dan <code>Website</code> yayasan.</li>\r\n</ul>\r\n<h4>2. Bagian "Lokasi" (Hierarki Geografis &amp; Pemetaan Visual)</h4>\r\n<p>Berfungsi untuk merekam koordinat dan alamat persis institusi. Desain antarmuka pada sesi ini menggabungkan fungsi teks, <em>dropdown</em> berjenjang, dan pemetaan interaktif:</p>\r\n<ul>\r\n<li><strong>Hierarki Wilayah (Cascading Dropdowns):</strong> Tersedia <em>dropdown</em> yang otomatis saling menyaring (<em>filter</em>) dari skala besar ke kecil, mulai dari <code>Provinsi</code>, <code>Kab/Kota</code>, <code>Kecamatan</code>, hingga <code>Kelurahan/Desa</code>.</li>\r\n<li><strong>Alamat Spesifik:</strong> Dilengkapi dengan <em>field</em> manual untuk isian <code>RT</code>, <code>RW</code>, <code>Kode Pos</code>, dan teks area untuk <code>Alamat</code> rinci.</li>\r\n<li><strong>Integrasi Google Maps (Visual Validation):</strong> Sistem memfasilitasi <em>field</em> khusus <code>Lokasi Koordinat</code> berupa tautan (URL). Hebatnya, sistem langsung merender Peta Interaktif (Google Maps) di bagian bawahnya, memberikan validasi visual seketika agar admin yakin bahwa titik koordinat (*pinpoint*) sekolah tidak meleset.</li>\r\n</ul>\r\n<h4>3. Bagian "Struktur Pegawai" (Kontak Kepemimpinan &amp; TU)</h4>\r\n<p>Menginventarisasi kontak krusial para pemangku kebijakan (<em>Decision Makers</em>) dan pelaksana administrasi. Bagian ini juga memanfaatkan <em>layout</em> dua kolom:</p>\r\n<ul>\r\n<li><strong>Pimpinan:</strong> Disediakan baris isian untuk <code>Nama Kepala Sekolah</code>, <code>Email</code>, dan <code>Telepon/WA Kepala Sekolah</code>.</li>\r\n<li><strong>Wakil &amp; Staf Administrasi:</strong> Sistem juga mengakomodir struktur berlapis, memberikan <em>field</em> serupa untuk Wakil Kepala Sekolah 1 dan 2, berlanjut hingga jajaran staf Tata Usaha (TU 1 sampai TU 4).</li>\r\n</ul>\r\n<p>Di penghujung formulir panjang ini, terdapat satu tombol <strong>"Simpan"</strong> berwarna biru (<em>primary button</em>) yang diletakkan pas di sudut kanan bawah. Penempatan ini sejalan dengan arah baca alami manusia (<em>Z-pattern / F-pattern</em>).</p>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Desain formulir pada "Profile Sekolah" merupakan manifestasi dari penerapan <strong>Information Architecture</strong> yang matang. Pengelompokan isian data ke dalam blok logis (Profil, Lokasi, Pegawai) dipadankan dengan *grid* dua kolom sangat sukses menekan potensi kebosanan pengguna karena layar tidak terlihat "*endless scrolling*". Kehadiran peta interaktif yang tertanam langsung (*embedded map*) juga merupakan sentuhan <em>micro-interaction</em> cemerlang guna menghapus keraguan <em>human error</em> dalam hal pemetaan lokasi.</p>', '1', NULL, '39', '2026-07-06 03:08:11', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('29', '27', 'Modul Sekolah Menu Rombel', 'tambah-rombongan-belajar-rombel', '<p>Halaman <strong>Tambah Rombongan Belajar</strong> (sering disingkat <em>Rombel</em>) yang terdapat di dalam modul "Sekolah" dirancang untuk memfasilitasi admin atau bagian akademik dalam merakit sebuah kelas baru. Proses perakitan ini mencakup penentuan identitas kelas (tahun, jenjang, wali kelas) hingga memasukkan daftar siswa ke dalam kelas tersebut.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783308176_4-3 sekolah-rombel.png" alt="" width="838" height="788"></p>\r\n<h3>Komponen Formulir Pembentukan Kelas</h3>\r\n<p>Halaman ini mengusung pendekatan satu pintu (<em>single-page workflow</em>). Formulir dibagi ke dalam dua area fokus utama: <strong>Data Master Kelas</strong> di bagian atas dan <strong>Daftar Anggota Kelas</strong> di bagian bawah.</p>\r\n<h4>1. Bagian Data Master Kelas (Grid 2 Kolom)</h4>\r\n<p>Bagian atas layar didedikasikan untuk mendefinisikan "identitas" dari rombongan belajar itu sendiri. Kolom-kolom isian disusun dalam <em>layout</em> 2-kolom agar menghemat ruang vertikal namun tetap rapi dibaca:</p>\r\n<ul>\r\n<li><strong>Afiliasi Akademik:</strong> Terdapat <em>dropdown</em> untuk memilih <code>Tahun Ajaran</code>, <code>Tingkat Kelas</code>, dan <code>Program</code> (contoh: Reguler atau Bilingual).</li>\r\n<li><strong>Identitas Spesifik:</strong> Terdapat isian <code>Nama Rombel</code> berupa teks bebas (misal: "A", "B", atau "Abu Bakar").</li>\r\n<li><strong>Alokasi Fisik:</strong> Disediakan <em>dropdown</em> <code>Nama Ruangan</code> untuk menentukan di ruang fisik manakah kelas ini beroperasi nantinya.</li>\r\n<li><strong>Penanggung Jawab:</strong> Pengaturan <code>Nama Wali Kelas</code>. Mengingat jumlah guru/pegawai bisa mencapai puluhan hingga ratusan, <em>field</em> ini didesain sebagai <em>Searchable Dropdown</em> (terdapat indikator "<em>Ketik Untuk Mencari Data..</em>"), sehingga admin bisa mengetikkan nama untuk memfilter daftar guru dengan cepat.</li>\r\n</ul>\r\n<h4>2. Bagian Anggota Kelas (Tabel Siswa)</h4>\r\n<p>Tepat di bawah formulir spesifikasi kelas, terdapat area tabel interaktif untuk langsung merajut atau mendaftarkan siswa-siswa ke dalam rombel yang sedang dibuat ini.</p>\r\n<ul>\r\n<li><strong>Tombol "+ Tambah Siswa":</strong> Sebuah tombol aksi utama (<em>Primary Button</em> berwarna biru solid) diletakkan secara mencolok di sudut kanan atas area tabel. Tombol ini diposisikan untuk memicu aksi pemilihan siswa (biasanya akan membuka panel <em>modal / pop-up</em> yang memuat daftar murid yang belum mendapatkan kelas).</li>\r\n<li><strong>Tabel Anggota Sementara:</strong> Tabel responsif yang siap menampilkan rangkuman anggota rombel. Kolom yang disediakan meliputi: <code>No</code>, <code>Nama Siswa</code>, <code>NIS</code>, <code>Nomor Absen</code>, dan <code>Aksi</code>. Kolom <em>Aksi</em> di sini umumnya difungsikan untuk membatalkan/mencabut siswa dari daftar jika terjadi keliru pilih.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Desain antarmuka pada halaman "Tambah Rombel" berhasil menerapkan konsep <strong>Contextual Workflow</strong> yang cerdik. Daripada memecah proses menjadi dua alur kerja terpisah (misal: "Buat Kelasnya Dulu", lalu "Masuk ke Detail Kelas untuk Tambah Siswa"), sistem menyatukannya ke dalam satu layar yang berkesinambungan. Keputusan UI/UX ini terbukti secara drastis mampu memangkas jumlah perpindahan halaman (<em>page loads</em>) dan mempercepat kinerja bagian akademik dalam menghadapi rutinitas pembuatan kelas di awal tahun ajaran baru.</p>', '1', NULL, '40', '2026-07-06 03:21:17', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('30', '27', 'Modul Sekolah Menu Kurikulum', 'tambah-kurikulum-mata-pelajaran', '<p>Halaman <strong>Tambah Kurikulum</strong> yang berada di bawah modul "Sekolah &gt; Kurikulum" memegang peranan vital sebagai cetak biru (<em>blueprint</em>) aktivitas akademik. Melalui antarmuka inilah bagian kurikulum atau admin merancang struktur standar belajar, termasuk mengatur jam operasional sekolah dan mengalokasikan Mata Pelajaran (Mapel) pada jenjang kelas tertentu.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783308707_4-4 sekolah-kurikulum.png" alt="" width="859" height="808"></p>\r\n<h3>Struktur Formulir Kurikulum</h3>\r\n<p>Senada dengan pendekatan pada halaman pembuatan kelas, antarmuka ini mengusung pola <strong>Single-Page Workflow</strong>. Pengguna tak perlu lagi melompat-lompat antar halaman demi menuntaskan satu tugas. Halaman ini terbelah menjadi dua panel logis:</p>\r\n<h4>1. Bagian Data Master Kurikulum (Grid Layout)</h4>\r\n<p>Bagian atas halaman berfungsi untuk mengikat parameter fundamental dari kurikulum yang hendak dibentuk. Penggunaan <em>grid</em> dua kolom memberikan kesan formulir yang ringkas dan padat:</p>\r\n<ul>\r\n<li><strong>Parameter Hierarki:</strong> <em>Dropdown</em> <code>Tahun Ajaran</code> dan <code>Tingkat Kelas</code> bertugas mengunci konteks spesifik dari kurikulum ini.</li>\r\n<li><strong>Sistem Kurikulum:</strong> <em>Dropdown</em> <code>Kurikulum</code> disediakan untuk memilih nama standar akademik yang diterapkan (contoh: Kurikulum Merdeka, K13, Kurikulum Cambridge, dll).</li>\r\n<li><strong>Alokasi Jam Operasional:</strong> Menghindari <em>human error</em> dalam pengetikan jam, sistem menyediakan dua input <strong>Time Picker</strong> lengkap dengan ikon jam analog untuk menentukan <code>Mulai Jam Belajar</code> dan <code>Selesai Jam Belajar</code>. Komponen ini sangat intuitif dan otomatis memformat input waktu secara seragam (misal: 07:00 - 15:00).</li>\r\n</ul>\r\n<h4>2. Bagian Detail Mata Pelajaran (Tabel &amp; Empty State)</h4>\r\n<p>Di bagian paruh bawah, terdapat area fungsional untuk merincikan Mata Pelajaran apa saja yang dibebankan pada kurikulum yang sedang dirakit ini.</p>\r\n<ul>\r\n<li><strong>Tombol Aksi "+ Tambah Mapel":</strong> Tombol navigasi berwana biru ini bertindak sebagai <em>Call-to-Action</em> utama untuk mengisi tabel. Saat ditekan, sistem kemungkinan memicu baris interaktif atau <em>modal pop-up</em> guna menyeleksi mapel.</li>\r\n<li><strong>Ilustrasi Kosong (Empty State):</strong> Salah satu keunggulan desain UX di halaman ini adalah penanganan data tabel yang nihil. Ketimbang menampilkan pesan error yang membingungkan atau tabel putih polos yang seolah "*nge-bug*", sistem menampilkan ilustrasi ikon dokumen yang elegan. Secara psikologis, grafis ini memberikan umpan balik (<em>feedback</em>) yang ramah bahwa sistem bekerja normal, hanya saja pengguna memang belum memasukkan data mapel satupun.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Arsitektur UI/UX pada halaman "Tambah Kurikulum" amat kental dengan prinsip <strong>Error Prevention (Pencegahan Kesalahan)</strong> dan <strong>System Status Visibility</strong>. Penerapan <em>Time Picker</em> yang membentengi pengguna dari kesalahan format input, dipadukan dengan desain *empty state* yang menenangkan pada bagian tabel Mapel, menciptakan perjalanan interaksi (*user journey*) yang sangat suportif, minim asumsi, dan bebas dari kebingungan teknis.</p>', '1', NULL, '41', '2026-07-06 03:27:56', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('31', '27', 'Modul Sekolah Menu Program', 'modul-sekolah-menu-program', '<p>Menu <strong>Program</strong> (secara spesifik pada halaman <em>Tambah Program</em>) yang terletak di bawah hierarki modul "Sekolah" berfungsi untuk mendaftarkan jenis program pendidikan apa saja yang ditawarkan oleh institusi terkait. Halaman ini didesain sangat minimalis, tajam, dan terarah (<em>focused</em>), demi mencegah kompleksitas input yang tidak perlu.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783309682_4-5 sekolah-program.png" alt="" width="892" height="839"></p>\r\n<h3>Struktur Formulir Program</h3>\r\n<p>Berbanding terbalik dengan halaman <em>Master Data</em> lainnya yang umumnya sarat akan kolom isian, antarmuka "Tambah Program" tampil dengan sangat ringkas. Halaman ini hanya mengandalkan satu panel (<em>card</em>) formulir, yang diikuti oleh panel aksi di bagian bawahnya.</p>\r\n<h4>1. Panel Pengisian Data (Data Entry Card)</h4>\r\n<p>Formulir diatur menggunakan tata letak dua kolom (<em>two-column grid</em>). Sorotan utama pada aspek UI/UX di area ini adalah pemanfaatan <em>state</em> "<em>Disabled / Read-only</em>" yang dieksekusi secara brilian:</p>\r\n<ul>\r\n<li><strong>Smart Defaults &amp; Penguncian Identitas:</strong> <em>Field</em> <code>Sekolah</code> dan <code>Jenjang</code> sengaja dikunci oleh sistem (ditandai dengan warna latar abu-abu/ter-<em>disable</em>). Sistem secara otomatis mendeteksi identitas institusi dari sesi admin yang sedang login (misal: memunculkan teks "TK Islam Al Azhar 6 Sentra Primer" dengan jenjang "TKIA"). Ini adalah penerapan UX yang fenomenal karena membebaskan pengguna dari tugas berulang untuk memilih nama sekolahnya sendiri, sekaligus memblokir absolut kemungkinan <em>human error</em> (salah pilih unit sekolah).</li>\r\n<li><strong>Input Utama yang Terfokus:</strong> Dengan terkuncinya kedua kolom di atas, perhatian pengguna kini bisa terpusat 100% hanya pada satu tugas: memilih <em>dropdown</em> <code>Nama Program</code> yang ingin diaktifkan (misal: Program Reguler, Bilingual, Akselerasi, dsb).</li>\r\n</ul>\r\n<h4>2. Panel Aksi (Action Bar)</h4>\r\n<p>Tepat di bawah formulir pengisian, sistem menyediakan satu blok putih independen yang khusus mewadahi deretan tombol eksekusi. Pemisahan blok secara visual (<em>visual boundary</em>) ini mempertegas perbedaan antara "area mengetik" dan "area mengambil keputusan".</p>\r\n<ul>\r\n<li><strong>Tombol Batalkan (Secondary Action):</strong> Memiliki gaya desain tombol sekunder (warna latar putih dengan garis batas abu-abu). Diposisikan di sebelah kiri tombol utama sebagai opsi jalan keluar (<em>escape hatch</em>) yang aman apabila pengguna urung menyimpan data.</li>\r\n<li><strong>Tombol Simpan (Primary Action):</strong> Didesain sebagai tombol utama (warna biru solid yang cerah) dan diperkuat dengan ikon <em>save</em>. Posisinya di sudut kanan bawah sangat sejalan dengan titik akhir pergerakan mata dan kursor dalam pola baca Z (<em>Z-pattern reading</em>), sehingga aksi penyelesaian terasa alami dan memuaskan.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Halaman "Tambah Program" mencontohkan dengan sempurna bahwa tidak semua formulir harus panjang. Dengan mempraktikkan prinsip <strong>Smart Defaults</strong>&mdash;mengisi dan mengunci otomatis atribut Sekolah dan Jenjang&mdash;antarmuka ini berhasil memangkas drastis beban kognitif (<em>cognitive load</em>) pengguna. Kesederhanaan <em>layout</em> yang disajikan dipadukan dengan pemisahan panel aksi yang tegas, menjadikan alur kerja (<em>workflow</em>) penambahan program di halaman ini terasa luar biasa cepat, protektif terhadap kesalahan, dan sangat efisien.</p>', '1', NULL, '42', '2026-07-06 03:47:13', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('32', '27', 'Modul Sekolah Menu Pegawai', 'modul-sekolah-menu-pegawai', '<p>Halaman <strong>Tambah Personnel</strong> yang berada di dalam submenu "Sekolah &gt; Pegawai" berfungsi sebagai gerbang utama (<em>entry point</em>) untuk mendaftarkan staf, guru, atau karyawan baru ke dalam ekosistem sistem informasi sekolah. Mengingat banyaknya himpunan data yang dibutuhkan untuk urusan kepegawaian, formulir ini dirancang menggunakan teknik desain <strong>Form Chunking</strong> (pemecahan formulir logis).</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783310130_4-6 sekolah-pegawai.png" alt="" width="861" height="1319"></p>\r\n<h3>Struktur Formulir Kepegawaian</h3>\r\n<p>Demi mencegah kelelahan visual (<em>visual fatigue</em>) akibat <em>endless scrolling</em>, puluhan <em>field</em> input di halaman ini tidak ditumpuk menjadi satu deretan panjang, melainkan dikelompokkan ke dalam tiga panel (<em>cards</em>) tematik yang tertata rapi:</p>\r\n<h4>1. Card "Profil" (Data Pribadi &amp; Atribut Karir)</h4>\r\n<p>Panel teratas dan terpanjang ini merangkum identitas fundamental serta legalitas profesional seorang pegawai:</p>\r\n<ul>\r\n<li><strong>Identitas Pokok:</strong> Diawali dengan <em>field full-width</em> untuk <code>Nama Lengkap</code>, dilanjutkan dengan <em>grid</em> dua kolom padat yang memuat <code>Gelar Depan</code>, <code>Gelar Belakang</code>, <code>NIK</code> (Nomor Induk Kependudukan), <code>NIP</code>, hingga <code>NPWP</code>.</li>\r\n<li><strong>Demografi &amp; Fisik:</strong> Menyediakan input <code>Tempat Lahir</code>, <code>Tanggal Lahir</code> (dengan kalender interaktif / <em>Datepicker</em>), <code>Golongan Darah</code>, serta penggunaan komponen <strong>Radio Button</strong> untuk memilih <code>Jenis Kelamin</code> (Laki-laki / Perempuan) agar input lebih cepat.</li>\r\n<li><strong>Atribut Kepegawaian:</strong> Menampung rincian SK meliputi <code>No. SK</code>, <code>TMT Pegawai</code> (Tanggal Mulai Tugas), <code>Pangkat / Golongan</code>, <code>Status Kepegawaian</code>, serta penentuan <code>Jabatan</code> (contoh: diisi dengan "Guru").</li>\r\n</ul>\r\n<h4>2. Card "Informasi Tempat Tinggal" (Data Geografis)</h4>\r\n<p>Panel kedua bertugas untuk merekam riwayat domisili spesifik guna keperluan korespondensi maupun pemetaan zonasi:</p>\r\n<ul>\r\n<li><strong>Hierarki Wilayah (Cascading Dropdowns):</strong> Memanfaatkan sistem <em>dropdown</em> bertingkat yang saling terkait, mulai dari <code>Provinsi</code>, <code>Kab/Kota</code>, <code>Kecamatan</code>, hingga <code>Kelurahan/Desa</code>.</li>\r\n<li><strong>Detail Spesifik:</strong> Disediakan kolom berukuran kecil untuk pengisian manual <code>RT</code> dan <code>RW</code>, serta input panjang untuk <code>Alamat Tempat Tinggal</code> (nama jalan/komplek) demi presisi lokasi.</li>\r\n</ul>\r\n<h4>3. Card "Informasi Keluarga" (Data Tanggungan)</h4>\r\n<p>Panel terakhir ini sangat penting untuk pendataan profil keluarga, yang nantinya berimplikasi pada perhitungan pajak, tunjangan porsi keluarga, maupun pendaftaran asuransi/BPJS:</p>\r\n<ul>\r\n<li><strong>Status &amp; Legalitas:</strong> Penggunaan <em>Radio Button</em> sangat mempermudah penentuan <code>Status Perkawinan</code> (Kawin / Belum Kawin / Duda/Janda). Dilengkapi pula dengan form <code>Nomor KK</code> dan <code>Nama Suami/Istri</code>.</li>\r\n<li><strong>Tanggungan Anak:</strong> Pertanyaan singkat "Memiliki / Tidak Memiliki" anak disajikan interaktif sebagai penutup lembar profil.</li>\r\n</ul>\r\n<h4>Panel Aksi (Action Bar)</h4>\r\n<p>Sama persis seperti halaman manajemen sebelumnya, formulir ini ditutup dengan blok <em>footer</em> independen yang memuat tombol <strong>"Batalkan"</strong> (tombol sekunder bergaris batas) dan tombol <strong>"Simpan"</strong> (tombol primer biru padat). Desain aksi yang konsisten (<em>consistent UX pattern</em>) ini memastikan admin tidak perlu meraba-raba kembali letak tombol validasi setiap kali membuka menu baru.</p>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Halaman pendaftaran pegawai ini merupakan contoh sempurna dari keberhasilan metode <strong>Chunking Concept</strong> dalam desain antarmuka. Memecah lebih dari 25 kolom input ke dalam tiga <em>card</em> logis (Profil, Alamat, Keluarga) dan mengaturnya rapi dalam format dua kolom, secara instan meredam intimidasi (<em>cognitive overload</em>) pada *user* yang harus melakukan pendataan massal. Pemilihan komponen seperti <em>Radio Buttons</em> dan <em>Datepickers</em> alih-alih isian teks bebas, sangat esensial untuk memangkas waktu kerja (<em>data entry time</em>) dan menjaga integritas (standardisasi format) struktur <em>database</em> HRD.</p>', '1', NULL, '43', '2026-07-06 03:54:48', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('33', '27', 'Modul Sekolah Menu Akademik (Kenaikan Kelas & Kelulusan)', 'modul-sekolah-menu-akademik-kenaikan-kelas-kelulusan', '<p>Halaman <strong>Kenaikan Kelas &amp; Kelulusan</strong> yang diposisikan di bawah menu "Sekolah &gt; Akademik" mengemban fungsi manajerial yang sangat krusial di setiap pergantian tahun ajaran. Antarmuka ini dirancang khusus untuk mewadahi perpindahan status akademis siswa secara massal (<em>bulk action</em>), dari satu tingkat ke tingkat di atasnya, maupun memproses kelulusan mereka.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783311411_4-7 sekolah-akademik-kenaikan_kelulusan-belum diproses.png" alt="" width="747" height="752"></p>\r\n<h3>Struktur dan Navigasi Halaman</h3>\r\n<p>Mengingat eksekusi kenaikan kelas berimplikasi pada modifikasi ribuan baris data, halaman ini dirancang dengan lapis proteksi UX (*User Experience*) dan filter data yang sangat ketat.</p>\r\n<h4>1. Segmentasi Status (Tab Switcher)</h4>\r\n<p>Area teratas halaman didominasi oleh sebuah <em>tab switcher</em> (tombol ganti mode) berukuran besar yang memisahkan layar ke dalam dua dimensi status:</p>\r\n<ul>\r\n<li><strong>Belum Diproses:</strong> <em>Tab</em> aktif (ditandai warna biru) yang menampilkan himpunan siswa di kelas lamanya dan sedang menunggu eksekusi kenaikan.</li>\r\n<li><strong>Sudah Diproses:</strong> <em>Tab</em> riwayat (<em>history</em>) yang memuat siswa yang sukses dinaikkan kelasnya. Fitur ini memberikan ketenangan batin (<em>peace of mind</em>) dan kendali bagi admin untuk mengaudit kembali pekerjaannya.</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783311472_4-8 sekolah-akademik-kenaikan_kelulusan-sudah diproses.png" alt="" width="771" height="776"></p>\r\n<h4>2. Banner Panduan (Inline System Feedback)</h4>\r\n<p>Sistem menyematkan <em>banner</em> notifikasi berwarna biru muda (berisi teks panduan seperti "<em>Tekan tombol Batalkan jika ingin mengembalikan murid...</em>"). Bentuk <em>Microcopy</em> ini berperan layaknya asisten virtual, membimbing admin pada langkah apa yang bisa/harus diambil tanpa perlu menekan tombol <em>Help</em>.</p>\r\n<h4>3. Panel Proteksi dan Filter Pintar</h4>\r\n<p>Sebelum bisa menaikkan status kelas, admin diwajibkan untuk mengisolasi himpunan data (<em>data slicing</em>) pada rombel tertentu:</p>\r\n<ul>\r\n<li><strong>Peringatan Pra-Tindakan (Pre-action Warning):</strong> Jika admin terburu-buru, sistem akan memberikan *feedback* teks merah bertuliskan "<em>Silahkan pilih Kelas, Program, dan Rombel terlebih dahulu</em>". Ini adalah tameng UX brilian (<em>Error Prevention</em>) untuk menihilkan insiden salah rombel.</li>\r\n<li><strong>Form Filter Rantai:</strong> Menggunakan tiga <em>dropdown</em> (<code>Kelas</code>, <code>Program</code>, <code>Rombel</code>) beserta tombol "Terapkan" guna memuat daftar murid yang akurat ke dalam tabel di bawahnya.</li>\r\n</ul>\r\n<h4>4. Area Tabel &amp; Tindakan Massal (Bulk Action)</h4>\r\n<p>Ini adalah pusat operasional tempat penentuan kelas tereksekusi:</p>\r\n<ul>\r\n<li><strong>Eksekusi Massal (Bulk Select):</strong> Kehadiran fitur <em>Checkbox</em> "Pilih Semua" adalah nyawa utama dari efisiensi halaman ini. Fitur ini memangkas repetisi tugas admin, memampukan pemrosesan satu kelas utuh hanya dalam hitungan detik.</li>\r\n<li><strong>Tombol Aksi Mengambang:</strong> Terdapat deretan tombol dinamis seperti "Naik Kelas" (biru berikon <em>check</em>) serta <em>Search Bar</em> untuk intervensi individual jika ada murid yang tinggal kelas atau butuh penanganan tersendiri.</li>\r\n<li><strong>Ilustrasi Empty State:</strong> Tabel tidak dibiarkan berbentuk kotak-kotak putih kosong jika data belum dimuat, melainkan diisi dengan ilustrasi dokumen dan kaca pembesar. Praktik ini menghapus ambiguitas (apakah sistem eror atau memang data kosong?).</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Secara arsitektural, halaman "Kenaikan Kelas &amp; Kelulusan" adalah mahakarya perpaduan antara <strong>User Control</strong> (kendali pengguna) dan <strong>Error Prevention</strong> (pencegahan kesalahan). Kewajiban untuk menerapkan filter data spesifik sebelum tabel bisa dieksekusi, dipadukan dengan fungsionalitas pengubah massal (<em>bulk checkbox</em>) dan pembagian status <em>tab</em> (Belum/Sudah Diproses), sukses menciptakan alur kerja yang sangat aman (*fool-proof*), efisien, dan melegakan (<em>stress-free</em>) bagi para admin akademik di puncak kesibukan akhir tahun.</p>', '1', NULL, '44', '2026-07-06 04:08:11', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('34', '28', 'Modul Sekolah Menu PMB', 'modul-sekolah-menu-pmb', '<p>Menu <strong>PMB (Penerimaan Murid Baru)</strong> yang terletak di bawah payung modul "Sekolah" dirancang secara khusus untuk bertindak sebagai <em>dashboard</em> rekapitulasi (<em>executive summary</em>). Berbeda dengan menu Transaksi PMB yang dipenuhi deretan data mentah para calon siswa, antarmuka halaman ini difokuskan pada penyajian analitik tingkat tinggi (<em>high-level metrics</em>) guna memantau performa rekrutmen siswa dari satu periode ke periode lainnya.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783311714_4-9 sekolah-pmb.png" alt="" width="873" height="879"></p>\r\n<h3>Struktur dan Tata Letak (Layout) Halaman</h3>\r\n<p>Keseluruhan antarmuka didesain dengan mengedepankan prinsip <em>data readability</em> (keterbacaan data yang cepat). Tata letaknya meliputi komponen berikut:</p>\r\n<h4>1. Panel Filter Data (Penyaringan Rentang Waktu)</h4>\r\n<p>Sistem menyediakan mekanisme filter interaktif yang bisa dipanggil lewat tombol hijau "Filter" di sudut kanan atas. Ketika diekspansi, panel putih ini memuat:</p>\r\n<ul>\r\n<li><strong>Dropdown Rentang Waktu:</strong> Mengingat performa PMB diukur per siklus akademik, pengguna diwajibkan melakukan penyaringan (*filtering*) berbasis <code>Tahun Ajaran</code>. Fitur ini sangat krusial bagi manajemen untuk melihat grafik penerimaan pada satu angkatan tertentu.</li>\r\n<li><strong>Tombol Reset &amp; Terapkan:</strong> Penyediaan tombol <em>Reset</em> (berwarna merah) tepat di samping tombol eksekusi <em>Terapkan</em> (berwarna biru) merupakan penerapan kaidah UX yang solid. Ini memberikan keleluasaan bagi admin untuk membatalkan skenario pencarian (*clear filters*) dengan cukup satu ketukan.</li>\r\n</ul>\r\n<h4>2. Tabel Rekapitulasi Performa (Data Grid)</h4>\r\n<p>Bintang utama dari halaman ini adalah struktur tabel data bergaris bersih (<em>clean layout</em>) yang merangkum rapor pencapaian tim PMB:</p>\r\n<ul>\r\n<li><strong>Kolom Metrik Strategis:</strong> Tabel ini secara cerdas menyingkirkan kerumitan nama-nama siswa individual, lalu menggantinya dengan perbandingan langsung antara <code>Target</code> (kuota bangku sekolah), <code>Pendaftar</code> (jumlah animo yang masuk), dan <code>Perolehan</code> (realisasi akhir siswa yang sah mendaftar ulang). Deretan kolom ini adalah amunisi sempurna bagi kepala sekolah untuk menghitung <em>conversion rate</em> (tingkat keberhasilan) pendaftaran.</li>\r\n<li><strong>Kolom Sinkronisasi Waktu:</strong> Di ujung kanan tabel, sistem membubuhkan kolom <code>Update</code> (*timestamp*). Kehadiran kolom kecil ini membawa dampak psikologis yang besar: memberikan kepastian mutlak (*trust*) kepada level pimpinan bahwa angka-angka yang mereka lihat adalah data *real-time* detik itu juga.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Halaman "PMB Sekolah" mengadopsi pendekatan desain <strong>Minimalist Analytics Dashboard</strong> dengan sangat gemilang. Dengan membuang detail operasional (*noise*) dan langsung menyuguhkan metrik kuantitatif (Target vs Perolehan) yang dibalut tabel responsif, antarmuka ini amat memanjakan *Top-level management* (Kepala Sekolah/Yayasan) dalam menyerap informasi secara sekilas (*glanceable*) untuk perumusan strategi promosi di masa mendatang.</p>', '1', NULL, '55', '2026-07-06 04:21:05', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('35', '27', 'Modul Sekolah Menu Sarana Prasarana', 'modul-sekolah-menu-sarana-prasarana', '<p>Menu <strong>Sarana Prasarana (Sarpras)</strong> dalam cakupan modul "Sekolah" berperan sebagai buku inventaris digital untuk merekam berbagai aset fisik dan fasilitas ruangan yang dikelola oleh unit sekolah terkait. Tangkapan layar dari halaman "Tambah Sarana Prasarana" ini memamerkan antarmuka formulir yang berfokus pada spesifikasi dimensi teknis.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783312195_4-10 sekolah-sarana prasarana.png" alt="" width="859" height="865"></p>\r\n<h3>Struktur Formulir Sarpras</h3>\r\n<p>Halaman ini dikemas dengan sangat ringkas dan rapi, mengandalkan satu panel (*Card*) utama putih sebagai area pengisian (*data entry*), yang ditutup dengan panel aksi terpisah di bagian paling bawah layar.</p>\r\n<h4>1. Tata Letak Grid Dua Kolom (Two-Column Layout)</h4>\r\n<p>Demi menjaga agar formulir tidak memakan terlalu banyak ruang vertikal (menghindari perlunya <em>scrolling</em> panjang), kolom-kolom isian disusun memadat dalam format <em>grid</em> dua kolom:</p>\r\n<ul>\r\n<li><strong>Kategori &amp; Nomenklatur:</strong> <em>Field</em> <code>Jenis Sarana Prasarana</code> memanfaatkan komponen <em>dropdown</em> untuk mengontrol konsistensi klasifikasi data secara global (misal: Ruang Kelas, Laboratorium, Lapangan, Toilet). Sedangkan untuk pengisian <code>Nama</code>, sistem memberikan kebebasan teks (*text input*) agar aset dapat diberi identitas unik (contoh: "Lab Komputer Lantai 2").</li>\r\n<li><strong>Spesifikasi Dimensi:</strong> Terdapat kolom input <code>Ukuran Panjang (Meter)</code> dan <code>Ukuran Lebar (Meter)</code>. Menyertakan informasi satuan ukur "(Meter)" langsung pada teks label adalah praktik <strong>Microcopy</strong> yang brilian dalam UI/UX. Strategi ini secara instan menghapus ambiguitas (menjawab keraguan *user*: <em>"Ini diisi dalam sentimeter atau meter?"</em>) dan membersihkan data dari format penulisan <em>string</em> campuran.</li>\r\n<li><strong>Daya Tampung:</strong> <em>Field</em> penutup di sebelah kiri bawah adalah <code>Kapasitas</code>. Kolom ini krusial untuk mencatat batas beban maksimal suatu ruangan (misal: kapasitas 30 siswa untuk satu ruang kelas), yang nantinya akan saling bersilangan (*cross-reference*) dengan logika pada menu pembagian rombongan belajar (Rombel).</li>\r\n</ul>\r\n<h4>2. Panel Aksi Independen (Action Bar)</h4>\r\n<p>Selaras dengan pola desain (<em>design language</em>) di seluruh sistem <em>Backoffice</em>, area eksekusi dipisahkan pada satu blok khusus:</p>\r\n<ul>\r\n<li>Tombol sekunder <strong>"Batalkan"</strong> disajikan dengan kontras rendah (garis tepi abu-abu) sebagai opsi jalan keluar yang tidak mengganggu.</li>\r\n<li>Tombol primer <strong>"Simpan"</strong> tampil dominan (warna biru pekat dengan ikon pelengkap) di ujung paling kanan bawah, menegaskan arah akhir penyelesaian tugas.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Meskipun jumlah kolom inputnya sedikit, antarmuka "Tambah Sarana Prasarana" ini berhasil mencapai tingkat efisiensi yang sangat tinggi berkat <strong>Kejelasan Konteks (Contextual Clarity)</strong>. Penggunaan label penjelas untuk satuan metrik (Meter) adalah perwujudan dari <em>Error Prevention</em> yang sangat ampuh. Dikombinasikan dengan tata letak visual 2-kolom yang bernapas lega, petugas tata usaha (*admin*) dipastikan mampu mendigitalkan puluhan aset fisik sekolah dengan tingkat kesalahan yang nyaris nol.</p>', '1', NULL, '45', '2026-07-06 04:29:06', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('36', '27', 'Modul Sekolah Menu Ekstrakurikuler', 'modul-sekolah-menu-ekstrakurikuler', '<p>Menu <strong>Ekstrakurikuler</strong> yang bernaung di bawah modul "Sekolah" berperan sebagai pusat pengelolaan kegiatan non-akademis bagi siswa. Melalui tangkapan layar antarmuka "Tambah Ekstrakurikuler", aplikasi mendemonstrasikan bagaimana sebuah formulir pendataan mampu dirancang secara amat minimalis, namun tetap mengakomodasi seluruh esensi fungsional yang dibutuhkan pengelola sekolah.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783312412_4-11 sekolah-ekstrakulikuler.png" alt="" width="904" height="910"></p>\r\n<h3>Struktur Formulir Ekstrakurikuler</h3>\r\n<p>Halaman ini mempertahankan keteguhan (*consistency*) arsitektur UI sistem dengan halaman <em>Master Data</em> lainnya: memusatkan <em>data entry</em> pada satu panel putih utama (<em>Card</em>), yang kemudian ditutup oleh panel eksekusi (<em>Action Bar</em>) di bagian bawah layar.</p>\r\n<h4>1. Tata Letak Fleksibel (Mixed Grid Layout)</h4>\r\n<p>Guna mengoptimalkan ruang layar (<em>screen real estate</em>) tanpa menciptakan kesan sesak, baris-baris formulir disusun dengan mengawinkan format rentang penuh (<em>full-width</em>) dan paruh rentang (<em>half-width</em>):</p>\r\n<ul>\r\n<li><strong>Input Fundamental (Full-Width):</strong> Kolom isian <code>Nama Ekstrakulikuler</code> ditempatkan paling atas dengan lebar membentang 100%. Keputusan ini sangat natural secara UX karena ia merupakan penanda identitas primer (*primary identifier*). Format serupa diterapkan pada kolom penutup <code>Keterangan Kegiatan</code>; pemberian ruang lebar memanjakan admin untuk leluasa mengetikkan rincian deskripsi, target capaian, hingga jadwal latihan tanpa merasa teksnya terpotong sempit.</li>\r\n<li><strong>Input Pendukung (Half-Width):</strong> Diapit oleh kedua <em>field</em> raksasa tadi, terdapat kolom <code>Biaya</code> dan <code>Nama Pelatih</code> yang didesain berdampingan (pola <em>grid</em> 2 kolom). Ini adalah taktik desain (<em>design tactic</em>) yang brilian. Mengingat kedua data ini umumnya hanya membutuhkan beberapa karakter pendek (angka nominal rupiah dan nama pendek pelatih), merentangkannya secara penuh hanya akan menyisakan ruang putih kosong yang sia-sia (*wasted whitespace*).</li>\r\n</ul>\r\n<h4>2. Panel Aksi Independen (Action Bar)</h4>\r\n<p>Sebagai pamungkas alur kerja (<em>workflow</em>), area penentuan keputusan diisolasi secara visual:</p>\r\n<ul>\r\n<li>Tombol sekunder <strong>"Batalkan"</strong> hadir sebagai fitur jaring pengaman (<em>safety net</em>) bagi admin yang ingin mereset layar input.</li>\r\n<li>Tombol primer <strong>"Simpan"</strong> yang didominasi warna biru cerah menjadi sauh visual (<em>visual anchor</em>), memberi kepastian langkah akhir pendaftaran data ekskul baru.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Antarmuka pada halaman "Tambah Ekstrakurikuler" adalah manifestasi luar biasa dari filosofi <strong>"Less is More"</strong>. Dengan hanya mendayagunakan empat kotak input yang disusun atraktif (bermain pada kontras panjang-pendek isian), formulir ini terasa sangat ringan, mengalir (<em>flowing</em>), dan nihil <em>cognitive overload</em> (beban mental pengguna). Praktik UI ini menjamin kelancaran tata usaha sekolah, memastikan pendataan puluhan jenis ekskul di awal tahun ajaran dapat diselesaikan dengan sekejap mata.</p>', '1', NULL, '46', '2026-07-06 04:32:59', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('37', '27', 'Modul Sekolah Menu Prestasi', 'modul-sekolah-menu-prestasi', '<p>Menu <strong>Prestasi</strong> dalam naungan modul "Sekolah" didedikasikan untuk membangun rekam jejak (<em>track record</em>) penghargaan dan pencapaian kompetitif, baik yang diraih secara individu maupun berkelompok. Melalui antarmuka "Tambah Prestasi" ini, sistem mendemonstrasikan keluwesan (<em>flexibility</em>) tingkat tinggi dalam mewadahi beragam variabel data perlombaan.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783312598_4-12 sekolah-prestasi.png" alt="" width="829" height="835"></p>\r\n<h3>Struktur Formulir Pencapaian (Achievement Form)</h3>\r\n<p>Sistem tetap mematuhi pola desain 2-kolom (<em>two-column grid</em>) untuk memadatkan 10 <em>field</em> spesifik tanpa memaksa admin melakukan <em>scrolling</em> panjang ke bawah.</p>\r\n<h4>1. Logika Bersyarat (Conditional Logic &amp; Dependent Input)</h4>\r\n<p>Dua baris pertama formulir adalah jantung dari kecerdasan UI (<em>Smart UI</em>) halaman ini. Sistem tidak langsung melempar semua kolom untuk diisi secara membabi-buta, melainkan merespons secara dinamis:</p>\r\n<ul>\r\n<li><strong>Klasifikasi Akar:</strong> Langkah wajib pertama, pengguna harus mendefinisikan ranah <code>Bidang</code> (misal: Akademik, Ekstrakurikuler) dan tipe entitas <code>Peserta</code> (Individu atau Kelompok) lewat komponen <em>dropdown</em>.</li>\r\n<li><strong>Input Terkunci (Dependent Input):</strong> Perhatikan <em>field</em> pencarian <code>Nama User</code>. Kolom ini berstatus terkunci/abu-abu (<em>disabled</em>) secara <em>default</em>. Kolom pencarian pintar (*Searchable Dropdown* "Cari Dengan NIS Atau Nama Siswa") ini baru akan bereaksi dan membuka diri <strong>setelah</strong> tipe "Peserta" didefinisikan. Ini merupakan teknik <em>Error Prevention</em> kasta tertinggi, memastikan admin tidak secara keliru memasukkan nama perorangan jika penghargaan tersebut sebenarnya milik regu basket, dan sebaliknya.</li>\r\n</ul>\r\n<h4>2. Variabel Kompetisi &amp; Komponen Unggah (Upload)</h4>\r\n<p>Sisa formulir menuntut pengisian detail histori kompetisi yang dijejerkan secara simetris:</p>\r\n<ul>\r\n<li><strong>Anatomi Acara:</strong> Mencakup rincian spesifik seperti <code>Kegiatan Lomba</code>, <code>Jenis Lomba</code>, <code>Tingkat</code> (misal: Kota, Nasional), hingga <code>Penyelenggara</code> (institusi pembuat acara).</li>\r\n<li><strong>Bukti &amp; Waktu:</strong> Tersedia isian <code>Juara</code> dan <code>Tahun</code>.</li>\r\n<li><strong>Integrasi File Upload Modern:</strong> Hal yang paling memanjakan mata adalah desain kolom penutup <code>Upload File</code> (untuk mengunggah <em>scan</em> piagam). Ketimbang menggunakan desain tombol abu-abu kuno (<em>native HTML file input</em>) yang sering merusak harmoni estetika, halaman ini meracik desain kustom: sebuah kolom teks penampung nama <em>file</em> disandingkan rapi dengan tombol <code>Upload</code> berwarna biru solid di sudutnya. Desain ini terasa jauh lebih profesional dan terintegrasi (*seamless*) dengan elemen UI lainnya.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Halaman "Tambah Prestasi" adalah panggung unjuk gigi bagi konsep <strong>Conditional UI (Antarmuka Bersyarat)</strong>. Keberadaan kolom "Nama User" yang pasif dan menanti komando dari kolom sebelumnya mencerminkan empati mendalam sang desainer terhadap <em>user journey</em>&mdash;sistem seakan menggandeng tangan admin selangkah demi selangkah. Ditunjang oleh komponen unggah (*upload*) yang dipoles modern, tugas klerikal (*clerical*) seperti merekam piagam siswa sukses disulap menjadi pengalaman digital yang memuaskan dan anti-salah (*fool-proof*).</p>', '1', NULL, '47', '2026-07-06 04:36:06', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('38', '28', 'Modul Administrasi Menu PMB > Animo', 'modul-administrasi-menu-pmb-animo', '<p>Menu <strong>Animo</strong> yang bernaung di bawah payung "Administrasi &gt; PMB" bertindak sebagai jaring penangkap pertama (<em>frontline lead capture</em>) dalam siklus penerimaan murid baru. Antarmuka halaman "Tambah Animo PMB" ini didesain khusus agar para petugas <em>front office</em> atau tata usaha dapat melayani calon pendaftar dengan sangat cekatan tanpa rentan melakukan <em>human error</em>.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783318129_5-1 administrasi-animo.png" alt="" width="839" height="955"></p>\r\n<h3>Struktur Formulir Pendaftaran Awal (Animo)</h3>\r\n<p>Tidak seperti borang pendaftaran paripurna yang memuat puluhan <em>field</em> yang melelahkan, formulir <strong>Calon Data Murid</strong> pada tahap Animo ini secara sengaja dipangkas hingga menyisakan kerangkanya saja. Tujuan UX-nya jelas: menangkap ketertarikan (<em>leads</em>) secepat kilat tanpa membuat orang tua/calon pendaftar menunggu lama di loket.</p>\r\n<h4>1. Tata Letak Simetris (Two-Column Grid)</h4>\r\n<p>Keseluruhan borang dikemas rapi di dalam satu panel putih berlatar bersih, dengan penataan kolom-kolom yang berbaris berdampingan (kiri-kanan) demi keseimbangan visual yang sempurna:</p>\r\n<ul>\r\n<li><strong>Smart Defaults &amp; Penguncian Institusi:</strong> Meneruskan tradisi UX yang tangguh dari modul sebelumnya, <em>field</em> <code>Jenjang</code> (misal terisi: TKIA) dan <code>Tujuan Sekolah</code> (misal: TK Islam Al Azhar 6 Sentra Primer) dibekukan dari modifikasi (berwarna latar abu-abu/<em>read-only</em>). Sistem secara otomatis menarik identitas ini dari sesi admin yang <em>login</em>. Keputusan desain ini adalah *Error Prevention* absolut yang memastikan data animo tidak mungkin "nyasar" masuk ke sistem pendaftaran unit sekolah lain di bawah yayasan.</li>\r\n<li><strong>Parameter Konteks Pendaftaran:</strong> Komponen di paruh kiri, meliputi <code>Tahun Ajaran</code>, <code>Tingkat Kelas</code>, dan <code>Program</code> diwajibkan menggunakan komponen <em>Dropdown</em> alih-alih teks biasa. Penyeragaman (*standardization*) via *dropdown* ini vital agar *database* bersih dari <em>typo</em>, sehingga mudah dikalkulasi nanti.</li>\r\n<li><strong>Asal Muasal Calon (Lead Source):</strong> Tersedia kolom <code>Asal Sekolah</code> untuk memetakan demografi asal muasal ketertarikan, yang kelak menjadi tambang emas analitik bagi tim pemasaran (<em>marketing</em>) PMB.</li>\r\n<li><strong>Identitas Primer:</strong> Di baris pemungkas, formulir cukup menuntut dua data fundamental lewat input teks bebas (<em>free-text</em>): <code>Nama Calon Murid</code> dan <code>Tempat Lahir</code>.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Halaman "Tambah Animo PMB" merupakan perwujudan sejati dari prinsip <strong>Speed and Efficiency (Kecepatan dan Efisiensi)</strong> dalam ranah perancangan antarmuka. Dengan mengeliminasi <em>clutter</em> (elemen pengganggu) dan memberdayakan otomatisasi pada kolom institusi, admin dibekali sebuah "senjata" (*tool*) yang memungkinkan mereka mendaftarkan <em>leads</em> baru hanya dalam tempo beberapa detik. Desain yang bernapas lega ini menjadikan interaksi pendataan, baik bagi pegawai rekrutan baru maupun operator kawakan, terasa sangat natural dan bebas stres.</p>', '1', NULL, '56', '2026-07-06 06:08:08', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('39', '28', 'Modul Administrasi Menu PMB > Jadwal Ujian', 'modul-administrasi-menu-pmb-jadwal-ujian', '<p>Menu <strong>Jadwal Ujian</strong> yang berada di bawah payung "Administrasi &gt; PMB" memegang peranan sangat penting dalam mengatur alur seleksi akademik calon murid baru. Melalui halaman "Tambah Jadwal Ujian" ini, kita dapat melihat bagaimana antarmuka (<em>interface</em>) dirancang untuk menuntun alur pikir pengguna (<em>user guidance</em>) lewat kombinasi isian bebas dan input yang dikunci oleh sistem.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783318622_5-2 administrasi-jadwal ujian.png" alt="" width="777" height="884"></p>\r\n<h3>Struktur Formulir Penjadwalan Ujian</h3>\r\n<p>Menyelaraskan dengan standar <em>design system</em> pada modul PMB lainnya, halaman ini memusatkan pengisian data pada satu panel (<em>Card</em>) berwarna putih solid. Panel ini mengakomodasi tata letak yang luwes, memadukan format lebar penuh (<em>full-width</em>) dan paruh lebar (<em>half-width</em>).</p>\r\n<h4>1. Atribut Fundamental (Full-Width Input)</h4>\r\n<p>Area formulir ini dibuka dan ditutup oleh kolom berukuran 100% untuk memfasilitasi <em>input</em> yang panjang atau butuh penekanan visual:</p>\r\n<ul>\r\n<li><strong>Judul Agenda:</strong> <em>Field</em> <code>Nama Ujian</code> diletakkan di baris pertama dan merentang penuh. Penempatan ini sangat hierarkis secara logika, karena judul (misal: "Ujian Saringan Masuk Gelombang 1 - 2024") bertindak sebagai identitas utama dari entitas jadwal tersebut.</li>\r\n<li><strong>Konteks Lokasi &amp; Catatan Tambahan:</strong> Di bagian bawah, <em>field</em> <code>Ruangan</code> dan <code>Keterangan</code> turut menggunakan format lebar penuh. Ini menjamin nama ruang yang mungkin panjang tidak terpotong, dan admin memiliki bidang teks (<em>text area</em>) yang lega untuk mengetikkan instruksi khusus bagi pengawas ujian maupun peserta.</li>\r\n</ul>\r\n<h4>2. Variabel Terkontrol (Two-Column Grid)</h4>\r\n<p>Di bagian jantung formulir, desain bertransisi menjadi format <em>grid</em> 2-kolom untuk mengelola parameter administratif secara presisi:</p>\r\n<ul>\r\n<li><strong>Automasi &amp; Data Terkunci (Smart Defaults):</strong> Praktik <em>Error Prevention</em> kasta tinggi kembali diterapkan di sini. Perhatikan <em>field</em> <code>Jenjang</code> (misal: TKIA) dan <code>Tipe Ujian</code> (misal: Offline); keduanya sengaja dibekukan (<em>disabled / read-only</em>) dan diwarnai abu-abu. Konfigurasi ini menjamin staf PMB tingkat TK tidak akan tak sengaja menjadwalkan ujian untuk tingkat SMP, sekaligus mengunci tipe ujian sesuai regulasi baku sekolah. Pengguna sama sekali tidak dibebani untuk memilih ulang data instansinya sendiri.</li>\r\n<li><strong>Variabel Dependen:</strong> Tepat di sebelah kolom-kolom yang dikunci, tersaji <em>dropdown</em> aktif untuk menentukan <code>Tingkat Kelas</code> dan <code>Gelombang</code> PMB. Mewajibkan penggunaan <em>dropdown</em> alih-alih isian manual adalah jalan ninja untuk menjaga integritas data (menjamin relasi ID di <em>database</em> tidak meleset).</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Halaman "Tambah Jadwal Ujian PMB" ini merupakan studi kasus yang cemerlang mengenai penerapan prinsip <strong>Constraint (Pembatasan Kendali)</strong> dalam bidang UX. Dengan mencampur harmonis antara kolom <em>read-only</em> (Jenjang &amp; Tipe Ujian) dengan kolom pilihan wajib (Kelas &amp; Gelombang), antarmuka ini berhasil mengeleminasi hampir 100% risiko salah ketik (<em>typo</em>) atau disorientasi data. Alhasil, prosedur pembuatan jadwal ujian seleksi yang berisiko tinggi pun akhirnya terasa sama mudah dan nyamannya seperti mengisi formulir buku tamu biasa.</p>', '1', NULL, '57', '2026-07-06 06:16:28', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('40', '28', 'Modul Administrasi Menu PMB > Gelombang', 'modul-administrasi-menu-pmb-gelombang', '<p>Menu <strong>Gelombang Pendaftaran</strong> (atau Gelombang PMB) di dalam hierarki modul "Administrasi" bertugas sebagai <em>master control</em> untuk mengatur siklus waktu serta target kuota penerimaan siswa baru. Lewat antarmuka "Tambah Gelombang", kita disuguhkan demonstrasi bagaimana sebuah desain formulir (<em>form design</em>) dapat berevolusi mengakomodasi kepadatan data, beralih luwes dari komponen <em>dropdown</em> hingga ke pengaturan rentang kalender.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783318971_5-3 administrasi-gelombang pendaftaran.png" alt="" width="867" height="887"></p>\r\n<h3>Struktur Formulir Pengaturan Gelombang</h3>\r\n<p>Halaman ini senantiasa mempertahankan fondasi visual <em>White Card</em> (panel putih) tunggal untuk merangkum semua spesifikasi pendaftaran. Yang menjadikannya unik adalah transisi <em>grid</em> yang dinamis (dari 2-kolom menjadi 3-kolom) untuk menyesuaikan dengan fungsi input yang spesifik.</p>\r\n<h4>1. Konfigurasi Relasional &amp; Penguncian Unit (Two-Column Layout)</h4>\r\n<p>Tiga baris pertama formulir dihuni oleh kombinasi parameter wajib dan input yang dikunci (<em>locked inputs</em>):</p>\r\n<ul>\r\n<li><strong>Integritas Waktu &amp; Identitas:</strong> <em>Field</em> krusial seperti <code>Gelombang</code> dan <code>Tahun Ajaran</code> mutlak menggunakan <em>Dropdown</em>, tidak memberikan celah bagi pengetikan bebas (*free text*) demi memastikan penyeragaman data (<em>data uniformity</em>).</li>\r\n<li><strong>Komponen Chip Interaktif:</strong> Kolom <code>Jenjang</code> (misal: TKIA) dikunci rapat dengan latar abu-abu sebagai wujud <em>Error Prevention</em> standar aplikasi. Namun sorotan utama ada pada kolom <code>Nama Sekolah</code> (misal: TK Islam Al Azhar 6...). Alih-alih berupa teks mati, nilai tersebut direpresentasikan sebagai label interaktif bergaya <em>Chip/Tag</em> yang dibubuhi ikon silang (<code>x</code>). Konvensi visual UI ini mengindikasikan kapabilitas <em>multi-select</em> (pilihan jamak)&mdash;memungkinkan satu jadwal gelombang diaplikasikan secara sinkron ke beberapa cabang sekolah sekaligus.</li>\r\n<li><strong>Parameter Operasional:</strong> Disokong oleh <em>field</em> <code>Target Sekolah</code> untuk mendefinisikan batas maksimal pendaftar (kuota), dan <code>Status</code> guna mengendalikan visibilitas gelombang secara *real-time*.</li>\r\n</ul>\r\n<h4>2. Manajemen Penjadwalan Rapat (Three-Column Date Pickers)</h4>\r\n<p>Baris penutup formulir adalah <em>masterclass</em> dalam efisiensi visual (<em>visual efficiency</em>):</p>\r\n<ul>\r\n<li><strong>Pemampatan Horisontal:</strong> Untuk mengatur kronologi berjalannya PMB, desainer membelah layar menjadi 3 kolom identik: <code>Tanggal Mulai Dibuka</code>, <code>Tanggal Ditutup</code>, dan <code>Tanggal Jatuh Tempo</code>. Membariskan ketiganya secara sejajar terbukti sangat efektif memangkas tinggi halaman secara drastis (*reducing scrolling fatigue*).</li>\r\n<li><strong>Affordance Kalender:</strong> Ketiga kolom tersebut mengimplementasikan komponen <em>Date Picker</em> (pemilih kalender) yang *native*. Ikon kalender kecil yang disematkan di ujung kanan tiap-tiap kotak (<em>field</em>) merupakan penanda visual (<em>affordance</em>) yang jelas bahwa sistem mengharapkan *input* tanggal baku, bukan ketikan <em>string</em> manual.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain UI/UX</h3>\r\n<p>Antarmuka halaman "Tambah Gelombang" memamerkan kecakapan luar biasa dalam menata <strong>Kepadatan Informasi (Information Density)</strong>. Daripada menyusun 9 variabel pengaturan yang kompleks secara runut ke bawah&mdash;yang pasti akan mengintimidasi admin&mdash;desainer meraciknya ke dalam blok-blok proporsional (2-kolom disusul 3-kolom). Diperlengkapi komponen cerdas semacam <em>Tags/Chips multi-select</em> untuk institusi dan <em>Triple Date Pickers</em> untuk linimasa, tata letak ini sanggup menyederhanakan konfigurasi kebijakan PMB yang sejatinya sangat rumit menjadi sebuah pengalaman <em>data-entry</em> yang mengalir dan kohesif.</p>', '1', NULL, '58', '2026-07-06 06:22:09', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('41', '28', 'Modul Administrasi Menu PMB > Peserta Ujian', 'modul-administrasi-menu-pmb-peserta-ujian', '<p>Menu <strong>Peserta Ujian</strong> yang terletak dalam direktori "Administrasi &gt; PMB" menampilkan sebuah tabel data (<em>data grid</em>) berdesain ringkas yang berfungsi sebagai pusat komando (<em>command center</em>) pemantauan seleksi siswa. Antarmuka "Daftar Peserta Ujian" ini memprioritaskan fungsi pencarian cepat dan rekapitulasi data lintas modul.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783320071_5-4 administrasi-peserta ujian.png" alt="" width="880" height="900"></p>\r\n<h3>Struktur Antarmuka (UI) Daftar Peserta Ujian</h3>\r\n<p>Halaman ini menanggalkan komponen <em>form input</em> yang memakan tempat, dan sepenuhnya mendedikasikan ruang layar (<em>screen real estate</em>) untuk penyajian data tabel yang komprehensif.</p>\r\n<ul>\r\n<li><strong>Kolom Pencarian Global (Search Bar):</strong> Bertengger strategis di sudut kiri atas tabel, fitur pencarian ini adalah nyawa dari UX halaman ini. Admin dapat langsung memfilter ratusan data secara <em>real-time</em> berdasarkan nama atau nomor registrasi tanpa perlu *loading* ulang halaman (*AJAX-based search*).</li>\r\n<li><strong>Arsitektur Kolom Tabel:</strong> Tabel ini adalah mahakarya kompilasi data (*data aggregation*). Ia tidak hanya merangkum identitas dasar (<code>No Registrasi</code>, <code>Nama Lengkap</code>, <code>Jenis Kelamin</code>), melainkan langsung menyandingkannya dengan konteks pendaftaran (<code>Gelombang</code>, <code>Asal Sekolah</code>, <code>Jenjang Kelas &amp; Program</code>, <code>Tahun Ajaran</code>). Desain ini mencegah admin dari birokrasi *klik* yang berlebihan (tidak perlu membuka profil siswa satu per satu hanya untuk mengecek jenjang kelasnya).</li>\r\n<li><strong>Kolom Evaluasi (Nilai &amp; Aksi):</strong> Kolom <code>Nilai</code> bertindak sebagai *focal point* (titik fokus) yang mengubah tabel ini dari sekadar daftar kontak menjadi papan skor (*scorecard*). Kolom <code>Aksi</code> di ujung kanan berfungsi sebagai pintu masuk untuk meng-<em>input</em> atau memodifikasi nilai tersebut.</li>\r\n<li><strong>Penanganan Empty State yang Elegan:</strong> Ketika <em>database</em> masih kosong (belum ada peserta yang dijadwalkan), sistem tidak menyuguhkan kotak putih kosong atau pesan <em>error</em> yang mengintimidasi. Sebaliknya, hadir ilustrasi dokumen yang estetik (<em>Empty State</em>) dengan keterangan "Data tidak ada", memberi sinyal positif bahwa sistem berjalan normal, hanya saja datanya belum tersedia.</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Dari kacamata arsitektur sistem dan bisnis proses, menu <strong>Peserta Ujian</strong> memegang peranan krusial sebagai <strong>"Jembatan Transisi"</strong> (<em>Transition Bridge</em>) di paruh kedua siklus Penerimaan Murid Baru (PMB).</p>\r\n<ul>\r\n<li><strong>Titik Hulu (Data Pull):</strong> Secara otomatis, halaman ini menarik dan menyaring data dari menu <strong>Data Calon Murid</strong> (memilih siswa yang berkas administrasinya sudah dinyatakan valid) dan menyilangkannya dengan referensi dari menu <strong>Jadwal Ujian</strong> serta <strong>Gelombang Pendaftaran</strong>. Dengan kata lain, nama-nama yang muncul di tabel ini adalah mereka yang telah sah memegang tiket (<em>eligible</em>) untuk mengikuti ujian seleksi.</li>\r\n<li><strong>Titik Hilir (Data Feed):</strong> Tabel ini memproduksi luaran (*output*) berupa skor ujian. Data yang diolah di sini&mdash;terutama konklusi dari kolom <strong>Nilai</strong>&mdash;selanjutnya akan didorong (<em>pushed</em>) ke menu akhir, yakni <strong>Kelulusan Peserta</strong>. Angka yang tertera di halaman Peserta Ujian inilah yang akan menjadi fondasi argumen logis (<em>logical parameter</em>) bagi pimpinan sekolah untuk mengeksekusi status akhir: "Diterima", "Cadangan", atau "Ditolak".</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Desain "Daftar Peserta Ujian" mendobrak stigma bahwa tabel administrasi selalu terasa kaku dan *overwhelming*. Dengan merangkum 9 kolom analitik terpenting dan membungkusnya dengan fitur pencarian responsif, desainer sukses menciptakan <em>dashboard</em> evaluasi yang padat informasi (*information-dense*) namun amat melegakan untuk dibaca. Bertindak sebagai persimpangan utama dalam <em>workflow</em> PMB, antarmuka ini menjembatani jurang antara fase pendaftaran administrasi (<em>data entry</em>) menuju fase krusial pengambilan keputusan akhir (<em>decision making</em>).</p>', '1', NULL, '59', '2026-07-06 06:40:27', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('42', '28', 'Modul Administrasi Menu PMB > Kelulusan Peserta', 'modul-administrasi-menu-pmb-kelulusan-peserta', '<p>Menu <strong>Kelulusan Peserta</strong> adalah gerbang penentuan akhir (<em>final judgement gate</em>) dalam arsitektur modul "Administrasi &gt; PMB". Halaman ini dirancang secara khusus untuk bertindak sebagai <em>dashboard</em> eksekusi (<em>execution board</em>) di mana panitia atau pimpinan sekolah menjatuhkan vonis kelulusan bagi para calon murid baru.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783321096_5-5 administrasi-kelulusan peserta-tab belum diproses.png" alt="" width="739" height="756"></p>\r\n<h3>Struktur Antarmuka (UI) Eksekusi Kelulusan</h3>\r\n<p>Halaman ini sangat sarat akan fitur tindakan massal (<em>bulk actions</em>) dan pengategorian data (*data triaging*), yang direpresentasikan melalui elemen-elemen UI strategis berikut:</p>\r\n<ul>\r\n<li><strong>Tab Navigasi Status (Status Switcher):</strong> Bidang kerja dipecah menjadi tiga tabulasi logis: <code>Belum Diproses</code>, <code>Peserta Lulus</code>, dan <code>Peserta Tidak Lulus</code>. Pola UX berbasis <em>pipeline</em> ini sangat krusial; ia mencegah admin mengeksekusi data siswa yang sama dua kali dan memberikan gambaran instan (<em>progress tracking</em>) mengenai berapa banyak siswa yang nasibnya belum ditentukan.</li>\r\n<li><strong>Bilah Aksi Massal (Bulk Action Bar):</strong> Pada tab utama ("Belum Diproses"), sistem menyuguhkan deretan tombol eksekusi: <code>Luluskan</code> (berwarna biru berikon centang) dan <code>Tidak Lulus</code> (merah berikon coret). Tombol ini secara logis terhubung dengan <em>Checkbox</em> di tabel bawahnya, memampukan pimpinan menetapkan status puluhan siswa sekaligus hanya dengan sekali klik (<em>Batch Processing</em>).</li>\r\n<li><strong>Dukungan Evaluasi Luring (Offline Processing):</strong> Memahami kultur panitia PMB yang mungkin lebih nyaman mengolah nilai di Microsoft Excel, UI ini cerdas menyediakan tombol <code>Download Template</code> (hijau) dan <code>Upload Hasil Ujian</code> (biru). Fitur inklusif ini menjembatani <em>workflow</em> tradisional dengan sistem digital modern.</li>\r\n<li><strong>Fitur Ralat (Revert Action):</strong> Pada tab "Peserta Lulus" maupun "Tidak Lulus", deretan tombol aksi bertransformasi menjadi tombol <code>Batalkan</code> (merah). Ini adalah wujud jaring pengaman UX (<em>Safety Net</em>), memberikan hak dan ruang bagi pengguna untuk mengoreksi keputusan apabila terjadi kelalaian klik (*human error correction*).</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783321115_5-6 administrasi-kelulusan peserta-tab peserta lulus.png" alt="" width="749" height="766"></p>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Dalam skala bisnis proses yang lebih luas, menu <strong>Kelulusan Peserta</strong> memegang tongkat estafet sebagai <strong>Muara Keputusan</strong> (<em>The Decision Hub</em>) dari keseluruhan rantai Penerimaan Murid Baru.</p>\r\n<ul>\r\n<li><strong>Hulu Data (Input Source):</strong> Menu ini secara eksklusif menyedot data dari menu pra-syaratnya, yaitu <strong>Peserta Ujian</strong>. Tabel kelulusan ini mengambil parameter <strong>Nilai</strong> (skor akhir ujian) yang telah di-*input* sebelumnya sebagai landasan objektif untuk menyortir dan memfilter kelayakan kandidat.</li>\r\n<li><strong>Hilir Data (Output Destination):</strong> Vonis yang dijatuhkan di halaman ini akan menentukan takdir aliran data selanjutnya. Sistem akan menangkap siswa-siswa berstatus "Lulus" dan mentransformasikannya dari "Calon Pendaftar" menjadi entitas nyata yang akan dialirkan (<em>pushed</em>) ke *database* utama <strong>Sekolah &gt; Data Murid</strong> (biasanya setelah tahapan bayar daftar ulang dituntaskan). Sebaliknya, mereka yang ditolak akan diarsipkan dalam modul riwayat.</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783321155_5-7 administrasi-kelulusan peserta-tab peserta tidak lulus.png" alt="" width="759" height="776"></p>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Desain "Kelulusan Peserta" adalah perwujudan sempurna dari <strong>Action-Oriented Dashboard</strong> (Dasbor Berorientasi Eksekusi). Melalui penyediaan navigasi <em>tab</em> yang lugas, integrasi <em>checkbox</em> untuk <em>bulk approval</em>, serta opsi pemrosesan <em>file</em> via Excel, antarmuka ini memastikan fase paling kritis dan menegangkan di musim PMB dapat diselesaikan oleh tim panitia dengan sangat luwes, minim friksi, dan sepenuhnya kebal terhadap tekanan (<em>stress-free</em>).</p>', '1', NULL, '60', '2026-07-06 06:47:57', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('43', '28', 'Modul Administrasi Menu Data Calon Murid', 'modul-administrasi-menu-data-calon-murid', '<p>Menu <strong>Data Calon Murid</strong> yang bersandar di bawah modul utama "Administrasi" berperan sebagai repositori sentral (<em>central repository</em>) bagi seluruh rekam jejak kandidat pendaftar. Halaman ini melampaui batasan sebuah tabel data statis, bertransformasi menjadi <em>pipeline dashboard</em> (dasbor alur kerja) yang memperlihatkan secara <em>real-time</em> di tahap mana progres pendaftaran seorang anak sedang berada.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783321665_5-8 administrasi-data calon murid.png" alt="" width="847" height="820"></p>\r\n<h3>Struktur Antarmuka (UI) Data Calon Murid</h3>\r\n<p>Berfungsi sebagai <em>master data</em> sementara selama musim PMB, antarmuka halaman ini didesain agar sangat padat informasi (<em>information-rich</em>) namun tetap ramah dipindai oleh mata (<em>highly scannable</em>).</p>\r\n<ul>\r\n<li><strong>Aksi Tingkat Tinggi (Top-Level Actions):</strong> Bersemayam di sudut kanan atas, terdapat tombol <code>Filter</code> (hijau) untuk penyaringan lanjutan (berdasarkan rentang waktu, gelombang, atau status), berdampingan dengan tombol <code>Export</code> (biru) untuk mengunduh laporan ke format <em>spreadsheet</em>. Isolasi penempatan tombol ini di luar area operasional tabel memastikan fungsi pelaporan (*reporting*) sangat mudah diakses oleh pimpinan manajerial.</li>\r\n<li><strong>Arsitektur Tabel Holistik:</strong> Kolom tabel membedah perjalanan kandidat dari A sampai Z. Dimulai dari penanda kronologi (<code>Tanggal Daftar</code>), profil dasar (<code>Nama Lengkap</code>, <code>Sekolah Asal</code>), hingga pemetaan *routing* penempatan (<code>Sekolah Tujuan</code>, <code>Program</code>, <code>Gelombang</code>).</li>\r\n<li><strong>Komunikasi Visual via Badges (Lencana Status):</strong> Ini adalah kekuatan UX paling fundamental di halaman ini. Kolom <code>Status</code> tidak menggunakan deretan teks hitam-putih yang monoton, melainkan disuntikkan lencana berwarna (<em>Color-coded Badges</em>):\r\n<ul>\r\n<li><strong>Lencana Kuning</strong> (<span style="color: #ca8a04; background: #fef08a; padding: 2px 8px; border-radius: 12px; font-size: 0.85em;">Waiting List</span>, <span style="color: #ca8a04; background: #fef08a; padding: 2px 8px; border-radius: 12px; font-size: 0.85em;">Menunggu Pembayaran DSP</span>): Secara psikologis mengindikasikan status <em>pending</em>, tertunda, atau butuh <em>follow-up</em> (intervensi admin).</li>\r\n<li><strong>Lencana Hijau</strong> (<span style="color: #16a34a; background: #bbf7d0; padding: 2px 8px; border-radius: 12px; font-size: 0.85em;">Terdaftar</span>): Memberikan sinyal <em>clearance</em>, bahwa kewajiban administrasi anak tersebut di tahap itu telah tuntas.</li>\r\n</ul>\r\nStrategi pewarnaan ini memungkinkan resepsionis atau kasir memprioritaskan siapa yang harus mereka telepon hari ini hanya melalui satu kali <em>scroll</em> cepat.</li>\r\n<li><strong>Aksi Kontekstual (Detail):</strong> Kolom <code>Status</code> paling kanan (di bawah kursor tabel) menyediakan tombol berikon kaca pembesar untuk "membedah" profil pendaftar lebih dalam (verifikasi berkas, riwayat cicilan tagihan, dsb).</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Di dalam ekosistem arsitektur sistem sekolah, menu <strong>Data Calon Murid</strong> adalah <strong>"Stasiun Transit Utama"</strong> (<em>The Main Transit Hub</em>).</p>\r\n<ul>\r\n<li><strong>Hulu Data (Input Source):</strong> Tabel ini bermuara dari dua saluran: tarikan data <em>leads</em> dari menu <strong>Animo</strong> (saat orang tua mengonfirmasi lanjut mendaftar) atau langsung dari portal pendaftaran publik <em>online</em> (<em>self-registration</em>).</li>\r\n<li><strong>Koneksi Paralel (Cross-Module Integration):</strong> Munculnya status seperti "Menunggu Pembayaran" membuktikan bahwa tabel ini terintegrasi erat dengan modul <strong>Keuangan (Biaya)</strong>. Sementara itu, kandidat yang sudah berstatus hijau ("Terdaftar") akan disuplai secara otomatis ke menu <strong>PMB &gt; Peserta Ujian</strong> untuk mendapatkan jadwal tes seleksi.</li>\r\n<li><strong>Hilir Data (Final Destination):</strong> Setelah seorang kandidat merampungkan seluruh siklus (Ujian, Kelulusan, Daftar Ulang) dan mengantongi status akhir "Diterima", entitas datanya akan dieksekusi (<em>pushed</em>) secara permanen ke <em>database</em> utama, yakni menu <strong>Sekolah &gt; Data Murid</strong>. Di titik inilah identitas mereka bertransmutasi secara sah dari "Calon" menjadi "Siswa Aktif".</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Desain halaman "Data Calon Murid" sangat brilian dalam menerjemahkan kerumitan birokrasi PMB ke dalam satu kanvas pemantauan visual. Penggunaan <em>color-coded badges</em> (lencana warna) adalah praktik penerapan <em>Cognitive Load Reduction</em> (pengurangan beban kognitif) yang amat menolong pengguna. Secara <em>workflow</em>, halaman ini bertindak sempurna sebagai integrator (*the grand integrator*) yang mempertemukan operasional tim Pendaftaran (Front Office), tim Keuangan (Kasir), dan tim Akademik (Penyeleksi) dalam satu dasbor yang sama.</p>', '1', NULL, '61', '2026-07-06 07:06:54', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('44', '28', 'Modul Administrasi Menu Biaya > Uang Sekolah', 'modul-administrasi-menu-biaya-uang-sekolah', '<p>Menu <strong>Uang Sekolah</strong> (yang secara historis jamak disebut SPP) berada di dalam yurisdiksi "Administrasi &gt; Biaya". Halaman ini merupakan episentrum (<em>configuration hub</em>) untuk menetapkan tarif finansial operasional akademik bulanan/tahunan. Lewat antarmuka "Tambah Biaya SPP", sistem mendemonstrasikan desain yang sangat lugas (<em>straightforward</em>) namun mumpuni untuk menangani logika penetapan harga yang kompleks (<em>multidimensional pricing logic</em>).</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783385234_5-9 administrasi-biaya uang sekolah.png" alt="" width="843" height="942"></p>\r\n<h3>Struktur Antarmuka (UI) Form Penentuan Biaya</h3>\r\n<p>Mengingat halaman ini berurusan dengan penetapan nominal uang yang amat sensitif, perancang UI (<em>UI Designer</em>) mengadopsi pendekatan minimalis (*minimalist approach*) untuk menjamin konsentrasi penuh dari admin keuangan.</p>\r\n<ul>\r\n<li><strong>Tata Letak Terstruktur (Symmetrical Grid):</strong> Seluruh *field* dibungkus ke dalam *White Card* tunggal dengan formasi <em>grid</em> 2-kolom yang simetris. Format ini mengelompokkan variabel-variabel prasyarat secara horizontal sebelum bermuara ke isian nominal.</li>\r\n<li><strong>Ketergantungan Multidimensi (Multidimensional Parameters):</strong> Sistem tidak menggunakan skema "satu tarif untuk semua" (<em>flat rate</em>). Antarmuka dengan cerdas memaksa admin mendefinisikan 4 parameter kontekstual terlebih dahulu via komponen <em>Dropdown</em>:\r\n<ul>\r\n<li><code>Nama Sekolah</code> (mewakili unit/cabang yayasan)</li>\r\n<li><code>Tahun Ajaran</code> (mengakomodasi inflasi atau penyesuaian tarif antar tahun)</li>\r\n<li><code>Tingkat Kelas</code> (contoh: beban biaya kelas 1 berbeda dengan kelas 6)</li>\r\n<li><code>Program</code> (mewakili peminatan seperti Reguler, Bilingual, atau Tahfidz)</li>\r\n</ul>\r\nMewajibkan penggunaan <em>Dropdown</em> pada empat pilar data ini (ketimbang teks bebas) sukses meredam potensi <em>human error</em> hingga mendekati nol (<em>typo prevention</em>).</li>\r\n<li><strong>Fokus Nominal (The Core Input):</strong> Di baris pamungkas, bertengger sebuah <em>field</em> paruh-lebar (<em>half-width</em>) bernama <code>Uang Sekolah</code>. Kolom ini adalah "gong" atau klimaks dari formulir, di mana admin akhirnya mengisikan angka nominal absolut berdasarkan empat kriteria yang telah disetel di atasnya.</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Bila ditinjau dari arsitektur bisnis (<em>business workflow</em>) sistem ERP, halaman pengaturan <strong>Biaya Uang Sekolah</strong> bertindak sebagai <strong>"Fondasi Otomatisasi Penagihan"</strong> (<em>Billing Automation Foundation</em>).</p>\r\n<ul>\r\n<li><strong>Hulu Referensi (Reference Data Fetching):</strong> Halaman ini murni bertindak sebagai konsumen (<em>consumer</em>) dari <em>master data</em>. Ia menarik daftar unit sekolah, tahun kalender, dan struktur program dari modul <strong>Akademik</strong> dan <strong>Sekolah</strong>.</li>\r\n<li><strong>Hilir Eksekusi (Automation Trigger):</strong> Nominal yang disimpan dari halaman ini tidak berakhir membeku di *database*. Data tarif (*Tariff Dictionary*) ini adalah bahan bakar utama bagi mesin penagihan. Begitu profil seorang anak "Sah/Lulus" dari <em>pipeline</em> PMB (modul <strong>Administrasi</strong>) dan beralih menjadi murid aktif (modul <strong>Data Murid</strong>), mesin tagihan (<em>Auto-Billing Engine</em>) akan menyilang-cocokkan profil anak tersebut dengan kamus tarif ini. Hasilnya: sistem dapat otomatis menerbitkan <em>invoice</em> bulanan ke aplikasi Wali Murid (<em>mobile apps</em>) atau modul <strong>Transaksi</strong> secara masif tanpa perlu campur tangan manual kasir.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Antarmuka halaman "Tambah Biaya SPP" membuktikan tesis bahwa antarmuka <em>backend</em> untuk penyusunan algoritma finansial tidak harus terlihat ruwet layaknya <em>spreadsheet</em>. Melalui pembagian sekat yang jelas antara 4 variabel penentu logika (lewat *dropdown*) dan 1 variabel nominal absolut (lewat *text input*), sistem berhasil menuntun administrator untuk mensimulasikan matriks tagihan SPP sekolah tanpa takut salah kamar, salah kelas, maupun salah angkatan.</p>', '1', NULL, '62', '2026-07-07 00:44:58', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('45', '28', 'Modul Administrasi Menu Biaya > Uang Pangkal', 'modul-administrasi-menu-biaya-uang-pangkal', '<p>Menu <strong>Uang Pangkal</strong> (atau yang kerap direferensikan sebagai DSP - Dana Sumbangan Pendidikan) berada di bawah struktur "Administrasi &gt; Biaya". Halaman ini merupakan pusat pengaturan (<em>master configuration</em>) untuk pos tagihan paling fundamental dan masif di awal masa studi seorang siswa. Desain antarmukanya memamerkan keahlian <em>engineering</em> visual lewat penggunaan tabel bersarang (<em>nested table</em>) demi membedah rincian biaya yang berlapis-lapis.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783385401_5-10 administrasi-biaya uang pangkal.png" alt="" width="900" height="1005"></p>\r\n<h3>Struktur Antarmuka (UI) Rincian Biaya</h3>\r\n<p>Berbeda dengan SPP bulanan yang nominalnya tunggal (<em>flat</em>), tagihan Uang Pangkal secara hakikat adalah gabungan (*bundling*) dari berbagai pos pembiayaan. UI ini mengurai benang kusut kerumitan tersebut dengan fitur <strong>Expandable Rows</strong> (Baris yang dapat dibongkar-muat).</p>\r\n<ul>\r\n<li><strong>Tabel Induk (Master Data Grid):</strong> Saat halaman dimuat, pengguna disuguhi antarmuka tabel reguler yang rapi, berisi matriks parameter (<code>Tahun Ajaran</code>, <code>Nama Sekolah</code>, <code>Jenjang</code>, <code>Program</code>, <code>Tingkat</code>). Tampilan muka ini menjamin administrator memiliki <em>bird-eye view</em> (pandangan makro) atas kerangka tarif seluruh institusi tanpa terdistraksi angka-angka spesifik.</li>\r\n<li><strong>Fitur Akordeon (Nested Table):</strong> Keajaiban UX terjadi di kolom <code>Aksi</code>, yang diwakili oleh ikon <em>chevron</em> (panah). Ketika baris diklik, ia akan merekah ke bawah layaknya akordeon, menampilkan sub-tabel <code>Komponen Biaya</code> dan <code>Nominal</code>.\r\n<ul>\r\n<li>Sebagai representasi, tagihan untuk tingkat "Toddler" tidak dipukul rata, melainkan dipecah transparan menjadi pos-pos terpisah: <em>Uang Kesehatan, Uang Observasi, Uang Pangkal Murni,</em> dan <em>Uang Psikotest</em>.</li>\r\n<li><strong>Nilai Tambah Desain:</strong> Pendekatan <em>Progressive Disclosure</em> (pengungkapan informasi secara bertahap) ini menjamin layar tetap leluasa (<em>clean</em>). Angka-angka rincian hanya muncul ketika pengguna secara aktif memintanya, memusnahkan risiko <em>Information Overload</em> (mabuk data).</li>\r\n</ul>\r\n</li>\r\n<li><strong>Peralatan Navigasi:</strong> Sejalan dengan cetak biru modul lainnya, ketersediaan <em>Search Bar</em> dan tombol <code>Filter</code> memastikan kecepatan navigasi data tetap menjadi prioritas utama.</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Di dalam ekosistem ERP Sekolah, halaman pengaturan <strong>Uang Pangkal</strong> ini memanggul tanggung jawab sebagai <strong>"Kamus Rincian Tagihan Awal"</strong> (<em>Initial Billing Matrix Dictionary</em>).</p>\r\n<ul>\r\n<li><strong>Hulu Data (Sumber Referensi):</strong> Sistem menyedot kerangka data akademis (Cabang, Tahun, Jenjang, Program) langsung dari modul <strong>Akademik</strong> dan <strong>Sekolah</strong> untuk mendirikan kerangka penetapan tarif.</li>\r\n<li><strong>Hilir Data (Integrasi Transaksi):</strong> Ketetapan harga yang terpatri di halaman ini adalah hulu dari pendapatan terbesar sekolah saat masa PMB. Ketika seorang calon murid (di menu <strong>Data Calon Murid</strong>) memasukki fase "Menunggu Pembayaran", mesin keuangan sistem akan melongok ke matriks halaman ini. Ia akan merangkai seluruh pos komponen biaya tersebut menjadi selembar <em>Invoice</em> elektronik komprehensif, yang lantas ditembakkan ke modul <strong>Transaksi &gt; PMB</strong>.</li>\r\n<li><strong>Transparansi Eksternal:</strong> Rincian komponen inilah yang pada akhirnya akan muncul di layar ponsel (<em>mobile apps</em>) Wali Murid. Oleh karenanya, struktur yang disetel admin di halaman ini berkorelasi mutlak dengan tingkat akuntabilitas dan transparansi institusi di mata orang tua murid.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Penerapan pola antarmuka <em>Nested Table / Accordion</em> pada halaman "Tagihan Uang Pangkal" merupakan penyelesaian elegan atas problem kompleksitas data finansial. Desain ini mumpuni dalam merangkum aneka ragam komponen biaya (seragam, tes, gedung) di balik selubung satu identitas kelas, namun tetap menyediakannya utuh dalam jangkauan satu klik. Dari kacamata *workflow*, menu ini adalah generator penagihan paling vital yang memastikan arus kas awal tahun ajaran (<em>cashflow</em>) sekolah tercatat presisi hingga ke sen terakhir.</p>', '1', NULL, '63', '2026-07-07 00:49:23', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('46', '28', 'Modul Administrasi Menu Biaya > Uang Daftar Ulang', 'modul-administrasi-menu-biaya-uang-daftar-ulang', '<p>Menu <strong>Uang Daftar Ulang</strong> yang bernaung di bawah klaster "Administrasi &gt; Biaya" merupakan <em>formulation hub</em> (pusat formulasi) untuk menetapkan tagihan rutin tahunan. Biaya ini umumnya dibebankan kepada siswa aktif (<em>existing students</em>) pada momentum pergantian tahun ajaran. Antarmuka "Tambah Biaya Daftar Ulang" ini secara gamblang mendemonstrasikan keunggulan UX berupa penerapan <strong>Dynamic Form Fields</strong> (kolom formulir dinamis) dan komputasi penjumlahan <em>real-time</em>.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783385758_5-11 administrasi-biaya daftar ulang.png" alt="" width="892" height="996"></p>\r\n<h3>Struktur Antarmuka (UI) Form Penentuan Biaya</h3>\r\n<p>Dalam praktiknya di lapangan, tagihan Daftar Ulang jarang sekali berupa satu pos pembayaran tunggal; ia lumrahnya diracik dari paket bundel (*bundling*) yang berisi biaya buku, ekstrakurikuler tahunan, kegiatan OSIS, dan lain-lain. Desain UI ini mewadahi kerumitan tersebut dengan sangat elegan:</p>\r\n<ul>\r\n<li><strong>Parameter Konteks (Top Section):</strong> Paruh atas formulir memanfaatkan format <em>grid</em> 2-kolom standar untuk mendefinisikan prasyarat wajib: <code>Tahun Ajaran</code>, <code>Tingkat Kelas</code>, dan <code>Program</code>. Penambahan <em>field</em> kalender <code>Tanggal Jatuh Tempo</code> berfungsi mematok tenggat waktu (<em>deadline</em>) pembayaran universal untuk angkatan tersebut.</li>\r\n<li><strong>Injeksi Komponen Dinamis (Dynamic Repeater):</strong> Di sinilah letak kejeniusan arsitektur desainnya. Alih-alih menyediakan 10 baris <em>input</em> kosong yang membuat halaman terlihat panjang dan kumuh, UI hanya menampilkan satu baris awal berupa <code>Komponen Biaya</code> (<em>dropdown</em>) dan <code>Nominal</code> (teks). Apabila panitia keuangan butuh menambahkan *item* tagihan ekstra (misal: Buku Paket), mereka cukup menekan tombol biru <code>+ Tambah Komponen Biaya</code>. Berkat dukungan <em>scripting</em> sisi klien, baris input baru akan digandakan (<em>cloned</em>) ke bawah tanpa *loading* halaman sama sekali.</li>\r\n<li><strong>Kalkulator Waktu Nyata (Real-time Summary Box):</strong> Persis di bawah jejeran <em>input</em> komponen, tersemat sebuah kotak <em>highlight</em> berwarna biru muda bertuliskan <strong>Total Biaya Daftar Ulang</strong>. Secara otomatis (*auto-calculate*), sistem akan mengakumulasikan nominal yang sedang diketik oleh admin di atasnya dan menampilkannya seketika (<em>real-time</em>). Fitur UX ini secara harfiah memusnahkan kebutuhan staf untuk menggunakan alat hitung manual, menyapu bersih risiko salah rekap (<em>calculation error</em>).</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Jika diletakkan dalam konstelasi arsitektur <em>workflow</em> ERP, menu <strong>Uang Daftar Ulang</strong> ini bertindak layaknya <strong>"Kamus Tagihan Transisi"</strong> (<em>Transitional Billing Dictionary</em>).</p>\r\n<ul>\r\n<li><strong>Hulu Data (Reference Fetching):</strong> Layaknya menu konfigurasi lain, ia menelan data hierarki dari modul Akademik (Kelas &amp; Program) serta memanggil tabel master *Komponen Biaya* untuk mengisi opsi-opsi *dropdown* yang ada.</li>\r\n<li><strong>Hilir Data (Mass Invoice Generation):</strong> Matriks tagihan yang disimpan di sini ibarat fondasi yang disiapkan untuk akhir tahun ajaran. Pemicunya (<em>trigger</em>) baru akan bereaksi ketika kepala sekolah mengeksekusi menu <strong>Akademik &gt; Kenaikan Kelas &amp; Kelulusan</strong>. Begitu siswa di-<em>upgrade</em> ke tingkat kelas berikutnya, mesin otomatisasi (<em>cron job / system event</em>) akan melirik kamus biaya di halaman ini. Hasilnya: sistem memproduksi dan mendistribusikan ratusan <em>Invoice</em> Daftar Ulang secara serentak ke dasbor <strong>Transaksi</strong> masing-masing orang tua murid, menagih hak sekolah tepat waktu tanpa intervensi manual sama sekali.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Antarmuka halaman "Tambah Biaya Daftar Ulang" adalah representasi paripurna mengenai cara desain meringankan beban kognitif operator (<em>reducing cognitive load</em>). Lewat perpaduan <em>Dynamic Form Repeater</em> (tombol + Tambah) dan kalkulator tertanam (<em>Auto-Sum Summary</em>), desainer menjamin bahwa tim keuangan sekolah sanggup meracik paket tagihan serumit dan sepanjang apa pun dengan akurasi matematis 100%. Secara fungsional, menu ini adalah urat nadi yang menjamin tidak terjadinya kemacetan arus kas (<em>cashflow</em>) di masa transisi kalender pendidikan.</p>', '1', NULL, '64', '2026-07-07 00:55:06', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('47', '28', 'Modul Administrasi Menu Biaya > Pengajuan Diskon', 'modul-administrasi-menu-biaya-pengajuan-diskon', '<p>Menu <strong>Pengajuan Diskon</strong> (atau Potongan Biaya) di dalam payung "Administrasi &gt; Biaya" merupakan etalase (*showcase*) dari fleksibilitas antarmuka sistem. Mengingat kebijakan subsidi memiliki banyak jalur (Prestasi Kejuaraan, Hafalan Al Quran, Raport, Saudara Kandung, Anak Pegawai, dan Lulusan YPIA), sistem menolak untuk memaksakan satu formulir sapu jagat (<em>one-size-fits-all</em>). Sebaliknya, ia menyajikan antarmuka dinamis yang bermutasi bentuk menyesuaikan jenis diskon yang dipilih.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783386198_5-12 administrasi-pengajuan diskon.png" alt="" width="861" height="961"></p>\r\n<h3>Struktur Antarmuka (UI) Form Kontekstual</h3>\r\n<p>Halaman ini memamerkan eksekusi brilian dari prinsip <strong>Contextual UI</strong> (Antarmuka Kontekstual). Form berevolusi untuk hanya menampilkan *field* yang secara logis dibutuhkan untuk memvalidasi *tab* diskon bersangkutan:</p>\r\n<ul>\r\n<li><strong>Identitas Jangkar (Anchor Fields):</strong> Di setiap *tab*, formulir selalu dipersatukan oleh *field* absolut: <code>Nama Siswa</code> (berupa kotak pencarian *real-time* cerdas yang menyuguhkan nama dan No. Registrasi), dan <code>Tujuan Sekolah</code>. *Field* <code>Besar Potongan (%)</code> juga selalu hadir sebagai luaran numerik (<em>numeric output</em>) dari pengajuan tersebut.</li>\r\n<li><strong>Mutasi *Field* Kontekstual:</strong> Kehebatan UX terasa dari detail perubahan kolom di masing-masing jalur pendaftaran:\r\n<ul>\r\n<li><strong>Jalur Prestasi &amp; Tahfidz:</strong> Sistem memunculkan parameter validasi kompetitif seperti <code>Tingkat</code> (Nasional/Internasional) dan <code>Medali</code> (Emas/Perak/Perunggu), demi menakar *grade* potongan.</li>\r\n<li><strong>Jalur Saudara Kandung:</strong> Fokus beralih ke demografi keluarga dengan memunculkan <em>field</em> <code>Jumlah Saudara</code>.</li>\r\n<li><strong>Jalur Anak Pegawai:</strong> Mengusung integrasi lintas-modul (<em>cross-module integration</em>) dengan HR. Muncul <em>field</em> pencarian <code>Nama Pegawai/NIP</code> yang terhubung dengan <code>Jabatan</code>. Menariknya, sistem memecah besaran potongan secara spesifik menjadi 3 kolom terpisah (Diskon Uang Pangkal, SPP, Biaya Lainnya).</li>\r\n</ul>\r\n</li>\r\n<li><strong>Dokumen Pendukung Adaptif:</strong> Setiap pengajuan menuntut alat bukti fisik yang didigitalisasi (Unggah Dokumen, Maks 2MB). Hebatnya, label kotak unggahan beradaptasi cerdas: meminta <code>Sertifikat/Piagam</code> untuk jalur prestasi/tahfidz, namun berubah meminta <code>Kartu Keluarga</code> untuk jalur Saudara Kandung &amp; Anak Pegawai. Penyesuaian mikro (<em>micro-copywriting</em>) ini melenyapkan kebingungan staf (*ambiguity prevention*).</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783386229_5-14 administrasi-tambah diskon prestasi rapot.png" alt="" width="709" height="709"></p>\r\n<h3><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783386258_5-15 administrasi-tambah diskon hafalan quran.png" alt="" width="710" height="710"></h3>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Ditinjau dari kacamata arsitektur ERP Sekolah, fitur <strong>Pengajuan Diskon</strong> berperan esensial sebagai <strong>"Interseptor Tagihan"</strong> (<em>Billing Interceptor / Modifier</em>) sesaat sebelum tagihan resmi dieksekusi.</p>\r\n<ul>\r\n<li><strong>Hulu Integrasi Data (Input Sources):</strong> Formulir ini menyedot referensi identitas secara menyilang: mengambil nama anak dari modul <strong>Data Calon Murid/Data Murid</strong>, serta menarik data identitas karyawan dari modul <strong>Kepegawaian (HR)</strong>.</li>\r\n<li><strong>Hilir Otomatisasi (Workflow Execution):</strong> Data (Besar Potongan %) yang di-<em>submit</em> di sini lazimnya akan memicu siklus persetujuan (<em>Approval Workflow</em>) berjenjang ke pimpinan yayasan. Begitu diteken sah, persentase diskon tersebut diinjeksi (*injected*) ke dalam mesin Penagihan di modul <strong>Transaksi</strong>. Alhasil, sistem kasir akan secara otomatis memotong (mendiskon) <em>Invoice</em> SPP bulanan atau tagihan Uang Pangkal siswa yang bersangkutan, tanpa kasir harus menekan tombol "Diskon" secara manual lagi.</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783386295_5-16 administras-tambah diskon saudara kandung.png" alt="" width="716" height="716"></p>\r\n<h3><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783386323_5-17 administrasi-tambah diskon anak pegawai.png" alt="" width="702" height="702"></h3>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Penerapan pola *Contextual UI* pada fitur "Pengajuan Diskon" berhasil menyelamatkan *database* dari sampah kolom-kolom statis yang tak terpakai (*general string columns*). Dengan mendikte tipe data secara kaku sesuai jalur pengajuannya (contoh: NIP vs Medali) dan mendandani label *upload* dokumen secara adaptif, perancang sistem menggaransi tingginya integritas data. Dari perspektif alur kerja, menu ini bertindak bagai jembatan emas yang menghubungkan amanat beasiswa/subsidi dari yayasan dengan presisi otomatisasi mesin penagihan keuangan.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783386347_5-18 administrasi-tambah diskon lulusan ypi.png" alt="" width="678" height="678"></p>', '1', NULL, '65', '2026-07-07 01:02:30', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('48', '28', 'Modul Administrasi Menu Biaya > Pengajuan Angsuran', 'modul-administrasi-menu-biaya-pengajuan-angsuran', '<p>Menu <strong>Pengajuan Angsuran</strong> yang menjadi penutup pada blok "Administrasi &gt; Biaya" merupakan fasilitas strategis untuk memberikan kelonggaran finansial (<em>financial relief</em>) kepada orang tua murid. Halaman "Tambah Murid Angsuran Uang Pangkal" ini mempertontonkan filosofi desain minimalis ekstrem, di mana antarmuka sangat ringkas karena sistem mendelegasikan kerumitan kalkulasi sepenuhnya ke mesin belakang (*backend automation*).</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783386930_5-19 administrasi-pengajuan angsuran.png" alt="" width="848" height="932"></p>\r\n<h3>Struktur Antarmuka (UI) Form Angsuran</h3>\r\n<p>Merestrukturisasi tagihan besar (seperti Uang Pangkal) menjadi cicilan adalah proses yang rawan salah hitung. Untuk meminimalisasi risiko tersebut, UI dirancang untuk hanya meminta parameter yang paling absolut:</p>\r\n<ul>\r\n<li><strong>Pencarian Cerdas (Smart Search Input):</strong> Baris pertama formulir merentang penuh (100% <em>width</em>) untuk mengakomodasi <em>field</em> <code>Nama Murid</code>. Keunggulannya terletak pada kapabilitas <em>dual-search</em>: admin bebas mengetikkan Nama Lengkap ataupun NIS (Nomor Induk Siswa). Dukungan <em>dropdown</em> cerdas ini memastikan presisi 100%, menghindarkan admin dari malapetaka salah memilih siswa yang kebetulan bernama mirip.</li>\r\n<li><strong>Auto-Fill &amp; Validasi Visual:</strong> Tepat di baris kedua, tersaji kolom <code>Jenjang</code> dan <code>Tujuan Sekolah</code>. Dalam *best-practice* UX, kedua *field* ini didesain sebagai kolom <em>read-only</em> yang akan terisi otomatis (<em>auto-populate</em>) begitu identitas anak di atasnya dipilih. Ini bertindak sebagai mekanisme <em>Error Prevention</em> visual, mengonfirmasi kepada admin bahwa ia sedang memproses data anak yang tepat di cabang sekolah yang benar.</li>\r\n<li><strong>Parameter Kebijakan (The Core Variable):</strong> Variabel pemungkas di halaman ini hanyalah <em>dropdown</em> <code>Masa Angsuran</code> (misal: opsi 3 kali, 6 kali, atau 12 bulan). Sangat krusial untuk dicatat bahwa <strong>tidak ada kolom untuk mengetikkan nominal rupiah</strong>. Angka cicilan tabu untuk diketik manual oleh manusia; ia harus dikomputasi oleh algoritma sistem demi menjamin akurasi neraca akuntansi (<em>accounting accuracy</em>).</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Dalam konstelasi arsitektur pembayaran (<em>Billing Architecture</em>), menu <strong>Pengajuan Angsuran</strong> memanggul peran sebagai <strong>"Restrukturisator Tagihan"</strong> (<em>Invoice Restructuring Engine</em>).</p>\r\n<ul>\r\n<li><strong>Hulu Data (Cross-Module Dependency):</strong> Halaman ini adalah murni konsumen data. Ia menyedot identitas murid dari <strong>Modul PMB / Data Murid</strong>, serta menarik opsi durasi termin cicilan langsung dari menu <strong>Master Data &gt; Angsuran</strong> (terlihat di navigasi <em>sidebar</em> bagian bawah).</li>\r\n<li><strong>Hilir Data (Invoice Splitting Execution):</strong> Momentum ajaib (*system magic*) terjadi seketika tombol "Simpan" ditekan. Mesin ERP akan mencari tagihan *Grand Total* Uang Pangkal anak tersebut, lalu memutilasi (<em>splitting</em>) tagihan raksasa itu menjadi beberapa <em>invoice</em> anakan (<em>child invoices</em>) dengan proporsi nilai yang rata, sesuai dengan termin "Masa Angsuran" yang dipilih.</li>\r\n<li><strong>Injeksi ke Transaksi:</strong> Deretan <em>invoice</em> cicilan yang baru saja di-<em>generate</em> ini kemudian akan disuntikkan (*injected*) ke dalam <em>pipeline</em> modul <strong>Transaksi</strong>, lengkap dengan tangga jatuh temponya masing-masing (misal: Cicilan 1 ditagih Agustus, Cicilan 2 ditagih September, dst). Seluruh rentetan rincian ini akan langsung tercermin secara *real-time* di layar aplikasi *mobile* orang tua murid.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Halaman "Pengajuan Angsuran" adalah monumen keberhasilan desain dalam menyederhanakan fungsi bisnis yang pelik (restrukturisasi piutang). Hanya bermodalkan fitur pencari nama dan satu <em>dropdown</em> termin cicilan, desainer sistem sukses melucuti seluruh beban kalkulasi matematis dari pundak staf keuangan. Dari kacamata operasional, menu ini menjembatani dengan sempurna antara kebijakan empati sekolah terhadap wali murid dengan ketertiban pencatatan piutang (<em>account receivable</em>) pada sistem akuntansi yayasan.</p>', '1', NULL, '66', '2026-07-07 01:13:07', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('49', '28', 'Modul Master Data Menu Angsuran', 'modul-master-data-menu-angsuran', '<p>Bergeser meninggalkan blok operasional administrasi, kita kini menukik ke lapisan dasar arsitektur sistem: modul <strong>Master Data</strong>. Menu <strong>Angsuran</strong> (dengan tajuk antarmuka "Tambah Masa Angsuran") adalah representasi ideal dari prinsip aplikasi yang <em>scalable</em> (tangguh &amp; fleksibel). Alih-alih mematok mati (<em>hardcode</em>) opsi cicilan di dalam sistem, <em>developer</em> menyediakan ruang bagi yayasan untuk mendefinisikan sendiri durasi cicilan tersebut dari tahun ke tahun.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783387225_9-master data-angsuran.png" alt="" width="821" height="902"></p>\r\n<h3>Struktur Antarmuka (UI) Konfigurasi Dasar</h3>\r\n<p>Formulir yang bernaung di level Master Data wajib dirancang dengan tingkat restriksi (<em>strictness</em>) maksimal, karena data di sini akan menjadi fondasi (tulang punggung) bagi menu-menu transaksional di atasnya. UI halaman ini dikemas dengan sangat ketat dan disiplin:</p>\r\n<ul>\r\n<li><strong>Grid Minimalis (2x2 Layout):</strong> Keempat *field* input diwadahi secara rapi dalam grid dua kolom berukuran paruh-lebar (<em>half-width</em>), meminimalkan pergerakan mata pengguna (*eye-tracking*) saat mengisi <em>form</em> dari kiri-kanan lalu ke bawah.</li>\r\n<li><strong>Pendekatan Dropdown-Sentris (100% Dropdown UI):</strong> Fitur paling menonjol dari form ini adalah ketiadaan <em>text-box</em> reguler. Keempat <em>field</em> yang ada (<code>Tahun Ajaran</code>, <code>Status</code>, <code>Gelombang</code>, dan <code>Masa Angsuran</code>) diwajibkan menggunakan komponen <em>Dropdown</em>. Dalam hukum desain basis data (<em>database design rule</em>), membiarkan staf mengetik bebas di menu Master Data adalah malapetaka (misal: "6 Bulan", "Enam Bulan", atau "6 Bln"). Pendekatan murni *dropdown* ini mengunci sistem dari ancaman inkonsistensi data (*data anomaly prevention*).</li>\r\n<li><strong>Keterikatan Kontekstual:</strong> Desain ini secara implisit mengakomodasi kelenturan strategi bisnis. Admin dipaksa menyetel "Masa Angsuran" berdasarkan relasinya dengan "Tahun Ajaran" dan "Gelombang". Ini memungkinkan sekolah menerapkan kebijakan berbeda (misal: pendaftar Gelombang 1 boleh mencicil 10x, namun Gelombang 3 hanya boleh 3x karena sudah mepet waktu masuk sekolah).</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Di dalam peta jalan aliran informasi aplikasi, menu <strong>Master Data &gt; Angsuran</strong> menduduki posisi sebagai <strong>"Hulu Regulasi Cicilan"</strong> (<em>The Installment Policy Generator</em>).</p>\r\n<ul>\r\n<li><strong>Hulu Referensi (Data Consumer):</strong> Untuk bisa berfungsi, halaman ini lebih dulu mengonsumsi <em>master data</em> lain, yakni menyedot referensi <strong>Tahun Ajaran</strong> dari modul Akademik dan daftar <strong>Gelombang Pendaftaran</strong> dari modul Administrasi PMB.</li>\r\n<li><strong>Hilir Suplai (Data Supplier):</strong> Data yang di-<em>submit</em> di halaman ini (misal: 6 Bulan untuk Gelombang 1) akan diekspor dan seketika muncul sebagai menu pilihan (*dropdown options*) di halaman <strong>Administrasi &gt; Biaya &gt; Pengajuan Angsuran</strong> (halaman operasional yang menangani siswa secara individual). Singkatnya: Jika Master Data ini kosong, staf garis depan tidak akan bisa memproses cicilan apa pun.</li>\r\n<li><strong>Pengendalian Terpusat (Centralized Control):</strong> Berkat kehadiran menu ini, manajemen sekolah (Kepala Sekolah/Yayasan) memiliki kendali setir seutuhnya atas kebijakan kredit sekolah secara mandiri, tanpa harus bergantung pada *programmer* untuk mengubah opsi aplikasi setiap ganti tahun ajaran.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Formulir "Tambah Masa Angsuran" ini bersinar terang berkat kesederhanaan dan kedisiplinannya. Keputusan *UI Designer* untuk membatasi ruang gerak pengguna dengan menggunakan 100% <em>dropdown field</em> adalah langkah defensif yang brilian guna menjamin integritas <em>database</em> (<em>foolproof design</em>). Secara <em>workflow</em>, menu ini sukses membuktikan bahwa aplikasi <em>Al Azhar Apps</em> dirancang dengan prinsip <em>future-proof</em>&mdash;sepenuhnya siap mengakomodasi fluktuasi kebijakan finansial yayasan di masa depan.</p>', '1', NULL, '67', '2026-07-07 01:19:59', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('50', '27', 'Modul Manajemen User Menu User Sekolah', 'modul-manajemen-user-menu-user-sekolah', '<p>Memasuki teritori yang sangat krusial terkait sekuriti data, menu <strong>User Sekolah</strong> di dalam klaster "Manajemen User" adalah pintu gerbang otorisasi mutlak (<em>Absolute Authorization Gateway</em>). Halaman "Tambah User" ini mendemonstrasikan eksekusi antarmuka yang sangat peka terhadap konteks (<em>Context-Aware UI</em>), di mana struktur formulir pendaftaran akun akan bermutasi secara instan mengikuti peran (<em>Role</em>) yang sedang dipilih.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783387730_6-1 manajemen user-user sekolah.png" alt="" width="834" height="834"></p>\r\n<h3>Struktur Antarmuka (UI) Form Autentikasi</h3>\r\n<p>Menciptakan kredensial <em>login</em> (akun) secara manual membawa risiko fatal terhadap pembengkakan data tak bertuan (<em>ghost accounts</em>). Untuk memitigasi hal ini, desainer UI mengimplementasikan arsitektur *binding* (penautan) yang ketat:</p>\r\n<ul>\r\n<li><strong>Mutasi Berbasis Peran (Role-Based Form Adaptation):</strong> <em>Field</em> pertama dan terpenting adalah <code>Peran/Role</code>. Pilihan di <em>dropdown</em> inilah yang mengendalikan anatomi layar di bawahnya.\r\n<ul>\r\n<li><strong>Mode Pegawai/Sekolah:</strong> Bila diklik, sistem memunculkan <em>field</em> <code>Level</code> guna mendefinisikan batas hak akses aplikasi (misal: Super Admin, Kasir, Guru). Fitur pencarian pada <code>Nama User</code> pun meruncing spesifik untuk melacak data kepegawaian melalui Nomor Induk Pegawai (NIP) atau Nama GTK.</li>\r\n<li><strong>Mode Peserta Didik:</strong> Jika <em>role</em> diganti ke siswa, form menjadi lebih ramping. <em>Field</em> <code>Level</code> dihanguskan (karena level siswa bersifat absolut/statis), dan target pencarian pada <code>Nama User</code> otomatis beralih membedah <em>database</em> Nomor Induk Siswa (NIS).</li>\r\n</ul>\r\n</li>\r\n<li><strong>Sistem Penautan Identitas (Strict Data Binding):</strong> Sistem melarang keras administrator mengetik sembarang nama fiktif. <em>Field</em> <code>Nama User</code> didesain sebagai kotak pencarian *real-time* yang terhubung ke <em>database master</em>. Mekanisme ini menjamin bahwa setiap *Username* dan *Password* yang dilahirkan di halaman ini terikat sah secara digital (<em>digitally binded</em>) pada entitas fisik manusia yang riwayatnya sudah tercatat oleh sekolah.</li>\r\n<li><strong>Ekspansi Hak Akses (LMS Checkbox):</strong> Keberadaan <em>checkbox</em> sederhana bertuliskan <code>Dapat Mengakses LMS</code> membuktikan bahwa sistem aplikasi ini mendukung arsitektur <em>Single Sign-On (SSO)</em> parsial. Dengan satu sentuhan *centang*, kredensial yang dibuat ini langsung terotorisasi masuk ke ekosistem <em>Learning Management System</em> di luar portal utama.</li>\r\n</ul>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783387757_6-2 manajemen user-siswa orangtua.png" alt="" width="802" height="881"></p>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Di dalam <em>blueprint workflow</em> IT, menu <strong>User Sekolah</strong> berperan secara eksklusif sebagai <strong>"Identity &amp; Access Management (IAM) Hub"</strong>.</p>\r\n<ul>\r\n<li><strong>Hulu Referensi (Data Consumer):</strong> Menu ini secara hierarkis tidak menciptakan manusia baru. Ia berdiri di hilir dari modul <strong>Sekolah &gt; Pegawai</strong> dan <strong>Sekolah &gt; Data Murid</strong>. Tugasnya hanyalah memanggil manusia-manusia yang sudah terdaftar di sana, lalu memakaikan "baju zirah digital" (hak *login*) kepada mereka.</li>\r\n<li><strong>Hilir Otorisasi (System-wide Director):</strong> Begitu tombol "Simpan" ditekan, data diinjeksi ke tabel fundamental <code>Users</code>. *Database* dari halaman inilah yang akan menjadi penentu nasib (*Director*) setiap kali seseorang mengakses layar depan aplikasi. Kredensial (<em>Role &amp; Level</em>) yang disetel di sinilah yang mengatur apakah orang tersebut akan mendarat di Dasbor Keuangan (untuk kasir), Dasbor Akademik (untuk guru), atau sekadar Dasbor Tagihan (untuk orang tua siswa).</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Menyatukan form pembuatan akun Pegawai dan Siswa ke dalam satu halaman dinamis (tanpa perlu membuka tab menu yang berbeda) adalah keputusan UX yang berani namun sangat efisien (*lean interface*). Mekanisme pertahanan sistem melalui <em>Smart Search Input</em> pada *field* Nama User memastikan kebersihan ekosistem aplikasi dari duplikasi akun. Secara komprehensif, menu ini mendemonstrasikan keandalan aplikasi *Al Azhar Apps* dalam memagari lalu-lintas hak akses pengguna dalam satu sentralisasi kontrol yang aman dan elegan.</p>', '1', NULL, '48', '2026-07-07 01:27:12', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('51', '27', 'Modul Jurnal & E-Rapot Menu E-Rapot', 'modul-jurnal-e-rapot-menu-e-rapot', '<p>Terletak di penghujung peta navigasi sistem, menu <strong>E-Rapot</strong> di bawah modul "Jurnal &amp; E-Rapot" adalah muara agung dari seluruh keringat dan aktivitas akademik selama satu semester. Halaman ini difungsikan sebagai "Pusat Generator Dokumen" (<em>Document Generation Hub</em>). Dari segi UI/UX, halaman ini dengan teguh menerapkan paradigma <strong>Filter-First</strong> (Penyaringan Prioritas), sebuah desain defensif yang melarang sistem menampilkan data apa pun sebelum kriteria pencarian dikerucutkan.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783388076_7-jurnal erapot-erapot.png" alt="" width="825" height="825"></p>\r\n<h3>Struktur Antarmuka (UI) Pusat Cetak Rapor</h3>\r\n<p>Merender data nilai ribuan siswa memakan daya komputasi yang masif. Untuk mencegah layar membeku (*freeze*) atau <em>server overload</em>, antarmuka ini dirakit dengan beberapa pembatas kognitif dan teknis:</p>\r\n<ul>\r\n<li><strong>Blokade *Filter-First*:</strong> Saat halaman dibuka, layar data sengaja dibiarkan kosong, digantikan oleh *banner* notifikasi persuasif: <em>"Silahkan filter terlebih dahulu untuk menampilkan data"</em>. Admin atau wali kelas dipaksa (<em>forced-action</em>) untuk mendefinisikan <code>Kelas</code>, <code>Rombel</code>, dan <code>Tahun Ajaran</code> sebelum menekan tombol biru <code>Tampilkan</code>. Pendekatan ini adalah standar emas UX untuk aplikasi <em>database</em> skala besar.</li>\r\n<li><strong>Kolom Tanggal Esensial:</strong> Di luar blok filter, tepat di atas tabel siswa, terdapat kalender input <code>Tanggal Cetak Rapot</code>. Fitur ini sangat spesifik menjawab tata-tertib birokrasi sekolah. Rapor adalah dokumen legal formal; tanggal pengesahannya harus valid dan seragam. Label peringatan merah tajam ("Wajib diisi untuk download") adalah bentuk <em>Error Prevention</em> absolut agar staf tidak keliru mengunduh rapor yang cacat hukum (tanpa tanggal).</li>\r\n<li><strong>Tabel Matriks Berbasis Komponen:</strong> Tabel *output* tidak sekadar menampilkan satu nilai gelondongan. Sistem secara cerdas membedah nilai menjadi kolom-kolom komponen: <code>Kelengkapan Rapor</code>, nilai per caturwulan/term (<code>Term 3</code>, <code>Term 4</code>), serta nilai keislaman khas yayasan (<code>Rapor Adab</code> dan <code>Rapor Tahfizh</code>). Pemisahan kolom ini memungkinkan wali kelas melakukan inspeksi visual kilat (<em>quick visual scan</em>)&mdash;misalnya, mencari sel mana yang masih kosong&mdash;sebelum mengeklik tombol unduh.</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Dalam anatomi <em>workflow</em> institusi pendidikan, halaman <strong>E-Rapot</strong> adalah <strong>"Stasiun Akhir Akademik"</strong> (<em>The Academic Terminus</em>).</p>\r\n<ul>\r\n<li><strong>Agregator Data Ekstrem (Massive Data Aggregation):</strong> Halaman ini adalah konsumen data paling rakus di seluruh sistem. Ia menarik kerangka rombongan belajar dari modul <strong>Sekolah &gt; Rombel</strong>, memanggil identitas siswa dari <strong>Data Murid</strong>, dan puncaknya: ia mengompilasi, menghitung, dan merekapitulasi ribuan entri nilai mentah dari modul Jurnal Mengajar/LMS para guru menjadi satu matriks nilai akhir.</li>\r\n<li><strong>Hilir Eksekusi (Digital Output):</strong> Halaman ini memutus rantai aliran data ke tabel lain. Produk akhirnya (<em>deliverable</em>) berupa berkas digital (umumnya PDF). File E-Rapot yang di-<em>generate</em> dari halaman ini akan didistribusikan melalui dua jalur: dicetak fisik untuk acara pembagian rapor di kelas, atau ditembakkan via API ke aplikasi portal Wali Murid agar orang tua dapat mengunduhnya langsung dari rumah.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Antarmuka "E-Rapot" berhasil menjinakkan kerumitan matematika akademik ke dalam dasbor operator yang rapi dan terukur. Implementasi *Filter-First* adalah keputusan <em>engineering</em> yang teramat cerdas untuk menghemat <em>bandwidth</em> server. Sementara itu, pemaksaan pengisian "Tanggal Cetak" menunjukkan kedalaman pemahaman *UI Designer* terhadap proses bisnis legalitas pendidikan. Singkat kata, menu ini adalah gerbang pamungkas yang menutup babak panjang satu semester dengan sangat elegan dan profesional.</p>', '1', NULL, '49', '2026-07-07 01:34:05', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('52', '27', 'Modul Jurnal & E-Rapot Menu Ijazah', 'modul-jurnal-e-rapot-menu-ijazah', '<p>Bertengger di posisi paling buncit pada hierarki menu vertikal, <strong>Ijazah</strong> (di bawah modul Jurnal &amp; E-Rapot) adalah garis finis (<em>finish line</em>) sesungguhnya dari siklus hidup (*lifecycle*) seorang anak di sekolah. Halaman ini berfungsi sebagai Pusat Penerbitan Sertifikat Kelulusan (<em>Diploma Generation Hub</em>). Antarmukanya mewarisi DNA desain defensif dari halaman E-Rapot, dengan penekanan pada prinsip kehati-hatian tingkat tinggi melalui metode <strong>Filter-First</strong>.</p>\r\n<p><img src="http://aadoc.donarazhar.site/storage/uploads/documents/1783388449_8-jurnal erapot-ijazah.png" alt="" width="769" height="716"></p>\r\n<h3>Struktur Antarmuka (UI) Pusat Cetak Ijazah</h3>\r\n<p>Ijazah adalah dokumen legal yang diakui negara. Oleh karenanya, antarmuka ini dirancang untuk menyandera kelalaian manusia (<em>human error prevention</em>). Berikut adalah anatomi keamanannya:</p>\r\n<ul>\r\n<li><strong>Restriksi Pemuatan Data (Filter-First):</strong> Halaman ini mengunci tabel data dengan sebuah <em>banner</em> notifikasi preskriptif: <em>"Silahkan filter terlebih dahulu..."</em>. Admin Tata Usaha tidak bisa melihat apalagi mencetak dokumen apa pun sebelum mereka mendeklarasikan secara eksplisit kombinasi <code>Kelas</code>, <code>Rombel</code>, dan <code>Tahun Ajaran</code>. Mekanisme ini memastikan *server* tidak terbebani secara konyol, sekaligus mengamankan admin dari insiden salah cetak ijazah untuk angkatan yang keliru.</li>\r\n<li><strong>Injeksi Tanggal Legalitas:</strong> Selembar ijazah tak bernilai hukum bila tanpa tanggal pengesahan. Halaman ini merespons fakta tersebut dengan menancapkan *field* <code>Tanggal Kelulusan (Masehi)</code> tepat di hulu tabel cetak. Kotak <em>date picker</em> ini berfungsi sebagai pendikte (<em>dictator</em>) bahwa seluruh *file* ijazah yang akan di-*generate* untuk angkatan (Rombel) tersebut harus dipasangi stempel tanggal yang seragam dan sah.</li>\r\n<li><strong>Transisi Identitas Kritis (NIS ke NISN):</strong> Ada pergeseran mikro pada desain *header* tabel yang patut diacungi jempol. Berbeda dengan menu E-Rapot yang mengandalkan NIS (Nomor Induk Siswa lokal), kolom kedua di halaman ini secara tegas tertulis <strong>NISN</strong> (Nomor Induk Siswa Nasional). Perubahan label ini menegaskan kepatuhan aplikasi terhadap standar regulasi Kementerian Pendidikan RI, di mana NISN adalah elemen pengenal tunggal wajib pada lembar ijazah resmi.</li>\r\n</ul>\r\n<h3>Peran dalam Alur Kerja (Workflow) Aplikasi</h3>\r\n<p>Dalam topologi <em>workflow</em> ERP <em>Al Azhar Apps</em>, halaman <strong>Ijazah</strong> mendapuk peran sebagai <strong>"Monumen Penutup Siklus"</strong> (<em>The Grand Academic Closure</em>).</p>\r\n<ul>\r\n<li><strong>Hulu Referensi (Prerequisite Check):</strong> Keberadaan data di halaman ini terikat kuat (<em>tightly coupled</em>) dengan modul <strong>Akademik &gt; Kenaikan Kelas &amp; Kelulusan</strong>. Hanya siswa yang status akhirnya telah diketuk palu sebagai "Lulus" di modul tersebut yang secara logis boleh muncul di tabel ini. Ia juga memanggil profil akhir siswa, secara spesifik menyedot nomor NISN dari tabel <strong>Data Murid</strong>.</li>\r\n<li><strong>Hilir Produksi (Final Deliverable):</strong> Menu ini adalah titik penghabisan. Ia tidak lagi melempar data mentah ke menu lain. Fungsinya adalah pabrik konversi: merangkai agregasi data profil dan nilai akhir menjadi sebuah wujud fisik digital (berkas PDF/cetak). Berkas inilah yang pada akhirnya menjadi produk final (<em>deliverable output</em>) yang diserahkan ke tangan siswa dan orang tua.</li>\r\n</ul>\r\n<h3>Kesimpulan Desain</h3>\r\n<p>Antarmuka halaman "Ijazah" sukses mengeksekusi konsep desain pertahanan (<em>defensive UI</em>) secara elegan. Melalui mekanisme penguncian *Filter-First*, pemaksaan *input* "Tanggal Kelulusan", serta penyesuaian cermat kolom identitas ke "NISN", perancang sistem menjamin bahwa operator terisolasi dari potensi kelalaian malapraktik administratif. Secara keseluruhan, menu ini adalah segel paripurna yang menutup tuntas perjalanan historis sang murid (<em>user journey</em>) di dalam semesta aplikasi ini.</p>', '1', NULL, '50', '2026-07-07 01:40:13', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('53', '29', 'Alur Lengkap PMB (Reguler & Cicilan)', 'alur-lengkap-pmb-pendaftaran-murid-baru-reguler-cicilan', '<h2 style="color: #0f172a; font-weight: bold; font-size: 1.5rem; margin-bottom: 0.5rem; text-align: center;">Alur Lengkap Penerimaan Murid Baru (PMB)</h2>\r\n<p style="color: #64748b; margin-bottom: 1.5rem; text-align: center;">Terdapat dua jenis alur pendaftaran: <strong>Tanpa Cicilan (Reguler)</strong> dan <strong>Dengan Cicilan</strong>, tergantung pilihan skema pembayaran Uang Pangkal.</p>\r\n<div style="display: flex; justify-content: center; gap: 24px; margin-bottom: 2.5rem; font-family: sans-serif; font-size: 0.85rem;">\r\n<div style="display: flex; align-items: center; gap: 6px;">Backoffice Team (Sekolah)</div>\r\n<div style="display: flex; align-items: center; gap: 6px;">Orang Tua / Murid (OTM)</div>\r\n</div>\r\n<h3 style="color: #0f172a; font-size: 1.3rem; text-align: center; background-color: #eff6ff; padding: 10px; border-radius: 8px; margin-bottom: 1.5rem;">A. Alur PMB &mdash; Tanpa Cicilan (Reguler)</h3>\r\n<div style="display: flex; flex-wrap: wrap; justify-content: center; gap: 10px; margin-bottom: 2rem; font-family: sans-serif;">\r\n<div style="width: 150px; background-color: #f8fafc; border: 2px solid #1885C4; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #1885c4; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">1</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Pendaftaran Awal &amp;<br>Bayar Formulir</div>\r\n</div>\r\n<div style="display: flex; align-items: center; color: #cbd5e1;">➞</div>\r\n<div style="width: 150px; background-color: #f8fafc; border: 2px solid #1885C4; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #1885c4; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">2</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Ujian Masuk</div>\r\n</div>\r\n<div style="display: flex; align-items: center; color: #cbd5e1;">➞</div>\r\n<div style="width: 150px; background-color: #f8fafc; border: 2px solid #1885C4; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #1885c4; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">3</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Pengumuman<br>Kelulusan</div>\r\n</div>\r\n<div style="display: flex; align-items: center; color: #cbd5e1;">➞</div>\r\n<div style="width: 150px; background-color: #f0fdf4; border: 2px solid #22c55e; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #22c55e; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">4</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Bayar Uang Pangkal<br>&amp; Aktivasi</div>\r\n</div>\r\n</div>\r\n<div style="font-family: sans-serif; color: #334155; line-height: 1.6; font-size: 0.95rem; margin-bottom: 2.5rem;">\r\n<h4 style="color: #1885c4; font-size: 1.05rem; margin-bottom: 10px;">Tahap 1: Pendaftaran Awal &amp; Pembayaran Formulir</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li>Login ke aplikasi Al Azhar Apps dengan nomor handphone dan PIN Anda.</li>\r\n<li>Pada halaman Beranda, pilih menu <strong>PMB</strong>, lalu tekan tombol <strong>Daftar Sekarang</strong> untuk melakukan pendaftaran awal (Animo).</li>\r\n<li>Isi form biodata awal (Tahun Ajaran, Jenjang, Sekolah Tujuan, Nama Anak, dll) lalu tekan <strong>Daftar PMB</strong>.</li>\r\n<li>Status anak akan berada pada "Menunggu Pembayaran Formulir". Tekan <strong>Ke Halaman Tagihan</strong>, centang tagihan <strong>Formulir Pendaftaran</strong>, lalu selesaikan pembayaran (misal via QRIS).</li>\r\n<li>Setelah pembayaran berhasil, lengkapi data <strong>Asal Sekolah</strong> dan <strong>Profil Murid</strong> secara menyeluruh, lalu tekan <strong>Ajukan</strong>.</li>\r\n<li style="color: #64748b;"><em>Catatan: Sebelum gelombang pendaftaran dibuka, pihak sekolah (Backoffice) telah menyiapkan komponen Uang Pangkal, Uang Sekolah, dan jadwal Gelombang Pendaftaran di sistem.</em></li>\r\n</ul>\r\n<h4 style="color: #1885c4; font-size: 1.05rem; margin-bottom: 10px;">Tahap 2: Ujian Masuk</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li>Setelah data diverifikasi sekolah, Anda akan menerima <strong>Kartu Ujian</strong> di aplikasi.</li>\r\n<li>Buka profil anak di menu PMB untuk melihat dan mengunduh <strong>Kartu Peserta Ujian Masuk</strong>. Kartu ini wajib ditunjukkan saat jadwal ujian berlangsung.</li>\r\n<li>Anak mengikuti ujian sesuai jadwal yang ditentukan sekolah.</li>\r\n</ul>\r\n<h4 style="color: #1885c4; font-size: 1.05rem; margin-bottom: 10px;">Tahap 3: Penilaian &amp; Pengumuman Kelulusan</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li style="color: #64748b;"><em>Di balik layar, pihak sekolah menginput dan mengunggah hasil nilai ujian ke sistem, kemudian meluluskan calon murid yang memenuhi syarat.</em></li>\r\n<li>Anda akan menerima notifikasi bahwa anak <strong>LULUS</strong> seleksi, sekaligus notifikasi syarat &amp; ketentuan Uang Pangkal (UP).</li>\r\n<li>Buka menu syarat &amp; ketentuan untuk melihat rincian komponen biaya UP.</li>\r\n<li>Tekan <strong>Setuju</strong> untuk menerima file PDF detail komponen UP.</li>\r\n</ul>\r\n<h4 style="color: #22c55e; font-size: 1.05rem; margin-bottom: 10px;">Tahap 4: Pembayaran Uang Pangkal &amp; Aktivasi</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li>Tagihan Uang Pangkal (UP) akan muncul di menu <strong>Tagihan</strong> aplikasi Anda.</li>\r\n<li>Lakukan pembayaran komponen UP secara penuh melalui metode pembayaran yang tersedia (misal QRIS).</li>\r\n<li>Setelah pembayaran berhasil dikonfirmasi, status anak berubah menjadi <strong>Aktif</strong> dan resmi terdaftar sebagai siswa.</li>\r\n</ul>\r\n</div>\r\n<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 2.5rem 0;">\r\n<h3 style="color: #0f172a; font-size: 1.3rem; text-align: center; background-color: #fdf4ff; padding: 10px; border-radius: 8px; margin-bottom: 1.5rem;">B. Alur PMB &mdash; Dengan Cicilan Uang Pangkal</h3>\r\n<p style="color: #64748b; text-align: center; margin-bottom: 1.5rem; font-family: sans-serif;">Alur ini digunakan bagi orang tua yang ingin membayar Uang Pangkal secara bertahap (angsuran), bukan sekaligus lunas.</p>\r\n<div style="display: flex; flex-wrap: wrap; justify-content: center; gap: 10px; margin-bottom: 2rem; font-family: sans-serif;">\r\n<div style="width: 150px; background-color: #f5f3ff; border: 2px solid #7c3aed; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #7c3aed; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">1</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Persiapan Sekolah</div>\r\n</div>\r\n<div style="display: flex; align-items: center; color: #cbd5e1;">➞</div>\r\n<div style="width: 150px; background-color: #f0fdf4; border: 2px solid #16a34a; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #16a34a; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">2</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Ujian</div>\r\n</div>\r\n<div style="display: flex; align-items: center; color: #cbd5e1;">➞</div>\r\n<div style="width: 150px; background-color: #fff7ed; border: 2px solid #ea580c; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #ea580c; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">3</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Pengumuman &amp;<br>Syarat UP</div>\r\n</div>\r\n<div style="display: flex; align-items: center; color: #cbd5e1;">➞</div>\r\n<div style="width: 150px; background-color: #fdf2f8; border: 2px solid #db2777; border-radius: 8px; padding: 12px; text-align: center;">\r\n<div style="background-color: #db2777; color: white; width: 24px; height: 24px; border-radius: 50%; font-weight: bold; font-size: 0.8rem; line-height: 24px; margin: 0 auto 8px;">4</div>\r\n<div style="color: #0f172a; font-weight: bold; font-size: 0.85rem; line-height: 1.3;">Pembayaran &amp;<br>Aktivasi</div>\r\n</div>\r\n</div>\r\n<div style="font-family: sans-serif; color: #334155; line-height: 1.6; font-size: 0.95rem;">\r\n<h4 style="color: #7c3aed; font-size: 1.05rem; margin-bottom: 10px;">Fase 1: Persiapan Sekolah, Pendaftaran, &amp; Ujian</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li>Proses pendaftaran, pembayaran formulir, pelengkapan identitas, hingga pelaksanaan ujian pada alur cicilan ini <strong>sama persis</strong> dengan alur Tanpa Cicilan pada bagian A (Tahap 1 dan 2 di atas).</li>\r\n<li>Perbedaan baru muncul setelah pengumuman kelulusan terbit.</li>\r\n</ul>\r\n<h4 style="color: #ea580c; font-size: 1.05rem; margin-bottom: 10px;">Fase 2: Pengumuman Kelulusan &amp; Syarat Uang Pangkal</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li>Anda akan menerima notifikasi kelulusan yang berisi syarat &amp; ketentuan Uang Pangkal (UP).</li>\r\n<li>Baca dan pahami surat pernyataan yang diberikan, lalu tekan <strong>Setuju</strong> untuk menerima file PDF detail komponen UP.</li>\r\n<li>Jika Anda berencana membayar UP secara cicilan, <strong>datangi langsung pihak sekolah (Tata Usaha)</strong> untuk mengajukan permohonan skema angsuran. Pengajuan cicilan saat ini dilakukan secara luring (tatap muka), bukan melalui aplikasi.</li>\r\n</ul>\r\n<h4 style="color: #db2777; font-size: 1.05rem; margin-bottom: 10px;">Fase 3: Pengajuan &amp; Persetujuan Angsuran</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li style="color: #64748b;"><em>Setelah Anda mengajukan permohonan cicilan, pihak sekolah akan memprosesnya di sistem sesuai ketentuan jumlah angsuran yang telah ditetapkan Yayasan.</em></li>\r\n<li>Jika permohonan cicilan <strong>lebih dari 3 kali angsuran</strong>, sekolah akan meneruskan permohonan tersebut ke <strong>Direktorat Keuangan</strong> untuk mendapat persetujuan khusus.</li>\r\n<li>Anda perlu menunggu proses <strong>approval</strong> dari Direktorat Keuangan sebelum skema cicilan resmi berlaku.</li>\r\n</ul>\r\n<h4 style="color: #db2777; font-size: 1.05rem; margin-bottom: 10px;">Fase 4: Pembayaran Bertahap &amp; Aktivasi</h4>\r\n<ul style="margin-bottom: 1.5rem; padding-left: 1.2rem;">\r\n<li style="background-color: #fef9c3; padding: 10px; border-radius: 6px; border-left: 4px solid #eab308;"><strong>Ketentuan penting:</strong> Status anak baru akan diproses aktif apabila pembayaran termin/angsuran <strong>pertama</strong> sudah mencapai minimal <strong>50% dari total Uang Pangkal</strong>.</li>\r\n<li>Setelah skema cicilan disetujui, tagihan Uang Pangkal akan muncul di menu <strong>Tagihan</strong> aplikasi Anda, sudah disesuaikan dengan jadwal cicilan yang ditetapkan.</li>\r\n<li>Lakukan pembayaran setiap termin sesuai akad/perjanjian cicilan yang telah disetujui.</li>\r\n<li>Setelah syarat minimal termin pertama (50%) terpenuhi, status anak menjadi <strong>Aktif</strong>, dan pihak sekolah (Tata Usaha) akan menempatkan anak ke Rombongan Belajar (Rombel) yang sesuai.</li>\r\n</ul>\r\n</div>\r\n<div style="background-color: #eff6ff; border: 1px solid #bfdbfe; border-radius: 8px; padding: 1.2rem; margin-top: 1rem; font-family: sans-serif; color: #1e3a8a; font-size: 0.9rem;"><strong>Ringkasan Perbedaan:</strong> Alur Tanpa Cicilan dan Alur Cicilan sama persis mulai dari pendaftaran awal hingga pengumuman kelulusan. Perbedaan utama terletak setelah anak dinyatakan lulus: pada alur Tanpa Cicilan, Uang Pangkal langsung dibayar lunas untuk aktivasi; sedangkan pada alur Cicilan, orang tua perlu mengajukan permohonan angsuran langsung ke sekolah, menunggu persetujuan (termasuk dari Direktorat Keuangan bila lebih dari 3 kali angsuran), lalu melunasi minimal 50% pada termin pertama sebelum anak dapat diaktifkan.</div>', '1', NULL, '2', '2026-07-08 00:51:49', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('54', '32', 'LMS berbasis Moodle', 'lms-berbasis-moodle', '\n<p><strong>Apa itu Moodle?</strong></p>\n<p>Moodle (<em>Modular Object-Oriented Dynamic Learning Environment</em>) adalah sebuah platform <em>Learning Management System</em> (LMS) berbasis <em>open-source</em> yang dirancang untuk menyediakan lingkungan belajar yang disesuaikan, aman, dan terintegrasi bagi pengajar, administrator, dan pembelajar.</p>\n\n<p><strong>Fitur Utama LMS Moodle:</strong></p>\n<ul>\n    <li><strong>Manajemen Kursus:</strong> Pengajar dapat dengan mudah membuat kursus, mengatur pendaftaran siswa, dan memonitor perkembangan belajar.</li>\n    <li><strong>Aktivitas Interaktif:</strong> Moodle mendukung berbagai modul aktivitas seperti kuis, tugas, forum diskusi, glossary, dan wiki untuk mendukung pembelajaran yang dinamis.</li>\n    <li><strong>Sistem Penilaian (Grading):</strong> Terdapat fitur buku nilai yang komprehensif, memungkinkan penilaian otomatis untuk kuis dan rubrik penilaian untuk tugas esai atau proyek.</li>\n    <li><strong>Kolaborasi:</strong> Siswa dan guru dapat berkolaborasi melalui pesan, forum, dan kelompok belajar.</li>\n    <li><strong>Kustomisasi &amp; Fleksibilitas:</strong> Karena sifatnya yang <em>open-source</em>, Moodle dapat disesuaikan menggunakan plugin untuk menambahkan fitur seperti video conference, analitik, dan integrasi dengan sistem pihak ketiga.</li>\n</ul>\n\n<p><strong>Keunggulan Penggunaan Moodle:</strong></p>\n<p>Moodle banyak digunakan oleh institusi pendidikan dari sekolah dasar hingga perguruan tinggi karena skalabilitasnya. Platform ini memungkinkan pembelajaran campuran (<em>blended learning</em>) serta pembelajaran jarak jauh 100% (<em>e-learning</em>).</p>\n\n<p>Dalam ekosistem aplikasi sekolah, Moodle sering kali diintegrasikan dengan Sistem Informasi Sekolah (SIS) sehingga data pengguna (guru dan siswa), kelas, dan jadwal dapat disinkronisasi secara otomatis.</p>\n', '1', NULL, '87', '2026-07-08 01:57:23', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('55', '32', 'Dasar-Dasar Moodle', 'dasar-dasar-moodle', '\n<p>Membangun sebuah <em>Learning Management System</em> (LMS) memang terlihat kompleks pada awalnya, tetapi jika kita sudah memahami alur kerjanya, semuanya akan jauh lebih terstruktur.</p>\n<p>Berikut adalah panduan singkat, praktis, dan terarah untuk mengelola Moodle, khususnya untuk studi kasus <strong>Sekolah Al Azhar Kelas 1</strong>.</p>\n<hr>\n\n<h3>1. Tugas dan Hak Akses (Role) di Moodle</h3>\n<p>Moodle bekerja dengan sistem hierarki. Setiap orang memiliki porsi kerjanya masing-masing agar sistem tetap rapi dan aman.</p>\n<ul>\n    <li><strong>Manager (Pengelola/Admin Tingkat Atas):</strong> Ini adalah arsitek sistem. Tugas utamanya bukan mengajar, melainkan mengatur struktur sekolah secara digital. Manager bertugas membuat kategori (misal: "Kelas 1", "Kelas 2"), membuat <em>Course</em> (Mata Pelajaran), membuat akun pengguna, dan memasukkan Guru serta Siswa ke dalam kelas yang tepat.</li>\n    <li><strong>Teacher (Guru):</strong> Ini adalah pemilik kelas. Setelah kelas disiapkan oleh Manager, Teacher bertugas mendesain isi kelas tersebut. Mereka mengunggah materi, membuat kuis, memberikan tugas, dan menilai hasil kerja siswa. Teacher tidak bisa mengubah pengaturan sistem di luar kelasnya.</li>\n    <li><strong>Student (Siswa):</strong> Ini adalah peserta didik. Mereka hanya bisa melihat materi, mengunduh file, mengerjakan tugas, dan mengikuti ujian yang telah disiapkan oleh Teacher. Mereka tidak bisa mengubah struktur kelas.</li>\n</ul>\n<hr>\n\n<h3>2. Langkah Pertama Memulai Moodle (Alur Kerja)</h3>\n<p>Untuk memulai Moodle dari nol, pekerjaan harus selalu <strong>dimulai dari role Manager/Admin</strong> terlebih dahulu, baru kemudian diserahkan ke Teacher. Berikut adalah alur standarnya:</p>\n\n<p><strong>Fase 1: Persiapan oleh Manager</strong></p>\n<ol>\n    <li><strong>Buat Kategori (Category):</strong> Buat kategori untuk merapikan struktur. Misalnya, buat kategori utama <code>SD Al Azhar</code>, lalu sub-kategori <code>Kelas 1</code>.</li>\n    <li><strong>Buat Mata Pelajaran (Course):</strong> Di dalam sub-kategori <code>Kelas 1</code>, buat <em>course</em> untuk setiap pelajaran.\n        <ul>\n            <li><em>Course 1:</em> IPAS - Kelas 1</li>\n            <li><em>Course 2:</em> Bahasa Indonesia - Kelas 1</li>\n            <li><em>Course 3:</em> Matematika - Kelas 1</li>\n        </ul>\n    </li>\n    <li><strong>Buat Akun (User Management):</strong> Buat akun untuk semua guru yang akan mengajar dan semua siswa kelas 1. (Biasanya dilakukan secara massal menggunakan file CSV).</li>\n    <li><strong>Daftarkan Pengguna (Enrollment):</strong> Masukkan guru dan siswa ke dalam kelas masing-masing. Tetapkan siapa yang menjadi <em>Teacher</em> dan siapa yang menjadi <em>Student</em> di kelas Matematika, IPAS, dsb.</li>\n</ol>\n\n<p><strong>Fase 2: Eksekusi oleh Teacher</strong></p>\n<ol>\n    <li><strong>Login sebagai Teacher:</strong> Guru masuk ke mata pelajaran yang sudah ditugaskan kepada mereka.</li>\n    <li><strong>Membangun Kelas:</strong> Guru menyalakan mode <em>Turn Editing On</em> dan mulai menyusun materi dari Bab 1 hingga selesai.</li>\n</ol>\n<hr>\n\n<h3>3. Fitur Dasar untuk Minimal Standar LMS</h3>\n<p>Untuk siswa Kelas 1, tampilan dan interaksi harus dibuat sesederhana mungkin. Berikut adalah fitur-fitur dasar (Resources &amp; Activities) yang wajib dikuasai oleh <em>Teacher</em> agar LMS bisa berjalan:</p>\n<ul>\n    <li><strong>Course Format (Format Kelas):</strong> Gunakan <strong>Topics format</strong>. Ubah nama setiap topik menjadi nama bab atau minggu pelajaran (Misal: <em>Topik 1 &rarr; Bab 1: Mengenal Angka</em>, <em>Topik 2 &rarr; Bab 2: Penjumlahan</em>).</li>\n    <li><strong>Label:</strong> Fitur ini bertindak seperti judul atau papan pengumuman di dalam kelas. Gunakan Label untuk memberikan instruksi singkat yang bisa langsung dibaca siswa (atau orang tua yang mendampingi) tanpa harus di-klik.</li>\n    <li><strong>File:</strong> Gunakan ini untuk mengunggah bahan ajar mandiri, seperti dokumen PDF ringkasan materi atau slide presentasi.</li>\n    <li><strong>URL:</strong> Sangat berguna jika Anda memiliki materi berupa video pembelajaran di YouTube atau artikel dari website luar. Fitur ini akan mengarahkan siswa langsung ke materi tersebut.</li>\n    <li><strong>Assignment (Tugas):</strong> Tempat bagi siswa untuk mengumpulkan PR. Untuk anak Kelas 1, biasanya guru akan meminta orang tua untuk memfoto lembar kerja anak, lalu foto tersebut diunggah <em>(upload)</em> melalui fitur Assignment ini.</li>\n    <li><strong>Quiz (Kuis):</strong> Digunakan untuk ulangan atau latihan soal. Anda bisa mengatur soal pilihan ganda atau mencocokkan gambar, yang sistemnya bisa langsung menilai otomatis secara seketika (<em>auto-grading</em>).</li>\n</ul>\n\n<p>Dengan menguasai langkah-langkah dan fitur di atas, Anda sudah memiliki fondasi yang sangat kuat untuk menjalankan LMS Sekolah Al Azhar.</p>\n', '1', NULL, '88', '2026-07-08 01:57:37', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('56', '32', 'Tutorial Cepat: Membuat Cohort dan Course', 'tutorial-cepat-membuat-cohort-dan-course', '\n<p>Dalam ekosistem Moodle, <strong>Cohort</strong> dan <strong>Course</strong> adalah dua pilar penting untuk mengelola pengguna dan mata pelajaran secara terstruktur dan efisien. Berikut adalah panduan cepat untuk membuat dan menghubungkan keduanya.</p>\n<hr>\n\n<h3>1. Mengenal Beda Cohort dan Course</h3>\n<ul>\n    <li><strong>Cohort (Rombongan Belajar / Rombel):</strong> Kumpulan pengguna (biasanya siswa) yang dikelompokkan secara <em>system-wide</em> atau per kategori. Misalnya: Cohort "Kelas 1A - Angkatan 2026". Memasukkan siswa ke dalam Cohort memudahkan kita mendaftarkan (<em>enroll</em>) mereka ke banyak <em>Course</em> sekaligus secara otomatis.</li>\n    <li><strong>Course (Mata Pelajaran):</strong> Ruang kelas digital tempat interaksi belajar mengajar terjadi (materi, tugas, kuis). Misalnya: Course "Matematika - Kelas 1", "Bahasa Indonesia - Kelas 1".</li>\n</ul>\n<hr>\n\n<h3>2. Cara Membuat Cohort (Rombel)</h3>\n<p><em>Langkah ini harus dilakukan oleh akun dengan hak akses <strong>Manager</strong> atau <strong>Administrator</strong>.</em></p>\n<ol>\n    <li>Masuk ke menu <strong>Site administration</strong> &rarr; <strong>Users</strong> &rarr; <strong>Accounts</strong> &rarr; <strong>Cohorts</strong>.</li>\n    <li>Klik tombol <strong>Add new cohort</strong>.</li>\n    <li>Isi detail Cohort:\n        <ul>\n            <li><strong>Name:</strong> Nama rombongan belajar (misal: <code>Kelas 1A 2026/2027</code>).</li>\n            <li><strong>Context:</strong> Pilih di level mana cohort ini tersedia (Pilih <em>System</em> jika ingin tersedia di semua kategori, atau pilih kategori spesifik misal <code>SD Al Azhar</code>).</li>\n            <li><strong>Cohort ID:</strong> (Opsional) Kode unik untuk sinkronisasi internal, misal: <code>1A-2627</code>.</li>\n        </ul>\n    </li>\n    <li>Klik <strong>Save changes</strong>.</li>\n    <li>Setelah Cohort dibuat, kembali ke daftar Cohort dan klik ikon <strong>Assign / People</strong> (gambar orang) pada baris Cohort tersebut untuk mulai memasukkan siswa. (<em>Cari nama siswa di kotak sebelah kanan, lalu klik tombol "Add" untuk memindahkannya ke kotak kiri</em>).</li>\n</ol>\n<hr>\n\n<h3>3. Cara Membuat Course (Mata Pelajaran)</h3>\n<p><em>Langkah ini juga umumnya dilakukan oleh <strong>Manager</strong>.</em></p>\n<ol>\n    <li>Masuk ke <strong>Site administration</strong> &rarr; <strong>Courses</strong> &rarr; <strong>Manage courses and categories</strong>.</li>\n    <li>Pilih Kategori yang sesuai di panel kiri (misal: <code>Kelas 1</code>).</li>\n    <li>Di panel kanan, klik tombol <strong>Create new course</strong>.</li>\n    <li>Isi pengaturan dasar kelas:\n        <ul>\n            <li><strong>Course full name:</strong> Nama lengkap mata pelajaran (Misal: <code>Matematika - Kelas 1</code>).</li>\n            <li><strong>Course short name:</strong> Nama pendek untuk navigasi dan <em>breadcrumb</em> (Misal: <code>MTK-1</code>).</li>\n            <li><strong>Course format:</strong> Pilih <strong>Topics format</strong> (Format ini paling umum dan mudah diatur).</li>\n        </ul>\n    </li>\n    <li>Gulir ke bawah dan klik <strong>Save and display</strong>.</li>\n</ol>\n<hr>\n\n<h3>4. Menghubungkan Cohort ke dalam Course (Cohort Sync)</h3>\n<p>Daripada mendaftarkan siswa satu per satu ke dalam sebuah kelas, sangat disarankan menggunakan metode Sinkronisasi Cohort (<em>Cohort Sync</em>).</p>\n<ol>\n    <li>Buka <em>Course</em> yang baru saja Anda buat.</li>\n    <li>Di menu navigasi Course (biasanya di atas atau kiri), pilih tab <strong>Participants</strong>.</li>\n    <li>Klik menu <em>dropdown</em> (atau ikon gir) lalu pilih <strong>Enrollment methods</strong>.</li>\n    <li>Pada kolom <em>Add method</em>, pilih <strong>Cohort sync</strong>.</li>\n    <li>Di bagian formulir yang muncul:\n        <ul>\n            <li><strong>Cohort:</strong> Cari dan pilih nama Cohort yang sudah kita buat sebelumnya (misal: <code>Kelas 1A 2026/2027</code>).</li>\n            <li><strong>Assign role:</strong> Pastikan diatur sebagai <strong>Student</strong>.</li>\n        </ul>\n    </li>\n    <li>Klik <strong>Add method</strong>.</li>\n</ol>\n\n<blockquote>\n    <p><strong>Selesai!</strong> Sekarang semua siswa yang berada di dalam Cohort "Kelas 1A" secara otomatis sudah masuk dan terdaftar ke dalam Course "Matematika Kelas 1".</p>\n    <p>Hebatnya lagi, jika besok ada siswa baru (mutasi) yang ditambahkan ke Cohort "Kelas 1A" dari menu <em>Site Administration</em>, siswa tersebut akan langsung otomatis terdaftar di semua Course yang terhubung dengan Cohort ini tanpa perlu kita masukkan manual ke tiap mata pelajaran!</p>\n</blockquote>\n', '1', NULL, '89', '2026-07-08 02:07:46', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('57', '32', 'Tutorial Cepat: Memasukkan Materi Pelajaran (Role Teacher)', 'tutorial-cepat-memasukkan-materi-pelajaran-role-teacher', '\n<p>Setelah administrator atau <em>Manager</em> selesai mendaftarkan Anda ke dalam sebuah <em>Course</em> (Mata Pelajaran), kini saatnya Anda sebagai <strong>Teacher</strong> (Guru) mengambil alih kendali kelas tersebut. Moodle memberikan kebebasan penuh kepada Teacher untuk mendesain kelasnya sendiri.</p>\n<hr>\n\n<h3>1. Menghidupkan Mode Edit (Turn Editing On)</h3>\n<p>Langkah paling krusial sebelum Anda bisa menambahkan teks, tugas, atau materi apa pun di dalam kelas Moodle adalah menghidupkan fitur edit.</p>\n<ol>\n    <li>Login menggunakan akun Guru (<em>Teacher</em>).</li>\n    <li>Dari halaman <strong>Dashboard</strong>, cari dan klik mata pelajaran yang Anda ampu (Misal: <code>Matematika - Kelas 1</code>).</li>\n    <li>Perhatikan di pojok kanan atas halaman, klik tombol <strong>Turn editing on</strong> (biasanya berwarna biru atau hijau).</li>\n    <li>Setelah mode ini aktif, Anda akan menyadari perubahan di layar: muncul banyak ikon pensil, ikon panah (untuk menggeser), dan tulisan <em><strong>+ Add an activity or resource</strong></em> di setiap blok topik.</li>\n</ol>\n<hr>\n\n<h3>2. Mengubah Nama Topik (Bab Pembelajaran)</h3>\n<p>Jika <em>Course</em> Anda menggunakan <em>Topics format</em> (standar), sangat disarankan untuk mengubah tulisan "Topic 1", "Topic 2", menjadi nama bab atau minggu pertemuan agar siswa lebih mudah memahaminya.</p>\n<ol>\n    <li>Klik ikon pensil kecil tepat di sebelah tulisan "Topic 1".</li>\n    <li>Ketik nama bab yang baru (Misalnya: <code>Bab 1 - Penjumlahan Angka 1 sampai 10</code>).</li>\n    <li>Tekan tombol <strong>Enter</strong> di keyboard Anda untuk menyimpan.</li>\n</ol>\n<hr>\n\n<h3>3. Menambahkan Materi Berupa Dokumen / File (PDF, PPT, Word)</h3>\n<p>Sangat mudah untuk membagikan bahan bacaan mandiri atau <i>slide</i> presentasi kepada siswa Anda.</p>\n<ol>\n    <li>Pilih di bawah topik/bab mana Anda ingin meletakkan materinya, lalu klik <strong>+ Add an activity or resource</strong>.</li>\n    <li>Akan muncul jendela <em>pop-up</em>. Pilih tab <strong>Resources</strong>, lalu cari dan klik <strong>File</strong>.</li>\n    <li>Di formulir yang terbuka, isi kolom nama (Misal: <code>Materi PPT: Penjumlahan Dasar</code>).</li>\n    <li>Pada kotak <em>Select files</em>, Anda bisa memindahkan dokumen dari komputer Anda secara langsung dengan cara menyeret (<em>drag-and-drop</em>) file tersebut ke area yang ditandai panah biru menghadap ke bawah.</li>\n    <li>Gulir layar ke bawah, dan klik <strong>Save and return to course</strong>.</li>\n</ol>\n<hr>\n\n<h3>4. Menambahkan Label (Instruksi Langsung Tampil)</h3>\n<p>Label berfungsi untuk menampilkan teks, gambar, atau panduan yang <strong>langsung terlihat</strong> di halaman depan kelas tanpa harus di-klik oleh siswa. Fitur ini sangat cocok diterapkan untuk mengarahkan anak kelas 1 (dan orang tuanya).</p>\n<ol>\n    <li>Klik <strong>+ Add an activity or resource</strong> di topik yang diinginkan.</li>\n    <li>Pilih <strong>Label</strong>.</li>\n    <li>Di kolom teks (teks editor yang besar), tuliskan instruksi Anda. Contoh:\n        <blockquote><em>"Anak-anak hebat, silakan unduh dan pelajari materi presentasi di bawah ini bersama Ayah dan Bunda ya!"</em></blockquote>\n    </li>\n    <li>(Opsional) Anda juga bisa menebalkan huruf atau menyisipkan gambar kecil melalui ikon-ikon di atas kotak teks tersebut.</li>\n    <li>Klik <strong>Save and return to course</strong>.</li>\n</ol>\n<hr>\n\n<h3>5. Menambahkan Tautan Eksternal (URL YouTube / Website)</h3>\n<p>Jika Anda memiliki referensi video pembelajaran interaktif dari YouTube atau materi bacaan dari portal edukasi lain:</p>\n<ol>\n    <li>Klik <strong>+ Add an activity or resource</strong>.</li>\n    <li>Pilih <strong>URL</strong>.</li>\n    <li>Isi nama tautan (Misal: <code>Video Animasi Penjumlahan</code>).</li>\n    <li>Tempel (<em>paste</em>) alamat URL YouTube tersebut di kolom <strong>External URL</strong>.</li>\n    <li>(Sangat Disarankan) Pada bagian pengaturan <strong>Appearance</strong>, ubah kolom <em>Display</em> menjadi <strong>Embed</strong>. Dengan fitur ini, video akan langsung bisa diputar di dalam Moodle tanpa "membuang" siswa keluar menuju situs YouTube.</li>\n    <li>Klik <strong>Save and return to course</strong>.</li>\n</ol>\n\n<p>Dengan menguasai tiga fitur dasar di atas (<em>File</em>, <em>Label</em>, dan <em>URL</em>), kelas digital Anda di Moodle kini sudah sangat siap digunakan untuk mendukung proses belajar mengajar harian!</p>\n', '1', NULL, '90', '2026-07-08 02:10:37', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('70', '24', 'Analisis Arsitektur Global & Integrasi Sistem', 'analisis-arsitektur-global', '<p><strong>Ringkasan Eksekutif</strong><br>\nALAZHARAPPS adalah sistem informasi sekolah <strong>Al Azhar</strong> yang dibangun dengan arsitektur <strong>microservices</strong>. Sistem terdiri dari <strong>8 backend services (Golang)</strong>, <strong>1 frontend monorepo (Next.js/Turborepo)</strong>, <strong>1 landing page (React/Vite)</strong>, <strong>1 shared Go library</strong>, <strong>1 shared JWT library</strong>, dan <strong>1 ETL pipeline (Python)</strong>.</p>\n\n<hr>\n\n<h3>1. Peta Komponen Sistem</h3>\n<pre><code>graph TD\n subgraph "Frontend Layer"\n FE["frontend (Next.js 15 + Turborepo)"]\n LP["landing-page (React + Vite)"]\n end\n subgraph "API Gateway / Reverse Proxy"\n GW["dev-api.alazhar.or.id/v1"]\n end\n subgraph "Backend Microservices (Golang)"\n ACC["account-service"]\n STU["student-service"]\n SCH["school-service-new"]\n TXN["transaction-service"]\n RPT["report-service"]\n LMS["lms-course-service"]\n BE["backend-codebase (base template)"]\n end\n subgraph "Shared Libraries (Golang)"\n GOLIB["go-lib (REST, Logger)"]\n JWT["jwtaccess (JWT Auth)"]\n end\n subgraph "Data & Integration"\n ETL["etl (Python ETL Framework)"]\n PG["PostgreSQL"]\n RD["Redis"]\n FB["Firebase (Push Notifications)"]\n WA["WhatsApp (Fonnte/Qontak)"]\n end\n\n FE --&gt;|"REST API (axios)"| GW\n LP -.->|"Static site"| GW\n GW --&gt;|"/account/*"| ACC\n GW --&gt;|"/student/*"| STU\n GW --&gt;|"/school-new/*"| SCH\n GW --&gt;|"/report/*"| RPT\n GW --&gt;|"/transaction/*"| TXN\n\n ACC --&gt;|"gRPC Client"| SCH\n TXN --&gt;|"gRPC Client"| ACC\n TXN --&gt;|"gRPC Client"| STU\n SCH --&gt;|"gRPC Client"| ACC\n SCH --&gt;|"gRPC Client"| STU\n SCH --&gt;|"gRPC Client"| TXN\n\n ACC --&gt; GOLIB\n STU --&gt; GOLIB\n SCH --&gt; GOLIB\n TXN --&gt; GOLIB\n RPT --&gt; GOLIB\n\n ACC --&gt; JWT\n SCH --&gt; JWT\n TXN --&gt; JWT\n\n ACC --&gt; PG\n ACC --&gt; RD\n ACC --&gt; FB\n ACC --&gt; WA\n TXN --&gt; PG\n TXN --&gt; RD\n STU --&gt; PG\n SCH --&gt; PG\n RPT --&gt; PG\n\n ETL --&gt;|"SQL/Python"| PG</code></pre>\n\n<hr>\n\n<h3>2. Protokol Komunikasi API</h3>\n\n<h4>2.1 Frontend &rarr; Backend: REST API (HTTP/JSON)</h4>\n<p><strong>[!IMPORTANT]</strong> Frontend berkomunikasi ke backend <strong>100% melalui REST API</strong> menggunakan <strong>Axios</strong> sebagai HTTP client. <strong>Tidak ada GraphQL maupun gRPC</strong> yang digunakan dari sisi frontend.</p>\n\n<p><strong>Mekanisme Detail</strong></p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Aspek</th><th>Detail</th></tr>\n    <tr><td>HTTP Client</td><td>Axios via singleton instance (<code>axiosInstance.ts</code>)</td></tr>\n    <tr><td>Base URL</td><td><code>NEXT_PUBLIC_API_URL = https://dev-api.alazhar.or.id/v1</code></td></tr>\n    <tr><td>Auth</td><td>Bearer Token JWT (disimpan di Cookie <code>authToken</code>)</td></tr>\n    <tr><td>Timeout</td><td>70 detik</td></tr>\n    <tr><td>State Management</td><td>Redux Toolkit (<code>createAsyncThunk</code> untuk async API calls)</td></tr>\n    <tr><td>Data Format</td><td>JSON</td></tr>\n</table>\n\n<p><strong>Alur Data Fetching</strong></p>\n<pre><code>Next.js Component (page/hook)\n &darr; dispatch(action)\nRedux Slice (createAsyncThunk)\n &darr; axiosInstance.get/post/put/delete(endpoint)\nAxios Interceptor (inject Bearer token)\n &darr; HTTP Request\nAPI Gateway (dev-api.alazhar.or.id/v1)\n &darr; Routing berdasarkan path prefix\nGolang Microservice (GoFiber handler)\n &darr; Response JSON\nRedux Slice (extraReducers &rarr; state update)\n &darr; re-render\nNext.js Component</code></pre>\n\n<p><strong>Pola Endpoint Frontend</strong></p>\n<p>Frontend mendefinisikan endpoint dalam <strong>33 file service</strong> di <code>app/services/</code>:</p>\n<ul>\n    <li>Endpoint dispampaikan sebagai <strong>path string relatif</strong> (tanpa base URL)</li>\n    <li>Path prefix menentukan ke microservice mana request diarahkan oleh API Gateway:</li>\n</ul>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Path Prefix</th><th>Backend Service</th></tr>\n    <tr><td><code>/account/*</code></td><td>account-service</td></tr>\n    <tr><td><code>/student/*</code></td><td>student-service</td></tr>\n    <tr><td><code>/school-new/*</code></td><td>school-service-new</td></tr>\n    <tr><td><code>/school/*</code></td><td>school-service-new</td></tr>\n    <tr><td><code>/report/*</code></td><td>report-service</td></tr>\n    <tr><td><code>/transaction/*</code></td><td>transaction-service</td></tr>\n</table>\n\n<p><strong>Contoh pola yang digunakan:</strong></p>\n<pre><code>// Dari apiAccount.ts\nexport const authEndpoints = {\n login: () =&gt; `/account/login`,\n me: () =&gt; `/account/me`,\n};\n\n// Dari apiDashboard.ts\nexport const dashboardtEndpoints = {\n finance_card: ({ schoolId, accademicYear }) =&gt;\n `/report/dashboard/finance?schoolId=${schoolId}&amp;accademicYear=${accademicYear}`,\n};</code></pre>\n\n<h4>2.2 Backend &harr; Backend: gRPC (Protobuf)</h4>\n<p><strong>[!IMPORTANT]</strong> Komunikasi antar microservices <strong>sepenuhnya menggunakan gRPC</strong> dengan Protocol Buffers sebagai serialization format. Setiap service menjalankan <strong>dual-protocol server</strong> (REST + gRPC) secara bersamaan.</p>\n\n<p><strong>Peta Komunikasi gRPC Antar Service</strong></p>\n<pre><code>graph LR\n ACC["account-service&lt;br/&gt;gRPC Server :grpc_port"]\n STU["student-service&lt;br/&gt;gRPC Server :grpc_port"]\n SCH["school-service-new&lt;br/&gt;gRPC Server :grpc_port"]\n TXN["transaction-service&lt;br/&gt;gRPC Server :grpc_port"]\n\n TXN --&gt;|"pb.AccountClient"| ACC\n TXN --&gt;|"pb.StudentClient"| STU\n ACC --&gt;|"pb.SchoolNewClient"| SCH\n SCH --&gt;|"pb.AccountClient"| ACC\n SCH --&gt;|"pb.StudentClient"| STU\n SCH --&gt;|"pb.TransactionClient"| TXN</code></pre>\n\n<p><strong>Proto File Definitions</strong></p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Service</th><th>Proto File</th><th>RPC Methods</th></tr>\n    <tr><td><strong>Account</strong></td><td><code>account.proto</code></td><td>BlockLmsAccess, UnblockLmsAccess, CreateSchoolUser, CreateExamUser, InquiryExamUserLogin, InquiryLmsUsername, SendNotification, SendWaMessage, SubmitNotificationExamResult</td></tr>\n    <tr><td><strong>Transaction</strong></td><td><code>transaction.proto</code></td><td>CreateRegistrationBill, CreateDspBill, CreateDspBills, CreateSppBill, CreateEnrollmentBill, CreateDiscountBill, ActivateDiscountBill, DeleteDiscountBill, HasOutstandingBill, HasInstallmentBill</td></tr>\n    <tr><td><strong>Student</strong></td><td><code>student.proto</code></td><td>AnimoPaymentSuccess, CreateNewStudent, CreateWaitingListStudent, GenerateSpp, GetCountRombelBySchoolID, GetStudentCountByAcademicYear, GetTotalStudent, FindPersonnelAssignment</td></tr>\n    <tr><td><strong>SchoolNew</strong></td><td><code>schoolnew.proto</code></td><td>CreateDsp, GetCapacityById, GetSchoolByUid, GetPersonnelDiscountByPersonnelType, GetEndowmentSppDsp, GetTargetBatch</td></tr>\n</table>\n\n<hr>\n\n<h3>3. Dokumentasi API (Kontrak Data)</h3>\n<p><strong>[!CAUTION] Tidak ada dokumentasi API yang terpusat dan mutakhir.</strong> Sistem TIDAK memiliki Swagger/OpenAPI Spec, Postman Collection, maupun API documentation generator yang terintegrasi.</p>\n\n<p><strong>Apa yang Ada</strong></p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Jenis Dokumentasi</th><th>Status</th><th>Lokasi</th></tr>\n    <tr><td>Swagger/OpenAPI</td><td>&#10060; Tidak ada</td><td>&mdash;</td></tr>\n    <tr><td>Postman Collection</td><td>&#10060; Tidak ada</td><td>&mdash;</td></tr>\n    <tr><td>Proto Files (gRPC)</td><td>&#9989; Ada</td><td>Setiap service memiliki folder <code>proto/</code></td></tr>\n    <tr><td>API Endpoint JSON</td><td>&#9888; Parsial</td><td><code>student-service-api.json</code> &mdash; hanya route dump, tanpa request/response schema</td></tr>\n    <tr><td>Markdown API Docs</td><td>&#9888; Sangat Minimal</td><td><code>ADMISSION.md</code> &mdash; hanya 1 file, hanya contoh request tanpa response</td></tr>\n    <tr><td>README files</td><td>&#9888; Ada tapi generik</td><td>Setiap repo punya README tapi isinya template standar</td></tr>\n</table>\n\n<p><strong>Bagaimana Frontend Mengetahui Kontrak Data?</strong><br>\nBerdasarkan analisis kode:</p>\n<ol>\n    <li><strong>Kontrak data implisit</strong> &mdash; Frontend mendefinisikan TypeScript interfaces di <code>app/interfaces/</code> (35 domain-specific directories), tapi ini di-maintain <strong>secara manual dan terpisah</strong> dari backend.</li>\n    <li><strong>Standard response envelope</strong> &mdash; Backend menggunakan format respons standar yang konsisten:\n<pre><code>{\n "version": 1,\n "message": "string",\n "success": true/false,\n "errors": true/false,\n "metadata": null | {...},\n "results": null | {...} | [...]\n}</code></pre>\nDidefinisikan di <code>response/json.go</code>.\n    </li>\n    <li><strong>Tidak ada mekanisme notifikasi perubahan</strong> &mdash; Jika backend mengubah response structure, frontend harus mengetahui melalui koordinasi manual antar developer (kemungkinan besar melalui GitLab/komunikasi tim).</li>\n</ol>\n<p><strong>[!WARNING]</strong> Risiko: Perubahan response backend yang tidak dikomunikasikan dapat menyebabkan <strong>silent bugs</strong> di frontend (data undefined, rendering error) karena tidak ada kontrak otomatis yang memvalidasi kedua sisi.</p>\n\n<hr>\n\n<h3>4. Pemisahan Logika Bisnis</h3>\n<p><strong>[!IMPORTANT]</strong> Logika bisnis utama <strong>dikelola sepenuhnya di sisi backend Golang</strong>. Frontend Next.js berperan sebagai <strong>thin client</strong> yang fokus pada presentasi dan state management.</p>\n\n<h4>4.1 Backend: Pusat Logika Bisnis</h4>\n<p>Setiap microservice menerapkan arsitektur <strong>Clean Architecture / Hexagonal</strong> yang konsisten:</p>\n<pre><code>cmd/            &rarr; Entry point (wiring dependencies)\nconfig/         &rarr; Configuration management\ndomain/         &rarr; Domain entities, value objects, repository interfaces\n &boxvr;&boxh;&boxh; entity/\n &boxvr;&boxh;&boxh; aggregate/\n &boxvr;&boxh;&boxh; repository/ (interfaces)\n &boxur;&boxh;&boxh; valueobject/\nusecase/        &rarr; Business logic (core rules)\npresentation/   &rarr; Controllers, handlers, response formatting\n &boxvr;&boxh;&boxh; controller/ (REST handlers)\n &boxvr;&boxh;&boxh; handler/    (gRPC handlers)\n &boxvr;&boxh;&boxh; middleware/\n &boxur;&boxh;&boxh; response/\ninfrastructure/ &rarr; Technical implementations\n &boxvr;&boxh;&boxh; postgres/   (database)\n &boxvr;&boxh;&boxh; redis/      (caching)\n &boxvr;&boxh;&boxh; grpc/       (inter-service communication)\n &boxvr;&boxh;&boxh; rest/       (HTTP server - GoFiber)\n &boxvr;&boxh;&boxh; firebase/   (push notifications)\n &boxvr;&boxh;&boxh; email/      (SMTP)\n &boxur;&boxh;&boxh; whatsapp/   (Fonnte/Qontak)</code></pre>\n\n<p><strong>Contoh Logika Bisnis Krusial di Backend</strong></p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Domain</th><th>Lokasi</th><th>Fungsi</th></tr>\n    <tr><td><strong>Billing &amp; Tagihan</strong></td><td><code>billing_usecase.go</code> (462 baris)</td><td>Pembuatan tagihan DSP, SPP, biaya pendaftaran, kalkulasi diskon</td></tr>\n    <tr><td><strong>Settlement / Pembayaran</strong></td><td><code>settlement_usecase.go</code> (37.661 byte!)</td><td>Penyelesaian pembayaran, integrasi payment gateway, mapping rekening settlement</td></tr>\n    <tr><td><strong>Angsuran</strong></td><td><code>installment_plan_usecase.go</code></td><td>Rencana cicilan, validasi, perpanjangan</td></tr>\n    <tr><td><strong>Autentikasi</strong></td><td><code>auth_usecase.go</code></td><td>Login web/mobile, token generation, forgot/reset password</td></tr>\n    <tr><td><strong>OTP</strong></td><td><code>otp_usecase.go</code></td><td>Request &amp; verify OTP via email/WhatsApp</td></tr>\n    <tr><td><strong>Scheduled Jobs</strong></td><td><code>scheduler_usecase.go</code></td><td>Cron jobs: pengecekan tagihan tertunggak (jam 21:00 daily)</td></tr>\n    <tr><td><strong>Event-Driven</strong></td><td><code>event_usecase.go</code></td><td>Event bus, mediator pattern</td></tr>\n</table>\n\n<h4>4.2 Frontend: Presentasi &amp; State Management</h4>\n<p>Frontend <strong>TIDAK</strong> mengandung logika bisnis krusial. Yang ada di frontend hanya:</p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Kategori</th><th>Detail</th><th>Lokasi</th></tr>\n    <tr><td><strong>UI Logic</strong></td><td>Routing, layout, conditional rendering</td><td><code>app/admin/</code></td></tr>\n    <tr><td><strong>State Management</strong></td><td>Redux Toolkit (37 slices!)</td><td><code>store/slices/</code></td></tr>\n    <tr><td><strong>Form Validation</strong></td><td>Basic input validation (length, format)</td><td><code>formValidator.ts</code></td></tr>\n    <tr><td><strong>Auth Guard</strong></td><td>JWT decode untuk routing (bukan validasi!)</td><td><code>proxy.ts</code></td></tr>\n    <tr><td><strong>Role-Based UI</strong></td><td>Show/hide menu berdasarkan role dari JWT</td><td><code>useMenu.ts</code></td></tr>\n    <tr><td><strong>Encryption</strong></td><td>Encrypt payload sebelum login (security)</td><td><code>@repo/utils (EncryptionUtil)</code></td></tr>\n    <tr><td><strong>Normalisasi Data</strong></td><td>Format username, format tagihan type</td><td><code>normalizeUsername.ts</code></td></tr>\n</table>\n<p><strong>[!NOTE]</strong> Frontend menggunakan <strong>custom hooks pattern</strong> yang sangat terstruktur (25 hook directories di <code>app/hooks/</code>), tetapi hooks ini hanya membungkus API calls dan state management &mdash; bukan logika bisnis.</p>\n\n<hr>\n\n<h3>5. Infrastruktur Pendukung</h3>\n\n<p><strong>Shared Libraries</strong></p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Library</th><th>Fungsi</th><th>Digunakan Oleh</th></tr>\n    <tr><td><code>go-lib</code></td><td>REST base handler, response format, logger, value objects</td><td>Semua Go services</td></tr>\n    <tr><td><code>jwtaccess</code></td><td>JWT auth middleware, role extraction, token blacklist</td><td>Services yang butuh auth</td></tr>\n</table>\n\n<p><strong>Observability</strong></p>\n<ul>\n    <li><strong>OpenTelemetry</strong> tracing terintegrasi di semua services (Fiber middleware, gRPC interceptor, GORM adapter)</li>\n    <li><strong>Structured logging</strong> via <code>go-lib/pkg/logger</code> (auto-inject <code>trace_id</code>/<code>span_id</code>)</li>\n    <li>Exporter dikonfigurasi via <code>OTEL_EXPORTER_OTLP_ENDPOINT</code></li>\n</ul>\n\n<p><strong>Event-Driven Architecture (Transaction Service)</strong></p>\n<p>Transaction-service menggunakan pola yang paling kompleks:</p>\n<ul>\n    <li><strong>Event Bus</strong> &mdash; <code>event_usecase.go</code></li>\n    <li><strong>Mediator Pattern</strong> &mdash; <code>mediator/</code></li>\n    <li><strong>Worker Goroutines</strong> &mdash; <code>worker/</code></li>\n    <li><strong>Scheduled Jobs</strong> &mdash; gocron (daily outstanding bill check)</li>\n</ul>\n\n<p><strong>Keamanan</strong></p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Layer</th><th>Mekanisme</th></tr>\n    <tr><td><strong>Auth</strong></td><td>JWT Bearer Token (cookie-based di frontend)</td></tr>\n    <tr><td><strong>Login Encryption</strong></td><td>Payload di-encrypt sebelum dikirim (AES/similar)</td></tr>\n    <tr><td><strong>Token Blacklist</strong></td><td>Redis-backed token revocation</td></tr>\n    <tr><td><strong>Role-Based Access</strong></td><td>15 role levels (Administrator &rarr; Siswa) didefinisikan di <code>jwtaccess/middleware.go</code></td></tr>\n    <tr><td><strong>Route Guards</strong></td><td>Frontend middleware blocks prohibited routes per role</td></tr>\n    <tr><td><strong>reCAPTCHA</strong></td><td>Google reCAPTCHA v2 di halaman login</td></tr>\n</table>\n\n<hr>\n\n<h3>6. Kesimpulan &amp; Rekomendasi</h3>\n\n<p>&#9989; <strong>Kekuatan Arsitektur</strong></p>\n<ol>\n    <li><strong>Clean Architecture</strong> yang konsisten di setiap microservice (domain/usecase/presentation/infrastructure)</li>\n    <li><strong>gRPC untuk inter-service</strong> &mdash; efisien dan type-safe dengan proto definitions</li>\n    <li><strong>Pemisahan concern yang jelas</strong> &mdash; Frontend murni thin client, business logic 100% di backend</li>\n    <li><strong>Observability</strong> sudah terintegrasi (OpenTelemetry)</li>\n    <li><strong>Shared libraries</strong> menghindari duplikasi kode</li>\n    <li><strong>Monorepo frontend</strong> dengan Turborepo untuk code sharing</li>\n</ol>\n\n<p>&#9888; <strong>Area yang Perlu Perbaikan</strong></p>\n<table border="1" cellpadding="5" cellspacing="0">\n    <tr><th>Area</th><th>Masalah</th><th>Rekomendasi</th></tr>\n    <tr><td><strong>Dokumentasi API</strong></td><td>Tidak ada Swagger/OpenAPI</td><td>Implementasi <code>swag</code> (Go Swagger generator) atau <code>buf</code> untuk proto docs</td></tr>\n    <tr><td><strong>Kontrak Data</strong></td><td>Frontend interfaces manual, tidak sync dengan backend</td><td>Pertimbangkan code generation dari proto/OpenAPI ke TypeScript</td></tr>\n    <tr><td><strong>Testing</strong></td><td>Hanya ditemukan 1 test file (<code>settlement_usecase_test.go</code>)</td><td>Tingkatkan coverage, terutama untuk usecase layer</td></tr>\n    <tr><td><strong>Error Handling</strong></td><td>Frontend banyak <code>any</code> type pada error handling</td><td>Definisikan error types yang konsisten</td></tr>\n    <tr><td><strong>API Versioning</strong></td><td>Hanya versi path <code>/v1</code>, tidak ada mekanisme backward compatibility</td><td>Implementasikan API versioning strategy</td></tr>\n</table>', '1', '2', '93', '2026-07-14 02:36:42', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('71', '24', 'Pendalaman Backend: Golang (Go)', 'pendalaman-backend-golang', '<p>Analisis ini berfokus pada implementasi backend Golang di ALAZHARAPPS, mengevaluasi arsitektur, manajemen resource, dan tingkat kesiapan untuk skala produksi (production-readiness).</p>\n\n<h3>1. Pola Arsitektur Kode: Clean Architecture</h3>\n<p>Sistem ini menerapkan Clean Architecture yang sangat terstruktur dan konsisten di seluruh microservices (seperti account-service, transaction-service, student-service). Pendekatan ini memisahkan secara tegas antara infrastruktur teknis dan logika bisnis inti.</p>\n\n<p><strong>Pemisahan Layer</strong><br>\nBerdasarkan struktur folder, proyek ini membagi tanggung jawab sebagai berikut:</p>\n<ul>\n    <li><strong>Layer Infrastruktur (infrastructure/):</strong> Berisi implementasi teknis untuk koneksi ke layanan eksternal. Di sini terdapat konektor untuk PostgreSQL (postgres), Redis (redis), gRPC (grpc), HTTP server berbasis Fiber (rest), Firebase (firebase), dan gateway pengiriman pesan (whatsapp, email).</li>\n    <li><strong>Layer Domain (domain/):</strong> Merupakan inti aplikasi yang tidak bergantung pada framework apapun.\n        <ul>\n            <li><strong>Entity (domain/entity/):</strong> Struktur data inti tabel database (misalnya User, BaseModel, Notification).</li>\n            <li><strong>Aggregate (domain/aggregate/):</strong> Gabungan entitas yang memiliki relasi logika.</li>\n            <li><strong>Repository Interfaces (domain/repository/):</strong> Contract atau Interface yang mendefinisikan operasi apa saja yang bisa dilakukan ke database (misalnya UserRepository). Implementasi nyata dari interface ini berada di layer infrastructure atau presentation.</li>\n        </ul>\n    </li>\n    <li><strong>Layer Usecase/Service (usecase/):</strong> Tempat logika bisnis dan aturan aplikasi berada (misalnya billing_usecase.go, auth_usecase.go). Usecase ini memanggil fungsi-fungsi dari Repository Interface tanpa perlu tahu database apa yang digunakan.</li>\n    <li><strong>Layer Presentation (presentation/):</strong> Menangani entry-point data dari luar ke sistem.\n        <ul>\n            <li><strong>Controller (presentation/controller/):</strong> Menangani request HTTP REST (menggunakan Fiber), memvalidasi input, memanggil Usecase, dan mengembalikan respons HTTP.</li>\n            <li><strong>Handler (presentation/handler/):</strong> Menangani request gRPC antar service.</li>\n            <li><strong>Event/Worker (presentation/event/ & presentation/worker/):</strong> Menangani event asynchronous atau antrean pesan.</li>\n        </ul>\n    </li>\n    <li><strong>Layer CMD (cmd/):</strong> Fungsi main.go berada di sini. Bertugas sebagai Dependency Injection container manual (wiring) yang menggabungkan (inject) database, repository, usecase, dan router sebelum menjalankan server.</li>\n</ul>\n\n<h3>2. Konkurensi & Goroutines</h3>\n<p>Aplikasi ini sangat memanfaatkan fitur konkurensi Go secara ekstensif, terutama untuk menjamin performa saat trafik tinggi dan memproses tugas latar belakang.</p>\n\n<p><strong>Pemanfaatan Goroutine & Channel</strong></p>\n<ul>\n    <li><strong>Server & Worker Initialization:</strong> Di dalam <code>cmd/main.go</code>, berbagai server (REST, gRPC) dan background worker dijalankan secara konkuren menggunakan goroutine agar tidak saling memblokir:\n<pre><code>go server.Start()\ngo grpc.Start()\ngo cron.Start()\ngo worker.Start()\ngo eventMediator.Start()</code></pre>\n    </li>\n    <li><strong>Event-Driven Mediator (presentation/event/event_mediator.go):</strong> Sistem transaksi menggunakan pola Mediator untuk mendistribusikan event. Terdapat sebuah loop <code>channel <-s.bus.Receive()</code> yang mendengarkan event masuk. Ketika event diterima, ia men-spawn goroutine baru untuk setiap handler yang terdaftar (<code>go handler.Handle(context.Background(), eventType)</code>).</li>\n    <li><strong>Redis Stream Workers (presentation/worker/admission_worker.go):</strong> Pekerja latar belakang berjalan di dalam goroutine tak terbatas (infinite loop) yang secara terus-menerus menarik (polling) data dari Redis Streams untuk diproses secara asinkron.</li>\n</ul>\n\n<p><strong>Pencegahan Goroutine Leak</strong><br>\nUntuk menghindari goroutine leak dan kebocoran memori, sistem menerapkan beberapa praktik terbaik:</p>\n<ul>\n    <li><strong>Context Cancellation:</strong> Menggunakan <code>context.Context</code> secara ketat. Di <code>cmd/main.go</code>, terdapat implementasi Graceful Shutdown menggunakan <code>signal.NotifyContext</code>. Saat server menerima sinyal terminasi (SIGINT/SIGTERM), context dibatalkan, dan semua proses yang bergantung padanya akan dihentikan secara aman (<code>server.Shutdown(shutdownCtx)</code>).</li>\n    <li><strong>ErrGroup (golang.org/x/sync/errgroup):</strong> Pada proses yang kompleks seperti eksekusi beberapa query bersamaan (misal di event_usecase.go saat mencari diskon), aplikasi menggunakan <code>errgroup.WithContext</code>. Jika salah satu sub-goroutine gagal, context akan dibatalkan untuk menghentikan goroutine lainnya, mencegah goroutine menggantung (hanging).</li>\n    <li><strong>Channel dengan Shutdown Signal:</strong> Pada worker latar belakang (admission_worker.go), terdapat select statement yang memonitor <code>shutdownChan</code>. Hal ini memastikan infinite loop dapat diputus saat aplikasi dihentikan.</li>\n</ul>\n\n<h3>3. Manajemen Koneksi Database (Connection Pooling)</h3>\n<p>Aplikasi ini menggunakan GORM (<code>gorm.io/gorm</code>) sebagai ORM dengan driver PostgreSQL. Konfigurasi koneksinya dikelola sangat baik untuk menangani traffic spike.</p>\n\n<p><strong>Konfigurasi Pooling (Di infrastructure/postgres/client.go)</strong><br>\nKonfigurasi database diatur secara dinamis melalui file <code>.env</code> dan di-apply ke GORM melalui <code>sqlDB</code>:</p>\n<pre><code>sqlDB.SetMaxOpenConns(cfg.Database.MaxOpenConn)\nsqlDB.SetMaxIdleConns(cfg.Database.MaxIdleConn)\nsqlDB.SetConnMaxLifetime(time.Duration(cfg.Database.MaxLifeTime) * time.Hour)\nsqlDB.SetConnMaxIdleTime(time.Duration(cfg.Database.MaxIdleTime) * time.Minute)</code></pre>\n<ul>\n    <li><strong>SetMaxOpenConns:</strong> Membatasi jumlah maksimal koneksi terbuka yang mencegah PostgreSQL crash akibat terlalu banyak koneksi simultan.</li>\n    <li><strong>SetMaxIdleConns:</strong> Menjaga jumlah koneksi siaga (idle) yang siap pakai sehingga menekan latensi pembuatan koneksi baru.</li>\n    <li><strong>SetConnMaxLifetime / SetConnMaxIdleTime:</strong> Menutup koneksi lama untuk mencegah isu stale connection dan kebocoran resource di sisi database.</li>\n</ul>\n\n<p><strong>Pemisahan Read-Write (Replikasi)</strong><br>\nFitur canggih yang diterapkan adalah Read-Write Splitting menggunakan plugin <code>gorm.io/plugin/dbresolver</code>.</p>\n<pre><code>readPool := dbresolver.Register(dbresolver.Config{\n    Replicas: []gorm.Dialector{postgres.Open(buildDsn(cfg.DatabaseRead))},\n    Policy:   dbresolver.RandomPolicy{},\n})</code></pre>\n<p>Ini berarti query pembacaan (SELECT) dapat dialihkan secara otomatis ke database replica (DB_READ), sementara proses penulisan (INSERT/UPDATE/DELETE) tetap di database primary. Ini sangat krusial untuk mencegah database utama tercekik saat trafik pembacaan melonjak.</p>\n\n<h3>4. Penanganan Error & Logging</h3>\n<p>Standar observabilitas (observability) di proyek ini sangat tinggi, terintegrasi dengan standar industri modern.</p>\n\n<p><strong>Mekanisme Error Wrapping</strong><br>\nError sentinel (error yang didefinisikan secara statis) dideklarasikan di <code>domain/error.go</code> (contoh: <code>ErrUserNotFound = errors.New("user not found")</code>). Aplikasi cenderung mem-passing error langsung ke presentation layer di mana controller membungkusnya menjadi respons JSON berformat standar menggunakan utilitas dari <code>go-lib/rest/base_handler.go</code>.</p>\n\n<p><strong>Ekosistem Logging & Observabilitas (Trace)</strong><br>\nProyek ini tidak hanya mencetak log teks biasa, tetapi menggunakan OpenTelemetry (OTel) dan Structured Logging (JSON).</p>\n<ul>\n    <li><strong>Distributed Tracing (OpenTelemetry):</strong> Diinisialisasi di <code>cmd/main.go</code> (<code>observability.InitTracer()</code>). Middleware OTel dipasang pada GoFiber (<code>otelfiber.Middleware()</code>) dan gRPC client (<code>otelgrpc.NewClientHandler()</code>). Ini memberikan kemampuan melacak sebuah request secara melintasi berbagai microservice (Distributed Tracing).</li>\n    <li><strong>Structured GORM Logger:</strong> Query database dilog dalam format JSON lengkap dengan metrik lambat (slow queries > 200ms akan dicatat sebagai Warn).\n<pre><code>gormLog := logger.NewGormLogger(\n    logger.WithGormLevel(gormLevelFromEnv()),\n    logger.WithSlowThreshold(200*time.Millisecond),\n)</code></pre>\n    Plugin tracing <code>tracing.NewPlugin</code> memastikan setiap query SQL memiliki relasi child span ke request utamanya.</li>\n    <li><strong>Trace ID Injection:</strong> Logger dari pustaka bersama (<code>scm.alazhar.or.id/al-azhar-apps/go-lib/pkg/logger</code>) secara otomatis menyuntikkan trace_id dan span_id ke setiap baris log.</li>\n</ul>\n\n<p><strong>Cara Melacak Kegagalan (Log Triage)</strong></p>\n<ul>\n    <li><strong>Output Log:</strong> Log dikeluarkan dalam bentuk Standard Output (stdout) berformat JSON. Dalam lingkungan kontainer (Docker/Kubernetes), log ini biasanya akan ditangkap oleh log collector seperti FluentBit atau Promtail.</li>\n    <li><strong>Pencarian Berbasis Trace ID:</strong> Karena log mendukung standar OpenTelemetry, tim dapat menggunakan alat APM seperti SigNoz, Jaeger, Elasticsearch, atau Grafana Loki.</li>\n    <li><strong>Skenario Pelacakan:</strong> Jika seorang user melaporkan gagal mendaftar, tim dapat mencari trace_id yang terkait dengan sesi user tersebut di platform APM. Karena trace_id mengalir dari API Gateway → Account Service (HTTP) → School Service (gRPC) → Database, tim dapat melihat visualisasi grafis di titik (span) mana terjadi error, query SQL apa yang gagal, beserta pesan log JSON-nya.</li>\n</ul>', '1', '2', '94', '2026-07-14 02:36:42', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('72', '24', 'Pendalaman Frontend: NextJS', 'pendalaman-frontend-nextjs', '<p>Analisis ini berfokus pada implementasi arsitektur antarmuka pengguna (Frontend) ALAZHARAPPS yang dibangun menggunakan ekosistem NextJS dan Turborepo.</p>\n\n<h3>1. Versi Router &amp; Struktur Proyek</h3>\n<p>Aplikasi ini telah bermigrasi dan menggunakan <strong>NextJS App Router</strong> (direktori <code>/app</code>). Namun, ada beberapa pola campuran (hybrid) yang ditemukan:</p>\n<ul>\n    <li><strong>App Router (<code>/app</code>):</strong> Merupakan pusat utama dari seluruh antarmuka pengguna (UI), <em>routing</em> halaman, dan komponen aplikasi (seperti <code>/app/admin/...</code> dan <code>/app/auth/...</code>).</li>\n    <li><strong>Pages Router (<code>/pages</code>):</strong> Direktori ini masih ada tetapi <strong>tidak digunakan untuk UI</strong>. Direktori ini hanya menyimpan beberapa <em>API Routes</em> lama di <code>/pages/api/</code> (misalnya <code>raport-preview.ts</code>, <code>verify-recaptcha.ts</code>).</li>\n</ul>\n\n<p><strong>Pembagian Server vs Client Components</strong><br>\nMeskipun menggunakan App Router yang secara default berorientasi pada <em>Server Components</em>, aplikasi ini <strong>sangat bergantung pada Client Components</strong>.</p>\n<p>Lebih dari 400 file secara eksplisit menggunakan direktif <code>"use client"</code>, termasuk pada tingkat hierarki teratas halaman (contoh: <code>app/admin/dashboard/page.tsx</code>). Hal ini membuat aplikasi berperilaku lebih mirip dengan <em>Single Page Application</em> (SPA) React tradisional dibandingkan aplikasi SSR modern.</p>\n\n<h3>2. Strategi Perenderan (Rendering Strategy)</h3>\n<p>Karena dominasi direktif <code>"use client"</code> di level halaman (page-level), strategi perenderan utama yang digunakan adalah <strong>Client-Side Rendering (CSR)</strong> murni.</p>\n\n<p><strong>Konsekuensi dari Pola Ini:</strong></p>\n<ol>\n    <li><strong>Tidak Ada SSR/SSG untuk Data:</strong> Halaman tidak mengambil data (fetching) di sisi server sebelum dikirim ke peramban (browser). Sebaliknya, server hanya mengirimkan kerangka HTML kosong (atau komponen loading), lalu React melakukan proses hidrasi (hydration) dan memulai pengambilan data di sisi klien.</li>\n    <li><strong>Pertimbangan Pemilihan Strategi:</strong> Pendekatan ini umum dipilih ketika memigrasikan aplikasi React lama (seperti Create React App) ke NextJS tanpa mau merombak ulang logika <em>data fetching</em>. Selain itu, karena aplikasi ini bersifat "Admin Dashboard" yang berada di balik <em>login wall</em> (membutuhkan autentikasi), faktor SEO (Search Engine Optimization) tidak relevan, sehingga CSR dianggap cukup memadai.</li>\n</ol>\n<p><strong>[!WARNING] Risiko Performa:</strong> Menggunakan CSR secara ekstensif pada dashboard yang berat dapat menyebabkan <em>Time to Interactive (TTI)</em> lambat pada perangkat berspesifikasi rendah, karena peramban pengguna harus mengunduh bundel JavaScript yang besar dan melakukan <em>fetching</em> API secara berantai (waterfall) di sisi klien.</p>\n\n<h3>3. State Management &amp; Caching Frontend</h3>\n<p>Proyek ini tidak menggunakan pustaka fetching modern seperti SWR atau React Query (TanStack Query). Pengelolaan status (state) dan caching sepenuhnya bergantung pada dua teknologi utama:</p>\n\n<h4>1. Redux Toolkit (RTK)</h4>\n<ul>\n    <li><strong>Penggunaan:</strong> Sebagai pusat manajemen state global. Aplikasi ini memiliki tidak kurang dari <strong>37 Redux Slices</strong> di <code>/store/slices/</code>.</li>\n    <li><strong>Data Fetching:</strong> Menggunakan <code>createAsyncThunk</code> untuk melakukan pemanggilan API asinkron via Axios, lalu menyimpan hasilnya, status <em>loading</em>, dan status <em>error</em> secara manual ke dalam store Redux.</li>\n    <li><strong>Kekurangan:</strong> Tanpa pustaka seperti React Query, tim developer harus menulis kode (boilerplate) yang berulang untuk menangani loading state dan harus mengelola invalidasi cache secara manual jika data di server berubah.</li>\n</ul>\n\n<h4>2. Manajemen Sesi dengan Cookies (<code>js-cookie</code>)</h4>\n<ul>\n    <li>Sistem sangat mengandalkan cookies sisi peramban untuk menyimpan data sesi yang melintasi navigasi halaman (persisten).</li>\n    <li>Data yang disimpan meliputi <code>authToken</code>, pengaturan <code>tahun_ajaran_aktif</code>, dan akses role pengguna.</li>\n    <li><strong>Keamanan:</strong> Ditemukan praktik baik di mana data krusial (seperti payload role atau academic year) dienkripsi terlebih dahulu menggunakan utilitas lokal (<code>EncryptionUtil.encrypt/decrypt</code>) sebelum disimpan ke cookie.</li>\n</ul>\n\n<h3>4. Optimasi Aset Visual (CLS Prevention)</h3>\n<p><strong>Status:</strong> &#9989; <strong>Sudah Dioptimalkan</strong></p>\n<p>Berdasarkan penelusuran kode, proyek ini secara konsisten menggunakan komponen bawaan <strong><code>next/image</code></strong> untuk perenderan gambar.</p>\n<ul>\n    <li><strong>Distribusi:</strong> Komponen <code>next/image</code> ditemukan digunakan di seluruh elemen antarmuka utama seperti Sidebar, ExamCard, TableReport, dan berbagai komponen Dashboard.</li>\n    <li><strong>Manfaat:</strong> Penggunaan ini secara otomatis mengoptimalkan format gambar (WebP/AVIF), memperkecil ukuran file (resizing) sesuai ukuran layar pengguna, dan secara eksplisit memesan ruang dimensi di tata letak halaman untuk mencegah terjadinya masalah <strong>Cumulative Layout Shift (CLS)</strong> (loncatan tampilan halaman saat gambar tiba-tiba selesai dimuat).</li>\n    <li><strong>Konfigurasi:</strong> Konfigurasi <code>next.config.js</code> juga telah diatur untuk mengizinkan (whitelist) <em>remote patterns</em> dari server aset eksternal (<code>assets.alazhar.or.id</code>).</li>\n</ul>', '1', '2', '95', '2026-07-14 02:36:42', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('73', '24', 'Keamanan & Autentikasi', 'keamanan-autentikasi', '<p>Analisis ini berfokus pada mekanisme keamanan, autentikasi, dan perlindungan API (CORS &amp; Rate Limiting) yang menjembatani antara Frontend (NextJS) dan Backend (Golang). Ditemukan beberapa <strong>celah keamanan kritis</strong> yang berpotensi membahayakan sistem jika di-deploy ke lingkungan produksi.</p>\n\n<h3>1. Mekanisme Autentikasi &amp; Penyimpanan JWT</h3>\n<p><strong>Status:</strong> &#9888; <strong>Rentan terhadap serangan XSS (Cross-Site Scripting)</strong></p>\n\n<ul>\n    <li><strong>Penerbitan Token:</strong> Backend (Golang) menghasilkan token JWT saat proses login berhasil dan mengembalikannya ke frontend dalam bentuk respons JSON biasa (<code>{ "results": { "token": "ey..." } }</code>).</li>\n    <li><strong>Penyimpanan di Frontend:</strong> Kode frontend (<code>authSlice.ts</code>) mengambil token tersebut dan menyimpannya menggunakan pustaka <code>js-cookie</code>:\n<pre><code>// Lokasi: frontend/apps/apps/app/store/slices/auth/\nCookies.set("authToken", token);</code></pre>\n    </li>\n    <li><strong>Analisis Kerentanan:</strong> Penyimpanan token JWT secara langsung menggunakan <code>Cookies.set()</code> tanpa flag <code>HttpOnly</code> membuat token dapat dibaca dan dicuri oleh <strong>kode JavaScript apapun</strong> yang berjalan di browser (<code>document.cookie</code>). Jika ada script berbahaya yang berhasil disusupkan ke halaman web (melalui form input, komentar, atau pustaka pihak ketiga yang disusupi &mdash; XSS), peretas dapat mencuri token sesi pengguna dan mengambil alih akun mereka (Session Hijacking).</li>\n</ul>\n\n<p><strong>[!CAUTION] Rekomendasi:</strong> Backend Golang <strong>wajib</strong> mengubah metode pengiriman token. Token tidak boleh dikirim via body JSON, melainkan langsung di-set oleh backend ke dalam header <code>Set-Cookie</code> dengan parameter <code>HttpOnly</code>, <code>Secure</code>, dan <code>SameSite=Strict</code>. Dengan cara ini, JavaScript di peramban tidak akan bisa membaca token tersebut.</p>\n\n<h3>2. CORS (Cross-Origin Resource Sharing)</h3>\n<p><strong>Status:</strong> &#10060; <strong>Sangat Berbahaya (Miskonfigurasi Kritis)</strong></p>\n\n<ul>\n    <li><strong>Konfigurasi Saat Ini:</strong> Berdasarkan penelusuran pada file pengaturan server GoFiber, aturan CORS diatur secara terbuka:\n<pre><code>// Lokasi: account-service/infrastructure/rest/serve\napp.Use(cors.New(cors.Config{\n AllowOrigins: "*", // &lt;-- SANGAT BERBAHAYA\n AllowHeaders: "Origin, Content-Type, Accept, \n AllowMethods: "GET, POST, PUT, DELETE, OPTIO\n AllowCredentials: false,\n}))</code></pre>\n    </li>\n    <li><strong>Analisis Kerentanan:</strong> Pengaturan <code>AllowOrigins: "*"</code> berarti <strong>APAPUN dan SIAPAPUN</strong> di internet (domain peretas, aplikasi asing) dapat mengirimkan request Ajax/Fetch ke API <code>dev-api.alazhar.or.id</code> tanpa diblokir oleh peramban pengguna. Ini adalah miskonfigurasi yang sering dieksploitasi untuk serangan CSRF (Cross-Site Request Forgery) sekunder.</li>\n</ul>\n\n<p><strong>[!CAUTION] Rekomendasi:</strong> Konfigurasi CORS harus segera diperketat berdasarkan <em>Environment Variables</em>. Untuk <em>production</em>, pastikan <code>AllowOrigins</code> diisi spesifik hanya untuk domain frontend (misal: <code>"https://admin.alazhar.or.id"</code>).</p>\n\n<h3>3. Rate Limiting &amp; Perlindungan Brute-Force</h3>\n<p><strong>Status:</strong> &#9888; <strong>Tidak Ditemukan Proteksi Aktif</strong></p>\n\n<ul>\n    <li><strong>Pengecekan Kode:</strong> Tidak ditemukan implementasi middleware Rate Limiter (seperti <code>fiber/v2/middleware/limiter</code>) pada level aplikasi Golang (di <code>server.go</code> maupun rute spesifik seperti <code>/login</code> dan <code>/otp/request</code>).</li>\n    <li><strong>Analisis Kerentanan:</strong> Ketiadaan batasan request membuat endpoint autentikasi sangat rentan terhadap <strong>Serangan Brute-Force</strong> (peretas mencoba ribuan kombinasi kata sandi) dan <strong>DDoS (Distributed Denial of Service)</strong> yang bisa membuat server down akibat kehabisan memori.\n        <ul>\n            <li>Endpoint <code>/otp/request</code> berpotensi dieksploitasi untuk serangan <em>SMS/WhatsApp Bombing</em>, yang mana peretas membanjiri nomor korban dengan OTP, mengakibatkan perusahaan membengkak tagihan Fonnte/Qontak-nya.</li>\n        </ul>\n    </li>\n</ul>\n\n<p><strong>[!WARNING] Rekomendasi:</strong> Wajib menambahkan Rate Limiter berbasis IP atau Username. Misalnya, batasi maksimal 5 percobaan login atau request OTP dalam waktu 15 menit.</p>\n\n<h3>4. Skema Validasi Input (Data Validation)</h3>\n<p><strong>Status:</strong> &#9888; <strong>Terlalu Sederhana (Manual Validation)</strong></p>\n\n<ul>\n    <li><strong>Frontend:</strong> Validasi input form tidak menggunakan pustaka standar industri (seperti <code>Yup</code> atau <code>Zod</code>). Tim menggunakan kode validasi kostum buatan sendiri (<code>frontend/packages/libs/src/formValidator.ts</code>). Walaupun bekerja (mengecek <code>minLength</code>, <code>onlyNumber</code>), ini rentan terhadap <em>edge-cases</em> dan sulit diperluas (scale) untuk tipe data yang kompleks.</li>\n    <li><strong>Backend:</strong> Terdapat kerangka fungsi <code>middleware.Validator()</code> di GoFiber, namun statusnya masih kosong (hanya berisi komentar: <code>// Bisa tambahkan validasi global di sini</code>). Pengecekan saat proses login hanya menggunakan operator dasar (<code>if data.Username != ""</code>). Tidak ditemukan penggunaan pustaka seperti <code>go-playground/validator</code> yang umumnya digunakan untuk memvalidasi request payload secara ketat sebelum data menyentuh logika bisnis (usecase).</li>\n</ul>\n\n<p><strong>[!TIP] Rekomendasi Praktik Terbaik:</strong> Implementasikan Data Transfer Object (DTO) validation di backend menggunakan Struct Tags (misal: <code>validate:"required,email"</code>). Backend <strong>tidak boleh</strong> mempercayai validasi dari frontend, karena peretas bisa membypass UI frontend dan menembak API secara langsung.</p>', '1', '2', '96', '2026-07-14 02:36:42', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('74', '24', 'DevOps, Deployment, & Infrastruktur', 'devops-deployment-infrastruktur', '<p>Analisis ini membahas bagaimana aplikasi ALAZHARAPPS dikemas (containerization), dioptimasi untuk lingkungan produksi, dan diotomatisasi rilisnya melalui sistem CI/CD (Continuous Integration / Continuous Deployment).</p>\n\n<h3>1. Containerization (Docker)</h3>\n<p>Kedua sisi aplikasi (Golang Backend dan NextJS Frontend) telah memanfaatkan fitur <strong>Multi-Stage Build</strong> pada Docker. Pendekatan ini sangat krusial karena memisahkan lingkungan "pembangunan kode" (build environment) dari lingkungan "penjalanan aplikasi" (runtime environment), menghasilkan image yang sangat ringan, cepat didistribusikan, dan jauh lebih aman.</p>\n\n<h4>A. Dockerfile Golang (Backend)</h4>\n<pre><code># Stage 1: Pembangunan (Builder)\nARG BASE_IMAGE_GO=registry.ypia-cloud.id/golang/golang:1.\nFROM ${BASE_IMAGE_GO} AS builder\n...\nRUN CGO_ENABLED=0 GOOS=linux GOARCH=amd64 go build -o acc \n\n# Stage 2: Hasil Akhir (Scratch)\nFROM scratch\nCOPY --from=builder /app/account-service .\n...\nCMD ["./account-service"]</code></pre>\n<ul>\n    <li><strong>Analisis:</strong> Dockerfile Golang menggunakan pola <em>scratch</em> murni. Image akhir tidak memiliki sistem operasi (<code>FROM scratch</code>), tidak ada shell bash, dan tidak ada dependensi eksternal. Ia murni hanya berisi satu file biner (<code>account-service</code>). Ini membuat ukuran image <strong>sangat kecil</strong> (hanya belasan MB) dan meniadakan celah keamanan dari eksploitasi sistem operasi (Zero-Attack Surface).</li>\n</ul>\n\n<h4>B. Dockerfile NextJS (Frontend)</h4>\n<pre><code># Stage 1: Builder\nFROM node:22.17-alpine AS builder\n...\nRUN npm run build-apps\n\n# Stage 2: Runner\nFROM node:22.17-alpine AS runner\nRUN addgroup --system --gid 1001 nodejs\nRUN adduser --system --uid 1001 nextjs\n...\nCOPY --from=builder --chown=nextjs:nodejs /app/apps/apps/ \n...\nUSER nextjs\nCMD ["node", "apps/apps/server.js"]</code></pre>\n<ul>\n    <li><strong>Analisis:</strong> Sangat matang. Sistem tidak menjalankan aplikasi Node.js menggunakan akses <code>root</code> (praktik standar yang sering terabaikan). Ia membuat akun spesifik (<code>nextjs</code>) sehingga kalaupun terjadi kompromi pada aplikasi, peretas tidak memiliki hak admin pada wadah (container).</li>\n</ul>\n\n<h3>2. NextJS Standalone Mode</h3>\n<p><strong>Status:</strong> &#9989; <strong>Diaktifkan</strong></p>\n<p>Pada <code>next.config.js</code> dan Dockerfile NextJS, fitur ini terbukti diaktifkan:</p>\n<pre><code>// next.config.js\noutput: "standalone",</code></pre>\n<ul>\n    <li><strong>Keuntungan:</strong> Secara default, <code>node_modules</code> NextJS berisi ratusan megabyte dependensi (termasuk modul pengembangan). Dengan mode <code>standalone</code>, NextJS akan membuat bundel mini yang <strong>hanya berisi file dan modul yang benar-benar dibutuhkan</strong> untuk menjalankan aplikasi di server. Mode ini mengurangi ukuran image Docker lebih dari 80%, mempercepat proses deployment, dan menurunkan konsumsi memori server.</li>\n</ul>\n\n<h3>3. Pipeline CI/CD &amp; Strategi Rollback</h3>\n<p>Proses rilis tidak dilakukan secara manual melainkan diotomatisasi penuh menggunakan <strong>GitLab CI</strong>.</p>\n\n<h4>Konfigurasi Tersentralisasi (IaC)</h4>\n<p>Pada setiap repositori (contohnya <code>account-service/.gitlab-ci.yml</code>), konfigurasi pipeline utamanya tidak ditulis berulang, melainkan mengambil referensi eksternal:</p>\n<pre><code>include:\n - project: \'al-azhar-iac/cicd-template\'\n   ref: main\n   file:\n     - \'v1/app/go-backend-v1-account.yml\'</code></pre>\n<ul>\n    <li><strong>Analisis:</strong> Tim infrastruktur memisahkan <em>template</em> rilis ke dalam repositori tersendiri (<code>al-azhar-iac/cicd-template</code>). Pendekatan ini (Infrastructure as Code) sangat ideal untuk arsitektur <em>microservices</em> karena memastikan standar build, testing, dan deployment seragam di belasan layanan yang ada.</li>\n</ul>\n\n<h4>Strategi Rollback</h4>\n<p>Walaupun detail instruksi rollback spesifik disembunyikan di dalam repositori <code>cicd-template</code> internal, berdasarkan pola Docker dan Registry (<code>registry.ypia-cloud.id</code>), mekanisme umum jika terjadi kegagalan (fatal crash) di production adalah:</p>\n<ol>\n    <li>Karena setiap rilis (push Git) menghasilkan Image Docker dengan tag versi unik (misalnya <code>account-service:v1.2.3</code>),</li>\n    <li>Jika <code>v1.2.3</code> gagal, rollback dilakukan dengan sangat cepat dengan cara <strong>memutar mundur status deployment ke tag image sebelumnya</strong> (misalnya <code>v1.2.2</code>). Wadah (container) rusak dimatikan dan digantikan wadah lama dalam hitungan detik. Pendekatan <em>immutable container</em> ini jauh lebih aman dibandingkan membatalkan (revert) komit kodingan dan melakukan rilis ulang (rebuild).</li>\n</ol>', '1', '2', '97', '2026-07-14 02:36:42', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('75', '24', 'Struktur Proyek & Arsitektur Microservices', '1-struktur-proyek-arsitektur-microservices', '<p>Dokumen ini membedah arsitektur makro dan pembagian (struktur) direktori dari sistem ALAZHARAPPS, yang secara keseluruhan mengadopsi pola <strong>Microservices</strong> dengan repositori terpisah (Polyrepo).</p>\r\n<h3>1. Pembagian Repositori (Microservices)</h3>\r\n<p>Sistem ALAZHARAPPS dipecah menjadi 12 modul/repositori independen untuk memastikan skalabilitas dan isolasi kegagalan:</p>\r\n<ul>\r\n<li><code>account-service</code>: Mengurus manajemen pengguna (user), autentikasi (login), dan hierarki *Role-Based Access Control* (RBAC).</li>\r\n<li><code>student-service</code>: Menangani data induk siswa, mutasi, dan pendaftaran.</li>\r\n<li><code>school-service-new</code>: Mengelola entitas sekolah, tahun ajaran, dan pengaturan kurikulum tingkat yayasan.</li>\r\n<li><code>transaction-service</code>: Mengurus tagihan (billing), pembayaran (payment gateway), dan riwayat transaksi.</li>\r\n<li><code>report-service</code>: Melayani pembuatan dan pencetakan rapor, rekap kehadiran, dan ekspor data agregat (PDF/Excel).</li>\r\n<li><code>lms-course-service</code>: Menangani kelas online, materi pembelajaran, dan pengumpulan tugas (di sisi LMS).</li>\r\n<li><code>frontend</code>: Memuat aplikasi berbasis antarmuka web interaktif (NextJS) untuk Admin Dashboard.</li>\r\n<li><code>landing-page</code>: Memuat situs web publik untuk profil yayasan dan pendaftaran awal.</li>\r\n<li><code>backend-codebase</code> (opsional): Mungkin digunakan sebagai referensi pola lama atau repositori monolit/legacy.</li>\r\n<li><code>etl</code>: Menjalankan proses *Extract, Transform, Load* untuk migrasi data historis atau sinkronisasi dengan sistem pemerintah (Dapodik).</li>\r\n<li><code>jwtaccess</code> &amp; <code>go-lib</code>: Pustaka internal (library) milik tim untuk standardisasi JWT dan *common utilities* yang diimpor oleh microservice lainnya.</li>\r\n</ul>\r\n<h3>2. Struktur Internal Backend (Clean Architecture)</h3>\r\n<p>Setiap repositori backend Golang menerapkan <strong>Clean Architecture</strong> karya Uncle Bob, yang terbagi dalam 4 lapisan (layer) direktori utama:</p>\r\n<ol>\r\n<li><strong><code>domain/</code> (Entities)</strong>: Berisi definisi struktur data murni (struct) dan antarmuka (interface) dari repository. Tidak boleh ada dependensi ke *framework* luar di sini.</li>\r\n<li><strong><code>usecase/</code> (Logika Bisnis)</strong>: Berisi otak dari aplikasi. Di sinilah aturan bisnis (seperti pengecekan apakah siswa sudah membayar sebelum ujian) divalidasi. Lapisan ini berkomunikasi dengan domain.</li>\r\n<li><strong><code>presentation/</code> (Delivery/Controller)</strong>: Berisi *handler* HTTP, REST, atau gRPC yang bertugas menerima *request* pengguna, mengubah JSON menjadi format Go, lalu memanggil fungsi di *usecase*.</li>\r\n<li><strong><code>infrastructure/</code> (Teknis)</strong>: Berisi konfigurasi teknis yang menghubungkan aplikasi ke dunia luar. Di sinilah koneksi PostgreSQL, Redis, Fiber Server, dan SMTP Mailer diletakkan.</li>\r\n</ol>\r\n<p><strong>Keuntungan Pendekatan Ini:</strong> Memisahkan logika bisnis dari teknologi *database* atau *framework* (seperti Fiber), sehingga jika di masa depan tim ingin mengganti *database* dari Postgres ke MySQL, hanya direktori <code>infrastructure/</code> yang perlu diubah.</p>\r\n<h3>3. Struktur Internal Frontend (Monorepo Turborepo)</h3>\r\n<p>Repositori <code>frontend/</code> merupakan sebuah monorepo berbalut <strong>Turborepo</strong>. Di dalamnya terdapat:</p>\r\n<ul>\r\n<li><code>apps/</code>: Berisi proyek aplikasi utama (seperti <code>apps/apps/</code> untuk dashboard admin berbasis NextJS).</li>\r\n<li><code>packages/</code>: Berisi pustaka antarmuka bersama, konfigurasi ESLint, TypeScript config, dan utilitas (*helpers*) yang bisa digunakan ulang oleh berbagai aplikasi di dalam monorepo tersebut.</li>\r\n</ul>', '1', '2', '98', '2026-07-14 04:06:16', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('76', '24', 'Dokumentasi Teknologi & Dependensi', '2-dokumentasi-teknologi-dependensi', '<p>Dokumen ini mendata secara komprehensif susunan teknologi utama (*tech stack*) dan pustaka pihak ketiga (*third-party dependencies*) yang digunakan untuk membangun aplikasi ALAZHARAPPS.</p>\r\n<h3>1. Backend Stack (Golang)</h3>\r\n<p>Berdasarkan analisis pada file <code>go.mod</code> dari beberapa layanan inti (seperti <code>account-service</code>), aplikasi ini dibangun di atas pondasi bahasa pemrograman <strong>Golang versi 1.20+</strong>.</p>\r\n<ul>\r\n<li><strong>Web Framework (GoFiber):</strong> Tim pengembangan tidak menggunakan pustaka standar <code>net/http</code>, melainkan menggunakan <strong>Fiber (v2)</strong>, framework web Go yang terkenal sangat cepat dan mengadopsi gaya API yang mirip dengan Express.js.</li>\r\n<li><strong>Database ORM (GORM):</strong> Interaksi dengan sistem manajemen basis data ditangani oleh <strong>GORM</strong> (Go Object Relational Mapper). GORM dipilih untuk mempercepat penulisan skema dan manipulasi data melalui pendekatan berbasis *struct*.</li>\r\n<li><strong>Driver Database:</strong> Menggunakan <code>gorm.io/driver/postgres</code> untuk menghubungkan aplikasi ke *database* utama PostgreSQL.</li>\r\n<li><strong>Message Broker &amp; Caching (Redis):</strong> Ketergantungan terhadap <code>go-redis/redis/v8</code> ditemukan. Ini menandakan Redis diimplementasikan secara aktif, kemungkinan besar untuk penyimpanan sementara (*caching*) dari *query* yang berat, token sesi, atau pembatasan kecepatan request (*rate-limiting*).</li>\r\n<li><strong>Logging Terstruktur:</strong> Log aplikasi dan aktivitas *debugging* ditangani oleh pustaka pihak ketiga ternama seperti <strong>Logrus</strong> (<code>github.com/sirupsen/logrus</code>) dan <strong>Zap</strong> (dari Uber).</li>\r\n<li><strong>gRPC (Microservices Communication):</strong> Meskipun ada REST API, terdapat pustaka <code>google.golang.org/grpc</code> dan <code>protobuf</code> yang digunakan secara ekstensif, menunjukkan bahwa antar-microservice berkomunikasi di belakang layar (*backend-to-backend*) dengan kecepatan sangat tinggi melalui gRPC.</li>\r\n</ul>\r\n<h3>2. Frontend Stack (Node.js &amp; NextJS)</h3>\r\n<p>Sisi antarmuka pengguna direpresentasikan oleh aplikasi di dalam folder <code>frontend/</code>. Lingkungan berjalannya menggunakan <strong>Node.js (v22.x)</strong>.</p>\r\n<ul>\r\n<li><strong>Core Framework (NextJS):</strong> Menggunakan NextJS versi 14+ dengan implementasi hibrida (menggunakan direktori <code>/app</code> yang baru, meski perenderan berfokus pada mode klien - CSR).</li>\r\n<li><strong>Bahasa Penulisan (TypeScript):</strong> Keseluruhan aplikasi (100%) ditulis dalam bahasa <strong>TypeScript</strong> untuk memastikan *type-safety* (keamanan tipe data), mencegah *bug runtime*, dan meningkatkan produktivitas pengetikan kode (*IntelliSense*).</li>\r\n<li><strong>Pengaturan Paket (NPM/Turborepo):</strong> Menjalankan aplikasi dalam arsitektur Monorepo menggunakan <strong>Turborepo</strong> (<code>turbo.json</code>). Manajemen dependensi dilakukan menggunakan manajer paket standar NPM.</li>\r\n<li><strong>Manajemen Keadaan (Redux Toolkit):</strong> Status aplikasi global dipertahankan oleh pustaka ekosistem <code>@reduxjs/toolkit</code>.</li>\r\n<li><strong>Pengaturan UI (Tailwind CSS):</strong> Gaya visual dan CSS dibuat sangat efisien menggunakan <strong>Tailwind CSS</strong>, dibantu dengan PostCSS dan Autoprefixer untuk kompabilitas antar peramban.</li>\r\n<li><strong>Pustaka Komponen (Ant Design / MUI):</strong> Selain *styling* manual dengan Tailwind, kemungkinan besar komponen antarmuka juga menggunakan pustaka pihak ketiga yang kaya fitur untuk mempercepat pembuatan tabel atau *form*.</li>\r\n</ul>\r\n<h3>3. Dependensi Infrastruktur</h3>\r\n<ul>\r\n<li><strong>Kontainer (Docker):</strong> Menjadi standar peluncuran seluruh layanan.</li>\r\n<li><strong>Continuous Integration (GitLab CI):</strong> Menggunakan <code>.gitlab-ci.yml</code> untuk automasi pembangunan paket dan peluncuran (Deployment).</li>\r\n</ul>', '1', '2', '99', '2026-07-14 04:06:16', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('77', '24', 'Panduan Gaya Penulisan Kode (Coding Standards)', '3-panduan-gaya-penulisan-kode-coding-standards', '<p>Dokumen ini merangkum konvensi atau standar aturan penulisan kode (*Coding Standards*) yang diterapkan oleh tim pengembang dalam proyek ALAZHARAPPS.</p>\r\n<h3>1. Standar Penulisan Golang (Backend)</h3>\r\n<p>Dalam ekosistem *backend*, pengembang mengikuti aturan dan konvensi *idiomatic* dari bahasa Go yang sangat ketat.</p>\r\n<ul>\r\n<li><strong>Gaya Penamaan Variabel (Naming Convention):</strong> Seluruh penamaan menggunakan standar <code>camelCase</code> (contoh: <code>userId</code>, <code>fetchData()</code>). Penamaan konstanta menggunakan <code>UPPER_SNAKE_CASE</code> (contoh: <code>MAX_RETRY_COUNT</code>).</li>\r\n<li><strong>Penamaan *Struct* &amp; *Interface*:</strong> Menggunakan <code>PascalCase</code>, dengan aturan bahwa jika huruf pertamanya kapital (contoh: <code>type UserRepository interface</code>), maka entitas tersebut akan diekspor (*public*). Jika huruf kecil, ia disembunyikan dalam *package* lokal (*private*).</li>\r\n<li><strong>Penamaan File:</strong> Secara universal menggunakan <code>snake_case.go</code> (contoh: <code>user_repository.go</code>, <code>auth_handler.go</code>). Tidak boleh ada spasi atau tanda hubung.</li>\r\n<li><strong>Manajemen Kesalahan (Error Handling):</strong> Menggunakan praktik standar Go yaitu mengembalikan *error* sebagai nilai balik kedua (<code>val, err := function()</code>). Terlihat juga penggunaan *custom error struct* untuk menstandarisasi respons API jika terjadi kegagalan (misalnya me-return *JSON Message: Internal Server Error*).</li>\r\n<li><strong>Komentar (Docstrings):</strong> Setiap fungsi *public* atau entitas yang diekspor idealnya didahului dengan komentar penjelasan teknis yang sesuai dengan standar GoDoc, meskipun implementasinya belum merata di seluruh kode.</li>\r\n</ul>\r\n<h3>2. Standar Penulisan TypeScript &amp; React (Frontend)</h3>\r\n<p>Sisi klien (frontend) memiliki sistem penegakan standar kode yang lebih otomatis dibandingkan backend, mengingat tim menggunakan Node.js.</p>\r\n<ul>\r\n<li><strong>Otomatisasi Linter (ESLint):</strong> Proyek menggunakan <code>eslint.config.mjs</code> untuk menertibkan aturan penulisan di seluruh monorepo. ESLint dikonfigurasi untuk mencegah pemanggilan variabel yang tidak terpakai (no-unused-vars) dan memberikan peringatan keras terhadap penulisan tipe <code>any</code> di dalam Typescript (karena berisiko merusak type-safety).</li>\r\n<li><strong>Pembentukan Komponen (React Components):</strong> Menggunakan pendekatan <em>Functional Components</em> modern dengan <em>React Hooks</em>. Penamaan file komponen antarmuka harus selalu menggunakan huruf kapital <code>PascalCase.tsx</code> (contoh: <code>Sidebar.tsx</code>, <code>ExamCard.tsx</code>), sedangkan penamaan fungsi internal atau utilitas (helpers) menggunakan <code>camelCase.ts</code>.</li>\r\n<li><strong>Pemisahan Modul (Modularity):</strong> Komponen dipecah berdasarkan ukuran hierarkinya menjadi kecil-kecil, tidak boleh ada satu file yang membengkak melebihi seribu baris. Ini menjaga efisiensi proses perenderan React saat DOM dimanipulasi.</li>\r\n<li><strong>Arahan Kompilator:</strong> Sering ditemukannya arahan eksplisit <code>"use client"</code> di awal deklarasi file halaman NextJS (*App Router*) yang menandakan pengembang dengan teliti memastikan bagian mana yang di-render di *client* dan bagian mana yang *server-side*.</li>\r\n</ul>\r\n<h3>3. Standar Pengelolaan Repositori Git</h3>\r\n<p>Kedua proyek (baik backend maupun frontend) menunjukkan kedewasaan alur kerja *version control*.</p>\r\n<ul>\r\n<li><strong>Pola *Git Branching*:</strong> Menerapkan konsep umum seperti <em>GitFlow</em> atau <em>Trunk-based development</em>, yang terbukti dengan adanya beberapa cabang referensi pada *pull history* (seperti branch <code>master</code>, <code>develop</code>, <code>hotfix</code>, dan bahkan cabang nama personal dari pembuat kodenya, contoh <code>rahmat</code>).</li>\r\n<li><strong>Commit Message:</strong> Tim infrastruktur cenderung memisahkan pembaruan spesifik di luar *master* sebelum siap diuji dan digabung (*merge*).</li>\r\n</ul>', '1', '2', '100', '2026-07-14 04:06:16', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('78', '24', 'Skema Database & Entitas Tabel Berdasarkan Migrasi', '4-skema-database-entitas-tabel-berdasarkan-migrasi', '<p>Dokumen ini memetakan desain fisik dari pangkalan data (database) yang digunakan oleh aplikasi ALAZHARAPPS, khususnya pola pemisahan data pada arsitektur <em>microservices</em>.</p>\r\n<h3>1. Pola Database per Layanan (Database-per-Service)</h3>\r\n<p>ALAZHARAPPS menerapkan pola desain terdistribusi di mana setiap <em>microservice</em> memiliki skema atau basis datanya sendiri. Hal ini ditunjukkan oleh konfigurasi di masing-masing repositori:</p>\r\n<ul>\r\n<li><strong>Isolasi Data:</strong> Layanan <code>account-service</code> hanya memiliki akses ke tabel yang berkaitan dengan pengguna dan kredensial (misalnya <code>users</code>, <code>roles</code>, <code>permissions</code>). Layanan <code>student-service</code> memegang tabel <code>students</code>, <code>parents</code>, dan <code>enrollments</code>.</li>\r\n<li><strong>Tidak Ada JOIN Lintas Layanan:</strong> Karena data terpisah, tidak mungkin melakukan *SQL JOIN* langsung antara tabel *User* dan tabel *Student*. Sebagai gantinya, layanan-layanan ini berkomunikasi lewat API (gRPC/REST) untuk menggabungkan data (*Data Composition*).</li>\r\n</ul>\r\n<h3>2. Entitas Utama dan Migrasi (Migrations)</h3>\r\n<p>Skema tabel dikelola menggunakan mekanisme migrasi (migration) bawaan dari GORM (AutoMigrate) atau alat pihak ketiga seperti Golang Migrate (berdasarkan file <code>.sql</code> di dalam direktori <code>infrastructure/postgres/migrations</code>).</p>\r\n<ul>\r\n<li><strong>Tabel Pengguna (<code>users</code>):</strong> Berisi kolom standar keamanan (<code>id</code>, <code>email</code>, <code>password_hash</code>). Terlihat penggunaan UUID (Universal Unique Identifier) pada <em>Primary Key</em> sebagai standar keamanan, alih-alih integer *Auto Increment*, untuk mencegah *ID Enumeration Attack*.</li>\r\n<li><strong>Tabel Relasional:</strong> Penggunaan *Foreign Key* diatur ketat (dengan klausa <code>ON DELETE CASCADE</code> atau <code>SET NULL</code>) untuk menjaga konsistensi data (*Referential Integrity*).</li>\r\n<li><strong>Kolom Pelacakan Audit (Audit Trails):</strong> Hampir setiap tabel penting memiliki kolom <code>created_at</code>, <code>updated_at</code>, <code>deleted_at</code> (mendukung <em>Soft Deletes</em>), dan <code>created_by</code>. Hal ini sangat penting untuk aplikasi pendidikan guna melacak siapa operator atau admin yang mengubah data nilai atau mutasi.</li>\r\n</ul>\r\n<h3>3. Optimasi Skema (Indeks)</h3>\r\n<p>Berdasarkan model data (<em>structs</em> di Golang), terlihat penggunaan *tag* khusus (seperti <code>gorm:"index"</code>) pada kolom-kolom yang sering dicari, seperti <code>email</code>, <code>nisn</code>, atau <code>school_id</code>. Pengindeksan ini sangat krusial untuk mencegah penurunan performa saat tabel siswa atau transaksi mencapai jutaan baris.</p>', '1', '2', '30', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('79', '24', 'Analisis Query Kritis & Logika Database', '5-analisis-query-kritis-logika-database', '<p>Dokumen ini mengkaji bagaimana lapisan akses data (Data Access Layer) dikelola di dalam ALAZHARAPPS, mengidentifikasi tingkat efisiensi kueri ke basis data.</p>\r\n<h3>1. Pendekatan Akses Data (ORM vs Raw Query)</h3>\r\n<p>Kode sumber Golang menunjukkan penggunaan <strong>GORM (Go Object Relational Mapper)</strong> sebagai perantara utama antara aplikasi dan basis data PostgreSQL. Namun, pengembang juga menunjukkan fleksibilitas dengan mengimplementasikan kueri SQL murni (Raw SQL) untuk fungsi-fungsi tertentu.</p>\r\n<ul>\r\n<li><strong>CRUD Dasar:</strong> Operasi standar seperti membuat pengguna, memperbarui data siswa, atau mengambil detail berdasarkan ID sepenuhnya mengandalkan metode bawaan GORM (<code>db.Create()</code>, <code>db.Where(...).First()</code>). Ini mempercepat pengembangan dan menjaga kode tetap rapi.</li>\r\n<li><strong>Query Kompleks (Raw SQL):</strong> Pada modul pelaporan (<code>report-service</code>) dan rekapitulasi nilai (<code>etl</code>), kueri GORM dihindari demi performa. Pengembang menggunakan <code>db.Raw("SELECT ... JOIN ... GROUP BY ...").Scan(&amp;results)</code>. Ini adalah langkah optimasi yang sangat tepat, karena ORM seringkali menghasilkan kueri yang lambat dan memakan banyak memori ketika menangani jutaan baris (Big Data) atau operasi agregasi.</li>\r\n</ul>\r\n<h3>2. Manajamen Transaksi (Database Transactions)</h3>\r\n<p>Dalam sistem yang menangani pembayaran atau perubahan massal (seperti <code>transaction-service</code> dan <code>school-service-new</code>), menjaga keutuhan data adalah syarat mutlak.</p>\r\n<ul>\r\n<li>Kode aplikasi menerapkan fungsi transaksi lokal GORM secara eksplisit: <code>tx := db.Begin()</code>, diikuti operasi data, dan diakhiri dengan <code>tx.Commit()</code> atau <code>tx.Rollback()</code> jika terjadi galat (error).</li>\r\n<li><strong>Area Kritis:</strong> Pada logika pembayaran (Payment Gateway callback), transaksi database ini menjamin bahwa saldo pengguna, status tagihan (invoice), dan jurnal akuntansi selalu diperbarui bersamaan. Jika salah satu gagal (misal server tiba-tiba mati di tengah jalan), maka semua perubahan dibatalkan, mencegah masalah uang melayang (Inconsistent State).</li>\r\n</ul>\r\n<h3>3. Kerentanan Query (N+1 Problem)</h3>\r\n<p>Salah satu kelemahan terbesar ORM adalah masalah *N+1 Query*, di mana aplikasi menembak kueri ke database berulang kali di dalam sebuah iterasi (loop).</p>\r\n<p><strong>[TIP] Temuan &amp; Rekomendasi:</strong> Tim ALAZHARAPPS telah memitigasi sebagian masalah ini dengan menggunakan fitur <code>Preload()</code> pada GORM untuk melakukan *Eager Loading* relasi. Walaupun begitu, disarankan untuk tetap menggunakan fitur *monitoring* database secara berkala (seperti PostgreSQL <code>pg_stat_statements</code>) untuk mendeteksi apabila ada kueri tersembunyi yang berjalan di dalam perulangan (*loop*) <em>usecase</em>.</p>', '1', '2', '29', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('80', '24', 'Strategi Manajemen Data (Backup & Archiving)', '6-strategi-manajemen-data-backup-archiving', '<p>Dokumen ini membahas strategi pengelolaan, pencadangan (backup), dan pengarsipan data di ALAZHARAPPS.</p>\r\n<h3>1. Strategi Retensi Data Terstruktur (Soft Deletes)</h3>\r\n<p>ALAZHARAPPS secara default mengimplementasikan prinsip perlindungan data maksimal di level kode aplikasi:</p>\r\n<ul>\r\n<li>Tidak ada penghapusan data secara fisik (Hard Delete) pada tabel-tabel utama (seperti siswa, guru, tagihan, atau nilai).</li>\r\n<li>GORM dikonfigurasi untuk menggunakan fitur <em>Soft Delete</em>, di mana setiap pemanggilan fungsi Hapus (<code>db.Delete()</code>) tidak akan menjalankan kueri <code>DELETE FROM</code>, melainkan mengubah kuerinya menjadi <code>UPDATE table SET deleted_at = NOW()</code>.</li>\r\n<li><strong>Manfaat:</strong> Hal ini sangat vital di industri pendidikan untuk menghindari hilangnya jejak akademis atau keuangan akibat kecerobohan pengguna, sekaligus memungkinkan pemulihan (restore) instan langsung dari panel admin (jika fitur tersebut diaktifkan).</li>\r\n</ul>\r\n<h3>2. Pencadangan Basis Data (Database Backups)</h3>\r\n<p>Karena arsitektur database mengikuti pola *Microservices* (banyak instance/skema yang terpisah per layanan), pencadangan tidak bisa mengandalkan satu skrip statis sederhana.</p>\r\n<p><strong>Rekomendasi Arsitektural:</strong></p>\r\n<ol>\r\n<li><strong>Infrastruktur Level:</strong> Back-up tidak didefinisikan di dalam baris kode Golang, melainkan harus ditangani di tingkat *Cloud Provider* atau kontainer pangkalan data (menggunakan alat seperti <code>pg_dumpall</code>) secara terjadwal (Cronjob).</li>\r\n<li><strong>Penyimpanan Dingin (Cold Storage):</strong> Hasil dump database harian idealnya dikompresi dan dikirim ke server penyimpanan pihak ketiga yang murah (seperti AWS S3 Glacier atau Backblaze B2) untuk mencegah kehilangan total (Data Loss) apabila data center utama terbakar atau diretas *ransomware*.</li>\r\n</ol>\r\n<h3>3. Pengarsipan Data (Data Archiving)</h3>\r\n<p>Data aktivitas siswa dan LMS biasanya tumbuh secara eksponensial (membengkak dari hitungan MegaByte menjadi GigaByte dalam hitungan bulan akibat file ujian dan laporan).</p>\r\n<p><strong>[IMPORTANT] Strategi yang Disarankan:</strong> Tim ALAZHARAPPS telah memisahkan layanan rekap historis ke dalam modul <code>etl</code> (Extract, Transform, Load) dan <code>report-service</code>. Disarankan agar sistem memiliki logika otomasi (bisa berbasis <em>cron scheduler</em> di Golang) untuk memindahkan data pendaftaran siswa atau nilai ujian yang sudah berumur lebih dari 5 tahun ajaran ke tabel terpisah (Tabel Arsip) atau ke *Data Warehouse* analitik, agar database operasional utama tetap ramping, cepat, dan ringan.</p>', '1', '2', '28', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('81', '24', 'Informasi Koneksi & Kredensial Staging', '7-informasi-koneksi-kredensial-staging', '<p>Dokumen ini memetakan arsitektur koneksi dan integrasi pihak ketiga pada lingkungan pengujian (Staging) ALAZHARAPPS.</p>\r\n<h3>1. Topologi Jaringan Staging</h3>\r\n<p>Lingkungan *Staging* (biasanya diakses melalui <code>dev-api.alazhar.or.id</code> atau <code>staging.alazhar.or.id</code>) dikonfigurasi menyerupai lingkungan *Production*, namun menggunakan replika data berskala kecil.</p>\r\n<ul>\r\n<li><strong>Gateway API:</strong> Semua *traffic* dari aplikasi *Frontend* masuk melalui satu titik *Reverse Proxy* (seperti Nginx atau Traefik) yang akan mendistribusikan *request* ke layanan yang tepat berdasarkan *path* (contoh: <code>/api/v1/users</code> diteruskan ke <code>account-service:8080</code>).</li>\r\n<li><strong>Komunikasi Internal:</strong> Layanan-layanan di belakang *firewall* (misalnya <code>student-service</code> ingin mengecek data tagihan di <code>transaction-service</code>) tidak menggunakan internet publik, melainkan terhubung langsung lewat alamat IP lokal kontainer (menggunakan protokol gRPC pada port <code>9090</code>).</li>\r\n</ul>\r\n<h3>2. Kredensial Pihak Ketiga (Third-Party Integrations)</h3>\r\n<p>Pada lingkungan *Staging*, seluruh interaksi ke sistem eksternal wajib diarahkan ke mode *Sandbox* atau *Testing* untuk mencegah terjadinya mutasi data finansial yang sebenarnya:</p>\r\n<ol>\r\n<li><strong>Payment Gateway (Midtrans/Xendit):</strong> Menggunakan kunci API (API Key) versi *Sandbox*. Kartu kredit atau *Virtual Account* yang digunakan untuk menguji pembayaran sumbangan sekolah adalah data fiktif.</li>\r\n<li><strong>OTP &amp; Notifikasi (Fonnte/Qontak/Sengrid):</strong> Pengiriman WhatsApp atau Email pada lingkungan staging biasanya dibatasi hanya ke daftar nomor staf IT yang terdaftar (Whitelist) untuk mencegah siswa atau orang tua asli menerima tagihan *dummy*.</li>\r\n<li><strong>Penyimpanan Berkas (AWS S3 / MinIO):</strong> Berkas yang diunggah (seperti foto profil atau tugas) tidak disimpan di *bucket* *Production*, melainkan di *bucket* *Staging* khusus yang diatur agar otomatis terhapus (auto-purge) setiap 30 hari guna menghemat biaya.</li>\r\n</ol>', '1', '2', '27', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('82', '24', 'Panduan Setup Lingkungan & Build Aplikasi', '8-panduan-setup-lingkungan-build-aplikasi', '<p>Dokumen ini menyediakan tata cara (guideline) standar untuk membangun dan menjalankan seluruh layanan aplikasi ALAZHARAPPS secara lokal di mesin pengembang (Developer Machine).</p>\r\n<h3>1. Persyaratan Sistem Lokal (Prerequisites)</h3>\r\n<p>Sebelum mengompilasi kode, mesin pengembang wajib memiliki peranti lunak berikut:</p>\r\n<ul>\r\n<li><strong>Golang (v1.20+)</strong>: Untuk melakukan kompilasi dan menjalankan *microservices* backend.</li>\r\n<li><strong>Node.js (v22+) &amp; NPM/PNPM</strong>: Untuk menjalankan *environment* Frontend (NextJS) dan ekosistem Turborepo.</li>\r\n<li><strong>Docker &amp; Docker Compose</strong>: Digunakan secara ekstensif untuk menjalankan layanan infrastruktur pendukung lokal (seperti PostgreSQL, Redis, dan simulasi Kafka/RabbitMQ) tanpa harus menginstalnya ke dalam OS utama pengembang.</li>\r\n<li><strong>Git</strong>: Untuk sinkronisasi versi dan integrasi dengan GitLab.</li>\r\n</ul>\r\n<h3>2. Panduan Eksekusi Backend (Golang)</h3>\r\n<p>Karena arsitekturnya terpisah menjadi lebih dari 8 *repository* (seperti `account-service`, `student-service`), pengembang lokal tidak perlu menjalankan semuanya sekaligus kecuali sedang menguji fitur lintas-layanan.</p>\r\n<ol>\r\n<li>Siapkan file konfigurasi: Salin <code>.env.example</code> menjadi <code>.env</code> di *root* folder layanan terkait.</li>\r\n<li>Nyalakan *database* lokal via Docker: <code>docker-compose up -d postgres redis</code> (jika tersedia di repo infrastruktur).</li>\r\n<li>Unduh modul dependensi Go: <code>go mod tidy</code></li>\r\n<li>Jalankan server: <code>go run cmd/main.go</code> (atau lokasi file utama yang memuat fungsi <code>main()</code>).</li>\r\n<li><em>(Opsional)</em> Jika ada pembaruan *Proto buffers* (gRPC), pengembang harus menginstal <code>protoc</code> dan menjalankan *script generate* sebelum *build*.</li>\r\n</ol>\r\n<h3>3. Panduan Eksekusi Frontend (NextJS Turborepo)</h3>\r\n<p>Aplikasi Frontend disatukan dalam sebuah monorepo, yang mempermudah proses inisialisasi:</p>\r\n<ol>\r\n<li>Masuk ke folder utama <code>frontend/</code>.</li>\r\n<li>Instal seluruh dependensi: <code>npm install</code> atau <code>npm ci</code>. Turborepo akan otomatis menautkan paket lokal (<em>hoisting</em>) dari <code>packages/</code> ke <code>apps/</code>.</li>\r\n<li>Pastikan file variabel lingkungan <code>.env.development</code> sudah terisi dengan alamat API lokal (contoh: <code>NEXT_PUBLIC_API_URL=http://localhost:8080/api/v1</code>).</li>\r\n<li>Jalankan server pengembangan: <code>npm run dev</code>. Turborepo akan memicu proses *watch* pada komponen dan menampilkan UI di <code>http://localhost:3000</code>.</li>\r\n</ol>', '1', '2', '26', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('83', '24', 'Analisis Otomatisasi Deployment (CI/CD Pipeline)', '9-analisis-otomatisasi-deployment-cicd-pipeline', '<p>Dokumen ini menyajikan analisis teknis mengenai alur otomatisasi *Deployment* atau siklus rilis piranti lunak (CI/CD Pipeline) di ALAZHARAPPS yang menggunakan GitLab CI.</p>\r\n<h3>1. Pendekatan IaC (Infrastructure as Code)</h3>\r\n<p>Alih-alih menulis ulang puluhan baris konfigurasi pipa (pipeline) di masing-masing direktori *microservice*, tim merancang repositori terpusat khusus untuk infrastruktur bernama <code>al-azhar-iac</code>.</p>\r\n<ul>\r\n<li>Semua file <code>.gitlab-ci.yml</code> di repositori layanan hanya berisi fungsi pemanggilan tunggal (<em>include</em>) yang menunjuk pada rujukan (<em>template</em>) di dalam repo IaC tersebut.</li>\r\n<li><strong>Keuntungan Tingkat Tinggi:</strong> Jika di masa depan tim DevOps ingin mengubah server tujuan (misalnya beralih dari AWS ke GCP) atau mengubah standar pengujian (SonarQube), mereka hanya perlu mengedit satu file *template* di repo IaC, dan otomatis 12 repositori aplikasi yang bergantung padanya akan menggunakan alur rilis yang baru tanpa sentuhan manual (*Zero-touch configuration update*).</li>\r\n</ul>\r\n<h3>2. Fase Pipeline (Pipeline Stages)</h3>\r\n<p>Berdasarkan praktik terbaik yang terlihat pada konfigurasi *Docker multi-stage*, CI/CD kemungkinan besar beroperasi melalui tahapan berikut ketika pengembang melakukan <code>git push</code> ke cabang utama (<em>main/master</em>):</p>\r\n<ol>\r\n<li><strong>Tahap LINT &amp; TEST:</strong> GitLab Runner mengeksekusi linter kode (seperti <code>golangci-lint</code> atau <code>eslint</code>) dan menjalankan <em>Unit Test</em>. Jika ada galat atau kode tidak memenuhi standar, proses rilis digagalkan saat itu juga (*Fail-fast*).</li>\r\n<li><strong>Tahap BUILD:</strong> GitLab merakit kode menjadi *Image Docker* murni. Seperti yang diketahui, ukuran *image backend* ditekan hingga belasan Megabyte (berkat OS Scratch) dan ukuran frontend dikompresi lewat modus *Standalone* NextJS.</li>\r\n<li><strong>Tahap PUSH REGISTRY:</strong> Hasil *image* diunggah (di-*push*) ke layanan *Private Docker Registry* milik YPIA (<code>registry.ypia-cloud.id</code>). GitLab akan memberi tag unik (berbasis *commit hash* atau *semantic versioning* seperti <code>v1.2.3</code>).</li>\r\n<li><strong>Tahap DEPLOY:</strong> Skrip GitLab mengakses *Server Production* (biasanya via agen SSH atau konfigurasi Kubernetes/Kustomize) untuk menarik (*pull*) image terbaru tadi, mematikan kontainer lama, dan menghidupkan versi baru tanpa *downtime* signifikan.</li>\r\n</ol>', '1', '2', '25', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('84', '24', 'Dokumentasi Konfigurasi Server & Variabel Lingkungan', '10-dokumentasi-konfigurasi-server-variabel-lingkungan', '<p>Dokumen ini mendokumentasikan pemetaan Variabel Lingkungan (Environment Variables) yang menjadi urat nadi konfigurasi dinamis seluruh <em>microservices</em> ALAZHARAPPS tanpa perlu mengubah (hardcode) kode sumber.</p>\r\n<h3>1. Backend Environment (.env)</h3>\r\n<p>Setiap repositori Golang (contohnya <code>account-service</code>) dikendalikan oleh puluhan variabel yang membedakan profil peluncurannya (Development, Staging, Production). Parameter kuncinya meliputi:</p>\r\n<ul>\r\n<li><strong>Aplikasi (App Info):</strong> <code>APP_ENV=production</code>, <code>APP_PORT=8080</code> (Port *binding* untuk GoFiber), dan <code>GRPC_PORT=9090</code>.</li>\r\n<li><strong>Koneksi Database:</strong> <code>DB_HOST</code>, <code>DB_PORT</code>, <code>DB_USER</code>, <code>DB_PASSWORD</code>, <code>DB_NAME</code>, beserta parameter batas koneksi (<code>DB_MAX_IDLE_CONNS</code>, <code>DB_MAX_OPEN_CONNS</code>) untuk mencegah kebocoran koneksi.</li>\r\n<li><strong>Redis Caching:</strong> <code>REDIS_HOST</code>, <code>REDIS_PORT</code>, dan <code>REDIS_PASSWORD</code>.</li>\r\n<li><strong>Keamanan &amp; Autentikasi:</strong> <code>JWT_SECRET</code> (Sangat Rahasia! Kunci untuk memvalidasi token sesi) dan <code>JWT_EXPIRATION</code> (Durasi aktifnya token sebelum pengguna harus <em>login</em> ulang).</li>\r\n<li><strong>Koneksi Antar-Layanan (Service Discovery):</strong> <code>STUDENT_SERVICE_GRPC_URL</code>, <code>TRANSACTION_SERVICE_GRPC_URL</code> (Alamat internal agar servis bisa saling bertukar data).</li>\r\n</ul>\r\n<h3>2. Frontend Environment</h3>\r\n<p>Di antarmuka NextJS, *environment variable* tidak semuanya dikirim ke peramban klien. Sesuai standar NextJS, hanya variabel dengan awalan tertentu yang diekspos secara publik.</p>\r\n<ul>\r\n<li><strong>Eksplisit Publik (NEXT_PUBLIC_*):</strong> Variabel seperti <code>NEXT_PUBLIC_API_URL</code> atau <code>NEXT_PUBLIC_APP_NAME</code> wajib diatur, karena kode di dalam peramban (CSR) membutuhkannya untuk menembak API *backend*.</li>\r\n<li><strong>Server-side Secrets:</strong> Variabel tanpa awalan *NEXT_PUBLIC* (seperti <code>ENCRYPTION_KEY</code> lokal) hanya hidup di level server Node.js dan terjamin kerahasiaannya.</li>\r\n</ul>\r\n<h3>3. Manajemen Konfigurasi (Best Practices)</h3>\r\n<p><strong>[TIP] Temuan Audit Konfigurasi:</strong></p>\r\n<p>Praktik yang diterapkan oleh ALAZHARAPPS sudah baik karena tidak melakukan *commit* file <code>.env</code> ke repositori Git (hanya menyertakan <code>.env.example</code>). Pada lingkungan *Production*, nilai-nilai asli dari variabel ini disuntikkan secara dinamis saat proses rilis (Deployment) berjalan, seringkali menggunakan <em>GitLab CI/CD Variables</em> atau <em>Kubernetes Secrets</em> untuk menyembunyikan kata sandi database dari staf non-Sistem Administrator.</p>', '1', '2', '24', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('85', '24', 'Dokumentasi API (Endpoint Summary)', '11-dokumentasi-api-endpoint-summary', '<p>Dokumen ini meringkas arsitektur titik temu (Endpoint) API yang bertindak sebagai jembatan komunikasi antara klien (Frontend/Mobile) dan pelayan (Backend) di ekosistem ALAZHARAPPS.</p>\r\n<h3>1. Pendekatan RESTful API</h3>\r\n<p>Komunikasi keluar (External Communication) dari klien ke backend dilayani menggunakan arsitektur REST (Representational State Transfer) murni dengan muatan data berupa JSON. Pola pengalamatannya diatur secara rapi berdasarkan versi (Versioning) di dalam direktori <code>infrastructure/rest/routes</code>.</p>\r\n<ul>\r\n<li><strong>Rute Autentikasi Publik:</strong> <code>POST /api/v1/auth/login</code>, <code>POST /api/v1/auth/otp/request</code>. Endpoint ini umumnya tidak membutuhkan token JWT karena di sinilah siklus login bermula.</li>\r\n<li><strong>Rute Terproteksi (Protected Routes):</strong> Semua endpoint dengan awalan fitur inti seperti <code>/api/v1/users/*</code>, <code>/api/v1/students/*</code>, atau <code>/api/v1/transactions/*</code> dibungkus oleh sebuah *Middleware* JWT. Jika *Request* dari frontend tidak menyertakan *Header Authorization: Bearer [Token]*, maka API akan menolaknya dengan pesan galat <em>401 Unauthorized</em>.</li>\r\n<li><strong>Struktur Respons Standar:</strong> Pengembang backend menggunakan pembungkus JSON standar agar frontend mudah mengurainya, contohnya: <code>{ "meta": { "code": 200, "message": "Success" }, "data": { ... } }</code>. Ini sesuai dengan *Coding Standards* untuk respons REST API modern.</li>\r\n</ul>\r\n<h3>2. Dokumentasi Otomatis (Swagger / OpenAPI)</h3>\r\n<p>Dalam proyek terdistribusi yang besar (lebih dari 10 servis), dokumentasi manual melalui *file teks* sangat berisiko kedaluwarsa. Oleh karenanya, pengembang backend ALAZHARAPPS menerapkan anotasi (komentar) langsung di atas *handler* fungsi GoFiber.</p>\r\n<ul>\r\n<li>Anotasi ini (contoh: <code>// @Summary Get User List</code>) dibaca oleh pustaka seperti <code>swaggo/swag</code> saat kompilasi.</li>\r\n<li>Hasilnya, sistem secara otomatis menghasilkan berkas <code>swagger.json</code> dan merender antarmuka UI interaktif yang biasanya dapat diakses di rute <code>/api/v1/docs/index.html</code> (jika rute Swagger tidak dimatikan pada *production*).</li>\r\n</ul>\r\n<h3>3. Komunikasi Internal (gRPC Protocol)</h3>\r\n<p>Walaupun Klien menggunakan REST, antar-servis backend (Internal Communication) berbicara satu sama lain menggunakan gRPC.</p>\r\n<ul>\r\n<li>Protokol RPC (Remote Procedure Call) ini menggunakan skema biner (Protobuf) yang sangat ringan dan berkali-kali lipat lebih cepat daripada REST JSON.</li>\r\n<li>Sebagai contoh, saat <code>transaction-service</code> ingin mendapatkan nama lengkap siswa, ia tidak memanggil <em>REST API</em> milik <code>student-service</code>, melainkan menggunakan klien gRPC internal melalui porta 9090. Hal ini secara drastis menekan latensi aplikasi (*response time*) pada saat trafik sedang tinggi.</li>\r\n</ul>', '1', '2', '23', '2026-07-14 04:06:16', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('86', '29', 'Alur Logika Bisnis Inti (Siklus Finansial & PPDB)', '12-alur-logika-bisnis-inti-siklus-finansial-ppdb', '<p>Dokumen ini memetakan Alur Logika Bisnis Inti (Core Business Workflows) pada aplikasi ALAZHARAPPS, dengan fokus pada modul finansial (Fintech) pendidikan, yaitu siklus pembayaran SPP dan pendaftaran murid baru (PPDB).</p>\r\n<h3>1. Siklus Pembayaran SPP (Billing &amp; Payment Gateway)</h3>\r\n<p>Proses ini melibatkan interaksi intensif antara Frontend, <code>transaction-service</code>, dan pihak ketiga (Payment Gateway).</p>\r\n<ol>\r\n<li><strong>Pembuatan Tagihan (Invoicing):</strong> Setiap awal bulan, sistem (melalui *cron job* atau *event-driven scheduler* di backend) secara massal menghasilkan tagihan (invoice) SPP untuk seluruh siswa aktif berdasarkan jenjang kelas dan kebijakan yayasan (ditarik dari <code>school-service-new</code>).</li>\r\n<li><strong>Akses Tagihan oleh Orang Tua:</strong> Orang tua login via aplikasi *Mobile* atau portal Web, menembak endpoint <code>GET /api/v1/transactions/bills</code>. Kueri ini akan menampilkan daftar tagihan tertunda (Unpaid).</li>\r\n<li><strong>Inisiasi Pembayaran:</strong> Saat orang tua mengklik "Bayar", frontend mengirim instruksi ke <code>transaction-service</code>. Servis ini kemudian berkomunikasi dengan Payment Gateway (seperti Midtrans/Xendit) via API HTTP untuk membuat <em>Virtual Account (VA)</em> atau tautan pembayaran dompet digital (e-Wallet).</li>\r\n<li><strong>Callback (WebHook) Payment Gateway:</strong> Setelah orang tua mentransfer dana via ATM/M-Banking, Payment Gateway akan memanggil rute *callback* publik di ALAZHARAPPS (misal: <code>POST /api/v1/payments/webhook</code>). <br><em>*Catatan Kritis: Di titik inilah transaksi *Database* berjalan ketat. Sistem akan memverifikasi *Signature Key* dari webhook untuk mencegah pemalsuan pembayaran.</em></li>\r\n<li><strong>Pencatatan Jurnal Otomatis:</strong> Setelah tervalidasi, <code>transaction-service</code> mengubah status tagihan menjadi "Lunas", lalu secara asinkron memicu pembentukan entri jurnal akuntansi (Buku Besar) yang mendebit Kas dan mengkredit Pendapatan SPP. Notifikasi lunas kemudian dikirim ke WhatsApp/Email orang tua via layanan terintegrasi (seperti Fonnte).</li>\r\n</ol>\r\n<h3>2. Proses Pendaftaran Murid Baru (PPDB)</h3>\r\n<p>Proses PPDB (Penerimaan Peserta Didik Baru) merupakan gerbang awal masuknya data ke dalam <code>student-service</code>.</p>\r\n<ol>\r\n<li><strong>Pendaftaran Akun Awal:</strong> Calon orang tua mengakses situs <code>landing-page</code> dan membuat akun dasar (hanya email dan telepon). Data ini masuk ke <code>account-service</code> dengan *role* khusus (misal: <code>prospective_parent</code>).</li>\r\n<li><strong>Pengisian Formulir Induk:</strong> Melalui *dashboard* PPDB, calon orang tua melengkapi formulir identitas siswa dan riwayat kesehatan. Data JSON dikirim ke <code>student-service</code>. Sistem mengizinkan penyimpanan berulang (*save as draft*) hingga formulir di-<em>submit</em> final.</li>\r\n<li><strong>Pembayaran Formulir/Uang Pangkal:</strong> Mirip dengan alur SPP, modul <code>transaction-service</code> menerbitkan tagihan pendaftaran. Jika belum dibayar, orang tua tidak dapat mencetak Kartu Ujian Masuk.</li>\r\n<li><strong>Validasi &amp; Penempatan (Placement):</strong> Setelah siswa lulus tes dan melunasi Uang Pangkal, admin sekolah (melalui <code>frontend</code>) mengubah status siswa di <code>student-service</code> dari *Candidate* menjadi *Active*. Pada fase ini, Nomor Induk (NISN/NIS) di-<em>generate</em> secara unik dan siswa dimasukkan ke relasi tabel kelas pada tahun ajaran yang sedang berjalan.</li>\r\n</ol>', '1', '2', '3', '2026-07-14 04:21:55', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('87', '32', 'Matriks Otorisasi & Hak Akses Berjenjang (RBAC)', '13-matriks-otorisasi-hak-akses-berjenjang-rbac', '<p>Dokumen ini membedah arsitektur keamanan tingkat lanjut pada ALAZHARAPPS, khususnya implementasi Matriks Otorisasi dan Hak Akses Berjenjang (Role-Based Access Control / RBAC) yang membentengi ratusan endpoint API.</p>\r\n<h3>1. Arsitektur Role &amp; Permission (RBAC)</h3>\r\n<p>Karena ALAZHARAPPS digunakan oleh puluhan sekolah di bawah naungan yayasan, struktur hak aksesnya sangat kompleks (Multi-Tenant RBAC). Model data dasar di dalam <code>account-service</code> berpusat pada 3 entitas utama:</p>\r\n<ul>\r\n<li><strong>Users:</strong> Individu otentik yang melakukan *login*.</li>\r\n<li><strong>Roles (Peran):</strong> Jabatan abstrak, contoh: <code>Superadmin</code>, <code>Principal</code> (Kepala Sekolah), <code>Teacher</code>, <code>Finance</code>, <code>Student</code>, dan <code>Parent</code>.</li>\r\n<li><strong>Permissions (Hak Spesifik):</strong> Izin granular terkecil, contoh: <code>create_student</code>, <code>delete_invoice</code>, <code>view_report_card</code>.</li>\r\n</ul>\r\n<p>Sebuah <em>Role</em> akan memiliki sekumpulan <em>Permissions</em>. Pengguna (User) kemudian dihubungkan ke <em>Role</em>. Khusus untuk posisi seperti Kepala Sekolah atau Guru, <em>Role</em> mereka juga diikat ke <strong>School_ID</strong> tertentu agar seorang Kepala Sekolah TK tidak bisa melihat data transaksi unit SD.</p>\r\n<h3>2. Siklus JWT (JSON Web Token)</h3>\r\n<p>Tim pengembangan mengandalkan JWT (melalui pustaka internal <code>jwtaccess</code>) untuk mendistribusikan informasi otorisasi ke seluruh *microservices* secara *stateless* (tanpa membebani *database* untuk mengecek akses di setiap klik).</p>\r\n<ol>\r\n<li>Saat berhasil login di <code>account-service</code>, *backend* mencetak (sign) string JWT menggunakan <code>JWT_SECRET</code>.</li>\r\n<li>Di dalam JWT <em>Payload (Claims)</em>, tidak hanya disematkan <code>user_id</code>, tetapi juga disisipkan <em>array</em> dari <code>roles</code> dan <code>school_id</code> pengguna tersebut (contoh: <code>"role": "finance", "school_id": 5</code>).</li>\r\n<li>Frontend (NextJS) atau Mobile menerima token ini dan menyimpannya (idealnya di dalam <em>HttpOnly Cookie</em> untuk Web, atau <em>Secure Storage</em> untuk Mobile). Di setiap pemanggilan API (seperti mengecek data murid), token ini dilampirkan di dalam <em>Header Authorization: Bearer [TOKEN]</em>.</li>\r\n</ol>\r\n<h3>3. Mekanisme Kunci pada Golang Middleware</h3>\r\n<p>Bagaimana layanan lain (seperti <code>student-service</code>) tahu bahwa yang mengakses adalah seorang Admin Keuangan? Di sinilah peran <strong>API Middleware</strong> Golang bekerja.</p>\r\n<ul>\r\n<li>Sebelum kode program masuk ke lapisan <em>Usecase</em> (logika bisnis), *request* akan ditangkap oleh *Middleware Auth*.</li>\r\n<li>*Middleware* ini akan mengurai (parse) JWT menggunakan <code>JWT_SECRET</code> publik/bersama. Jika tanda tangannya (*signature*) valid dan belum kedaluwarsa, ia akan mengekstrak informasi <code>role</code> dari token.</li>\r\n<li>Jika *Endpoint* dideklarasikan dengan syarat <em>"Hanya bisa diakses oleh Role: Finance"</em>, maka *Middleware* akan mencocokkannya dengan isi token. Jika pengguna terdeteksi sebagai <code>Student</code>, *Middleware* langsung menendang *request* dengan kode respons <strong>403 Forbidden</strong> tanpa pernah menyentuh <em>database</em> sama sekali.</li>\r\n<li><strong>Isolasi Multi-Tenant:</strong> Pada level *Usecase*, klaim <code>school_id</code> dari JWT digunakan secara otomatis pada setiap <em>query</em> SQL (contoh: <code>WHERE school_id = ?</code>) untuk memastikan kebocoran data silang-sekolah (*Cross-Tenant Data Leakage*) mustahil terjadi.</li>\r\n</ul>', '1', '2', '91', '2026-07-14 04:21:55', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('88', '24', 'Komunikasi Asinkron antar Layanan (Inter-Service Mapping)', '14-komunikasi-asinkron-antar-layanan-inter-service-mapping', '<p>Dokumen ini memetakan diagram ketergantungan dan metode komunikasi asinkron yang terjadi antar layanan (*Microservices*) di dalam ekosistem ALAZHARAPPS dan LMSALAZHARAPPS.</p>\r\n<h3>1. Dilema Microservices: Komunikasi Lintas Layanan</h3>\r\n<p>Dalam arsitektur *monolith*, ketika tabel Tagihan butuh melihat nama Siswa, ia cukup melakukan <em>SQL JOIN</em>. Di ALAZHARAPPS, karena <code>transaction-service</code> dan <code>student-service</code> adalah dua server dengan *database* yang berbeda, mereka harus berbicara satu sama lain melalui jaringan.</p>\r\n<h3>2. Solusi 1: Pemanggilan Langsung (gRPC)</h3>\r\n<p>Kapan ini digunakan? Saat layanan butuh data <strong>secara instan (real-time)</strong> sebelum membalas *request* dari *Frontend*.</p>\r\n<ul>\r\n<li><strong>Skenario:</strong> Guru membuka halaman <em>Input Nilai</em> di <code>lms-course-service</code>. Layanan LMS ini hanya tahu <code>student_id</code>, tapi butuh Nama dan NISN untuk ditampilkan di layar.</li>\r\n<li><strong>Pelaksanaan:</strong> LMS akan bertindak sebagai *Client* gRPC yang menembak <code>student-service</code> (berjalan di port 9090). Protokol ini mengemas data dalam biner (Protobuf), sehingga pertukaran ratusan data murid terjadi hanya dalam hitungan milidetik (*low-latency*).</li>\r\n<li><strong>Manajemen Kegagalan (Circuit Breaker):</strong> Jika <code>student-service</code> tiba-tiba mati, gRPC akan mengalami <em>Timeout</em>. Agar <code>lms-course-service</code> tidak ikut macet/hang, pengembang harus menyisipkan batas tunggu (*context deadline*), misalnya maksimal 2 detik. Jika gagal, LMS bisa me-return data kosong atau *cache* terakhir.</li>\r\n</ul>\r\n<h3>3. Solusi 2: Pendekatan Asinkron (Message Broker / Event-Driven)</h3>\r\n<p>Kapan ini digunakan? Saat layanan <strong>tidak butuh menunggu balasan</strong> secara instan (proses berjalan di latar belakang / *fire-and-forget*).</p>\r\n<ul>\r\n<li><strong>Skenario:</strong> Saat orang tua berhasil melunasi SPP di <code>transaction-service</code>.</li>\r\n<li><strong>Pelaksanaan:</strong> <code>transaction-service</code> tidak memanggil API notifikasi WhatsApp sambil menyuruh orang tua menunggu halaman *loading*. Sebaliknya, ia cukup melempar pesan *"SPP Lunas untuk Siswa A"* ke dalam antrean (Redis Pub/Sub, RabbitMQ, atau Kafka).</li>\r\n<li><strong>Konsumen (Consumer):</strong> Servis lain (misalnya <code>jurnal-service</code> atau servis notifikasi) yang sedang *subscribe* ke saluran tersebut akan "mendengar" pesan itu, lalu memproses jurnal keuangannya masing-masing di latar belakang tanpa mengganggu alur aplikasi utama.</li>\r\n</ul>', '1', '2', '20', '2026-07-14 04:25:23', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('89', '24', 'Panduan Troubleshooting & Pemulihan Bencana (Disaster Recovery)', '15-panduan-troubleshooting-pemulihan-bencana-disaster-recovery', '<p>Dokumen ini menyajikan panduan praktis (Playbook) bagi tim IT/DevOps Internal untuk melakukan mitigasi, pelacakan masalah (Troubleshooting), dan pemulihan sistem (Disaster Recovery) saat krisis terjadi di ALAZHARAPPS.</p>\r\n<h3>1. Melacak Galat (Error Tracing) di Kontainer</h3>\r\n<p>Saat laporan *bug* masuk (misalnya: "Gagal memuat detail tagihan murid"), administrator harus segera meninjau rekaman (Log) dari *microservice* yang bersangkutan (dalam hal ini, <code>transaction-service</code>).</p>\r\n<ul>\r\n<li><strong>Masuk ke Server Produksi:</strong> Akses mesin via SSH (<code>ssh root@server_ip</code>).</li>\r\n<li><strong>Membaca Log Realtime:</strong> Gunakan perintah Docker: <code>docker logs -f transaction-service</code> (ganti nama kontainer sesuai yang bermasalah).</li>\r\n<li><strong>Analisis Log Berstruktur:</strong> Karena aplikasi Golang ALAZHARAPPS menggunakan pustaka *Logger* mumpuni (seperti Logrus/Zap), *error* akan muncul dalam format JSON yang bersih (contoh: <code>{"level":"error", "msg":"failed to connect to db", "time":"..."}</code>). Perhatikan pesan kunci seperti <em>Timeout</em>, <em>Connection Refused</em>, atau <em>Null Pointer</em>.</li>\r\n</ul>\r\n<h3>2. Skenario Pemulihan Bencana (Disaster Scenarios)</h3>\r\n<p>Berikut adalah beberapa insiden umum dan langkah pertolongan pertamanya (First Aid):</p>\r\n<ol>\r\n<li><strong>Layanan Tiba-Tiba Mati (Crash/OOM):</strong> Jika lonjakan pengguna (misalnya saat hari pembukaan ujian LMS) menghabiskan RAM server (Out Of Memory), kontainer mungkin mati. <br><em>Aksi:</em> Cek status kontainer <code>docker ps -a</code>. Jika statusnya *Exited (137)*, segera *restart* layanan dengan <code>docker-compose restart lms-course-service</code>, lalu pertimbangkan untuk memperbesar batas memori (*scale-up resource*) di server.</li>\r\n<li><strong>Database Terkunci (Deadlock) atau Lambat:</strong> Jika kueri terasa macet total, kemungkinan besar ada *Database Lock* atau lonjakan batas maksimal koneksi (Max Open Connections terpenuhi). <br><em>Aksi:</em> *Restart* kontainer *microservice* agar ia memutus paksa kumpulan koneksi (Connection Pool) yang menggantung. Jika tak mempan, *restart* paksa pangkalan data PostgreSQL.</li>\r\n</ol>\r\n<h3>3. Rollback (Kembali ke Versi Lama)</h3>\r\n<p>Jika masalah terjadi tepat setelah pembaruan kode (Deployment terbaru memiliki *bug* fatal), jangan panik. Tim tidak perlu membedah kode di *Production*.</p>\r\n<ul>\r\n<li>Buka *pipeline* GitLab CI/CD dari repositori yang bersangkutan.</li>\r\n<li>Cari status *pipeline Deployment* sebelumnya (yang berwarna hijau/lulus dan stabil).</li>\r\n<li>Klik tombol <strong>Rollback</strong> atau jalankan ulang (<em>Retry/Re-deploy</em>) *pipeline* versi lama tersebut. Dalam hitungan menit, *image* Docker lama akan kembali menimpa versi yang *buggy*, meredakan krisis selagi pengembang mencari solusinya di lingkungan lokal.</li>\r\n</ul>', '1', '2', '19', '2026-07-14 04:25:23', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('90', '24', 'Sinkronisasi Data Lintas Sistem (ETL & Dapodik)', '16-sinkronisasi-data-lintas-sistem-etl-dapodik', '<p>Dokumen ini mengupas repositori khusus bernama <code>etl</code> (Extract, Transform, Load) dalam sistem ALAZHARAPPS, yang berfungsi sebagai "Pekerja Keras" untuk memindahkan dan menyinkronkan data massal (*Bulk Data*).</p>\r\n<h3>1. Apa itu Modul ETL?</h3>\r\n<p>Aplikasi pendidikan modern jarang berdiri sendiri. ALAZHARAPPS tidak hanya harus menyimpan datanya sendiri, tetapi seringkali harus menyinkronkan data murid ke sistem Kementerian Pendidikan (seperti Dapodik) atau memigrasikan jutaan baris data absensi dari sistem (legacy) sekolah yang lama. Jika tugas seberat ini diproses oleh <code>student-service</code>, *server* bisa mogok melayani antarmuka web.</p>\r\n<p>Oleh karena itu, tim pengembang memisahkan tugas ini ke dalam repositori <code>etl</code>. Skrip di dalam repositori ini dirancang khusus untuk berjalan di latar belakang (Background Worker) dan didesain tahan banting dalam memproses jutaan baris data secara *streaming*.</p>\r\n<h3>2. Proses Inti ETL (Extract, Transform, Load)</h3>\r\n<ul>\r\n<li><strong>Extract (Tarik):</strong> Layanan ini terhubung ke *database* sumber (bisa berupa basis data MySQL lawas, API Dapodik, atau berkas CSV raksasa berukuran GB). Ia menarik (querying) data secara bergelombang (batch) &mdash; misal 10.000 baris per tarikan, agar RAM server tidak meluap (OOM).</li>\r\n<li><strong>Transform (Olah/Pembersihan):</strong> Data sumber biasanya "kotor". Misalnya, format tanggal lahir di sistem lama adalah <code>DD/MM/YYYY</code>, sementara ALAZHARAPPS butuh <code>YYYY-MM-DD</code>. Atau data jenis kelamin ditulis "Laki-laki", yang harus diubah menjadi <code>M</code>. Tahapan *Transform* menyapu bersih, memvalidasi, dan menyeragamkan data mentah tersebut menggunakan fungsi-fungsi Golang (*string manipulation*).</li>\r\n<li><strong>Load (Muat):</strong> Setelah data bersih dan sesuai dengan skema (struct) GORM aplikasi modern, modul ETL melakukan <em>Bulk Insert</em> atau <em>Upsert (Update if Exist)</em> ke basis data target (seperti PostgreSQL milik <code>student-service</code>).</li>\r\n</ul>\r\n<h3>3. Orkestrasi dan Penjadwalan (Scheduling)</h3>\r\n<p>Kapan modul ETL ini berjalan?</p>\r\n<ul>\r\n<li><strong>Sistem Terjadwal (Cronjob):</strong> Beberapa proses sinkronisasi (seperti menarik rekap absen mesin *fingerprint* ke dalam aplikasi rapor) berjalan otomatis tengah malam (pukul 01.00) saat *traffic* aplikasi sedang lengang.</li>\r\n<li><strong>Ekseskusi Manual (On-Demand):</strong> Kadang-kadang, admin yayasan perlu mengunggah file Excel pembagian kelas siswa. Saat tombol "Import" ditekan di aplikasi, *Frontend* mengirim tugas asinkron ke modul ETL untuk memproses file Excel tersebut. Admin bisa menutup jendela peramban, dan akan menerima notifikasi jika unggahan selesai.</li>\r\n</ul>', '1', '2', '18', '2026-07-14 04:25:23', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('91', '24', 'Bedah Arsitektur Ekosistem LMS', '1-bedah-arsitektur-ekosistem-lms', '<p>Dokumen ini membedah arsitektur dan pola integrasi dari sistem manajemen pembelajaran (LMSALAZHARAPPS), yang merupakan subsistem vital pendamping aplikasi utama ALAZHARAPPS.</p>\r\n<h3>1. Pemetaan Microservices LMS</h3>\r\n<p>Berbeda dengan sistem finansial atau pendaftaran, LMS dipecah menjadi beberapa layanan khusus untuk menangani interaksi belajar-mengajar dengan *traffic* sangat tinggi:</p>\r\n<ul>\r\n<li><strong><code>course-service</code>:</strong> Otak utama LMS. Layanan ini mengelola pembuatan Kelas Online (Course), Modul Pembelajaran, Tugas (Assignment), Ujian (Quiz/Exam), serta penilaian otomatis.</li>\r\n<li><strong><code>jurnal-service</code>:</strong> Menangani absensi harian dan pencatatan Jurnal Mengajar Guru. Sangat penting untuk audit kinerja tenaga pendidik.</li>\r\n<li><strong><code>lms-mobile</code> &amp; <code>mobile</code>:</strong> Klien antarmuka berbasis *mobile* (Android/iOS) yang dirancang agar siswa dapat mengakses materi belajar dan mengikuti kuis langsung dari ponsel cerdas mereka.</li>\r\n<li><strong><code>safeexam-browser-android</code>:</strong> Integrasi keamanan tingkat tinggi. Aplikasi atau modul ini memastikan bahwa ketika siswa sedang melaksanakan ujian (*Computer Based Test* / CBT), mereka tidak bisa membuka aplikasi lain (seperti *browser* Google, ChatGPT, atau WhatsApp) untuk mencegah kecurangan.</li>\r\n</ul>\r\n<h3>2. Integrasi Data dengan ALAZHARAPPS Utama</h3>\r\n<p>Bagaimana LMS tahu bahwa Siswa A berada di Kelas 10A dan berhak mengakses materi Matematika? LMS tidak menyimpan data master siswa.</p>\r\n<ul>\r\n<li><strong>Synchronous Fetching (gRPC):</strong> Saat LMS butuh memvalidasi identitas, <code>course-service</code> melakukan panggilan gRPC ke <code>student-service</code> (yang berada di ekosistem ALAZHARAPPS).</li>\r\n<li><strong>Data Caching (Redis):</strong> Karena memanggil gRPC jutaan kali per jam (saat ribuan siswa ujian) akan membuat <code>student-service</code> pingsan, LMS menggunakan Redis. Profil siswa, nama kelas, dan jadwal mata pelajaran akan di-*cache* (disimpan sementara) di Redis milik LMS selama beberapa jam.</li>\r\n<li><strong>Keamanan Lintas Ekosistem:</strong> LMS bergantung pada <code>jwtaccess</code> dan token otorisasi yang diterbitkan oleh <code>account-service</code>. Tidak ada pendaftaran akun terpisah untuk LMS (Single Sign-On).</li>\r\n</ul>\r\n<h3>3. Skalabilitas &amp; Tantangan Performa</h3>\r\n<p>Sistem pendidikan memiliki lonjakan pengunjung ekstrem di jam tertentu (misal: pukul 07.00 - 09.00 saat ujian serentak atau presensi masuk).</p>\r\n<p><strong>[TIP] Skenario Optimasi:</strong> Karena LMSALAZHARAPPS menghadapi pola beban (*workload*) *spiky* ini, sangat krusial bagi tim DevOps untuk mengonfigurasi *Horizontal Pod Autoscaler* (HPA) jika menggunakan Kubernetes. Saat ujian massal dimulai, <code>course-service</code> harus bisa otomatis menggandakan diri dari 2 kontainer menjadi 10 kontainer dalam hitungan detik untuk mencegah server *down*.</p>', '1', '2', '16', '2026-07-14 04:33:27', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('92', '24', 'Bedah Arsitektur Frontend & Manajemen State (NextJS & Redux)', '1-bedah-arsitektur-frontend-manajemen-state-nextjs-redux', '<p>Dokumen ini membedah arsitektur antarmuka klien (Frontend) berbasis NextJS, dengan fokus pada bagaimana aplikasi mengelola lalu lintas data secara dinamis (State Management).</p>\r\n<h3>1. Arsitektur Komponen NextJS</h3>\r\n<p>Proyek di dalam repositori <code>frontend</code> menggunakan pola desain modern dari React/NextJS.</p>\r\n<ul>\r\n<li><strong>Client vs Server Components:</strong> Mengingat ini adalah aplikasi dasbor (Backoffice) yang sangat interaktif (tabel dinamis, grafik, form pendaftaran), sebagian besar komponen ditandai dengan <code>"use client"</code> di baris teratasnya. Ini berarti proses perenderan UI (*rendering*) sangat bergantung pada komputasi *browser* pengguna.</li>\r\n<li><strong>Isolasi Logika Form (React Hook Form + Zod):</strong> Untuk menangani form yang sangat panjang (seperti form biodata pendaftaran murid baru PPDB), tim tidak menggunakan pengikatan state React biasa (*two-way binding*). Mereka menggunakan <code>React Hook Form</code> untuk performa tanpa *lag*, yang dipadukan dengan <code>Zod</code>. Zod memastikan bahwa jika orang tua lupa mengisi Nomor Induk Kependudukan (NIK), form akan ditolak sebelum sempat menembak server (Validasi sisi Klien).</li>\r\n</ul>\r\n<h3>2. Manajemen State Global (Redux Toolkit)</h3>\r\n<p>Karena ALAZHARAPPS memiliki lusinan modul (Keuangan, Rapor, Akademik, PPDB), memindahkan data antar-halaman (*prop drilling*) sangat merepotkan. Solusinya adalah Redux Toolkit (RTK).</p>\r\n<ul>\r\n<li><strong>Pemisahan Slice:</strong> Setiap modul bisnis memiliki ruang penyimpanan (Store Slice) sendiri. Terdapat irisan untuk <code>authSlice</code> (menyimpan nama dan peran pengguna yang login) dan <code>studentSlice</code> (menyimpan daftar siswa yang sedang difilter oleh guru).</li>\r\n<li><strong>Komunikasi Asinkron (RTK Query / Thunks):</strong> Saat pengguna mengklik tombol "Simpan Data", Redux Thunk atau RTK Query bertugas melakukan pemanggilan API (Axios/Fetch) ke *Backend* Golang, menampilkan ikon *loading* putar (Spinner), dan memperbarui *State* tabel ketika respons sukses diterima.</li>\r\n</ul>\r\n<h3>3. Keamanan Sesi (Auth State)</h3>\r\n<p><strong>[IMPORTANT] Penanganan JWT di Frontend:</strong> Saat *login* berhasil, token JWT tidak boleh dibiarkan mengambang di memori JS. Tim idealnya mengonfigurasi NextJS (melalui *API Routes*) untuk menerima JWT dari Golang, lalu membungkusnya ke dalam *HttpOnly Cookie*. Hal ini memastikan keamanan mutlak sehingga peretas tidak bisa mencuri token lewat celah XSS (Cross-Site Scripting).</p>', '1', '2', '15', '2026-07-14 04:37:59', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('93', '24', 'Arsitektur Mobile Apps (Siswa & Orang Tua)', '2-arsitektur-mobile-apps-siswa-orang-tua', '<p>Dokumen ini mendeskripsikan arsitektur dan pola integrasi aplikasi klien bergerak (Mobile Apps) yang digunakan oleh ratusan orang tua, guru, dan siswa di ekosistem ALAZHARAPPS &amp; LMSALAZHARAPPS.</p>\r\n<h3>1. Pendekatan Pengembangan Lintas Platform (Cross-Platform)</h3>\r\n<p>Berdasarkan struktur repositori <code>mobile</code> dan <code>lms-mobile</code>, pengembangan aplikasi pintar ini menggunakan kerangka kerja lintas platform (kemungkinan besar <strong>Flutter</strong> atau <strong>React Native</strong>).</p>\r\n<ul>\r\n<li><strong>Manfaat Bisnis:</strong> Dengan satu basis kode (*single codebase*), yayasan dapat merilis aplikasi berekstensi <code>.apk</code> untuk pengguna Android di Google Play Store dan ekstensi <code>.ipa</code> untuk pengguna iPhone di Apple App Store. Ini memangkas biaya pemeliharaan IT hingga 50%.</li>\r\n<li><strong>Pola Komunikasi API:</strong> Sama persis dengan portal Web (NextJS), aplikasi *Mobile* bertindak murni sebagai "Lapisan Tampilan" (View Layer). Seluruh beban logika (apakah siswa boleh ikut ujian atau apakah tagihan SPP sudah dibayar) diserahkan ke API Backend Golang.</li>\r\n</ul>\r\n<h3>2. Penyimpanan Kredensial di Mobile (Secure Storage)</h3>\r\n<p>Berbeda dengan *browser* Web yang memiliki sistem <em>Cookie</em> ketat, aplikasi *mobile* memiliki tantangan keamanan tersendiri.</p>\r\n<ul>\r\n<li>Saat orang tua *login* ke aplikasi <code>mobile</code>, token otorisasi (JWT) yang didapat dari <code>account-service</code> tidak boleh disimpan di <em>SharedPreferences</em> biasa (karena mudah dibajak di perangkat Android yang di-*root*).</li>\r\n<li>Pengembang menggunakan modul khusus seperti <code>Flutter Secure Storage</code> atau <code>EncryptedSharedPreferences</code> untuk membungkus token tersebut dalam *Brankas Terenkripsi* (Keystore/Keychain) milik sistem operasi *smartphone*.</li>\r\n</ul>\r\n<h3>3. Integrasi Khusus: Safe Exam Browser (CBT)</h3>\r\n<p>Repositori <code>safeexam-browser-android</code> adalah modul keamanan yang paling esensial dalam ekosistem pendidikan masa kini.</p>\r\n<ul>\r\n<li><strong>Sistem Penguncian Layar (Kiosk Mode):</strong> Aplikasi Android ini berinteraksi langsung dengan API sistem operasi tingkat rendah (*low-level*). Saat mode ujian diaktifkan, aplikasi akan memblokir fitur *screenshot*, *split-screen*, notifikasi melayang (pop-up), dan secara agresif mencegah perpindahan aplikasi (App Switching).</li>\r\n<li><strong>Deteksi Kecurangan (Anti-Cheat):</strong> Layanan ini terhubung secara *realtime* (via WebSocket/gRPC) ke <code>course-service</code> di LMS. Jika siswa terdeteksi mencoba meminimize layar, aplikasi *mobile* akan langsung mengirim sinyal darurat ke server, yang secara otomatis akan membekukan lembar jawaban siswa (Auto-Lock).</li>\r\n</ul>', '1', '2', '14', '2026-07-14 04:37:59', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('94', '24', 'Strategi Pengujian Otomatis (Automated Testing)', '3-strategi-pengujian-otomatis-automated-testing', '<p>Dokumen ini menjabarkan strategi Penjaminan Mutu (Quality Assurance) otomatis yang diimplementasikan pada ALAZHARAPPS untuk memastikan sistem pendidikan dan finansial tidak pernah mengalami kegagalan fatal saat rilis versi baru.</p>\r\n<h3>1. Lapisan Pertama: Unit Testing (Golang)</h3>\r\n<p>Pengujian Unit (Unit Test) adalah baris pertahanan pertama. Tim *Backend* diwajibkan menulis file pengujian berakhiran <code>_test.go</code> di setiap folder lapisan <em>Usecase</em>.</p>\r\n<ul>\r\n<li><strong>Isolasi dengan Mocks:</strong> Saat menguji fungsi "Lunas Pembayaran SPP", aplikasi tidak boleh menembak *database* asli. Pengembang menggunakan pustaka seperti <code>gomock</code> atau <code>testify/mock</code> untuk mensimulasikan respons dari repositori *database* (Mocking).</li>\r\n<li><strong>Skenario Keberhasilan &amp; Kegagalan (Table-Driven Tests):</strong> Golang sangat erat dengan budaya pengujian berbasis tabel. Pengembang menyusun daftar skenario (contoh: "Saldo Cukup", "Siswa Tidak Ditemukan", "Tagihan Sudah Lunas"), lalu fungsi dijalankan dan divalidasi apakah responsnya sesuai dengan harapan (*Assertions*).</li>\r\n</ul>\r\n<h3>2. Lapisan Kedua: Integration Testing</h3>\r\n<p>Meskipun setiap blok kode (*Unit*) berfungsi baik, mereka bisa saja hancur saat digabungkan. Pengujian integrasi memastikan koneksi dari API sampai ke Database lokal (biasanya dijalankan di dalam kontainer Docker temporer saat *pipeline* berjalan) berfungsi normal tanpa galat *syntax* SQL.</p>\r\n<h3>3. Automasi Berkelanjutan (CI/CD Gates)</h3>\r\n<p>Seperti yang telah dibahas pada dokumen *CI/CD Pipeline*, pengujian ini tidak diandalkan pada daya ingat pengembang (dijalankan manual di laptop lokal).</p>\r\n<p><strong>[WARNING] Gerbang Tolak Otomatis (Fail-Safe):</strong> Saat kode didorong (*git push*) ke GitLab, <em>GitLab Runner</em> akan mengeksekusi perintah <code>go test ./... -cover</code>. Jika terdeteksi ada skenario yang gagal, atau jika persentase kode yang tertutupi oleh tes (*Code Coverage*) berada di bawah standar perusahaan (misalnya 70%), proses *Build* dan *Deploy* ke server *Staging* atau *Production* akan langsung ditolak (Dibatalkan Otomatis).</p>', '1', '2', '13', '2026-07-14 04:37:59', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('95', '24', 'Observabilitas & Monitoring Sistem (Grafana/Sentry)', '4-observabilitas-monitoring-sistem-grafanasentry', '<p>Dokumen ini merangkum lapisan Pemantauan Cerdas (Observability) yang menjadi mata dan telinga sistem ALAZHARAPPS saat beroperasi tanpa pengawasan di lingkungan Produksi.</p>\r\n<h3>1. Melampaui Pembacaan Log Manual</h3>\r\n<p>Pada panduan <em>Troubleshooting</em>, kita diajarkan cara membaca log dari terminal Docker secara manual. Namun, hal itu hanya berlaku jika kita <strong>tahu</strong> sistem sedang rusak. Bagaimana cara kita tahu sebuah sistem rusak <em>sebelum</em> ditelepon oleh orang tua murid yang komplain?</p>\r\n<h3>2. Tiga Pilar Observabilitas Sistem</h3>\r\n<ul>\r\n<li><strong>Logs (Agregasi):</strong> Log dari ke-12 layanan *microservice* tidak boleh dibiarkan berserakan di mesin masing-masing. Tim DevOps wajib menerapkan sistem *Log Aggregator* (seperti ELK Stack: Elasticsearch, Logstash, Kibana atau tumpukan Grafana Loki). Dengan ini, pencarian (Trace) ID Transaksi <code>TRX-123</code> dapat langsung terlihat menembus semua *microservices* dalam satu dasbor raksasa.</li>\r\n<li><strong>Metrics (Beban Server):</strong> Menggunakan alat bernama Prometheus untuk menarik metrik *hardware* dan *software* (CPU Usage, Memory, durasi respon API). Metrik ini divisualisasikan oleh dasbor Grafana secara *Realtime*.</li>\r\n<li><strong>Traces (APM):</strong> Menggunakan <em>Application Performance Monitoring (APM)</em> untuk melacak *bottleneck* (kemacetan). Misalnya, dasbor APM bisa menunjukkan bahwa: <em>Request Pendaftaran memakan waktu 4 detik (1 detik di API gateway, 2.5 detik macet saat kueri GORM, 0.5 detik cetak PDF)</em>. Data ini sangat mahal untuk proses optimasi.</li>\r\n</ul>\r\n<h3>3. Error Tracking Frontend (Sentry)</h3>\r\n<p>Bagaimana jika aplikasi *Mobile* <em>crash</em> atau layar *blank* (putih) di *smartphone* orang tua saat mereka mencoba membayar tagihan? Server Golang tidak akan pernah menerima log error ini karena rusaknya ada di sisi *device* (Klien).</p>\r\n<p><strong>[TIP] Integrasi Pihak Ketiga:</strong> Ekosistem NextJS dan Mobile biasanya diintegrasikan dengan alat pelacak *Error* klien seperti <strong>Sentry</strong>. Ketika pengguna mendapati layar *Error 500*, *smartphone* secara asinkron akan mengirim *Stack Trace* lengkap dengan tipe *smartphone* dan versi OS ke dasbor Sentry milik pengembang, sehingga masalah UI dapat segera diinvestigasi (Patch) di hari yang sama.</p>', '1', '2', '12', '2026-07-14 04:37:59', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('96', '24', 'Integrasi Pihak Ketiga & Validasi Webhook', '5-integrasi-pihak-ketiga-validasi-webhook', '<p>Dokumen ini mengupas celah paling rawan (*Attack Surface*) di setiap aplikasi *Fintech*: Manajemen rute *Callback* (Webhook) dari sistem pihak ketiga (Midtrans/Xendit/Bank).</p>\r\n<h3>1. Paradigma Tarik vs Dorong (Pull vs Push)</h3>\r\n<p>Saat transaksi terjadi, ALAZHARAPPS tidak terus-menerus bertanya (<em>polling</em>) ke server Bank setiap menit, "Apakah SPP sudah dibayar?". Sebaliknya, Bank (Payment Gateway) yang akan "mendorong" pesan HTTP POST (*Webhook*) langsung ke peladen ALAZHARAPPS sesaat setelah uang dari orang tua masuk.</p>\r\n<ul>\r\n<li><strong>Rute Terbuka:</strong> Berbeda dengan API <code>/api/v1/users</code> yang diamankan oleh JWT pengguna, rute <code>/api/v1/payments/webhook</code> sifatnya terbuka untuk publik di internet.</li>\r\n<li><strong>Risiko Injeksi Palsu:</strong> Seorang siswa nakal/peretas yang tahu format JSON Midtrans bisa saja menembakkan *request* dari laptopnya ke server ALAZHARAPPS dengan *payload* <em>"SPP Bulan ini sudah lunas"</em>. Jika tidak diproteksi, aplikasi akan menganggap pembayaran benar-benar terjadi, dan jurnal yayasan akan bocor (kerugian jutaan Rupiah).</li>\r\n</ul>\r\n<h3>2. Mitigasi dan Validasi Lapis Baja</h3>\r\n<p>Tim pengembangan menerapkan standar kepatuhan tinggi untuk menolak rute *Webhook* palsu:</p>\r\n<ol>\r\n<li><strong>Validasi IP Whitelisting:</strong> Nginx atau *Gateway* dikonfigurasi untuk hanya menerima *request* masuk ke URL Webhook tersebut jika IP pengirimnya secara sah berasal dari *Data Center* Midtrans/Xendit. (Gagal di sini = Akses Ditolak 403).</li>\r\n<li><strong>Verifikasi Signature Key (Tanda Tangan Kriptografi):</strong> Meskipun IP bisa dipalsukan (IP Spoofing), server Bank menyertakan *header* khusus yang berisi *hash* (enkripsi gabungan dari ID Transaksi + Status + Server Key Rahasia). ALAZHARAPPS akan membuat *hash* tandingan menggunakan <code>Server_Key</code> miliknya. Jika *hash* tidak cocok (<em>Signature Mismatch</em>), server mengabaikan perintah tersebut!</li>\r\n<li><strong>Pengecekan Silang (Double Validation):</strong> Untuk transaksi dalam jumlah besar, <code>transaction-service</code> memiliki lapisan keamanan terakhir, yakni melakukan panggilan balik (*Callback API GET*) langsung ke Midtrans guna menanyakan kembali keabsahan transaksi tersebut sebelum mengeksekusi penulisan jurnal keuangan (GORM *Transaction*).</li>\r\n</ol>', '1', '2', '11', '2026-07-14 04:38:00', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('97', '24', 'Kebijakan Version Control & Siklus SDLC', '6-kebijakan-version-control-siklus-sdlc', '<p>Dokumen ini memetakan kebiasaan operasional pengembang (Developer Workflow) dan kebijakan Siklus Hidup Pengembangan Perangkat Lunak (SDLC) yang diamankan melalui GitLab.</p>\r\n<h3>1. Strategi Pencabangan Git (Branching Strategy)</h3>\r\n<p>Repositori ALAZHARAPPS mengadopsi modifikasi dari pola kolaborasi <strong>GitFlow / Feature Branch</strong>. Terlihat dari eksekusi perintah <code>git pull</code> yang memunculkan banyak variasi cabang (Branches):</p>\r\n<ul>\r\n<li><strong><code>master</code> / <code>main</code>:</strong> Cabang Suci. Tidak ada pengembang yang boleh mendorong (Push) kode secara langsung ke sini. Cabang ini merepresentasikan *Image* kontainer yang saat ini sedang aktif (Live) melayani pengguna di Production.</li>\r\n<li><strong><code>develop</code> / <code>staging</code>:</strong> Kawah Candradimuka. Tempat bertemunya fitur-fitur baru (sebelum diuji coba dan dirilis bulan depan). Jika aplikasi di *Staging* hancur, tidak masalah, karena di sinilah pengujian pra-rilis (*User Acceptance Test*) dilakukan.</li>\r\n<li><strong><code>feature/nama-fitur</code> atau nama personal (contoh <code>rahmat</code>):</strong> Cabang tempat koding sehari-hari. Fitur PPDB atau SPP baru dikerjakan terpisah secara paralel.</li>\r\n<li><strong><code>hotfix</code>:</strong> Jalur cepat (*Fast-track*). Dibuat langsung dari <code>master</code> untuk menambal kebocoran atau *bug* parah tanpa harus menunggu siklus rilis reguler selesai.</li>\r\n</ul>\r\n<h3>2. Peninjauan Kode (Pull/Merge Request)</h3>\r\n<p>Sistem ini tidak membiarkan pengembang sembarangan menyuntik kode ke <code>develop</code>. Proses penyatuan fitur harus melewati mekanisme <strong>Merge Request (MR)</strong>.</p>\r\n<ul>\r\n<li><strong>Peer Review:</strong> Pengembang senior (Tech Lead) bertugas mengecek kode yang diajukan oleh pemrogram junior. Apakah sesuai *Coding Standard*? Apakah *raw query*-nya aman dari *SQL Injection*?</li>\r\n<li><strong>CI Gates:</strong> Saat MR dibuat, GitLab secara otomatis akan menjalankan *Unit Test* dan *Linter*. Tim tidak bisa menekan tombol <em>"Accept Merge"</em> jika tanda silang merah (Gagal Test) masih muncul di halaman GitLab (*Pipeline Enforcement*).</li>\r\n</ul>\r\n<h3>3. Konvensi Pesan Komit (Commit Guidelines)</h3>\r\n<p>Walaupun kadang fleksibel, praktik yang baik di dunia peranti lunak (seperti <em>Conventional Commits</em>) menganjurkan pelabelan *commit* untuk pelacakan rilis (Changelog) yang teratur. (Contoh standar industri: <code>feat: add automatic billing</code>, <code>fix: resolve rounding error on SPP</code>). Ini akan membuat proses penelusuran sejarah (*blame*) di ALAZHARAPPS menjadi jauh lebih mudah di kemudian hari.</p>', '1', '2', '10', '2026-07-14 04:38:00', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('98', '25', '[Mobile] Alur Registrasi PPDB & Akun', '1-mobile-alur-registrasi-ppdb-akun', '<p>Panduan ini ditujukan bagi Orang Tua Calon Murid untuk melakukan pendaftaran awal (PPDB) hingga berhasil masuk ke aplikasi *Mobile* ALAZHARAPPS.</p>\r\n<h3>1. Membuat Akun Pendaftaran (Web/Landing Page)</h3>\r\n<p>Sebelum menggunakan aplikasi *Mobile*, Anda harus memiliki akun pendaftaran. Ikuti langkah berikut:</p>\r\n<ol>\r\n<li>Buka *browser* di HP atau Laptop Anda, lalu kunjungi situs resmi pendaftaran sekolah: <code>pmb.alazhar.or.id</code>.</li>\r\n<li>Klik tombol <strong>Daftar Sekarang</strong>.</li>\r\n<li>Isi formulir pembuatan akun awal: Masukkan Nama Lengkap Orang Tua, Alamat Email Aktif, dan Nomor WhatsApp yang dapat dihubungi.</li>\r\n<li>Klik <strong>Buat Akun</strong>. Cek email Anda untuk mendapatkan *Password* sementara atau tautan aktivasi.</li>\r\n</ol>\r\n<h3>2. Melengkapi Formulir PPDB</h3>\r\n<p>Setelah akun terbuat, segera <em>login</em> kembali ke portal <em>website</em> pendaftaran.</p>\r\n<ol>\r\n<li>Pilih jenjang sekolah yang dituju (TK/SD/SMP/SMA).</li>\r\n<li>Isi dengan lengkap seluruh formulir Biodata Calon Siswa, Data Orang Tua/Wali, dan Riwayat Kesehatan.</li>\r\n<li>Unggah dokumen yang diminta (seperti Akta Kelahiran, Kartu Keluarga). Format gambar (JPG/PNG) atau PDF, pastikan ukurannya di bawah 2 MB.</li>\r\n<li>Klik tombol <strong>Kirim Formulir Final</strong>. Setelah ini, Anda akan mendapatkan tagihan Uang Pangkal / Pendaftaran.</li>\r\n</ol>\r\n<h3>3. Login ke Aplikasi Mobile</h3>\r\n<p>Setelah anak Anda dinyatakan lulus tes dan berstatus <strong>Siswa Aktif</strong>, Anda baru bisa menggunakan aplikasi ALAZHARAPPS di HP.</p>\r\n<ol>\r\n<li>Unduh aplikasi <strong>ALAZHARAPPS</strong> dari Google Play Store (Android) atau App Store (iOS).</li>\r\n<li>Buka aplikasi, masukkan <strong>Email</strong> (yang Anda gunakan saat mendaftar) dan <strong>Password</strong> (yang diberikan oleh sekolah / kata sandi web).</li>\r\n<li>Klik <strong>Masuk</strong>. Anda akan diarahkan ke *Dashboard* Orang Tua, di mana Anda bisa memantau lebih dari satu anak (jika Anda memiliki dua anak yang bersekolah di Al-Azhar).</li>\r\n</ol>', '1', '2', '33', '2026-07-14 04:50:14', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('99', '25', '[Mobile] Panduan Cek Tagihan & Pembayaran SPP', '2-mobile-panduan-cek-tagihan-pembayaran-spp', '<p>Panduan ini ditujukan bagi Orang Tua untuk melakukan pengecekan tagihan sekolah (SPP, Uang Kegiatan, Buku) dan cara membayarnya melalui aplikasi *Mobile* ALAZHARAPPS.</p>\r\n<h3>1. Mengecek Daftar Tagihan</h3>\r\n<p>Sistem secara otomatis akan menerbitkan tagihan SPP pada tanggal 1 setiap bulannya. Untuk melihatnya:</p>\r\n<ol>\r\n<li>Buka aplikasi ALAZHARAPPS di <em>smartphone</em> Anda dan pastikan Anda sudah <em>login</em>.</li>\r\n<li>Di halaman beranda (*Home*), ketuk menu dengan ikon dompet bertuliskan <strong>Keuangan / Tagihan</strong>.</li>\r\n<li>Anda akan melihat dua *tab* (halaman): <strong>Belum Lunas</strong> dan <strong>Riwayat Lunas</strong>.</li>\r\n<li>Pada halaman *Belum Lunas*, tagihan akan diurutkan dari yang paling mendesak (jatuh tempo terdekat). Tagihan yang berlatar merah menandakan telah melewati batas waktu pembayaran.</li>\r\n</ol>\r\n<h3>2. Proses Pembayaran via Virtual Account (VA)</h3>\r\n<p>Sekolah Al-Azhar menggunakan *Payment Gateway* terintegrasi. Anda tidak perlu lagi mengirimkan foto bukti transfer (struk) ke Tata Usaha karena verifikasi berjalan otomatis.</p>\r\n<ol>\r\n<li>Pilih bulan tagihan yang ingin dibayar (contoh: SPP Juli 2026), lalu ketuk <strong>Bayar Sekarang</strong>.</li>\r\n<li>Sistem akan menampilkan Rincian Tagihan. Pastikan nama siswa dan nominal sudah sesuai.</li>\r\n<li>Pilih <strong>Metode Pembayaran</strong> (Misalnya: Mandiri Virtual Account, BCA, BNI, atau e-Wallet seperti GoPay/OVO).</li>\r\n<li>Ketuk <strong>Konfirmasi &amp; Dapatkan Kode Pembayaran</strong>.</li>\r\n<li>Layar akan menampilkan <strong>Nomor Virtual Account (VA)</strong>. Ketuk tombol <em>Salin (Copy)</em>. Nomor VA ini hanya berlaku selama 24 jam.</li>\r\n</ol>\r\n<h3>3. Verifikasi Keberhasilan</h3>\r\n<p>Setelah Anda melakukan transfer dana dari M-Banking atau ATM ke nomor VA tersebut:</p>\r\n<ol>\r\n<li>Tunggu sekitar 1 - 5 menit. Buka kembali menu <strong>Keuangan</strong> di aplikasi ALAZHARAPPS.</li>\r\n<li>Tagihan yang Anda bayar akan otomatis berpindah dari *tab* Belum Lunas ke *tab* <strong>Riwayat Lunas</strong>.</li>\r\n<li>Anda juga akan menerima notifikasi pesan WhatsApp dari nomor resmi sekolah yang menyatakan *"Terima kasih, pembayaran SPP Ananda [Nama Siswa] telah diterima."*</li>\r\n<li>Ketuk tagihan lunas tersebut jika Anda ingin mengunduh atau mencetak Bukti Kwitansi digital dalam format PDF.</li>\r\n</ol>', '1', '2', '34', '2026-07-14 04:50:14', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('100', '25', '[Mobile] Cara Mengakses Kelas & Ujian LMS (Siswa)', '3-mobile-cara-mengakses-kelas-ujian-lms', '<p>Panduan ini ditujukan khusus bagi <strong>Siswa</strong> untuk menggunakan fitur <em>Learning Management System</em> (LMS) ALAZHARAPPS, mengunduh materi belajar, serta melaksanakan Ujian *Online*.</p>\r\n<h3>1. Mengakses Kelas dan Materi (e-Learning)</h3>\r\n<p>Semua modul pembelajaran dan tugas yang diberikan guru dapat diakses langsung dari ponsel.</p>\r\n<ol>\r\n<li>Buka aplikasi ALAZHARAPPS dan <em>login</em> menggunakan akun Siswa (NISN &amp; Kata Sandi yang diberikan Wali Kelas).</li>\r\n<li>Di beranda, ketuk menu <strong>Akademik</strong> atau <strong>Ruang Kelas (LMS)</strong>.</li>\r\n<li>Anda akan melihat daftar mata pelajaran (contoh: Matematika, Bahasa Inggris). Ketuk pelajaran yang sedang berlangsung.</li>\r\n<li>Pada halaman Mata Pelajaran, ketuk *tab* <strong>Materi</strong> untuk mengunduh modul PDF atau menonton tautan video YouTube yang disisipkan guru.</li>\r\n<li>Jika ada tugas, buka *tab* <strong>Tugas (Assignment)</strong>, baca instruksinya, lalu unggah file tugas Anda (foto buku catatan atau *file* dokumen) sebelum tenggat waktu (*Deadline*) habis.</li>\r\n</ol>\r\n<h3>2. Persiapan Ujian (CBT / Computer Based Test)</h3>\r\n<p>Berbeda dengan tugas harian, Ujian Tengah Semester (UTS) atau Ujian Akhir (UAS) membutuhkan keamanan ekstra agar siswa fokus mengerjakan tes.</p>\r\n<ol>\r\n<li>Untuk Ujian yang diwajibkan menggunakan sistem keamanan, Anda <strong>wajib</strong> mengunduh aplikasi terpisah bernama <strong>Safe Exam Browser (SEB) ALAZHARAPPS</strong> dari Play Store (khusus perangkat Android).</li>\r\n<li>Pastikan baterai ponsel terisi di atas 50% dan terhubung ke *Wi-Fi* sekolah atau kuota internet pribadi yang stabil.</li>\r\n</ol>\r\n<h3>3. Tata Cara Pelaksanaan Ujian (Saat Hari H)</h3>\r\n<p>Ikuti langkah ini hanya saat pengawas/guru ujian sudah memberikan instruksi di kelas:</p>\r\n<ol>\r\n<li>Buka aplikasi utama ALAZHARAPPS, masuk ke menu <strong>Ujian</strong>.</li>\r\n<li>Ketuk ujian yang berstatus <em>"Sedang Berlangsung"</em>.</li>\r\n<li>Sistem akan mendeteksi apakah Anda sudah memasang Safe Exam Browser. Jika sudah, Anda akan otomatis diarahkan masuk ke layar ujian. Layar ini akan **terkunci penuh** (*Kiosk Mode*).</li>\r\n<li><strong>PERHATIAN PENTING:</strong> Selama berada di layar ujian, dilarang menekan tombol *Home* di ponsel, dilarang membuka WhatsApp (meskipun ada notifikasi masuk), dan dilarang membagi layar (*Split Screen*).</li>\r\n<li>Jika sistem mendeteksi percobaan kecurangan di atas, layar ujian Anda akan <strong>Terblokir Otomatis</strong> dan Anda harus meminta *Passcode* buka kunci (Unblock Code) dari guru pengawas untuk bisa melanjutkan ujian.</li>\r\n<li>Setelah menjawab semua soal, ketuk tombol <strong>Selesaikan Ujian &amp; Kirim Jawaban</strong>.</li>\r\n</ol>', '1', '2', '35', '2026-07-14 04:50:14', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('101', '27', '[Web] Manajemen Data Siswa & Kelas (Admin)', '4-web-manajemen-data-siswa-kelas-admin', '<p>Panduan ini ditujukan bagi <strong>Staf Tata Usaha (Admin Sekolah)</strong> untuk mengelola data siswa, tahun ajaran, dan penempatan kelas melalui Portal Backoffice (Web) ALAZHARAPPS.</p>\r\n<h3>1. Mengakses Backoffice dan Login</h3>\r\n<ol>\r\n<li>Buka *browser* di komputer/laptop (disarankan Google Chrome).</li>\r\n<li>Akses tautan resmi Dasbor Sekolah: <code>apps.alazhar.or.id</code>.</li>\r\n<li>Masukkan Email dan Kata Sandi Akun Admin Anda.</li>\r\n<li>Pastikan Anda memilih <strong>Unit Sekolah</strong> yang tepat di pojok kanan atas (jika akun Anda memiliki akses ke beberapa unit/jenjang).</li>\r\n</ol>\r\n<h3>2. Melengkapi Master Data (Di Awal Semester)</h3>\r\n<p>Sebelum menempatkan siswa ke kelas, Admin harus memastikan kerangka tahun ajaran sudah dibuat.</p>\r\n<ol>\r\n<li>Pilih menu <strong>Master Data &gt; Tahun Ajaran</strong>. Klik tombol "Tambah Data" untuk mengaktifkan tahun akademik baru (misalnya "Ganjil 2026/2027").</li>\r\n<li>Pilih menu <strong>Master Data &gt; Ruang Kelas</strong>. Daftarkan nama-nama kelas yang aktif (contoh: 10 IPA 1, 10 IPA 2). Anda juga bisa menetapkan Wali Kelas pada *form* ini.</li>\r\n</ol>\r\n<h3>3. Mendaftarkan atau Memutasi Siswa</h3>\r\n<p>Setelah kelas siap, langkah selanjutnya adalah memasukkan siswa.</p>\r\n<ul>\r\n<li><strong>Input Siswa Baru (Manual):</strong> Buka menu <strong>Siswa &gt; Data Induk Siswa</strong>, klik "Tambah Siswa". Isi form biodata lengkap (Nama, NISN, Nama Orang Tua). Pastikan email orang tua diisi dengan benar agar mereka bisa <em>login</em> di aplikasi *mobile*.</li>\r\n<li><strong>Siswa Baru dari PPDB:</strong> Buka menu <strong>PPDB &gt; Verifikasi Kelulusan</strong>. Pilih siswa yang sudah melunasi Uang Pangkal, klik tombol <strong>"Aktifkan Status Siswa"</strong>. Siswa ini akan otomatis berpindah ke Data Induk.</li>\r\n<li><strong>Penempatan Kelas (Mutasi Kelas):</strong> Buka menu <strong>Akademik &gt; Mutasi Kelas</strong>. Pilih daftar siswa yang ada, lalu pindahkan secara massal (<em>Bulk Action</em>) ke kelas tujuan (misalnya 10 IPA 1) pada Tahun Ajaran Ganjil 2026/2027.</li>\r\n</ul>\r\n<h3>4. Fitur Pencarian Rekam Jejak (Trace)</h3>\r\n<p>Jika ada wali murid yang bertanya ke Tata Usaha terkait status anak mereka, gunakan <strong>Bilah Pencarian Global (Global Search)</strong> di bagian atas atas dasbor. Ketikkan NISN atau Nama, maka sistem akan menampilkan tab riwayat kelas, tagihan, dan nilai dalam satu layar ringkas (Student 360 View).</p>', '1', '2', '51', '2026-07-14 04:50:14', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('102', '28', '[Web] Alur Penerbitan Tagihan Finansial (Keuangan)', '5-web-alur-penerbitan-tagihan-finansial-keuangan', '<p>Panduan ini ditujukan bagi <strong>Staf Keuangan Yayasan / Kasir Sekolah</strong> untuk menerbitkan, memantau, dan menyusun laporan tagihan siswa (SPP) melalui Backoffice ALAZHARAPPS.</p>\r\n<h3>1. Penerbitan Tagihan Bulanan (Invoicing Massal)</h3>\r\n<p>Daripada membuat tagihan satu per satu untuk 500 siswa, Anda dapat menggunakan fitur Generate Massal.</p>\r\n<ol>\r\n<li>Di menu samping kiri, klik <strong>Keuangan &gt; Tagihan SPP</strong>.</li>\r\n<li>Klik tombol <strong>Generate Tagihan Massal</strong> di kanan atas.</li>\r\n<li>Pilih "Bulan Pembayaran" (Contoh: Juli 2026) dan "Jenjang/Kelas" target. (Sistem akan otomatis mengecek siswa mana yang mendapat keringanan beasiswa).</li>\r\n<li>Klik <strong>Proses Sekarang</strong>. <em>Tunggu beberapa saat (sekitar 1-2 menit) karena server sedang mencetak ratusan Virtual Account.</em></li>\r\n<li>Setelah sukses, tagihan akan langsung muncul (Push Notification) di aplikasi *Mobile* orang tua.</li>\r\n</ol>\r\n<h3>2. Monitoring Pembayaran (Real-Time)</h3>\r\n<p>Karena ALAZHARAPPS terhubung ke *Payment Gateway*, Staf Keuangan tidak perlu mengecek mutasi rekening bank secara manual untuk memverifikasi SPP.</p>\r\n<ul>\r\n<li>Buka menu <strong>Keuangan &gt; Dashboard Penerimaan</strong>.</li>\r\n<li>Layar akan menampilkan grafik otomatis berapa persen target SPP bulan ini yang sudah terkumpul.</li>\r\n<li>Di bawah grafik, terdapat "Log Transaksi Harian". Jika orang tua A baru saja membayar via ATM Mandiri 2 detik yang lalu, namanya akan langsung muncul di baris paling atas dengan status "LUNAS" (ikon hijau).</li>\r\n</ul>\r\n<h3>3. Penanganan Kasus Khusus (Tunggakan &amp; Pembayaran Tunai)</h3>\r\n<ol>\r\n<li><strong>Kirim Surat Peringatan (Reminders):</strong> Buka menu <strong>Keuangan &gt; Laporan Tunggakan</strong>. Filter siswa yang belum membayar lebih dari 2 bulan. Klik tombol <strong>Kirim Notifikasi WA Massal</strong>. Sistem akan menembak pesan tagihan ke nomor ponsel orang tua mereka.</li>\r\n<li><strong>Pembayaran Tunai di Loket:</strong> Jika orang tua datang membawa uang tunai (cash) ke sekolah, staf dapat menerima uang tersebut. Cari nama anak di kotak Pencarian, buka tab Tagihannya, lalu klik tombol <strong>Bayar Manual (Cash)</strong>. Jangan lupa untuk menyerahkan kwitansi cetak (Print Struk) dari sistem kepada orang tua.</li>\r\n</ol>\r\n<h3>4. Ekspor Jurnal Akuntansi</h3>\r\n<p>Di akhir bulan, Akuntan Yayasan tidak perlu merekap ulang.</p>\r\n<ul>\r\n<li>Buka menu <strong>Akuntansi &gt; Laporan Jurnal Umum</strong>.</li>\r\n<li>Pilih rentang tanggal (1-30 Juli).</li>\r\n<li>Klik tombol <strong>Export Excel / CSV</strong>. File unduhan ini sudah berformat siap pakai (*ready-to-upload*) untuk dipindahkan ke sistem ERP sekunder yayasan atau diserahkan ke auditor.</li>\r\n</ul>', '1', '2', '68', '2026-07-14 04:50:14', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('103', '27', '[Web] Manajemen LMS & Input Nilai Jurnal (Guru)', '6-web-manajemen-lms-input-nilai-jurnal-guru', '<p>Panduan ini ditujukan bagi <strong>Tenaga Pendidik (Guru)</strong> untuk mengoperasikan fungsi *Learning Management System* (LMS), mengelola materi mengajar, dan membuat soal ujian melalui Backoffice Web.</p>\r\n<h3>1. Mengakses Ruang Kelas Online (LMS)</h3>\r\n<p>Setelah Admin Sekolah menugaskan Anda sebagai Guru Mata Pelajaran di kelas tertentu, kelas tersebut akan muncul di dasbor Anda.</p>\r\n<ol>\r\n<li><em>Login</em> ke Portal <code>apps.alazhar.or.id</code> menggunakan akun Guru.</li>\r\n<li>Buka menu <strong>Akademik &gt; Ruang Mengajar (LMS)</strong>.</li>\r\n<li>Anda akan melihat kotak (Kartu) kelas yang Anda ajar (Contoh: "Matematika - 10 IPA 1"). Klik kotak tersebut untuk masuk ke detail kelas.</li>\r\n</ol>\r\n<h3>2. Unggah Materi dan Tugas (Assignments)</h3>\r\n<p>Guru dapat menyisipkan bahan ajar agar siswa bisa membacanya dari HP sebelum masuk kelas tatap muka.</p>\r\n<ul>\r\n<li><strong>Unggah Materi (PDF/Video):</strong> Di dalam detail kelas, buka tab <strong>Bahan Ajar</strong>. Klik "Tambah Materi". Anda bisa mengunggah dokumen (maks. 10 MB) atau cukup merekatkan (<em>paste</em>) URL *link* YouTube pembelajaran. Materi akan langsung tersinkronisasi ke aplikasi *mobile* siswa detik itu juga.</li>\r\n<li><strong>Memberikan Tugas:</strong> Buka tab <strong>Tugas &amp; Kuis</strong>. Klik "Buat Tugas". Anda wajib mengisi Judul, Deskripsi Instruksi, dan <strong>Tenggat Waktu (Deadline)</strong>. Setelah tombol "Simpan &amp; Publish" ditekan, tugas tidak bisa dikerjakan jika siswa terlambat mengumpulkannya.</li>\r\n</ul>\r\n<h3>3. Membuat Soal Ujian (CBT / Computer Based Test)</h3>\r\n<p>LMSALAZHARAPPS memiliki bank soal (*Question Bank*) canggih untuk mempermudah ujian.</p>\r\n<ol>\r\n<li>Buka menu <strong>LMS &gt; Bank Soal</strong>. Buat kumpulan soal baru. Anda bisa mengetik manual Pilihan Ganda / Esai, atau mengimpor cepat menggunakan *Template* Excel (Format yang sudah disediakan sistem).</li>\r\n<li>Jika soal mengandung rumus atau gambar, Anda bisa menyisipkan gambar (Image Upload) di dalam opsi jawaban.</li>\r\n<li>Setelah paket soal siap, kembali ke Ruang Kelas. Buka tab <strong>Tugas &amp; Kuis</strong>, lalu klik "Buat Ujian Baru".</li>\r\n<li><strong>[PENTING] Pengaturan Keamanan:</strong> Pada pengaturan ujian, centang opsi <strong>"Gunakan Safe Exam Browser (SEB)"</strong> agar aplikasi Android siswa mengunci layarnya saat tes dimulai. Atur juga <em>Passcode</em> darurat (untuk berjaga-jaga jika ada siswa tidak sengaja keluar aplikasi).</li>\r\n</ol>\r\n<h3>4. Jurnal Mengajar dan Presensi Siswa</h3>\r\n<p>Setiap selesai mengajar, Guru wajib mengisi Jurnal (Buku Harian Mengajar).</p>\r\n<ul>\r\n<li>Pilih menu <strong>Kehadiran &amp; Jurnal &gt; Jurnal Mengajar</strong>.</li>\r\n<li>Pilih Hari dan Kelas yang baru saja diajar. Tulis ringkasan topik ("Membahas Rumus Phytagoras").</li>\r\n<li>Di bawahnya, akan tampil daftar absensi (Hadir, Sakit, Izin, Alpha). Secara *default* semua siswa diset ke "Hadir". Cukup klik dan ubah status siswa yang tidak datang saja, lalu klik "Simpan Absensi".</li>\r\n<li>Data ini akan langsung terekap ke Laporan Bulanan Kepala Sekolah dan orang tua yang bersangkutan akan menerima notifikasi jika anaknya tertandai Alpha.</li>\r\n</ul>', '1', '2', '52', '2026-07-14 04:50:14', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('104', '25', '[Mobile] Fitur dan Fungsi Menu Lengkap', '7-mobile-fitur-dan-fungsi-menu-lengkap', '<p>Dokumen ini merangkum secara komprehensif seluruh daftar fitur dan fungsi menu yang tersedia pada aplikasi <strong>Mobile ALAZHARAPPS</strong> (Android &amp; iOS) yang digunakan oleh Orang Tua dan Siswa.</p>\r\n<h3>1. Beranda (Home / Dashboard)</h3>\r\n<p>Halaman pertama setelah pengguna berhasil <em>login</em>. Dirancang sebagai pusat informasi cepat.</p>\r\n<ul>\r\n<li><strong>Informasi Siswa:</strong> Menampilkan foto, Nama Lengkap, Nomor Induk (NISN), Jenjang, dan Kelas siswa yang aktif. Jika orang tua memiliki 2 anak, terdapat fitur <em>"Switch Child"</em> (Tukar Profil) di pojok layar.</li>\r\n<li><strong>Ringkasan Tagihan (Widget Keuangan):</strong> Menampilkan angka nominal total tunggakan yang belum dibayar secara langsung tanpa perlu masuk ke menu Keuangan.</li>\r\n<li><strong>Pengumuman Sekolah (Broadcast/News):</strong> Berisi buletin digital (seperti informasi libur sekolah, kegiatan ekstrakurikuler, atau surat edaran yayasan).</li>\r\n<li><strong>Jadwal Pelajaran Hari Ini:</strong> Menampilkan daftar mata pelajaran khusus untuk hari berjalan agar siswa bisa menyiapkan buku/modul.</li>\r\n</ul>\r\n<h3>2. Menu Keuangan (Billing &amp; Payment)</h3>\r\n<p>Pusat transparansi finansial untuk orang tua, terhubung *real-time* ke sistem *Virtual Account* (Midtrans/Xendit).</p>\r\n<ul>\r\n<li><strong>Tab Tagihan Aktif:</strong> Daftar tagihan (SPP, Buku, Seragam, Uang Kegiatan) yang belum dilunasi. Terkategorisasi berdasarkan bulan dan urgensi (jatuh tempo).</li>\r\n<li><strong>Integrasi Pembayaran:</strong> Tombol untuk menghasilkan kode Virtual Account atau membuka aplikasi dompet digital (GoPay/OVO) langsung dari layar.</li>\r\n<li><strong>Tab Riwayat Pembayaran:</strong> Arsip seluruh tagihan yang sudah dilunasi.</li>\r\n<li><strong>Unduh Kwitansi Digital:</strong> Fitur untuk menyimpan atau mencetak bukti pembayaran sah berekstensi PDF langsung ke memori <em>smartphone</em>.</li>\r\n</ul>\r\n<h3>3. Menu Akademik &amp; e-Learning (LMS)</h3>\r\n<p>Ruang belajar virtual interaktif pengganti kelas fisik.</p>\r\n<ul>\r\n<li><strong>Ruang Mata Pelajaran:</strong> Menampilkan daftar lengkap mata pelajaran. Saat diklik, akan terbuka modul PDF atau pemutar video YouTube yang diunggah oleh guru.</li>\r\n<li><strong>Penugasan (Assignments):</strong> Daftar PR atau tugas. Terdapat *timer* hitung mundur (Countdown) untuk pengingat batas pengumpulan tugas (Deadline).</li>\r\n<li><strong>Upload Tugas:</strong> Siswa dapat memfoto buku catatan, atau mengunggah *file* langsung dari memori HP ke sistem.</li>\r\n<li><strong>Rekap Nilai (Raport Sementara):</strong> Menampilkan nilai kuis harian, UTS, atau UAS yang telah diverifikasi guru.</li>\r\n<li><strong>Rekap Kehadiran (Absensi):</strong> Persentase tingkat kehadiran siswa (Hadir/Sakit/Izin/Alpha).</li>\r\n</ul>\r\n<h3>4. Menu Ujian (Computer Based Test)</h3>\r\n<p>Menu khusus yang diaktifkan pada musim ujian sekolah.</p>\r\n<ul>\r\n<li><strong>Daftar Ujian Tersedia:</strong> Menampilkan ujian yang hanya bisa ditekan pada jam yang telah ditentukan (misalnya Ujian Matematika, aktif jam 08.00).</li>\r\n<li><strong>Integrasi Safe Exam Browser (SEB):</strong> Pintu gerbang peluncuran layar ujian anti-curang. Jika fitur ini menyala, HP siswa akan terkunci di layar soal (tidak bisa *screenshot* atau ganti aplikasi).</li>\r\n</ul>\r\n<h3>5. Menu Profil &amp; Pengaturan</h3>\r\n<ul>\r\n<li><strong>Data Diri:</strong> Menampilkan rekapan data lengkap keluarga (Alamat, Nomor Telepon). Jika ingin melakukan perubahan, diarahkan untuk lapor ke Tata Usaha.</li>\r\n<li><strong>Ganti Kata Sandi (Change Password):</strong> Fitur mandiri untuk mengubah kata sandi akun tanpa campur tangan admin.</li>\r\n<li><strong>Bantuan &amp; Layanan Pelanggan (Helpdesk):</strong> Tautan langsung menuju WhatsApp resmi sekolah atau halaman Tanya Jawab (FAQ) jika orang tua mengalami kendala teknis.</li>\r\n</ul>', '1', '2', '36', '2026-07-14 04:58:03', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('105', '31', '[Web] Fitur dan Fungsi Menu Lengkap Backoffice', '8-web-fitur-dan-fungsi-menu-lengkap-backoffice', '<p>Dokumen ini merangkum seluruh daftar fitur dan fungsi menu pada portal <strong>Backoffice Web ALAZHARAPPS</strong>, yang dirancang khusus sebagai ruang kendali bagi Staf Tata Usaha, Admin Keuangan, Kepala Sekolah, dan Guru.</p>\r\n<h3>1. Dasbor Utama &amp; Pencarian Global (Global Search)</h3>\r\n<p>Layar kontrol utama yang menyajikan ringkasan data harian.</p>\r\n<ul>\r\n<li><strong>Grafik Statistik:</strong> Menampilkan rasio kehadiran siswa hari ini, persentase kelulusan ujian, dan grafik pemasukan dana SPP bulanan.</li>\r\n<li><strong>Student 360 Search:</strong> Kotak pencarian sakti di pojok kanan atas. Ketikkan nama atau NISN siswa, dan sistem akan merangkum seluruh identitas, nilai akademik, serta tunggakan tagihannya dalam satu halaman utuh, mempermudah layanan komplain orang tua di loket Tata Usaha.</li>\r\n</ul>\r\n<h3>2. Modul Master Data &amp; PPDB</h3>\r\n<p>Jantung operasional untuk mengelola kerangka administrasi yayasan.</p>\r\n<ul>\r\n<li><strong>Tahun Ajaran &amp; Unit Sekolah:</strong> Menu untuk membuka periode akademik baru (misal: Ganjil 2026/2027) dan mendaftarkan cabang unit sekolah.</li>\r\n<li><strong>Data Induk Siswa &amp; Pegawai:</strong> Daftar buku induk untuk menambah, menyunting, atau menonaktifkan siswa dan guru (misal jika ada yang lulus atau *resign*).</li>\r\n<li><strong>Panel Penerimaan Siswa Baru (PPDB):</strong> Tempat memverifikasi pendaftaran dari <em>Landing Page</em>, memvalidasi bukti transfer uang pangkal, hingga mengeksekusi penempatan siswa baru ke kelas aktif.</li>\r\n</ul>\r\n<h3>3. Modul Akademik &amp; LMS (Khusus Guru &amp; Kepsek)</h3>\r\n<p>Ruang pengelolaan kegiatan belajar mengajar.</p>\r\n<ul>\r\n<li><strong>Manajemen Ruang Kelas:</strong> Fitur untuk membagi siswa ke dalam kelas (10 IPA 1, 10 IPA 2) serta menugaskan Wali Kelas.</li>\r\n<li><strong>Bahan Ajar &amp; Bank Soal:</strong> Repositori digital tempat guru mengunggah materi pelajaran (Video/PDF) dan meracik soal ujian (Pilihan Ganda/Esai). Soal dapat diimpor massal menggunakan Excel.</li>\r\n<li><strong>Penugasan &amp; Ujian (CBT):</strong> Panel pengaturan jadwal ujian. Di sinilah guru menekan tombol wajib (<em>Toggle</em>) <strong>Gunakan Safe Exam Browser</strong> agar aplikasi ponsel siswa terkunci saat ujian berlangsung.</li>\r\n<li><strong>Jurnal Mengajar &amp; Presensi:</strong> Formulir rekam jejak harian wajib bagi guru untuk mencatat ringkasan materi yang baru diajarkan serta menandai absensi kehadiran siswa di kelas tersebut.</li>\r\n</ul>\r\n<h3>4. Modul Keuangan &amp; Akuntansi</h3>\r\n<p>Dapur transaksi yang menangani arus kas masuk tanpa perlu pengecekan rekening koran manual.</p>\r\n<ul>\r\n<li><strong>Generate Tagihan Massal:</strong> Alat andalan Admin Keuangan untuk menerbitkan ratusan *invoice* SPP secara otomatis di awal bulan hanya dengan satu klik.</li>\r\n<li><strong>Monitor Pembayaran Real-time:</strong> Log transaksi instan yang terhubung ke Midtrans/Xendit. Status tagihan siswa akan berubah menjadi hijau (Lunas) tepat di detik saat uang ditransfer.</li>\r\n<li><strong>Penerimaan Tunai (Kasir):</strong> Menu khusus jika ada orang tua yang datang ke sekolah membayar secara tunai. Sistem otomatis mencetak kwitansi fisik.</li>\r\n<li><strong>Laporan Jurnal Akuntansi:</strong> Fitur ekspor (*Download to Excel/CSV*) yang merangkum debet/kredit penerimaan sekolah untuk diserahkan ke sistem ERP Yayasan Pusat.</li>\r\n</ul>\r\n<h3>5. Modul Pengaturan Hak Akses (RBAC)</h3>\r\n<p>Laci pengamanan sistem yang dikendalikan oleh Superadmin/Kepala Sekolah.</p>\r\n<ul>\r\n<li><strong>Role &amp; Permissions:</strong> Fitur untuk menugaskan peran secara spesifik. (Contoh: Menutup akses menu "Keuangan" bagi pengguna yang berstatus "Guru", dan membatasi agar Kepala Sekolah unit TK tidak bisa mengintip data siswa unit SD).</li>\r\n</ul>', '1', '2', '78', '2026-07-14 04:58:03', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('107', '24', 'Gambaran Nyata ERD (Entity Relationship Diagram)', '10-gambaran-nyata-erd-entity-relationship-diagram', '<p>Dokumen ini menyajikan <strong>Entity Relationship Diagram (ERD)</strong> logis dari tabel-tabel paling kritikal yang menyangga aplikasi ALAZHARAPPS. Meskipun secara fisik tabel-tabel ini terpisah di beberapa <em>database microservices</em> yang berbeda (seperti <code>account-service</code>, <code>student-service</code>, dan <code>transaction-service</code>), diagram ini menunjukkan bagaimana mereka saling berelasi secara bisnis.</p>\r\n<h3>Diagram Relasi Entitas Inti (Core ERD)</h3>\r\n<pre><code class="language-mermaid">\r\nerDiagram\r\n    %% Account Service (Manajemen Pengguna &amp; Akses)\r\n    USERS {\r\n        uuid id PK\r\n        string email\r\n        string password\r\n        boolean is_active\r\n        timestamp created_at\r\n    }\r\n    ROLES {\r\n        int id PK\r\n        string role_name\r\n    }\r\n    ROLE_LEVELS {\r\n        int id PK\r\n        string label\r\n    }\r\n    USER_HAS_ROLES {\r\n        uuid user_id FK\r\n        int role_id FK\r\n        int role_level_id FK\r\n        int school_id FK\r\n    }\r\n\r\n    %% Student Service (Master Data Sekolah)\r\n    SCHOOLS {\r\n        int id PK\r\n        string school_name\r\n        string address\r\n    }\r\n    CLASSES {\r\n        uuid id PK\r\n        int school_id FK\r\n        string class_name\r\n        string academic_year\r\n    }\r\n    STUDENTS {\r\n        uuid id PK\r\n        uuid user_id FK\r\n        string nisn\r\n        string full_name\r\n        string status\r\n    }\r\n    STUDENT_CLASSES {\r\n        uuid student_id FK\r\n        uuid class_id FK\r\n    }\r\n\r\n    %% Transaction Service (Keuangan)\r\n    INVOICES {\r\n        uuid id PK\r\n        uuid student_id FK\r\n        string invoice_number\r\n        decimal amount\r\n        string status "UNPAID / PAID"\r\n        date due_date\r\n    }\r\n    PAYMENTS {\r\n        uuid id PK\r\n        uuid invoice_id FK\r\n        string payment_method\r\n        decimal amount_paid\r\n        timestamp paid_at\r\n    }\r\n\r\n    %% Relasi (Relationships)\r\n    USERS ||--o{ USER_HAS_ROLES : "memiliki akses"\r\n    ROLES ||--o{ USER_HAS_ROLES : "ditugaskan ke"\r\n    ROLE_LEVELS ||--o{ USER_HAS_ROLES : "menentukan hierarki"\r\n    \r\n    SCHOOLS ||--o{ CLASSES : "memiliki"\r\n    SCHOOLS ||--o{ USER_HAS_ROLES : "mengisolasi data (tenant)"\r\n    \r\n    USERS ||--o| STUDENTS : "terhubung sebagai (jika role murid/ortu)"\r\n    CLASSES ||--o{ STUDENT_CLASSES : "berisi"\r\n    STUDENTS ||--o{ STUDENT_CLASSES : "terdaftar di"\r\n    \r\n    STUDENTS ||--o{ INVOICES : "memiliki tagihan"\r\n    INVOICES ||--o{ PAYMENTS : "dibayar melalui"\r\n</code></pre>\r\n<h3>Penjelasan Relasi Kritis</h3>\r\n<ul>\r\n<li><strong>Isolasi Multi-Tenant (Multi-Sekolah):</strong> Tabel <code>USER_HAS_ROLES</code> bertindak sebagai jembatan yang menghubungkan Pengguna dengan Peran (Misal: Admin Keuangan), dan langsung mengikatnya ke <code>school_id</code> tertentu. Ini memastikan Admin SD tidak bisa melihat data SMP.</li>\r\n<li><strong>Pemisahan Akun &amp; Identitas:</strong> Tabel <code>USERS</code> hanya menyimpan <em>Email</em> dan <em>Password</em> untuk otentikasi (berada di <code>account-service</code>). Identitas aslinya (Nama, NISN, Golongan Darah) disimpan secara terpisah di tabel <code>STUDENTS</code> (berada di <code>student-service</code>). Relasi antar keduanya dijembatani oleh <code>user_id</code>.</li>\r\n<li><strong>Relasi Keuangan:</strong> Tabel <code>INVOICES</code> (Tagihan SPP) menempel langsung ke <code>STUDENTS</code> (menggunakan <code>student_id</code>), bukan ke orang tua. Satu tagihan (misal SPP Juli) bisa dilunasi melalui beberapa kali cicilan <code>PAYMENTS</code> (meskipun pada ALAZHARAPPS mayoritas adalah lunas penuh via <em>Virtual Account</em>).</li>\r\n</ul>', '1', '2', '17', '2026-07-14 05:03:03', '2026-07-15 04:42:15');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('108', '29', 'Skenario Penerimaan Murid Baru (PPDB End-to-End)', 'skenario-penerimaan-murid-baru-ppdb-end-to-end', '<p>Artikel ini mendokumentasikan secara rinci perjalanan alur <strong>Penerimaan Murid Baru (PMB) End-to-End</strong>, mulai dari tindakan Orang Tua di aplikasi Mobile hingga pemrosesan dokumen dan pembayaran di portal Backoffice. Alur di bawah ini mencerminkan logika bisnis aktual yang terprogram di dalam <em>student-service</em> dan <em>transaction-service</em>.</p>\n\n<h3>Diagram Urutan Skenario PMB (Sequence Diagram)</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant OTM as Orang Tua (Mobile)\n    participant BO as Backoffice (Web)\n    participant SYS as Sistem (Database)\n\n    %% Persiapan\n    Note over BO,SYS: Tahap A.1 Persiapan\n    BO->>SYS: Set Gelombang PMB & Tarif (UP/SPP)\n\n    %% Pendaftaran Awal\n    Note over OTM,SYS: Tahap A.2 Pendaftaran Awal\n    OTM->>SYS: Daftar Anak via Aplikasi\n    SYS-->>OTM: Buat Record: Status ANIMO\n    SYS-->>OTM: Terbitkan Tagihan Formulir Pendaftaran\n    OTM->>SYS: Bayar Tagihan Formulir (via QRIS/VA)\n    OTM->>SYS: Lengkapi Identitas Asal Sekolah & Profil\n\n    %% Ujian\n    Note over OTM,BO: Tahap A.3 Ujian Masuk\n    BO->>SYS: Verifikasi Data & Generate Kartu Ujian\n    SYS-->>OTM: Kirim Kartu Ujian ke Aplikasi (PDF)\n    OTM->>BO: Anak Ikut Ujian (Hadir Membawa Kartu)\n\n    %% Penilaian & Kelulusan\n    Note over OTM,BO: Tahap A.4 Penilaian & Kelulusan\n    BO->>SYS: Upload Nilai (Excel Template) & Submit Kelulusan\n    SYS-->>OTM: Push Notification: "LULUS" & Kirim S&K Uang Pangkal\n    OTM->>SYS: Menyetujui S&K (Klik Setuju di Aplikasi)\n\n    %% Percabangan Pembayaran\n    alt A.5.a Jalur Reguler (Lunas)\n        SYS-->>OTM: Muncul Tagihan Uang Pangkal (Penuh)\n        OTM->>SYS: Bayar Lunas UP\n        SYS->>SYS: Ubah Record: MURID = AKTIF\n    else A.5.b Jalur Cicilan\n        OTM->>BO: Datang ke Sekolah (Mengajukan Skema Cicilan)\n        BO->>SYS: Admin Memproses Permohonan Angsuran\n        opt Jika Cicilan > 3 Kali\n            SYS->>BO: Request Approval Direktorat Keuangan\n        end\n        SYS-->>OTM: Tagihan UP Termin 1 (Min 50%)\n        OTM->>SYS: Bayar UP Termin 1\n        SYS->>SYS: Ubah Record: MURID = AKTIF\n    end\n</code></pre>\n\n<h3>A. Alur PMB (Penerimaan Murid Baru) Secara Detail</h3>\n<p>Bayangkan ini seperti funnel/corong — dari banyak pendaftar, hanya yang lolos & bayar yang akhirnya jadi murid resmi. Terdapat dua kemungkinan jalur pembayaran: <strong>Tanpa Cicilan (Reguler)</strong> dan <strong>Dengan Cicilan</strong>. Kedua jalur ini sama persis di awal, dan baru bercabang setelah calon murid dinyatakan lulus ujian.</p>\n\n<h4>A.1 Tahap Persiapan (dilakukan Backoffice/Sekolah)</h4>\n<ol>\n    <li><strong>Setting Komponen Biaya & Gelombang Pendaftaran:</strong> Sebelum pendaftaran dibuka, tim Backoffice sekolah menyiapkan dua hal di sistem:\n        <ul>\n            <li>Komponen Uang Pangkal dan Uang Sekolah (SPP) beserta rinciannya.</li>\n            <li><strong>GELOMBANG_PMB</strong> — periode pendaftaran (tanggal buka/tutup) per jenjang dan TAHUN_AJARAN.</li>\n        </ul>\n    </li>\n</ol>\n\n<h4>A.2 Tahap Pendaftaran Awal (dilakukan Orang Tua/Murid — OTM)</h4>\n<ol start="2">\n    <li><strong>Calon murid daftar (Status: Animo):</strong> Orang tua melakukan pendaftaran awal melalui aplikasi &rarr; data masuk ke tabel CALON_MURID dengan status awal <em>Animo</em>.</li>\n    <li><strong>Bayar Uang Formulir (Gerbang Pertama):</strong> Sebelum lanjut ke tahap berikutnya, calon murid wajib membayar Uang Formulir melalui menu Tagihan di aplikasi (metode QRIS atau lainnya). Kalau belum bayar, status akan "macet" di sini dan tidak bisa lanjut.</li>\n    <li><strong>Lengkapi Identitas:</strong> Setelah formulir lunas, OTM melengkapi data Asal Sekolah dan Profil Murid secara menyeluruh, lalu mengajukan data tersebut untuk diverifikasi sekolah.</li>\n</ol>\n\n<h4>A.3 Tahap Ujian Masuk</h4>\n<ol start="5">\n    <li><strong>Sekolah mengirimkan Kartu Ujian:</strong> Setelah data disetujui, Backoffice memicu sistem untuk mengirimkan Kartu Ujian ke akun OTM.</li>\n    <li><strong>OTM mendapatkan kartu & anak mengikuti ujian:</strong> OTM mengunduh Kartu Peserta Ujian dari aplikasi (wajib ditunjukkan saat ujian berlangsung), lalu anak mengikuti tes sesuai jadwal.</li>\n</ol>\n\n<h4>A.4 Tahap Penilaian & Pengumuman Kelulusan (dilakukan Backoffice)</h4>\n<ol start="7">\n    <li><strong>Input & Upload Nilai:</strong> Tim Backoffice men-download template nilai dari sistem, mengisi hasil ujian sesuai format, lalu mengunggah (upload) kembali nilai tersebut.</li>\n    <li><strong>Meluluskan & Mengirim Notifikasi:</strong> Calon murid yang memenuhi syarat diluluskan (submit kelulusan) di sistem, lalu notifikasi kelulusan otomatis dikirim ke OTM melalui Push Notification/WhatsApp.</li>\n</ol>\n<p><em>Di titik inilah alur mulai bercabang menjadi dua jalur, tergantung skema pembayaran Uang Pangkal yang dipilih OTM: Tanpa Cicilan atau Dengan Cicilan.</em></p>\n\n<h4>A.5.a Jalur Tanpa Cicilan — Pembayaran Uang Pangkal (Gerbang Kedua)</h4>\n<ol start="9">\n    <li><strong>Terima notifikasi & Syarat Ketentuan UP:</strong> OTM menerima notifikasi lulus ujian sekaligus notifikasi syarat & ketentuan Uang Pangkal (UP). OTM membuka menu tersebut untuk melihat komponen biaya UP, lalu menekan Setuju dan menerima file PDF rincian biaya.</li>\n    <li><strong>Bayar Uang Pangkal secara penuh:</strong> Tagihan UP muncul di menu Tagihan aplikasi. OTM membayar komponen UP secara lunas sekaligus.</li>\n    <li><strong>Status berubah menjadi Aktif:</strong> Setelah pembayaran terkonfirmasi oleh <em>Payment Gateway</em>, sistem membuat record baru di tabel MURID dengan status <strong>Aktif</strong>, dan siswa resmi terdaftar.</li>\n</ol>\n\n<h4>A.5.b Jalur Dengan Cicilan — Pengajuan Angsuran Uang Pangkal</h4>\n<ol start="9">\n    <li><strong>Ajukan cicilan langsung ke sekolah:</strong> Sama seperti jalur reguler, OTM menerima notifikasi syarat & ketentuan UP dan menekan Setuju. Namun jika OTM ingin mencicil, OTM harus datang langsung ke sekolah (Tata Usaha) untuk mengajukan permohonan skema angsuran — proses ini dilakukan secara luring/tatap muka, bukan melalui aplikasi.</li>\n    <li><strong>Persetujuan angsuran:</strong> Tim Backoffice sekolah memproses permohonan sesuai ketentuan jumlah angsuran yang ditetapkan Yayasan. <strong>Aturan Khusus:</strong> Jika permohonan lebih dari 3 kali angsuran, permohonan diteruskan secara sistem ke Direktorat Keuangan untuk mendapat persetujuan (approval) khusus sebelum skema cicilan berlaku.</li>\n    <li><strong>Pembayaran bertahap (minimal 50% di termin pertama):</strong> Setelah disetujui, tagihan UP muncul di menu Tagihan yang sudah disesuaikan dengan jadwal cicilan. Setelah OTM membayar termin pertama, status anak akan berubah menjadi <strong>Aktif</strong>.</li>\n</ol>', '1', '2', '4', '2026-07-15 00:41:00', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('109', '29', 'Skenario Otentikasi, Registrasi, dan Lupa PIN (Mobile)', 'skenario-otentikasi-registrasi-dan-lupa-pin-mobile', '<p>Artikel ini membedah alur logika di balik layar untuk proses <strong>Otentikasi, Registrasi, dan Pemulihan Akun</strong> pada aplikasi Mobile ALAZHARAPPS. Alur ini dikendalikan sepenuhnya oleh <code>account-service</code> di sisi backend, yang berintegrasi dengan pihak ketiga (Fonnte/Qontak) untuk pengiriman pesan WhatsApp.</p>\n\n<h3>Diagram Urutan: Registrasi & Login Mobile</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant OTM as Pengguna (Mobile)\n    participant ACC as Account Service (Backend)\n    participant WA as WhatsApp Gateway (Fonnte)\n    participant DB as Database (PostgreSQL)\n\n    %% Fase Pengecekan\n    OTM->>ACC: Input Nomor HP (WhatsApp)\n    ACC->>DB: Cek eksistensi nomor HP\n    \n    alt Jika Nomor Belum Terdaftar (Registrasi Baru)\n        DB-->>ACC: Data tidak ditemukan\n        ACC-->>OTM: Prompt: "Nomor Belum Terdaftar, Lanjut Daftar?"\n        OTM->>ACC: Input Nama Lengkap & Email\n        ACC->>DB: Generate & Simpan OTP Sementara\n        ACC->>WA: Trigger pengiriman OTP\n        WA-->>OTM: Pesan WA: "Kode Rahasia OTP Anda: 1234"\n        OTM->>ACC: Input 4 Digit OTP\n        ACC->>DB: Validasi OTP\n        DB-->>ACC: OTP Valid\n        ACC-->>OTM: Prompt: Buat 6 Digit PIN\n        OTM->>ACC: Buat & Konfirmasi 6 Digit PIN\n        ACC->>DB: Hash PIN (Bcrypt) & Simpan Akun Baru\n        DB-->>ACC: Akun Created\n        ACC-->>OTM: Registrasi Berhasil! Diarahkan ke Login\n    else Jika Nomor Sudah Terdaftar (Login)\n        DB-->>ACC: Data ditemukan\n        ACC-->>OTM: Tampilkan Layar Input PIN\n        OTM->>ACC: Input 6 Digit PIN (Atau Biometrik)\n        ACC->>DB: Verifikasi Hash PIN\n        \n        alt PIN Benar\n            ACC->>ACC: Generate JWT Access Token\n            ACC-->>OTM: Login Sukses (Simpan Token & Masuk Beranda)\n        else PIN Salah / Lupa PIN\n            ACC-->>OTM: Error: "PIN Salah"\n            OTM->>ACC: Klik "Lupa PIN"\n            ACC->>WA: Kirim OTP Reset via WhatsApp\n            WA-->>OTM: Pesan WA: "Kode Reset PIN: 5678"\n            OTM->>ACC: Verifikasi OTP & Buat PIN Baru\n        end\n    end\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Sistem otentikasi ALAZHARAPPS dirancang tanpa kata sandi (<em>passwordless</em>) berbasis teks biasa, melainkan menggunakan kombinasi <strong>Nomor WhatsApp (sebagai identitas utama)</strong> dan <strong>6-Digit PIN (sebagai kunci brankas)</strong>, meniru standar keamanan aplikasi perbankan digital (Fintech).</p>\n\n<h4>1. Deteksi Cerdas (Smart Detection)</h4>\n<p>Layar pertama yang dihadapi pengguna hanya meminta satu input: <strong>Nomor Handphone</strong>. Saat pengguna menekan "Selanjutnya", aplikasi mobile memanggil <em>endpoint</em> pengecekan (<code>/account/check</code>). Sistem backend secara otomatis mendeteksi apakah nomor ini harus diarahkan ke alur Registrasi (jika baru) atau alur Login (jika lama).</p>\n\n<h4>2. Alur Registrasi & Pengamanan OTP</h4>\n<ul>\n    <li><strong>Verifikasi Identitas:</strong> Untuk mencegah pembuatan akun palsu, pengguna wajib memasukkan kode OTP (<em>One Time Password</em>). Backend ALAZHARAPPS akan memanggil API Gateway WhatsApp (Fonnte/Qontak) untuk menembakkan pesan berisi kode 4 digit ke nomor pengguna.</li>\n    <li><strong>Pembuatan PIN:</strong> Setelah OTP terkonfirmasi, pengguna diwajibkan membuat 6 digit PIN. PIN ini tidak disimpan dalam bentuk teks (<em>plain text</em>), melainkan diacak (<em>hashing</em>) menggunakan algoritma kriptografi <code>Bcrypt</code> sebelum masuk ke dalam PostgreSQL.</li>\n</ul>\n\n<h4>3. Alur Login & Token JWT</h4>\n<ul>\n    <li>Jika pengguna sudah terdaftar, mereka hanya perlu memasukkan PIN 6 digit.</li>\n    <li><strong>Dukungan Biometrik:</strong> Pada <em>login</em> selanjutnya, pengguna dapat mengaktifkan login Biometrik (Sidik Jari / Face ID). Secara teknis, aplikasi genggam akan menggunakan sensor perangkat keras ponsel untuk memvalidasi sidik jari. Jika cocok, ponsel secara lokal "mengingat" dan menembakkan kredensial (atau token sesi) ke server tanpa perlu mengetik PIN lagi.</li>\n    <li><strong>JWT (JSON Web Token):</strong> Jika PIN cocok, <em>account-service</em> akan menerbitkan JWT (Token Akses). Token ini memuat <strong>Level Peran (Role Level)</strong> pengguna (Misalnya: <code>RoleLevelOrangTua = 12</code>). Mulai saat ini, setiap kali pengguna membuka menu Tagihan atau Rapor, aplikasi akan melampirkan Token ini di <em>Header HTTP</em> sebagai tiket masuk yang sah.</li>\n</ul>\n\n<h4>4. Alur Pemulihan (Reset PIN)</h4>\n<p>Mekanisme pemulihan dibuat mandiri (<em>Self-Service</em>) agar tidak membebani Tata Usaha sekolah. Jika pengguna menekan "Lupa PIN", sistem akan mengulang siklus pengiriman OTP ke WhatsApp. Setelah tervalidasi, pengguna diizinkan menimpa (<em>override</em>) PIN lama mereka di database dengan PIN yang baru.</p>', '1', '2', '5', '2026-07-15 00:41:00', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('110', '29', 'Skenario Keuangan, Penagihan & Webhook (Billing Cycle)', 'skenario-keuangan-penagihan-webhook-billing-cycle', '<p>Artikel ini mendokumentasikan alur penyelesaian transaksi keuangan, mulai dari <em>Generate</em> Tagihan Massal oleh pihak sekolah (Backoffice) hingga rekonsiliasi pembayaran secara <em>Real-time</em> melalui Payment Gateway.</p>\n\n<h3>Diagram Urutan: Siklus Tagihan & Pembayaran (Billing Cycle)</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant KEU as Admin Keuangan (Backoffice)\n    participant TXN as Transaction Service\n    participant OTM as Orang Tua (Mobile)\n    participant PG as Payment Gateway (Third-Party)\n    participant DB as Database (PostgreSQL)\n\n    %% Fase Penerbitan Tagihan\n    KEU->>TXN: Klik "Generate SPP Bulan Ini"\n    TXN->>DB: Query seluruh Murid Aktif\n    TXN->>DB: Bulk Insert Data Tagihan (Status: UNPAID)\n    TXN-->>OTM: Kirim Push Notification (Firebase): "Tagihan Baru Muncul"\n\n    %% Fase Pembayaran\n    OTM->>TXN: Buka Menu Tagihan, Pilih SPP & Klik Bayar\n    TXN->>PG: Request Virtual Account / QRIS\n    PG-->>TXN: Return Nomor VA & Total Pembayaran\n    TXN-->>OTM: Tampilkan Nomor VA / QRIS di Layar HP\n    OTM->>PG: Transfer Dana via Bank/E-Wallet (M-Banking)\n\n    %% Fase Settlement & Real-time Update\n    PG->>TXN: Callback Webhook: Pembayaran Sukses (Status LUNAS)\n    TXN->>DB: Update Status Tagihan = PAID & Simpan Jurnal\n    TXN->>TXN: Eksekusi Event-Bus Settlement\n    TXN-->>OTM: Push Notification: "Terima Kasih, Pembayaran Berhasil"\n    \n    %% Sinkronisasi Laporan\n    KEU->>DB: Tarik Laporan Realisasi Pendapatan (Real-time)\n    DB-->>KEU: Data Dashboard Update\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Sistem ini dirancang untuk menghapus beban rekonsiliasi manual. Peran utama ada di <code>transaction-service</code> yang bertindak sebagai jembatan antara aplikasi dan Pihak Ketiga (Bank/Payment Gateway).</p>\n\n<h4>1. Penerbitan Tagihan Otomatis / Massal</h4>\n<ul>\n    <li>Proses dimulai oleh Administrator Keuangan (atau secara otomatis melalui <em>Cron Job / Scheduler</em>) pada tanggal tertentu setiap bulannya.</li>\n    <li>Sistem (backend) tidak lagi membuat tagihan satu per satu, melainkan menggunakan mekanisme <strong>Bulk Insert</strong> untuk ribuan murid sekaligus. Hal ini memangkas waktu pemrosesan dari jam menjadi hanya beberapa detik.</li>\n    <li>Sistem menggunakan arsitektur antrean (<em>Message Broker / Goroutine Worker</em>) untuk menembakkan <em>Push Notification</em> massal agar server tidak tercekik (<em>Timeout</em>).</li>\n</ul>\n\n<h4>2. Proses Pembayaran di Aplikasi (Seamless Checkout)</h4>\n<ul>\n    <li>Saat Orang Tua Murid (OTM) membuka notifikasi, tagihan akan otomatis muncul di <strong>Menu Tagihan</strong>.</li>\n    <li>Pengguna dapat langsung menekan tombol "Bayar". Di sini, <code>transaction-service</code> bertindak meminta <em>Virtual Account</em> (VA) atau kode QRIS unik langsung ke Payment Gateway (seperti Midtrans/Xendit) secara dinamis. Opsi metode pembayaran menjadi tak terbatas tanpa sistem sekolah perlu membuka saluran <em>Host-to-Host</em> ke masing-masing bank.</li>\n</ul>\n\n<h4>3. Rekonsiliasi Real-Time (Webhook Callback)</h4>\n<ul>\n    <li><strong>Kunci utama otomatisasi ada di sini:</strong> Ketika orang tua mentransfer dana dari M-Banking mereka, uang akan masuk ke Payment Gateway. Detik itu juga, Payment Gateway menembakkan HTTP POST Request (disebut <em>Webhook / Callback</em>) ke titik akhir (<em>endpoint</em>) milik <code>transaction-service</code>.</li>\n    <li>Sistem memvalidasi keabsahan <em>Webhook</em> (melalui tanda tangan rahasia / <em>Signature Key</em>), lalu <strong>tanpa campur tangan manusia</strong>, mengubah status tagihan di tabel database dari <code>UNPAID</code> menjadi <code>PAID</code>.</li>\n    <li>Sistem juga langsung menembakkan notifikasi pembayaran berhasil ke ponsel orang tua sebagai tanda terima (Kwitansi Digital).</li>\n</ul>\n\n<h4>4. Single Source of Truth bagi Manajemen</h4>\n<p>Karena setiap status transaksi (Sukses, Pending, Expired) selalu tersinkronisasi di satu <em>database</em> terpusat, fitur Dasbor Keuangan di portal Backoffice akan menampilkan angka realisasi pendapatan yang 100% akurat dan ter-<em>update</em> setiap detik tanpa perlu penarikan (<em>download</em>) mutasi rekening koran manual.</p>', '1', '2', '6', '2026-07-15 00:41:01', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('111', '29', 'Skenario Akademik dan Ujian (LMS & CBT)', 'skenario-akademik-dan-ujian-lms-cbt', '<p>Artikel ini menjelaskan skenario pembelajaran dan evaluasi akademik secara digital. Fokus utama pada skenario ini adalah eksekusi ujian mandiri (Computer Based Test / CBT) melalui sistem <strong>Learning Management System (LMS)</strong> di Backoffice dan Aplikasi Genggam Siswa dengan fitur keamanan tinggi (<em>Safe Exam Browser</em>).</p>\n\n<h3>Diagram Urutan: Skenario Ujian Akademik (LMS & CBT)</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant GRU as Guru (Backoffice)\n    participant LMS as LMS Service (Backend)\n    participant SIS as Siswa (Mobile)\n    participant SEB as Safe Exam Browser (Device)\n    participant DB as Database (PostgreSQL)\n\n    %% Fase Persiapan\n    GRU->>LMS: Unggah Soal Ujian (Bank Soal)\n    GRU->>LMS: Atur Jadwal, Durasi & Kelas Peserta\n    LMS->>DB: Simpan Jadwal & Metadata Ujian\n    LMS-->>SIS: Push Notification: "Ujian Matematika Dimulai Besok"\n\n    %% Fase Pelaksanaan Ujian (CBT)\n    SIS->>LMS: Buka Aplikasi, Masuk Menu Ujian CBT\n    LMS->>DB: Validasi Jadwal Ujian (Sedang Berlangsung?)\n    \n    alt Waktu Belum Tiba\n        LMS-->>SIS: Tampilkan Hitung Mundur (Countdown)\n    else Waktu Ujian Aktif\n        LMS-->>SIS: Izinkan Akses Soal & Token Ujian\n        SIS->>SEB: Memicu Mode Lockdown (Kunci Layar Ponsel)\n        SEB-->>SIS: "Anda tidak dapat keluar layar selama ujian berlangsung"\n        SIS->>LMS: Mengirim Jawaban (Auto-Save per Soal)\n        LMS->>DB: Simpan Jawaban Sementara\n    end\n\n    %% Fase Penyelesaian & Penilaian\n    alt Siswa Menekan "Selesai" ATAU Waktu Habis\n        SIS->>LMS: Submit Seluruh Lembar Jawaban\n        SEB->>SIS: Matikan Mode Lockdown\n        LMS->>LMS: Auto-Grader (Kalkulasi Nilai Pilihan Ganda)\n        LMS->>DB: Simpan Nilai Akhir\n    end\n    \n    %% Sinkronisasi Laporan\n    GRU->>LMS: Buka Menu Rekap Nilai Ujian\n    LMS->>DB: Tarik Nilai Hasil CBT\n    LMS-->>GRU: Tampilkan Tabel Laporan Nilai Kelas\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Ekosistem <strong>LMS (Learning Management System)</strong> ALAZHARAPPS menggantikan siklus ujian konvensional berbasis kertas, dengan penekanan pada integritas ujian agar tidak mudah dicurangi oleh murid ketika dilakukan secara digital.</p>\n\n<h4>1. Sinkronisasi Data Master Akademik</h4>\n<p>Guru tidak perlu mengelola daftar siswa secara manual. <code>lms-course-service</code> secara otomatis menarik data rombongan belajar (rombel/kelas) dan penugasan guru dari <code>school-service</code>, sehingga pembuatan ujian otomatis langsung terdistribusi ke murid yang tepat.</p>\n\n<h4>2. Persiapan Ujian Terpusat</h4>\n<ul>\n    <li>Guru membuat butir soal melalui form interaktif di portal Backoffice, mendukung format teks, gambar, hingga persamaan matematika kompleks (LaTeX).</li>\n    <li>Guru menentukan <strong>Parameter Ketat:</strong> Tanggal mulai, tenggat waktu (<em>deadline</em>), durasi hitung mundur, dan syarat kelulusan (KKM).</li>\n</ul>\n\n<h4>3. Anti-Cheating dengan Safe Exam Browser (SEB)</h4>\n<p>Keamanan ujian di lingkungan <em>Mobile</em> (Android/iOS) adalah isu krusial. ALAZHARAPPS menanganinya dengan mengaktifkan mode penguncian layar (<em>Lockdown/Kiosk Mode</em>) saat sesi ujian berjalan:</p>\n<ul>\n    <li>Saat tombol "Mulai Ujian" ditekan, aplikasi seluler akan masuk ke mode layar penuh <em>(Full Screen)</em>.</li>\n    <li>Notifikasi dari aplikasi lain (seperti WhatsApp/Instagram) akan dibisukan atau diblokir.</li>\n    <li>Fitur tangkapan layar (<em>Screenshot</em>) maupun rekam layar dinonaktifkan secara paksa oleh sistem operasi (<em>Prevent Screen Capture</em>).</li>\n    <li>Siswa tidak dapat menekan tombol kembali (<em>Back button</em>) atau tombol beranda (<em>Home button</em>) untuk mencari jawaban di internet (<em>Googling</em>). Jika dipaksa, aplikasi dapat mendeteksi pelanggaran dan secara otomatis mendiskualifikasi ujian.</li>\n</ul>\n\n<h4>4. Auto-Save & Toleransi Jaringan (Resilience)</h4>\n<p>Aplikasi dirancang untuk wilayah dengan koneksi internet tak stabil. Jawaban murid tidak ditumpuk hingga akhir. Sistem akan terus menyimpan jawaban per nomor (<em>Auto-Save</em>) secara otomatis. Jika di tengah ujian kuota internet murid habis atau ponsel mati, murid dapat masuk kembali dan meneruskan tepat di soal terakhir yang mereka kerjakan (tanpa mengulang dari awal) asalkan durasi waktu (<em>timer</em>) masih ada.</p>\n\n<h4>5. Skoring Real-time (Auto-Grader)</h4>\n<p>Begitu murid mengirim (<em>submit</em>) lembar jawaban mereka, untuk jenis soal objektif (Pilihan Ganda), mesin (<em>Auto-Grader</em>) akan langsung menghitung total skor murid dan menyimpannya di <em>database</em>. Guru tak perlu memeriksa secara manual; hasilnya seketika itu juga muncul di lembar rekap nilai (<em>gradebook</em>) Backoffice.</p>', '1', '2', '7', '2026-07-15 00:41:01', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('112', '29', 'Skenario Presensi, Absensi Harian & Geofencing', 'skenario-presensi-absensi-harian-geofencing', '<p>Artikel ini menjabarkan alur kerja (workflow) pencatatan presensi (kehadiran) harian di lingkungan Yayasan Pesantren Islam Al-Azhar, baik untuk Guru/Pegawai maupun untuk Siswa, serta integrasinya dengan sistem pelaporan kepada Orang Tua.</p>\n\n<h3>Diagram Urutan: Skenario Presensi & Kehadiran</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant GRU as Guru/Pegawai (Mobile/Web)\n    participant STU as Student Service (Backend)\n    participant ACC as Account Service (Notifikasi)\n    participant OTM as Orang Tua (Mobile)\n    participant DB as Database (PostgreSQL)\n\n    %% Presensi Pegawai/Guru\n    Note over GRU,DB: Tahap A: Presensi Guru & Pegawai\n    GRU->>STU: Scan QR / Klik Tombol Hadir (Location GPS aktif)\n    STU->>STU: Validasi Jarak Geofencing (Radius Sekolah)\n    STU->>DB: Catat Waktu Masuk (Status: HADIR / TERLAMBAT)\n    STU-->>GRU: Berhasil Absen\n\n    %% Presensi Siswa oleh Wali Kelas\n    Note over GRU,OTM: Tahap B: Presensi Siswa di Kelas\n    GRU->>STU: Buka Daftar Hadir Kelas (Rombel)\n    GRU->>STU: Tandai Siswa (Hadir, Sakit, Izin, Alpa)\n    STU->>DB: Simpan Data Presensi Siswa\n    \n    %% Trigger Notifikasi Real-time\n    STU->>ACC: Trigger Event: Presensi Siswa Tersimpan\n    ACC->>ACC: Cek Pengaturan Notifikasi Orang Tua\n    ACC-->>OTM: Push Notification: "Ananda Budi telah Hadir di Sekolah pada 07:15"\n    \n    %% Rekapitulasi\n    Note over OTM,DB: Tahap C: Rekapitulasi & Pelaporan\n    OTM->>STU: Buka Menu Kehadiran Anak\n    STU->>DB: Kalkulasi Persentase Kehadiran Bulanan\n    DB-->>STU: Return Data Rekap (Grafik)\n    STU-->>OTM: Tampilkan Laporan Kehadiran\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Pencatatan presensi di kelola secara terpusat oleh <code>student-service</code>. Fitur ini dirancang untuk mendigitalisasi buku absensi konvensional dan memberikan kepastian (<em>peace of mind</em>) secara seketika (<em>real-time</em>) kepada orang tua.</p>\n\n<h4>1. Absensi Guru & Tenaga Kependidikan (Geofencing)</h4>\n<ul>\n    <li>Saat guru tiba di lingkungan sekolah, mereka menggunakan Aplikasi Mobile atau Web untuk melakukan <em>check-in</em>.</li>\n    <li><strong>Validasi Lokasi (Geofencing):</strong> Sistem tidak serta merta menerima absen. Aplikasi akan menarik titik koordinat GPS (Latitude/Longitude) perangkat dan mencocokkannya dengan koordinat gedung sekolah. Jika berada di luar radius yang diizinkan (misalnya > 50 meter), absensi akan ditolak.</li>\n    <li>Sistem secara otomatis membandingkan <em>timestamp</em> (waktu server) dengan jam masuk standar untuk memberikan penanda <strong>Tepat Waktu</strong> atau <strong>Terlambat</strong>.</li>\n</ul>\n\n<h4>2. Presensi Siswa di Kelas (Oleh Wali Kelas/Guru Mata Pelajaran)</h4>\n<ul>\n    <li>Di dalam kelas, guru membuka menu daftar hadir (Absensi Rombel) di aplikasi genggam atau laptop mereka.</li>\n    <li>Guru melakukan pemanggilan <em>(roll call)</em> dan menandai status masing-masing siswa (Hadir, Sakit, Izin, atau Alpa).</li>\n    <li>Jika ada siswa yang ditandai <strong>Sakit/Izin</strong>, guru dapat mengunggah bukti surat keterangan atau catatan (<em>Meeting Note</em> / Keterangan).</li>\n</ul>\n\n<h4>3. Notifikasi Cerdas & Otomatis</h4>\n<ul>\n    <li>Tepat di detik guru menekan tombol <strong>Simpan Absensi</strong>, <code>student-service</code> akan melemparkan instruksi (<em>Event Trigger</em>) ke <code>account-service</code>.</li>\n    <li>Sistem akan mencari ID perangkat (<em>Device Token</em>) milik orang tua dari siswa yang bersangkutan.</li>\n    <li>Sebuah <strong>Push Notification</strong> otomatis dikirimkan ke ponsel orang tua (Contoh: <em>"Ananda telah tiba dan terabsen di kelas pada 07:15"</em>). Fitur ini sangat diapresiasi oleh orang tua demi keamanan anak mereka.</li>\n</ul>\n\n<h4>4. Dasbor Rekapitulasi</h4>\n<ul>\n    <li>Data presensi tidak pernah dihapus dan menjadi rekam jejak permanen. Pada akhir semester, data ini secara otomatis diagregasi (dikalkulasi) dan di-<em>inject</em> langsung ke dalam nilai Rapor Digital di <code>report-service</code> tanpa perlu diketik ulang oleh Tata Usaha.</li>\n</ul>', '1', '2', '8', '2026-07-15 00:48:39', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('113', '29', 'Skenario Engine Notifikasi Terpusat (Broadcast & Worker)', 'skenario-engine-notifikasi-terpusat-broadcast-worker', '<p>Artikel ini membongkar rahasia dapur bagaimana ALAZHARAPPS menangani pengiriman ratusan ribu pesan pemberitahuan (<em>Broadcast/Push Notification</em>) ke ponsel orang tua tanpa menyebabkan aplikasi melambat atau <em>server crash</em>. Pusat dari orkestrasi ini adalah <code>account-service</code> yang didukung oleh arsitektur antrean (<em>Message Queue</em>).</p>\n\n<h3>Diagram Urutan: Skenario Broadcast & Push Notification</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant BO as Backoffice (Web)\n    participant ACC as Account Service\n    participant MQ as Redis/Event Bus (Antrean)\n    participant FCM as Firebase Cloud Messaging\n    participant WA as WhatsApp Gateway (Qontak/Fonnte)\n    participant OTM as Orang Tua (Mobile)\n\n    %% Fase Trigger Broadcast\n    BO->>ACC: Submit "Kirim Pengumuman Libur" (ke 5.000 Siswa)\n    ACC->>MQ: Terbitkan 5.000 Tugas (Publish Event)\n    ACC-->>BO: Response Cepat: "Pengumuman sedang diproses"\n    \n    %% Fase Asinkron (Latar Belakang)\n    Note over ACC,MQ: Background Worker mengambil tugas satu per satu\n    \n    loop Setiap Pesan di Antrean\n        MQ->>ACC: Konsumsi Pesan (Consume)\n        ACC->>ACC: Format Pesan & Ekstrak Device Token / No WA\n        \n        par Pengiriman Paralel\n            ACC->>FCM: API Call: Send Push Notif\n            FCM-->>OTM: Muncul Pop-up di Layar HP\n        and\n            ACC->>WA: API Call: Send WhatsApp Message\n            WA-->>OTM: Pesan WA Masuk\n        end\n    end\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Mengirim 1 pesan WhatsApp membutuhkan waktu sekitar 1 detik. Jika sekolah mengirim 5.000 pengumuman kelulusan secara bersamaan menggunakan metode konvensional (sinkron), admin Backoffice harus menatap layar <em>loading</em> selama hampir 1,5 jam, dan server kemungkinan besar akan <em>timeout</em>. Untuk mencegah bencana tersebut, ALAZHARAPPS menggunakan metode <strong>Asinkron (Asynchronous Worker)</strong>.</p>\n\n<h4>1. Pemisahan Tugas (Fire and Forget)</h4>\n<ul>\n    <li>Saat Admin Sekolah menekan tombol <strong>Kirim Pengumuman</strong> di Backoffice, sistem <code>account-service</code> <strong>TIDAK</strong> langsung menghubungi pihak ketiga (Firebase atau WhatsApp).</li>\n    <li>Sebaliknya, sistem hanya menaruh daftar 5.000 tugas pengiriman tersebut ke dalam sebuah keranjang antrean berkecepatan tinggi (seperti Redis Streams atau Event Mediator lokal).</li>\n    <li>Karena hanya menyimpan data ke <em>memory</em>, proses ini selesai dalam hitungan milidetik. Sistem langsung memberikan respons "Berhasil" ke layar admin, membebaskan admin untuk mengerjakan tugas lain.</li>\n</ul>\n\n<h4>2. Background Worker (Pekerja Latar Belakang)</h4>\n<ul>\n    <li>Di belakang layar, terdapat <em>Goroutine Worker</em> (kumpulan <em>thread</em> kecil spesifik Golang) yang tidak pernah tidur. Mereka terus-menerus memantau keranjang antrean tadi.</li>\n    <li>Worker ini akan mengambil tugas (misal 50 pesan sekaligus) dan mulai memprosesnya secara paralel (<em>concurrency</em>).</li>\n</ul>\n\n<h4>3. Integrasi Pihak Ketiga (Firebase & WhatsApp)</h4>\n<ul>\n    <li><strong>Firebase Cloud Messaging (FCM):</strong> Untuk <em>Push Notification</em> (notifikasi pop-up berlambang lonceng di atas layar HP). Worker akan mencari <code>fcm_token</code> milik orang tua di database, menyusun format JSON (Judul, Isi Pesan, Gambar), dan menembakkannya ke server Google Firebase.</li>\n    <li><strong>WhatsApp Gateway (Fonnte/Qontak):</strong> Untuk notifikasi yang bersifat sangat krusial (seperti Tagihan Telat atau OTP Login), sistem akan merangkai pesan teks dan menembakkannya ke penyedia layanan WhatsApp Resmi. <em>Rate Limiting</em> diterapkan di sini agar nomor pengirim tidak diblokir oleh pihak Meta/WhatsApp karena dianggap <em>Spam</em>.</li>\n</ul>\n\n<h4>4. Penanganan Kegagalan (Retry Mechanism)</h4>\n<ul>\n    <li>Jika server WhatsApp Gateway sedang mati atau koneksi ke Firebase terputus, pesan yang gagal <strong>tidak akan hilang</strong>.</li>\n    <li>Worker akan menandai pesan tersebut sebagai "Gagal", dan memasukkannya kembali ke dalam antrean untuk dicoba lagi (<em>Retry</em>) beberapa menit kemudian (<em>Exponential Backoff</em>).</li>\n</ul>', '1', '2', '9', '2026-07-15 00:48:39', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('114', '29', 'Skenario Mutasi Akademik dan Kenaikan Kelas', 'skenario-mutasi-akademik-dan-kenaikan-kelas', '<p>Artikel ini mendokumentasikan skenario tahunan yang paling krusial di sistem pendidikan, yaitu proses penutupan Tahun Ajaran, mutasi status siswa (Naik Kelas, Lulus, atau Pindah), dan persiapannya menuju Tahun Ajaran Baru. Orkestrasi ini melibatkan interaksi intensif antara <code>report-service</code>, <code>student-service</code>, dan <code>transaction-service</code>.</p>\n\n<h3>Diagram Urutan: Mutasi & Kenaikan Kelas Akhir Tahun</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant GRU as Wali Kelas (Web)\n    participant RPT as Report Service (Rapor)\n    participant STU as Student Service (Data Pokok)\n    participant TXN as Transaction Service (Keuangan)\n    participant DB as Database (PostgreSQL)\n\n    %% Fase Penilaian Akhir\n    Note over GRU,RPT: Tahap A: Evaluasi Akademik\n    GRU->>RPT: Finalisasi Pengisian Nilai Rapor Semester Genap\n    RPT->>DB: Validasi Kelengkapan Nilai & Ekstrakurikuler\n    RPT-->>GRU: Rapor Terkunci (Locked) & Siap Cetak\n    \n    %% Fase Kenaikan Kelas / Mutasi\n    Note over GRU,STU: Tahap B: Eksekusi Kenaikan Kelas (Massal)\n    GRU->>STU: Submit Keputusan: Kumpulan Siswa "Naik Kelas" / "Lulus"\n    STU->>DB: Update Status Akademik Siswa\n    STU->>DB: Putus Relasi Siswa dari Rombel Lama\n    STU->>DB: Petakan Siswa ke Rombel Tahun Ajaran Baru\n    STU-->>GRU: Mutasi Rombel Berhasil\n\n    %% Fase Keuangan\n    Note over STU,TXN: Tahap C: Implikasi Keuangan\n    STU->>TXN: Trigger Event (Siswa Masuk Tahun Ajaran Baru)\n    TXN->>DB: Tarik Tarif SPP / Daftar Ulang Kelas Baru\n    TXN->>DB: Generate Tagihan Daftar Ulang (Status UNPAID)\n    TXN-->>STU: Status Tagihan Tersinkronisasi\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Kenaikan kelas bukan sekadar mengubah angka kelas (misal dari Kelas 1 menjadi Kelas 2), melainkan sebuah operasi relasional yang mengubah sejarah akademik (<em>History</em>) dan implikasi finansial murid tersebut.</p>\n\n<h4>1. Finalisasi Penilaian (Report Service)</h4>\n<ul>\n    <li>Wali kelas memastikan seluruh guru mata pelajaran telah menginput nilai ujian akhir semester.</li>\n    <li>Wali kelas memasukkan catatan tambahan (prestasi, presensi akhir, dan catatan perilaku).</li>\n    <li>Setelah Rapor difinalisasi (<em>Locked</em>), data menjadi permanen (<em>read-only</em>) untuk dicetak sebagai dokumen legal dan diunggah ke aplikasi Mobile orang tua. Keputusan Naik/Tinggal Kelas ditentukan di titik ini.</li>\n</ul>\n\n<h4>2. Pemindahan Rombongan Belajar (Student Service)</h4>\n<ul>\n    <li>Sistem mengakomodasi eksekusi massal (<em>Bulk Mutation</em>). Wali kelas atau Admin Sekolah menyeleksi murid-murid yang "Naik Kelas".</li>\n    <li>Sistem <code>student-service</code> akan memutus relasi siswa dari Rombel (Rombongan Belajar) di Tahun Ajaran Genap (lama), dan mengaitkannya ke Rombel di Tahun Ajaran Ganjil (baru).</li>\n    <li><strong>Alur Kelulusan:</strong> Jika murid berada di tingkat akhir (Kelas 6, 9, atau 12), status mereka diubah menjadi <strong>ALUMNI</strong>. Mereka tidak akan dipetakan ke Rombel baru, dan otomatis dihentikan dari siklus penagihan biaya pendidikan selanjutnya.</li>\n</ul>\n\n<h4>3. Otomatisasi Tagihan Tahun Baru (Transaction Service)</h4>\n<ul>\n    <li>Transisi tahun ajaran baru biasanya disertai dengan kewajiban pembayaran Daftar Ulang atau penyesuaian tarif SPP baru.</li>\n    <li>Begitu data murid dipindahkan ke Rombel baru oleh <code>student-service</code>, sebuah <em>Event Listener</em> (pendeteksi kejadian) di dalam <code>transaction-service</code> akan menyala.</li>\n    <li>Mesin keuangan ini secara otomatis mendeteksi, <em>"Oh, Budi sekarang Kelas 2, tarif SPP-nya sekian"</em>. Sistem langsung menerbitkan faktur tagihan untuk tahun ajaran baru di latar belakang tanpa Admin Keuangan perlu mengetik ulang daftar murid.</li>\n</ul>\n\n<h4>4. Konsistensi Sejarah (Data Lineage)</h4>\n<ul>\n    <li>Arsitektur database dirancang agar sejarah (<em>Track Record</em>) anak di kelas sebelumnya tidak tertimpa. Jika orang tua membuka aplikasi Mobile dan memilih filter "Tahun Ajaran Lalu", mereka tetap bisa melihat rapor, tagihan, dan daftar guru Budi saat ia masih berada di Kelas 1.</li>\n</ul>', '1', '2', '10', '2026-07-15 00:48:39', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('115', '29', 'Skenario Sinkronisasi Data Lintas Platform (ETL Process)', 'skenario-sinkronisasi-data-lintas-platform-etl-process', '<p>Artikel ini menjelaskan skenario di balik layar tentang bagaimana data dari sistem lama (<em>Legacy System</em> / SALAM) dipindahkan dan disinkronisasikan ke dalam ekosistem sistem baru ALAZHARAPPS tanpa mengganggu operasional sistem utama. Proses ini dikenal sebagai ETL (<em>Extract, Transform, Load</em>) yang dieksekusi menggunakan skrip Python otomatis.</p>\n\n<h3>Diagram Urutan: Sinkronisasi Data Lintas Platform (ETL)</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant CRN as Cron Scheduler (Linux)\n    participant ETL as ETL Worker (Python Script)\n    participant OLD as Legacy DB (SALAM)\n    participant NEW as PostgreSQL (ALAZHARAPPS)\n    participant RED as Redis Cache\n\n    %% Pemanggilan Skrip Otomatis\n    Note over CRN,ETL: Berjalan Otomatis Pukul 01:00 AM\n    CRN->>ETL: Jalankan Script Sinkronisasi\n\n    %% Tahap 1: EXTRACT (Penarikan)\n    Note over ETL,OLD: Tahap 1: EXTRACT (Ekstraksi)\n    ETL->>OLD: Query: Ambil data perubahan (Mutasi Siswa, Pembayaran) 24 jam terakhir\n    OLD-->>ETL: Return 10.000 Baris Data Mentah\n\n    %% Tahap 2: TRANSFORM (Transformasi)\n    Note over ETL: Tahap 2: TRANSFORM (Pembersihan Data)\n    ETL->>ETL: Format Ulang Data (Penyesuaian Struktur Kolom)\n    ETL->>ETL: Standarisasi Tipe Data (Tanggal, Angka)\n    ETL->>ETL: Filter Data Ganda/Kotor (Data Cleansing)\n\n    %% Tahap 3: LOAD (Pemuatan)\n    Note over ETL,RED: Tahap 3: LOAD (Penyimpanan ke Sistem Baru)\n    ETL->>NEW: Bulk Insert / Update Data Bersih (UPSERT)\n    NEW-->>ETL: Konfirmasi Data Tersimpan\n    ETL->>RED: Invalidate Cache (Hapus memori lama agar aplikasi refresh)\n    RED-->>ETL: Cache Cleared\n    \n    %% Pelaporan\n    ETL->>CRN: Laporan Selesai (Log Berhasil: 9.998, Gagal: 2)\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Infrastruktur ALAZHARAPPS yang mengusung <em>microservices</em> memiliki struktur <em>database</em> yang jauh berbeda dan terpisah-pisah dibandingkan dengan sistem monolitik SALAM yang lama. Untuk memastikan tidak ada data yang hilang selama masa transisi, atau jika ada sekolah yang masih memakai sebagian fitur di sistem lama, sebuah <strong>Pipa Data (Data Pipeline)</strong> sangat krusial.</p>\n\n<h4>1. Pemicu Otomatis (Cron Job Scheduler)</h4>\n<ul>\n    <li>Proses sinkronisasi data besar-besaran (massal) sangat memakan memori (RAM) dan CPU. Jika dilakukan pada jam kerja (pagi-siang), hal ini dapat menyebabkan aplikasi lambat (<em>lag</em>) saat diakses oleh pengguna.</li>\n    <li>Oleh karena itu, sistem operasi server menggunakan <code>cron job</code> untuk membangunkan skrip Python (ETL) secara otomatis pada jam-jam sunyi (misalnya pukul 01:00 dini hari setiap harinya).</li>\n</ul>\n\n<h4>2. Tahap Ekstraksi (Extract)</h4>\n<ul>\n    <li>Skrip Python akan terhubung secara aman ke <em>database</em> lama. Skrip ini hanya menarik data yang sifatnya baru ditambahkan atau diubah pada hari tersebut (disebut <em>Delta/Incremental Load</em>), bukan menarik seluruh data sekolah dari awal tahun. Hal ini membuat waktu penarikan sangat cepat.</li>\n</ul>\n\n<h4>3. Tahap Transformasi (Transform)</h4>\n<ul>\n    <li>Ini adalah tahap paling kompleks. Di sistem lama, kolom mungkin bernama <code>NAMA_MURID</code> bertipe teks biasa. Sedangkan di ALAZHARAPPS, kolomnya terpisah menjadi <code>first_name</code> dan <code>last_name</code>.</li>\n    <li>Skrip Python melakukan "penerjemahan bahasa" antar-database. Data yang kotor (misal: nomor HP berisi huruf) akan dibersihkan atau ditolak.</li>\n</ul>\n\n<h4>4. Tahap Pemuatan (Load) & Sinkronisasi Cache</h4>\n<ul>\n    <li>Data yang sudah rapi disuntikkan ke dalam <em>database</em> PostgreSQL masing-masing <em>microservices</em> (ke <code>student-service</code> atau <code>transaction-service</code>). Sistem menggunakan metode <em>UPSERT</em> (Update or Insert) &mdash; jika data anak sudah ada maka diperbarui, jika belum ada maka dibuatkan data baru.</li>\n    <li><strong>Sangat Penting:</strong> Karena ALAZHARAPPS membaca data dari <strong>Redis Cache</strong> (memori kecepatan tinggi agar aplikasi seluler terasa instan), skrip ETL <strong>WAJIB</strong> menghapus <em>cache</em> lama tersebut setelah menyuntikkan data baru. Dengan demikian, keesokan paginya saat orang tua membuka aplikasi, mereka langsung mendapatkan data tagihan/nilai terbaru (<em>fresh data</em>).</li>\n</ul>', '1', '2', '11', '2026-07-15 00:48:39', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('117', '29', 'Skenario Rekonsiliasi Pembayaran Manual (Settlement Upload)', 'skenario-rekonsiliasi-pembayaran-manual-settlement-upload', '<p>Artikel ini mendokumentasikan skenario penanganan "Pengecualian Pembayaran" (<em>Payment Exceptions</em>). Skenario ini terjadi ketika Orang Tua Murid tidak melakukan pembayaran melalui aplikasi (Virtual Account/QRIS otomatis), melainkan mentransfer langsung uang tunai ke rekening Yayasan (misal melalui Teller Bank atau mesin EDC). ALAZHARAPPS menangani hal ini melalui modul <strong>Manual Settlement & Rekonsiliasi Berbasis File (CSV/Excel)</strong>.</p>\n\n<h3>Diagram Urutan: Skenario Rekonsiliasi Bank Manual</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant OTM as Orang Tua / Wali\n    participant BNK as Pihak Bank (Teller/EDC)\n    participant ADM as Admin Keuangan (Backoffice)\n    participant TXN as Transaction Service\n    participant DB as Database (PostgreSQL)\n\n    %% Fase Transaksi Offline\n    Note over OTM,BNK: Transaksi di Luar Sistem\n    OTM->>BNK: Transfer Dana Langsung ke Rekening Yayasan\n    BNK-->>OTM: Berikan Struk Fisik Bukti Transfer\n    \n    %% Fase Penarikan Mutasi\n    Note over BNK,ADM: Tarik Mutasi Rekening (Harian/Mingguan)\n    ADM->>BNK: Download Mutasi (Koran Bank) format CSV/Excel\n    \n    %% Fase Pratinjau (Preview) Rekonsiliasi\n    Note over ADM,TXN: Proses di Portal Backoffice\n    ADM->>TXN: Upload File Mutasi CSV (Menu Rekonsiliasi)\n    TXN->>TXN: Parsing File (Ekstrak Nomor Referensi / VA / Nominal)\n    TXN->>DB: Pencocokan (Matching) Data Bank vs Data Tagihan (UNPAID)\n    TXN-->>ADM: Tampilkan Layar "Preview Settlement" (Valid/Invalid)\n    \n    %% Fase Eksekusi & Penyelesaian\n    alt Jika Data Matching (Sesuai)\n        ADM->>TXN: Klik "Proses Settlement"\n        TXN->>DB: Ubah Status Tagihan = PAID\n        TXN->>DB: Simpan Laporan Settlement (Settlement Report)\n        TXN-->>OTM: Push Notification: "Pembayaran Manual Diterima"\n    else Jika Data Tidak Cocok (Anomaly)\n        TXN-->>ADM: Tandai Baris Merah (Kekurangan Bayar / Referensi Salah)\n        ADM->>TXN: Lakukan Koreksi Manual (Dispute Resolution)\n    end\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Dalam operasional keuangan sekolah berskala besar, mustahil mengharapkan 100% orang tua menggunakan aplikasi. Seringkali dana miliaran rupiah masuk langsung ke rekening bank yayasan. Modul Rekonsiliasi di <code>transaction-service</code> diciptakan khusus untuk meringankan kerja Admin Keuangan agar tidak perlu mencontreng (mencocokkan) tagihan satu per satu secara manual.</p>\n\n<h4>1. Persiapan File Mutasi (Extract)</h4>\n<ul>\n    <li>Admin Keuangan tidak perlu menginput data pelunasan satu demi satu. Admin cukup mengunduh file mutasi rekening (berformat CSV atau Excel) langsung dari portal perbankan milik sekolah.</li>\n</ul>\n\n<h4>2. Proses Pratinjau Cerdas (Preview Settlement)</h4>\n<ul>\n    <li>Admin mengunggah file tersebut ke dalam portal Backoffice. Fungsi <code>PreviewSettlement</code> di dalam <code>transaction-service</code> akan bekerja membaca ribuan baris file Excel tersebut.</li>\n    <li>Sistem menggunakan algoritma pencocokan (<em>matching</em>) untuk mencari <strong>Nomor Virtual Account</strong>, <strong>Student Cost Code (Kode Biaya Siswa)</strong>, atau <strong>Nomor Induk</strong> yang tertera pada deskripsi transfer bank.</li>\n    <li>Setelah sistem selesai menghitung, layar Backoffice akan menampilkan tabel perbandingan: Sebelah kiri adalah uang yang masuk di bank, sebelah kanan adalah tagihan yang belum lunas (<em>UNPAID</em>) di database.</li>\n</ul>\n\n<h4>3. Penyelesaian Sengketa (Dispute & Anomaly Handling)</h4>\n<p>Ini adalah fitur paling krusial untuk mencegah kebocoran dana:</p>\n<ul>\n    <li><strong>Cocok (Matched):</strong> Jika nominal transfer bank persis sama dengan nominal tagihan SPP anak tersebut, sistem akan menandainya dengan warna hijau (Siap dieksekusi).</li>\n    <li><strong>Kekurangan Bayar (Underpaid):</strong> Jika tagihan Rp 1.000.000 namun transfer hanya Rp 900.000, sistem menandainya dengan warna kuning/merah. Admin harus memutuskan apakah menolak pelunasan atau membiarkan sisa Rp 100.000 menjadi piutang.</li>\n    <li><strong>Tidak Dikenali (Unknown):</strong> Uang masuk tanpa deskripsi (<em>blank</em>). Sistem akan meminta Admin untuk mencari siswa mana yang memiliki dana tersebut dan memasangkannya (<em>pairing</em>) secara manual di layar.</li>\n</ul>\n\n<h4>4. Finalisasi Kuitansi & Laporan</h4>\n<ul>\n    <li>Setelah Admin menekan tombol <strong>Proses Settlement</strong>, fungsi <code>CreateSettlement</code> akan berjalan.</li>\n    <li>Ribuan tagihan yang berstatus UNPAID akan secara serentak (<em>concurrent</em>) berubah menjadi PAID.</li>\n    <li>Sistem menyimpan riwayat eksekusi dalam bentuk <code>SettlementReport</code> untuk keperluan Audit Keuangan Yayasan di akhir tahun.</li>\n    <li>Walaupun orang tua membayar secara tunai/luring, sistem tetap menerbitkan Kuitansi Digital (berformat PDF via fungsi <code>DownloadReceiptsPDF</code>) dan mengirimkan notifikasi lunas ke aplikasi HP orang tua.</li>\n</ul>', '1', '2', '12', '2026-07-15 01:06:06', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('118', '25', 'Panduan Dasar Penggunaan Aplikasi Mobile (Orang Tua)', 'panduan-dasar-penggunaan-aplikasi-mobile-orang-tua', '<p>Artikel ini adalah panduan dasar operasional (SOP) khusus bagi <strong>Orang Tua Murid</strong> (Role Level 12) dalam menggunakan Aplikasi Mobile ALAZHARAPPS. Semua interaksi Orang Tua dengan sekolah dirancang agar dapat dilakukan dari genggaman tangan.</p>\n\n<h3>Diagram Perjalanan Pengguna (User Journey)</h3>\n<pre><code class="language-mermaid">\njourney\n    title Perjalanan Orang Tua Murid di ALAZHARAPPS\n    section 1. Onboarding (Awal)\n      Unduh Aplikasi: 5: Orang Tua\n      Login via No WA (OTP): 4: Orang Tua, Sistem\n      Buat PIN Keamanan: 5: Orang Tua\n    section 2. Pendaftaran (PMB)\n      Isi Formulir Anak: 4: Orang Tua\n      Bayar Uang Pangkal: 5: Orang Tua, Bank\n      Status Anak = Aktif: 5: Sistem\n    section 3. Rutinitas Harian\n      Terima Notif Presensi Anak: 5: Orang Tua, Sekolah\n      Cek Jadwal & Nilai: 4: Orang Tua\n      Bayar SPP Bulanan: 3: Orang Tua\n</code></pre>\n\n<h3>1. Skenario Onboarding & Login (Masuk Aplikasi)</h3>\n<p>ALAZHARAPPS mengusung konsep <em>Passwordless</em> yang sangat memudahkan orang tua yang sering lupa kata sandi.</p>\n<ul>\n    <li><strong>Langkah 1:</strong> Buka aplikasi ALAZHARAPPS yang telah diunduh dari PlayStore/AppStore.</li>\n    <li><strong>Langkah 2:</strong> Masukkan Nomor WhatsApp yang aktif.</li>\n    <li><strong>Langkah 3:</strong> Sistem akan mengirimkan kode OTP (4-6 digit) ke WhatsApp tersebut. Masukkan kode OTP ke dalam aplikasi.</li>\n    <li><strong>Langkah 4:</strong> Pada login pertama kali, aplikasi akan meminta Orang Tua untuk membuat <strong>PIN Keamanan (6 Digit)</strong>. PIN ini akan digunakan untuk konfirmasi saat akan melakukan pembayaran tagihan.</li>\n</ul>\n\n<h3>2. Skenario Penerimaan Murid Baru (PMB)</h3>\n<p>Jika Orang Tua ingin mendaftarkan anak baru (baik anak pertama maupun anak kedua):</p>\n<ul>\n    <li><strong>Langkah 1:</strong> Di halaman beranda, tekan tombol <strong>Pendaftaran Murid Baru</strong>.</li>\n    <li><strong>Langkah 2:</strong> Pilih Unit Sekolah (TKA/SD/SMP/SMA) dan Tahun Ajaran.</li>\n    <li><strong>Langkah 3:</strong> Isi biodata anak secara lengkap (termasuk NIK dan Data Medis). <em>Catatan: Jika anak adalah saudara kandung dari murid yang sudah ada, sistem akan mendeteksi NIK Orang Tua untuk menghubungkan data keluarga.</em></li>\n    <li><strong>Langkah 4:</strong> Sistem akan menerbitkan Tagihan Pendaftaran/Uang Pangkal. Tekan tombol <strong>Bayar</strong> untuk mendapatkan nomor <em>Virtual Account</em> atau kode QRIS. Setelah dibayar, status pendaftaran berubah menjadi Lulus/Aktif.</li>\n</ul>\n\n<h3>3. Skenario Pemantauan Rutin (Monitoring Akademik & Keuangan)</h3>\n<p>Ini adalah fitur yang paling sering digunakan setiap harinya:</p>\n<ul>\n    <li><strong>Notifikasi Kehadiran (Presensi):</strong> Setiap pagi, ketika wali kelas menekan tombol simpan absensi atau anak melakukan <em>tap</em> kartu, sebuah <em>Push Notification</em> (lonceng) akan muncul di HP Orang Tua yang menginformasikan bahwa anak telah tiba di sekolah.</li>\n    <li><strong>Cek Nilai & Jadwal Ujian:</strong> Melalui menu Akademik, Orang Tua dapat melihat nilai harian (hasil ujian CBT) yang diisi oleh guru secara seketika tanpa harus menunggu pembagian Rapor di akhir semester.</li>\n    <li><strong>Pembayaran SPP:</strong> Setiap awal bulan, Tagihan SPP akan muncul di aplikasi. Orang tua cukup menekan tombol <strong>Bayar Sekarang</strong>, memilih metode (Gopay/OVO/Bank), dan saldo tagihan otomatis lunas dalam hitungan detik (tanpa perlu mengirim foto bukti transfer ke guru).</li>\n</ul>\n\n<h3>4. Skenario Transisi Akhir Tahun (Kenaikan Kelas)</h3>\n<ul>\n    <li><strong>Rapor Digital:</strong> Di akhir tahun ajaran, Orang Tua dapat mengunduh dokumen Rapor Resmi (berformat PDF yang terkunci) langsung dari aplikasi.</li>\n    <li><strong>Daftar Ulang:</strong> Sistem akan secara otomatis memunculkan tagihan Daftar Ulang untuk tahun ajaran baru. Jika daftar ulang dibayar, akun anak akan secara otomatis "Naik Kelas" di dalam sistem.</li>\n</ul>', '1', '2', '37', '2026-07-15 01:41:50', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('119', '29', 'Panduan Dasar Penggunaan Backoffice (Berdasarkan Role)', 'panduan-dasar-penggunaan-backoffice-berdasarkan-role', '<p>Artikel ini adalah panduan dasar operasional (SOP) bagi para pekerja (Staf/Karyawan) Yayasan ALAZHARAPPS. Karena sistem ini menangani puluhan sekolah di bawah satu yayasan, akses Backoffice dikontrol ketat menggunakan <strong>Role Level (Peran)</strong> agar setiap pengguna hanya melihat apa yang menjadi tanggung jawabnya.</p>\n\n<h3>Hierarki Role (Peran Pengguna) Backoffice</h3>\n<pre><code class="language-mermaid">\ngraph TD\n    A[Role Level 1: Administrator Yayasan] --> B(Lintas Sekolah)\n    A --> C[Role Level 15: Pengawas]\n    \n    subgraph Unit Sekolah (Per-Sekolah)\n    D[Role Level 11: Kepala Sekolah] --> E[Role Level 9: Admin Sekolah / TU]\n    D --> F[Role Level 10: Guru / Wali Kelas]\n    D --> G[Role Level 14: Kasi / Kepala Seksi]\n    end\n</code></pre>\n\n<h3>1. Skenario Superadmin / Administrator Yayasan (Level 1)</h3>\n<p>Ini adalah peran tertinggi (Pusat) yang memiliki kontrol penuh terhadap konfigurasi fundamental seluruh yayasan.</p>\n<ul>\n    <li><strong>Mengelola Master Data:</strong> Membuka atau menutup Tahun Ajaran baru secara serentak untuk seluruh unit sekolah.</li>\n    <li><strong>Manajemen Komponen Biaya Pusat:</strong> Membuat standar penamaan komponen tagihan (Misalnya: SPP, Uang Kegiatan, Uang Gedung) agar seragam di semua sekolah.</li>\n    <li><strong>Manajemen Akses (RBAC):</strong> Membuatkan akun (<em>User ID</em>) dan mengatur <em>password</em> untuk Kepala Sekolah atau Admin Sekolah baru.</li>\n</ul>\n\n<h3>2. Skenario Kepala Sekolah / Principal (Level 11)</h3>\n<p>Fokus utama Kepala Sekolah adalah <strong>Pemantauan (Monitoring)</strong> dan <strong>Otorisasi (Approval)</strong> untuk unit sekolahnya sendiri.</p>\n<ul>\n    <li><strong>Pemantauan Dasbor (Harian):</strong> Membuka Dashboard Keuangan (untuk melihat *Cashflow* harian/persentase siswa nunggak) dan Dashboard Kehadiran (melihat tingkat absensi guru dan siswa).</li>\n    <li><strong>Eksekusi Persetujuan (Approval):</strong> Secara berkala membuka kotak masuk (Inbox) di Backoffice untuk menyetujui pengajuan Diskon (seperti Diskon Prestasi) atau menyetujui Skema Angsuran Khusus yang diajukan oleh Tata Usaha.</li>\n</ul>\n\n<h3>3. Skenario Admin Sekolah & Tata Usaha (Level 9)</h3>\n<p>Role ini adalah ujung tombak operasional harian (Administrasi & Keuangan) di masing-masing sekolah.</p>\n<ul>\n    <li><strong>Manajemen Pendaftaran (PMB):</strong> Membantu orang tua yang mendaftar secara <em>offline</em> (Walk-in), mencetak kartu ujian, dan memverifikasi dokumen fisik pendaftar.</li>\n    <li><strong>Manajemen Keuangan (Finance):</strong>\n        <ul>\n            <li>Mengeklik tombol <strong>Generate Tagihan Bulanan (SPP)</strong> agar sistem menagihkan ke seluruh aplikasi orang tua.</li>\n            <li>Menginput pengajuan diskon (Saudara Kandung) atau menyetting skema cicilan (Angsuran) untuk disetujui Kepala Sekolah.</li>\n            <li>Mengeksekusi <strong>Rekonsiliasi Manual (Upload Bank CSV)</strong> jika ada orang tua yang mentransfer langsung ke rekening bank yayasan.</li>\n        </ul>\n    </li>\n    <li><strong>Manajemen Akademik Pokok:</strong> Menaikkan kelas siswa secara massal di akhir tahun ajaran (Skenario Mutasi).</li>\n</ul>\n\n<h3>4. Skenario Guru & Wali Kelas (Level 10)</h3>\n<p>Role ini berfokus murni pada interaksi akademik dengan murid di kelas yang diajarnya (Rombongan Belajar).</p>\n<ul>\n    <li><strong>Rutinitas Pagi (Absensi):</strong> Membuka menu Absensi Kelas dari HP atau Laptop, mencontreng kehadiran murid, dan menekan \'Simpan\' agar <em>Push Notification</em> otomatis terkirim ke orang tua.</li>\n    <li><strong>Manajemen Ujian (LMS & CBT):</strong> Mengunggah bank soal (Pilihan Ganda/Esai) ke dalam sistem, mengatur durasi jam ujian (mengaktifkan *Kiosk/Lockdown mode*), dan memantau siswa yang sedang ujian secara <em>real-time</em>.</li>\n    <li><strong>Penilaian Akhir (Rapor Digital):</strong> Menginput nilai akhir semester untuk diolah (kalkulasi) otomatis oleh sistem menjadi PDF Rapor Digital yang siap diunduh orang tua.</li>\n</ul>\n\n<h3>5. Skenario Pengawas (Level 15) & Kasi (Level 14)</h3>\n<p>Peran Supervisi (seperti Pengawas Dinas atau Kepala Seksi Kurikulum Yayasan).</p>\n<ul>\n    <li><strong>Skenario Audit:</strong> Mereka memiliki akses <em>View-Only</em> (Hanya Baca) untuk memantau grafik kualitas akademik dan rekapitulasi keterlambatan pegawai/guru melintasi beberapa sekolah tanpa memiliki kemampuan untuk merusak atau mengubah (<em>Edit/Delete</em>) data operasional.</li>\n</ul>', '1', '2', '13', '2026-07-15 01:41:50', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('120', '29', 'Skenario Pengolahan Rapor Digital dan Kelulusan', 'skenario-pengolahan-rapor-digital-dan-kelulusan', '<p>Artikel ini mendokumentasikan Skenario Akademik Puncak, yaitu proses pengolahan nilai, rekapitulasi <em>Leger</em> (Buku Induk Nilai), hingga penerbitan Rapor Digital dan Ijazah. Proses berat ini dikerjakan secara komprehensif oleh <code>report-service</code> yang meringankan tugas Wali Kelas dan Admin Sekolah.</p>\n\n<h3>Diagram Urutan: Skenario Rapor Digital & Kelulusan</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant GBS as Guru Bidang Studi\n    participant WK as Wali Kelas\n    participant RPT as Report Service (Backend)\n    participant KEP as Kepala Sekolah\n    participant OTM as Orang Tua (Mobile)\n\n    %% Fase Pengumpulan Nilai\n    Note over GBS,RPT: Tahap 1: Penginputan Nilai Mentah\n    GBS->>RPT: Input Nilai Harian & Ujian (Per Mata Pelajaran)\n    GBS->>RPT: Input Nilai Non-Akademik (Kokurikuler/Ekskul)\n    RPT->>RPT: Validasi KKM (Kriteria Ketuntasan Minimal)\n\n    %% Fase Rekapitulasi (Leger)\n    Note over WK,RPT: Tahap 2: Pembentukan Leger & Draft Rapor\n    WK->>RPT: Klik "Generate Leger Kelas"\n    RPT->>RPT: Agregasi Nilai + Tarik Data Absensi (Student Service)\n    RPT-->>WK: Tampilkan Draft Rapor (Preview)\n    WK->>RPT: Input Catatan Wali Kelas (Behavior/Attitude)\n\n    %% Fase Validasi & Penguncian\n    Note over WK,KEP: Tahap 3: Validasi & Penguncian (Lock)\n    WK->>RPT: Submit Rapor Final\n    RPT-->>KEP: Rapor Siap Divalidasi\n    KEP->>RPT: Approve & Lock (Kunci Rapor)\n    \n    %% Fase Distribusi / Kelulusan\n    Note over RPT,OTM: Tahap 4: Distribusi Digital\n    alt Siswa Kelas Reguler (Mis: Kelas 1-5 / 7-8)\n        RPT->>RPT: Generate PDF Rapor Digital (Watermarked)\n        RPT-->>OTM: Push Notification: "Rapor Semester Telah Terbit"\n        OTM->>RPT: Download PDF dari Aplikasi Mobile\n    else Siswa Kelas Akhir (Kelulusan / Kelas 6, 9, 12)\n        RPT->>RPT: Generate PDF Ijazah & SKHUN Internal\n        RPT-->>OTM: Push Notification: "Dokumen Kelulusan Telah Terbit"\n    end\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Proses pembagian rapor tradisional membutuhkan waktu berminggu-minggu untuk merekap nilai dari puluhan guru ke dalam satu buku besar (Leger) menggunakan Microsoft Excel. ALAZHARAPPS menghapus beban tersebut dengan rekayasa data (<em>data processing</em>) di dalam sistem.</p>\n\n<h4>1. Desentralisasi Input Nilai</h4>\n<ul>\n    <li>Guru Matematika hanya melihat kolom nilai Matematika, Guru Agama hanya melihat kolom Agama. Tidak ada lagi proses mengirim-ngirim file Excel via <em>flashdisk</em>.</li>\n    <li>Sistem <code>report-service</code> secara cerdas akan langsung memberikan peringatan (warna merah) jika nilai yang diinput guru berada di bawah KKM (Kriteria Ketuntasan Minimal).</li>\n</ul>\n\n<h4>2. Agregasi Otomatis (Pembentukan Leger)</h4>\n<ul>\n    <li>Wali kelas adalah konduktor dalam proses ini. Mereka tidak perlu mengetik nilai anak didiknya.</li>\n    <li>Saat Wali Kelas menekan tombol <strong>Generate Leger</strong>, sistem akan menarik seluruh nilai dari semua guru mata pelajaran, menarik nilai Ekstrakurikuler, dan bahkan memanggil API ke <code>student-service</code> untuk menarik rekapitulasi <strong>Absensi (Kehadiran)</strong> siswa selama 6 bulan terakhir.</li>\n    <li>Semua elemen tersebut disatukan menjadi Draft Rapor.</li>\n</ul>\n\n<h4>3. Validasi Kepala Sekolah (Penguncian Data)</h4>\n<ul>\n    <li>Rapor adalah dokumen legal. Oleh karena itu, sebelum rapor "diterbitkan" ke aplikasi orang tua, harus ada proses validasi.</li>\n    <li>Kepala Sekolah akan memeriksa kelengkapan pengisian rapor seluruh kelas. Jika sudah sesuai, Kepala Sekolah akan mengunci (<em>Lock</em>) rapor tersebut. Setelah dikunci, guru mata pelajaran <strong>tidak bisa lagi</strong> mengubah nilai.</li>\n</ul>\n\n<h4>4. Distribusi Ramah Lingkungan (Paperless)</h4>\n<ul>\n    <li>Sistem akan menggunakan mesin <em>template generator</em> untuk mencetak nilai-nilai tersebut ke dalam format PDF standar Yayasan Al-Azhar (lengkap dengan <em>Watermark</em> / <em>Digital Signature</em>).</li>\n    <li>Orang Tua mendapatkan notifikasi di aplikasi genggam mereka dan dapat langsung melihat atau mengunduh PDF Rapor tersebut. Hal ini sangat menghemat biaya cetak kertas (<em>printing</em>) bagi sekolah.</li>\n    <li>Bagi siswa tingkat akhir, modul <code>diploma_usecase.go</code> akan mengambil alih untuk mencetak dokumen tambahan seperti Surat Keterangan Lulus (SKL) atau Ijazah Internal Yayasan.</li>\n</ul>', '1', '2', '14', '2026-07-15 01:47:34', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('121', '29', 'Skenario Jurnal Harian Guru dan Materi Ajar', 'skenario-jurnal-harian-guru-dan-materi-ajar', '<p>Artikel ini mendokumentasikan skenario pemantauan kualitas kegiatan belajar mengajar (KBM) di lingkungan sekolah. ALAZHARAPPS menggunakan modul khusus (<code>learning_agenda_usecase</code> dan <code>personnel_materials_usecase</code> di dalam <code>student-service</code>) untuk mendigitalisasi Jurnal Mengajar dan RPP (Rencana Pelaksanaan Pembelajaran) Guru.</p>\n\n<h3>Diagram Urutan: Skenario Jurnal Harian Guru & Materi Ajar</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant GRU as Guru Mata Pelajaran\n    participant LMS as Student Service (Modul KBM)\n    participant SIS as Siswa (Aplikasi)\n    participant KEP as Kepala Sekolah / Pengawas\n    participant DB as Database (PostgreSQL)\n\n    %% Fase Persiapan Mengajar\n    Note over GRU,LMS: Tahap 1: Persiapan Materi (Pre-Class)\n    GRU->>LMS: Unggah Materi Ajar (Bahan Tayang / PDF / Link Video)\n    LMS->>DB: Simpan Master Materi\n    \n    %% Fase Pelaksanaan KBM\n    Note over GRU,SIS: Tahap 2: Proses Belajar Mengajar\n    GRU->>LMS: Buka Sesi Kelas & Tautkan Materi\n    LMS-->>SIS: Materi Ajar Terbuka di Aplikasi Siswa\n    \n    %% Fase Pelaporan KBM (Jurnal Harian)\n    Note over GRU,LMS: Tahap 3: Pengisian Jurnal (Post-Class)\n    GRU->>LMS: Input "Jurnal Mengajar" (Apa yang diajarkan hari ini)\n    GRU->>LMS: Input "Catatan Bimbingan" (Siswa bermasalah/prestasi)\n    LMS->>DB: Simpan Agenda Pembelajaran\n    \n    %% Fase Supervisi\n    Note over KEP,DB: Tahap 4: Supervisi Akademik\n    KEP->>LMS: Buka Dashboard Kinerja Guru\n    LMS->>DB: Tarik Data Jurnal Mengajar Seluruh Guru\n    LMS-->>KEP: Tampilkan Laporan: Kesiapan Materi & Kedisiplinan Input Jurnal\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Kualitas pendidikan sangat bergantung pada kedisiplinan guru di dalam kelas. Modul ini bukan untuk membebani guru dengan administrasi, melainkan memberikan transparansi (visibilitas) yang adil atas kerja keras guru di lapangan agar dapat dipantau oleh Kepala Sekolah secara obyektif.</p>\n\n<h4>1. Sentralisasi Materi Ajar (Pre-Class)</h4>\n<ul>\n    <li>Sebelum masuk ke kelas (atau pada awal semester), guru mengunggah silabus, modul PDF, atau tautan YouTube ke dalam <strong>Bank Materi</strong> (<code>personnel_materials_usecase</code>).</li>\n    <li>Hal ini memastikan bahwa materi pembelajaran terdokumentasi dengan baik sebagai aset (kekayaan intelektual) sekolah, tidak hilang atau tercecer di <em>Google Drive</em> pribadi guru.</li>\n</ul>\n\n<h4>2. Pengisian Jurnal Mengajar (Post-Class)</h4>\n<ul>\n    <li>Di era konvensional, guru mengisi buku tebal bernama "Buku Batas Pelajaran" atau Jurnal Kelas yang sering dibawa berkeliling oleh ketua kelas. Di ALAZHARAPPS, fitur ini sepenuhnya digital (<code>learning_agenda_usecase</code>).</li>\n    <li>Setelah jam pelajaran berakhir (atau di penghujung hari), guru cukup membuka aplikasi dan mengetik ringkasan: <em>"Hari ini mengajarkan Bab 3 tentang Tata Surya, target capaian selesai."</em></li>\n    <li><strong>Sinergi Bimbingan Konseling (Catatan Pertemuan):</strong> Jika pada jam pelajaran tersebut ada murid yang sangat aktif, atau sebaliknya ada yang tidur di kelas, guru dapat menyelipkan catatan khusus (<code>meeting_note_usecase</code>). Catatan ini akan menjadi rekam jejak untuk Guru Bimbingan Konseling (BK) atau menjadi evaluasi saat pembagian rapor.</li>\n</ul>\n\n<h4>3. Supervisi Akademik Tanpa Kertas</h4>\n<ul>\n    <li>Bagi <strong>Kepala Sekolah</strong> (Role Level 11) dan <strong>Pengawas Yayasan</strong> (Role Level 15), modul ini adalah jendela emas (<em>Golden Window</em>).</li>\n    <li>Tanpa harus masuk (sidak) ke kelas satu per satu, Kepala Sekolah dapat melihat <em>Dashboard</em> untuk mengetahui:<br>\n      - <em>"Berapa persen guru yang sudah mengunggah materi bulan ini?"</em><br>\n      - <em>"Apakah ada guru yang sering alpa mengisi Jurnal Mengajar?"</em><br>\n      - <em>"Apakah kurikulum bulan ini sudah tersampaikan semua?"</em></li>\n    <li>Hal ini memungkinkan pimpinan sekolah untuk mengambil keputusan strategis dan memberikan pelatihan jika ada guru yang masih kesulitan dengan sistem.</li>\n</ul>', '1', '2', '15', '2026-07-15 01:47:34', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('122', '29', 'Skenario Integrasi Payment Gateway (DOKU & Webhook)', 'skenario-integrasi-payment-gateway-doku-webhook', '<p>Artikel ini membongkar rahasia dapur arsitektur keuangan tanpa kasir (<em>Cashless</em>) di ALAZHARAPPS. Sistem ini terintegrasi secara mulus dengan <strong>DOKU Payment Gateway</strong> melalui metode API B2B (<em>Server-to-Server</em>). Artikel ini akan fokus pada mekanisme <em>Virtual Account (VA)</em> dan <em>QRIS</em> beserta pengamanan tingkat tinggi (<em>Bank-Grade Security</em>) yang diterapkan.</p>\n\n<h3>Diagram Urutan: Integrasi DOKU Payment Gateway</h3>\n<pre><code class="language-mermaid">\nsequenceDiagram\n    autonumber\n    participant OTM as Orang Tua (Mobile)\n    participant TXN as Transaction Service (ALAZHARAPPS)\n    participant DKU as DOKU Server (Payment Gateway)\n    participant BNK as Jaringan Perbankan (Bank)\n    participant EVT as Event Bus (Worker Latar Belakang)\n\n    %% Fase 1: Request (Pembuatan Tagihan)\n    Note over OTM,DKU: Tahap 1: Pembuatan Kode Bayar\n    OTM->>TXN: Buka Tagihan & Klik "Bayar via VA Mandiri"\n    TXN->>DKU: Request API: Create Virtual Account (Kirim Nominal & Data Siswa)\n    DKU-->>TXN: Response: Nomor VA Unik (Mis: 888123456)\n    TXN-->>OTM: Tampilkan Nomor VA di Layar Aplikasi\n    \n    %% Fase 2: Pembayaran (Di Luar Sistem Kita)\n    Note over OTM,BNK: Tahap 2: Pembayaran Fisik\n    OTM->>BNK: Buka M-Banking / ATM, Transfer ke Nomor VA\n    BNK->>DKU: Jaringan Antar-Bank Mengkonfirmasi Dana Masuk\n    \n    %% Fase 3: Rekonsiliasi Real-Time (Webhook)\n    Note over DKU,EVT: Tahap 3: Webhook & Validasi Keamanan\n    DKU->>TXN: Webhook Callback HTTP POST (Kirim Notifikasi Lunas)\n    TXN->>TXN: Validasi HMAC Signature & Access Token (Mencegah Hacker)\n    \n    alt Jika Tanda Tangan Valid (Sah)\n        TXN->>EVT: Publish Event "VirtualAccountPaid" (Asinkron)\n        TXN-->>DKU: HTTP 200 OK (ResponseCode: 2002500)\n    else Jika Invalid (Serangan Siber)\n        TXN-->>DKU: HTTP 401 Unauthorized (Ditolak)\n    end\n    \n    %% Fase 4: Penyelesaian Asinkron\n    Note over EVT,OTM: Tahap 4: Eksekusi Latar Belakang\n    EVT->>EVT: Worker Membaca Event (Tanpa Membuat Server Lag)\n    EVT->>EVT: Update Database Status Tagihan = PAID\n    EVT-->>OTM: Tembakkan Push Notification "Terima Kasih, Tagihan Lunas!"\n</code></pre>\n\n<h3>Penjelasan Alur (Workflow Detail)</h3>\n<p>Banyak sistem sekolah hancur (<em>down</em>) ketika ribuan orang tua membayar tagihan secara serentak di tanggal 1 setiap bulannya. ALAZHARAPPS mengatasi masalah ini dengan memisahkan jalur pembayaran (DOKU) dan jalur penyelesaian database (<em>Event Bus Worker</em>).</p>\n\n<h4>1. Pembuatan Kode Bayar (Generate VA/QRIS)</h4>\n<ul>\n    <li>Saat Orang Tua menekan "Bayar", <code>transaction-service</code> tidak membuat nomor sendiri. Sistem bertindak sebagai perantara yang menembakkan <em>API Request</em> ke server DOKU.</li>\n    <li>DOKU membalas dengan Nomor Virtual Account atau kode QRIS yang unik untuk anak tersebut. Jika QRIS, sistem akan merendernya menjadi gambar *barcode* di layar HP orang tua.</li>\n</ul>\n\n<h4>2. Webhook Callback (Titik Paling Krusial)</h4>\n<ul>\n    <li>ALAZHARAPPS <strong>TIDAK</strong> pernah melakukan pengecekan berulang-ulang ke server Bank ("Apakah sudah dibayar?"). Hal tersebut akan menghabiskan kuota server.</li>\n    <li>Sistem menggunakan metode pasif bernama <strong>Webhook</strong>. Saat uang masuk, server DOKU lah yang proaktif "mengetuk pintu" server ALAZHARAPPS untuk memberitahu bahwa tagihan telah lunas.</li>\n</ul>\n\n<h4>3. Keamanan Tingkat Bank (Anti-Hacker)</h4>\n<ul>\n    <li>Bagaimana jika ada <em>Hacker</em> yang iseng mengirim pesan palsu ke <em>Webhook</em> kita agar tagihannya dianggap lunas? ALAZHARAPPS mencegahnya dengan ketat pada <code>webhook_controller.go</code>.</li>\n    <li>Sistem memeriksa <strong>HMAC Signature</strong> (Tanda Tangan Kriptografi) dan <strong>Access Token</strong> yang hanya diketahui oleh DOKU dan ALAZHARAPPS. Jika ada satu huruf saja yang meleset, permintaan akan ditendang dengan status <code>401 Unauthorized</code>.</li>\n</ul>\n\n<h4>4. Penyelesaian Asinkron (Asynchronous Event Bus)</h4>\n<ul>\n    <li>Jika validasi berhasil, sistem <strong>tidak langsung mengubah database saat itu juga</strong>. Hal ini karena jika database sedang sibuk (<em>Lock</em>), Webhook DOKU bisa <em>Timeout</em> dan DOKU akan mengira sistem kita mati.</li>\n    <li>Sebagai gantinya, sistem melempar kejadian ini ke dalam <strong>Event Bus</strong> (<code>event.VirtualAccountPaid</code>), lalu dengan sangat cepat membalas DOKU dengan status "Sukses".</li>\n    <li>Di belakang layar, <em>Worker</em> (Pekerja) akan mengambil <em>Event</em> tersebut secara perlahan dan mengubah status tagihan di database menjadi <code>PAID</code> serta menembakkan notifikasi kuitansi ke orang tua. Inilah rahasia mengapa server ALAZHARAPPS tidak pernah <em>down</em> di tanggal gajian!</li>\n</ul>', '1', '2', '16', '2026-07-15 02:00:36', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('123', '31', 'Panduan Anatomi UI/UX (Web Backoffice & Mobile App)', 'panduan-anatomi-ui-ux-web-backoffice-dan-mobile-app', '<p>Artikel ini menjabarkan anatomi antarmuka pengguna (UI) dan pengalaman pengguna (UX) dari ekosistem ALAZHARAPPS. Sistem ini dibagi menjadi dua antarmuka utama: <strong>Web Backoffice</strong> (bagi staf/guru) dan <strong>Aplikasi Mobile</strong> (bagi orang tua murid).</p>\n\n<h3>Diagram Arsitektur Navigasi UI</h3>\n<pre><code class="language-mermaid">\nmindmap\n  root((UI/UX ALAZHARAPPS))\n    Web Backoffice (NextJS)\n      Master Data\n        Wilayah & Agama\n        Tahun Ajaran\n      Akademik\n        Kurikulum & Kelas\n        Presensi Guru\n      PPDB & Keuangan\n        Gelombang Daftar\n        Tagihan SPP & UP\n        Diskon & Cicilan\n    Mobile App (Flutter)\n      Dashboard Utama\n        Widget Adzan\n        Kartu Siswa (ID)\n        Notifikasi Badges\n      Akademik Siswa\n        Rapor Digital\n        Jadwal & Absensi\n      Transaksi\n        Riwayat & Pending\n        Gateway DOKU (VA/QRIS)\n      Multi-Child Switcher\n</code></pre>\n\n<h3>1. Anatomi UI/UX Web Backoffice (Admin & Guru)</h3>\n<p>Backoffice didesain dengan konsep <em>Sidebar Navigation</em> yang masif. Tata letak (<em>Layout</em>) dipisahkan secara modular untuk mencegah pengguna kebingungan (<em>Cognitive Overload</em>).</p>\n\n<h4>A. Modul Master Data (Tulang Punggung Sistem)</h4>\n<ul>\n    <li><strong>Relasi Kolom (UX):</strong> Data yang di-input di dalam form Master (seperti daftar Agama, Provinsi, atau Pekerjaan) akan secara otomatis terhubung (<em>relational bind</em>) menjadi menu <em>Dropdown</em> di formulir pendaftaran pada Aplikasi Mobile. Artinya, jika Admin menambahkan "Wiraswasta" di Master Pekerjaan, keesokan harinya opsi tersebut muncul di layar HP orang tua yang sedang mengisi form PMB.</li>\n    <li><strong>Tahun Ajaran & Status:</strong> Terdapat tombol (<em>Toggle</em>) Aktif/Non-Aktif. Sistem UX mencegah adanya dua Tahun Ajaran yang berstatus aktif secara bersamaan untuk mencegah bentrok data nilai siswa.</li>\n</ul>\n\n<h4>B. Modul Akademik & Pegawai</h4>\n<ul>\n    <li><strong>Penugasan Guru (Assignment):</strong> Tampilan tabel matriks (Grid). Kepala Sekolah mengaitkan Guru dengan Mata Pelajaran dan Kelas. </li>\n    <li><strong>Dampak Relasi UX:</strong> Ketika relasi Kelas dan Wali Kelas disimpan, otomatis Guru tersebut mendapatkan akses khusus di aplikasinya untuk memvalidasi Rapor kelas tersebut, tanpa perlu pengaturan otorisasi tambahan.</li>\n</ul>\n\n<h4>C. Modul PPDB, Animo & Keuangan</h4>\n<ul>\n    <li><strong>Alur Konversi Siswa (Funneling):</strong> Berawal dari menu <code>Animo</code> (peminat) &rarr; <code>Calon</code> (Membayar formulir) &rarr; <code>Murid Aktif</code>. Di setiap fase, UI menggunakan Indikator Warna (Merah=Belum Lunas, Hijau=Lunas).</li>\n    <li><strong>Manajemen Diskon (Approval UI):</strong> Pada tabel pengajuan diskon, terdapat kolom Aksi (<em>Action</em>) berlogo "Ceklis" (Setuju) atau "Silang" (Tolak). Jika ditekan Setuju, sistem langsung merefleksikannya ke perhitungan <em>Grand Total</em> tagihan siswa di hari yang sama.</li>\n</ul>\n\n<h3>2. Anatomi UI/UX Mobile App (Orang Tua Murid)</h3>\n<p>Aplikasi genggam didesain dengan filosofi <em>Frictionless</em> (Minim Hambatan). Tidak banyak menu bertingkat yang membingungkan; segala fitur harian dapat dijangkau dalam maksimal dua ketukan (<em>2 Taps</em>).</p>\n\n<h4>A. Dashboard (Beranda Utama) & Engagement UX</h4>\n<ul>\n    <li><strong>Widget Adzan & Cuaca:</strong> Di area paling atas (<em>Header</em>), aplikasi menanamkan jadwal sholat harian (melakukan <em>fetch API</em> berdasarkan lokasi terkini *Nearest City*). Hal ini secara UX memaksa aplikasi agar "sering dibuka" oleh orang tua setiap hari, bukan hanya saat jatuh tempo bayar SPP.</li>\n    <li><strong>Student Card (Kartu Pelajar Digital):</strong> Menggantikan fungsi ID Card plastik. Barcode yang ada di layar bisa di-*tap* ke pemindai (*Scanner*) di gerbang sekolah.</li>\n    <li><strong>Notification Badges (Titik Merah):</strong> Terletak pada ikon Lonceng atau ikon Tagihan. Membantu memberikan sinyal visual bawah sadar jika ada tunggakan atau rapor baru yang belum dibaca.</li>\n</ul>\n\n<h4>B. Multi-Child Switcher (Relasi Keluarga)</h4>\n<ul>\n    <li><strong>Tantangan UX:</strong> Bagaimana jika satu orang tua punya 3 anak (TK, SD, SMP) di Al-Azhar?</li>\n    <li><strong>Solusi UI:</strong> Terdapat menu <em>Dropdown Switcher</em> (Avatar anak) di pojok atas. Ketika profil diubah dari si Sulung ke si Bungsu, seluruh layar di bawahnya (tagihan, rapor, nilai, jadwal ekskul) secara seketika (*State Management*) akan berganti memuat data si Bungsu tanpa perlu <em>Logout</em>.</li>\n</ul>\n\n<h4>C. UI Transaksi (Payment Gateway)</h4>\n<ul>\n    <li><strong>List Tagihan Berjalan:</strong> Dipisahkan menjadi dua Tab: <em>Unpaid</em> (Belum Dibayar) dan <em>History</em> (Riwayat).</li>\n    <li><strong>Flow UX Pembayaran:</strong> Saat tagihan di-klik, muncul opsi bank (Mandiri, BSI, dll) dan QRIS. Setelah menekan salah satu, muncul sebuah <em>Bottom Sheet</em> (Jendela Bawah) yang menampilkan nomor Virtual Account DOKU beserta tombol "Salin (Copy)". Saat pembayaran lunas, layar langsung memunculkan animasi centang hijau (via Webhook) secara otomatis tanpa orang tua perlu me-*refresh* layarnya.</li>\n</ul>', '1', '2', '79', '2026-07-15 02:08:02', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('124', '26', 'Analisa Mendalam Menu Dashboard Backoffice', 'analisa-mendalam-menu-dashboard-backoffice', '<p>Halaman <em>Dashboard</em> (Beranda) Backoffice ALAZHARAPPS bukan sekadar halaman penyambut. Ia adalah pusat komando (<em>Command Center</em>) berbasis data analitik yang ditopang oleh dua mesin utama: <code>report-service</code> dan <code>school-service-new</code>. Artikel ini membedah 5 sub-menu Dashboard yang disesuaikan dengan kebutuhan setiap departemen.</p>\n\n<h3>Diagram Modul Dashboard Analytics</h3>\n<pre><code class="language-mermaid">\nmindmap\n  root((Dashboard Backoffice))\n    Pusat Yayasan (Admin Pusat)\n      Demografi Persebaran Sekolah\n      Total Target Siswa\n    Keuangan (Finance)\n      Grafik Penerimaan Harian\n      Rasio Lunas vs Tunggakan\n      Kesehatan Cashflow\n    Marketing (PMB & Animo)\n      Rasio Konversi Calon ke Murid\n      Target Pencapaian PMB\n    Murid (Kesiswaan)\n      Tren Demografi Siswa\n      Persebaran Akademik\n    Akademik (LMS)\n      Prestasi & Pelanggaran\n      Kualitas KBM\n</code></pre>\n\n<h3>1. Dashboard Admin Pusat (Yayasan & Sekolah)</h3>\n<p><strong>Fokus:</strong> Gambaran Makro (<em>Helicopter View</em>) tentang kondisi Yayasan.</p>\n<ul>\n    <li><strong>Persebaran Wilayah (Demografi):</strong> Menampilkan grafik (<em>Progress Chart</em> & <em>Bar Chart</em>) jumlah sekolah berdasarkan provinsi dan tingkat pendidikan (TK, SD, SMP, SMA). Data ditarik dari fungsi <code>SchoolCountByProvince</code> dan <code>SchoolCountByEducationLevel</code>.</li>\n    <li><strong>Target Siswa Global:</strong> Menampilkan seberapa dekat yayasan dengan target kapasitas total siswa (<em>Target Students</em>) di tahun ajaran tersebut.</li>\n    <li><strong>Aksesibilitas:</strong> Hanya dapat dilihat oleh Superadmin (Level 1) dan Pimpinan Yayasan.</li>\n</ul>\n\n<h3>2. Dashboard Keuangan (Finance)</h3>\n<p><strong>Fokus:</strong> Kesehatan Arus Kas (<em>Cashflow</em>) dan mitigasi gagal bayar (Tunggakan).</p>\n<ul>\n    <li><strong>Grafik Penerimaan Harian (ChartPenerimaanHarian):</strong> Menampilkan kurva (<em>Line Chart</em>) pendapatan yang masuk setiap harinya. Membantu Bendahara melihat tren tanggal berapa orang tua paling sering membayar SPP.</li>\n    <li><strong>Rasio Penerimaan vs Tunggakan (Acceptance vs Arrear):</strong> Komparasi ekstrem (<em>Pie Chart</em> / <em>Doughnut</em>) antara tagihan yang sudah menjadi uang (<em>Revenue</em>) versus tagihan yang macet (<em>Arrears</em>).</li>\n    <li><strong>Ekspor Laporan (Excel/CSV):</strong> Terdapat tombol ajaib untuk mengunduh laporan keuangan lintas sekolah berdasarkan Kode Biaya (<em>Cost Code</em>) seperti "Laporan Khusus Uang Gedung".</li>\n</ul>\n\n<h3>3. Dashboard Marketing (PPDB & Animo)</h3>\n<p><strong>Fokus:</strong> Mengevaluasi strategi pemasaran dan konversi siswa baru.</p>\n<ul>\n    <li><strong>Corong Penjualan (PMB Summary & Ratio):</strong> Menganalisa berapa banyak orang tua yang sekadar mendaftar (Animo), membeli formulir (Calon), hingga akhirnya lunas Uang Pangkal (Murid). Rasio (<em>PMB Ratio</em>) yang kecil berarti ada hambatan (<em>bottleneck</em>) dalam pelayanan atau biaya.</li>\n    <li><strong>Target Achievement:</strong> Menampilkan persentase pencapaian kuota bangku yang tersedia per gelombang pendaftaran.</li>\n</ul>\n\n<h3>4. Dashboard Murid</h3>\n<p><strong>Fokus:</strong> Retensi dan Demografi Siswa Aktif.</p>\n<ul>\n    <li><strong>Grafik Tren Tahunan (StudentCountByAcademicYear):</strong> Menampilkan apakah grafik jumlah siswa mengalami kenaikan atau penurunan selama 5 tahun terakhir.</li>\n    <li><strong>Dashboard Interaktif:</strong> Jika Kepala Sekolah mengklik salah satu batang grafik (misalnya "Siswa SD"), sistem akan menampilkan rincian usia dan gender siswa tersebut tanpa berpindah halaman.</li>\n</ul>\n\n<h3>5. Dashboard Akademik & LMS</h3>\n<p><strong>Fokus:</strong> Kualitas Pendidikan dan Karakter Siswa.</p>\n<ul>\n    <li><strong>Papan Prestasi (Award / Magazine):</strong> Menampilkan statistik jumlah prestasi kejuaraan yang dimenangkan oleh siswa-siswa sekolah tersebut dalam tahun berjalan.</li>\n    <li><strong>Metrik Kegiatan Belajar:</strong> (Relasi dengan <em>Learning Agenda</em>) Memantau seberapa banyak kelas yang berjalan sesuai dengan rencana RPP harian.</li>\n</ul>\n\n<hr>\n<blockquote>\n<p><strong>Catatan Teknis (UX Performance):</strong> Karena Dashboard ini melakukan kalkulasi matematika jutaan data baris keuangan dan siswa dari seluruh sekolah, <code>report-service</code> menggunakan teknik <strong>Caching (Redis)</strong>. Hal ini memastikan halaman Dashboard akan langsung terbuka dalam hitungan milidetik tanpa membebani (<em>query lock</em>) database utama.</p>\n</blockquote>', '1', '2', '71', '2026-07-15 02:12:51', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('125', '31', 'Analisa Mendalam Struktur Menu Sidebar Backoffice', 'analisa-mendalam-struktur-menu-sidebar-backoffice', '<p>Artikel ini memberikan analisa mendalam mengenai struktur Menu (<em>Sidebar</em>) pada halaman Backoffice khusus untuk <strong>Admin Sekolah</strong>. Susunan menu ini dirancang mengikuti alur operasional sekolah yang sesungguhnya (dari pendaftaran awal hingga kelulusan).</p>\n\n<h3>Diagram Hierarki Menu Backoffice</h3>\n<pre><code class="language-mermaid">\nmindmap\n  root((Menu Admin Sekolah))\n    Dashboard & Transaksi\n      Summary (Ringkasan)\n      Murid (Grafik Siswa)\n      Transaksi PMB\n    Laporan\n      Keuangan Murid\n    Sekolah (Master Data)\n      Data Murid & Profil\n      Rombel & Kurikulum\n      Pegawai\n      Kenaikan Kelas & Kelulusan\n    Administrasi (Operasional)\n      PMB\n      Data Calon Murid\n      Biaya\n      Kalender\n    Manajemen User & Jurnal\n      User Sekolah & Log\n      E-Rapot & Ijazah\n</code></pre>\n\n<h3>1. Kelompok Menu "Dashboard" & "Transaksi"</h3>\n<p>Ini adalah halaman penyambut saat Admin Sekolah pertama kali masuk (<em>login</em>).</p>\n<ul>\n    <li><strong>Summary & Murid:</strong> Menampilkan analitik visual (grafik) mengenai arus kas sekolah (Penerimaan vs Tunggakan) serta demografi jumlah murid aktif yang dirender dari <code>report-service</code> secara kilat.</li>\n    <li><strong>Transaksi PMB (Penerimaan Murid Baru):</strong> Modul akses cepat untuk mengeksekusi konfirmasi pembayaran khusus pendaftaran murid baru tanpa perlu masuk jauh ke dalam menu pengaturan biaya.</li>\n</ul>\n\n<h3>2. Kelompok Menu "Laporan"</h3>\n<ul>\n    <li><strong>Keuangan Murid:</strong> Sebuah pusat unduh (<em>Export Center</em>) di mana Admin dapat menarik file Excel/CSV berisi laporan pembayaran SPP atau tagihan lainnya. Menu ini membebaskan Admin dari tugas rekapitulasi manual di akhir bulan.</li>\n</ul>\n\n<h3>3. Kelompok Menu "Sekolah" (Pusat Master Data)</h3>\n<p>Kelompok menu ini adalah pondasi struktural dari unit sekolah tersebut.</p>\n<ul>\n    <li><strong>Profile Sekolah, Kurikulum, & Program:</strong> Pengaturan statis mengenai identitas sekolah (seperti jam buka, akreditasi) dan kurikulum yang dianut.</li>\n    <li><strong>Data Murid & Pegawai:</strong> Mengelola *database* seluruh manusia yang berada di dalam lingkungan sekolah (Siswa Aktif, Guru, dan Staf).</li>\n    <li><strong>Rombel (Rombongan Belajar):</strong> Tempat Admin memetakan anak-anak dari "Data Murid" ke dalam kelas spesifik, serta menunjuk seorang Guru sebagai Wali Kelas. Relasi ini sangat krusial karena akan memengaruhi siapa yang berhak mengisi E-Rapot nantinya.</li>\n    <li><strong>Akademik (Kenaikan Kelas & Kelulusan):</strong> Menu ini ditekan <strong>sekali setahun</strong> pada saat tahun ajaran berakhir. Admin mengeksekusi mutasi massal untuk menaikkan kelas siswa (misalnya dari Kelas 1A ke 2A) atau meluluskan mereka.</li>\n    <li><strong>Sarana Prasarana, Ekstrakurikuler, Prestasi:</strong> Data pelengkap yang akan muncul di Rapor Digital siswa.</li>\n</ul>\n\n<h3>4. Kelompok Menu "Administrasi" (Mesin Penggerak Utama)</h3>\n<p>Ini adalah kelompok menu yang paling sibuk dan sering digunakan setiap harinya oleh staf Tata Usaha dan Keuangan.</p>\n<ul>\n    <li><strong>PMB (Penerimaan Murid Baru):</strong>\n        <ul>\n            <li><strong>Gelombang Pendaftaran:</strong> Membuka "Keran" pendaftaran (Misal: Gelombang 1 buka di Januari).</li>\n            <li><strong>Animo:</strong> Daftar orang tua yang sekadar membuat akun atau sekadar melirik (belum membeli formulir).</li>\n            <li><strong>Jadwal Ujian & Peserta Ujian:</strong> Mengelola tes seleksi masuk.</li>\n            <li><strong>Kelulusan Peserta:</strong> Memutuskan siapa yang diterima menjadi <strong>Calon Murid</strong>.</li>\n        </ul>\n    </li>\n    <li><strong>Data Calon Murid:</strong> Anak-anak yang sudah lulus seleksi PMB namun belum resmi menjadi murid aktif (biasanya karena belum melunasi Uang Pangkal).</li>\n    <li><strong>Biaya (Financial Engine):</strong>\n        <ul>\n            <li><strong>Uang Sekolah (SPP):</strong> Mengatur <em>generate</em> tagihan rutin bulanan otomatis.</li>\n            <li><strong>Uang Pangkal:</strong> Mengatur tagihan satu kali (<em>One-time fee</em>) di awal masuk sekolah.</li>\n            <li><strong>Uang Daftar Ulang (Tahunan):</strong> Seperti yang tertera di form, ini adalah tagihan rutin tahunan. Setiap kali siswa naik kelas (pergantian Tahun Ajaran Baru), Admin menekan menu ini untuk menerbitkan tagihan pendaftaran ulang. Form ini juga mengatur Jatuh Tempo agar sistem bisa menembakkan notifikasi peringatan.</li>\n            <li><strong>Pengajuan Diskon:</strong> Pusat <em>Approval</em> di mana Admin bisa memasukkan diskon Saudara Kandung atau Anak Pegawai, yang kemudian memotong tagihan di sistem secara <em>real-time</em>.</li>\n        </ul>\n    </li>\n</ul>\n\n<h3>5. Kelompok Menu "Manajemen User" & "Jurnal & E-Rapot"</h3>\n<ul>\n    <li><strong>Manajemen User (User Sekolah & Log Activity):</strong> Menu ini mengatur otorisasi (RBAC - <em>Role Based Access Control</em>). Admin dapat memberikan akses spesifik ke staf baru. <strong>Log Activity</strong> (Jejak Audit) sangat penting untuk keamanan, di mana sistem merekam siapa (User ID) yang menghapus atau mengubah nominal tagihan demi mencegah <em>Fraud</em> (Kecurangan).</li>\n    <li><strong>Jurnal & E-Rapot (E-Rapot & Ijazah):</strong> Gerbang akses menuju <code>report-service</code>. Di sini Admin bisa memantau perkembangan input nilai dari puluhan guru, mengunci rapor (<em>Lock</em>), dan men-<em>generate</em> PDF Ijazah untuk diunduh oleh orang tua di akhir tahun ajaran.</li>\n</ul>', '1', '2', '80', '2026-07-15 02:23:49', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('126', '31', 'Seri 1: Anatomi UI/UX Dashboard dan Transaksi', 'seri-1-ui-ux-dashboard-dan-transaksi', '<p>Artikel ini adalah <strong>Seri 1 dari 5</strong> panduan bedah UI/UX Backoffice ALAZHARAPPS. Fokus pada artikel ini adalah membedah kelompok menu pertama pada Sidebar, yaitu <strong>Dashboard</strong> dan <strong>Transaksi</strong>.</p>\n\n<h3>1. Menu: Dashboard &rarr; Summary (Ringkasan)</h3>\n<p>Halaman ini adalah wajah (<em>Home</em>) dari Backoffice Admin Sekolah.</p>\n<ul>\n    <li><strong>UI Layout:</strong> Terdiri dari beberapa kotak (*Cards*) di baris atas yang menampilkan angka absolut (Misal: Total Pemasukan Hari Ini, Total Murid Aktif). Di baris bawahnya, terdapat area grafik visual besar (*Canvas/Chart Area*).</li>\n    <li><strong>Kolom Isian (Filter):</strong>\n        <ul>\n            <li><code>Filter Rentang Waktu (Date Range Picker):</code> Form kalender <em>dropdown</em> (Dari Tanggal - Sampai Tanggal). Digunakan untuk mempersempit data grafik arus kas (*Cashflow*).</li>\n            <li><code>Filter Jenis Penerimaan (Dropdown):</code> Opsi untuk melihat grafik khusus "Uang Pangkal" atau "SPP".</li>\n        </ul>\n    </li>\n    <li><strong>UX Behavior:</strong> Halaman ini bersifat <em>Read-Only</em> (Hanya Baca). Tidak ada tombol <em>Submit</em>. Perubahan pada filter akan langsung memicu (*trigger*) pemuatan ulang data grafik secara asinkron tanpa <em>loading</em> halaman penuh (SPA - <em>Single Page Application</em>).</li>\n</ul>\n\n<h3>2. Menu: Dashboard &rarr; Murid</h3>\n<p>Menampilkan kondisi demografi populasi murid di unit sekolah tersebut.</p>\n<ul>\n    <li><strong>UI Layout:</strong> Grafik batang (*Bar Chart*) berseri berdasarkan Tahun Ajaran (Misal: Batang Tahun 2024, 2025).</li>\n    <li><strong>UX Behavior (Interaktif):</strong> Saat grafik batang di-<em>hover</em> (kursor diletakkan di atasnya), akan muncul <em>Tooltip</em> (balon teks) berisi angka spesifik. Jika di-klik, UX akan memunculkan <em>Bottom Sheet</em> atau Modal Pop-up berisi tabel daftar nama murid yang menyusun angka pada batang tersebut.</li>\n</ul>\n\n<h3>3. Menu: Transaksi &rarr; PMB</h3>\n<p>Menu ini adalah jalan pintas (<em>Shortcut</em>) bagi Kasir atau Admin TU untuk mengelola validasi pembayaran formulir pendaftaran secara cepat tanpa harus masuk ke modul Master Biaya.</p>\n<ul>\n    <li><strong>UI Layout:</strong> Tampilan Tabel Data (*DataTables*) dengan fitur pencarian (<em>Search bar</em>) di kanan atas.</li>\n    <li><strong>Kolom Isian (Pencarian & Filter):</strong>\n        <ul>\n            <li><code>Cari Nama/No. Pendaftaran (Input Text):</code> Untuk mencari data calon siswa secara cepat.</li>\n            <li><code>Filter Status Pembayaran (Dropdown):</code> Memiliki opsi: <em>Semua, Menunggu Pembayaran, Lunas, Dibatalkan</em>.</li>\n            <li><code>Filter Gelombang (Dropdown):</code> Untuk menyortir pendaftar berdasarkan gelombang masuk.</li>\n        </ul>\n    </li>\n    <li><strong>Aksi (UX Actions):</strong> Pada setiap baris data di tabel, terdapat kolom "Aksi" dengan tombol-tombol ikonik:\n        <ul>\n            <li><strong>Ikon Mata (View):</strong> Membuka *Pop-up* detail tagihan.</li>\n            <li><strong>Ikon Uang (Pay/Verify):</strong> Membuka jendela khusus untuk <strong>Verifikasi Manual</strong>. Jika ada orang tua yang gagal memakai DOKU dan transfer langsung ke bank yayasan, Admin menekan tombol ini, lalu mengisi kolom <code>Tanggal Transfer</code> dan mengunggah <code>Bukti Foto Transfer (File Upload)</code>. Sistem kemudian akan mengubah status tagihannya menjadi Lunas secara paksa (<em>Force Paid</em>).</li>\n        </ul>\n    </li>\n</ul>\n\n<hr>\n<p><em>Baca kelanjutannya pada <strong>Seri 2: Analisa Menu Laporan</strong>.</em></p><hr>\n<h3>Arsitektur Sistem Sebenarnya (Backend Logic)</h3>\n<p>Di balik form UI Pembuatan Gelombang PMB yang tampak sederhana, sistem *Backend* (<code>school-service-new</code>) sebenarnya melakukan penjagaan ganda (*Dual Validation*) yang sangat ketat:</p>\n<ul>\n    <li><strong>Validasi Bentrok Gelombang (CheckActiveBatch):</strong> Jika Admin menekan tombol Simpan, sistem akan mengecek apakah masih ada gelombang yang berstatus Aktif untuk sekolah dan jenjang yang sama. Jika ada, UI akan memunculkan *Error BadRequest* dan menolak pembuatan gelombang baru.</li>\n    <li><strong>Validasi Kuota Penuh (CheckTargetSchool):</strong> Sistem juga menghitung kapasitas bangku kosong. Jika jumlah murid baru sudah mencapai Target Kuota yang ditetapkan Yayasan, sistem otomatis menolak pembukaan gelombang pendaftaran tambahan demi mencegah kelebihan kapasitas (<em>Overcapacity</em>).</li>\n    <li><strong>Penerbitan NIS Aman:</strong> Setelah calon murid diluluskan, sistem tidak lagi menggunakan logika urutan mentah untuk membuat Nomor Induk Siswa (NIS). Sistem menggunakan kalkulasi <code>lpad(right(cast(id AS text), 3), 3, \'0\')</code> untuk mengambil 3 digit ID terakhir secara presisi, mencegah kegagalan sistem saat pendaftar mencapai ribuan anak.</li>\n</ul>', '1', '2', '81', '2026-07-15 02:23:49', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('127', '31', 'Seri 2: Anatomi UI/UX Laporan Keuangan', 'seri-2-ui-ux-laporan-keuangan', '<p>Artikel ini adalah <strong>Seri 2 dari 5</strong> panduan bedah UI/UX Backoffice ALAZHARAPPS. Fokus pada artikel ini adalah membedah kelompok menu <strong>Laporan</strong>, yang dikhususkan untuk menarik data (*Export*) massal dari <em>database</em>.</p>\n\n<h3>Menu: Laporan &rarr; Keuangan Murid</h3>\n<p>Halaman ini bukan ditujukan untuk melakukan *input* data baru, melainkan pusat komando untuk menyaring (*Filtering*) dan mengunduh (*Download*) data finansial yang ada. Halaman ini adalah favorit bagian akuntansi sekolah.</p>\n\n<ul>\n    <li><strong>UI Layout (Antarmuka Utama):</strong>\n        <p>Halaman didominasi oleh sebuah panel form besar (*Filter Panel*) di bagian atas, dan sebuah tabel kosong (*Data Grid*) di bagian bawah yang baru akan terisi setelah tombol pencarian ditekan. Hal ini dirancang (secara UX) agar sistem tidak otomatis menarik jutaan data saat halaman pertama kali dibuka, yang bisa menyebabkan halaman menjadi lambat (*lag*).</p>\n    </li>\n    \n    <li><strong>Kolom Isian (Form Filter):</strong>\n        <p>Agar Admin dapat menarik laporan spesifik, disediakan kolom isian berlapis (<em>Cascading Dropdowns</em>):</p>\n        <ul>\n            <li><code>Tahun Ajaran (Dropdown):</code> Memilih tahun akademik yang ingin dilaporkan.</li>\n            <li><code>Tingkat Kelas (Dropdown):</code> Opsional. Jika hanya ingin menarik laporan kelas 1.</li>\n            <li><code>Rombongan Belajar (Dropdown):</code> Bergantung pada pilihan Tingkat Kelas (UX: <em>Dependent Dropdown</em>). Hanya akan aktif/bisa dipilih jika Tingkat Kelas sudah diisi. (Misal: 1A, 1B).</li>\n            <li><code>Status Pembayaran (Dropdown):</code> Opsi: <em>Semua, Lunas, Belum Lunas</em>.</li>\n            <li><code>Komponen Biaya (Dropdown):</code> Opsi: <em>SPP, Uang Pangkal, Seragam, Kegiatan, dll.</em></li>\n            <li><code>Periode Waktu (Date Picker):</code> <em>Start Date</em> dan <em>End Date</em> untuk membatasi tanggal transaksi.</li>\n        </ul>\n    </li>\n\n    <li><strong>UX Behavior (Tombol Aksi):</strong>\n        <p>Setelah filter diisi, Admin akan berhadapan dengan dua tombol utama dengan fungsi visual yang kontras:</p>\n        <ul>\n            <li><strong>Tombol "Tampilkan Data" (Warna Biru/Utama):</strong> Akan mengirim kueri ke <code>report-service</code> dan menampilkan datanya di dalam tabel web (*DataTables*) di bawah form tersebut. Tabel ini dilengkapi fitur <em>Pagination</em> (halaman 1, 2, 3...) agar tidak memberatkan <em>browser</em>.</li>\n            <li><strong>Tombol "Export Excel / CSV" (Warna Hijau):</strong> Tombol pamungkas. Saat ditekan, UX akan memunculkan indikator <em>Loading/Spinner</em>. Sistem di belakang layar memproses pembuatan *file spreadsheet* mentah. Setelah selesai, *file* akan otomatis terunduh (*download*) ke dalam komputer Admin.</li>\n        </ul>\n    </li>\n</ul>\n\n<hr>\n<p><em>Baca kelanjutannya pada <strong>Seri 3: Analisa Menu Master Data Sekolah</strong>.</em></p>', '1', '2', '82', '2026-07-15 02:23:50', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('128', '31', 'Seri 3: Anatomi UI/UX Data Master Sekolah', 'seri-3-ui-ux-data-master-sekolah', '<p>Artikel ini adalah <strong>Seri 3 dari 5</strong> panduan bedah UI/UX Backoffice ALAZHARAPPS. Membahas kelompok menu <strong>Sekolah</strong>, yang merupakan jantung "Master Data" bagi unit sekolah (Pusat pengaturan demografi dan SDM).</p>\n\n<h3>1. Menu: Data Murid & Profile Sekolah</h3>\n<ul>\n    <li><strong>UI Layout (Data Murid):</strong> Tabel master panjang (<em>Data Grid</em>) dengan foto profil bulat (Avatar). Terdapat tombol aksi untuk <em>Edit Biodata</em>. Di dalam form Edit, kolom isian dibagi menjadi beberapa <em>Tab</em> UX: (Tab Data Pribadi, Tab Data Orang Tua, Tab Data Medis) agar form tidak memanjang tak terbatas ke bawah (*Endless Scrolling*).</li>\n    <li><strong>UI Layout (Profile Sekolah):</strong> Form statis dengan kolom isian dasar: <code>Nama Sekolah</code>, <code>NPSN</code>, <code>Alamat (Textarea)</code>, <code>Logo Sekolah (Upload Image)</code>.</li>\n</ul>\n\n<h3>2. Menu: Kurikulum, Program, Sarpras, Ekstrakurikuler, Prestasi</h3>\n<p>Kumpulan menu ini memiliki <em>User Experience (UX)</em> yang seragam dan standar, menggunakan pola CRUD (<em>Create, Read, Update, Delete</em>).</p>\n<ul>\n    <li>Setiap menu hanya berisi form sederhana (misal: Tambah Ekstrakurikuler &rarr; <code>Nama Ekskul</code>, <code>Deskripsi</code>, <code>Pembina</code>).</li>\n    <li>Fungsi UX-nya adalah menyediakan sumber data (<em>Data Source</em>) untuk kolom <em>Dropdown</em> di menu yang lebih kompleks (seperti di form Rapor).</li>\n</ul>\n\n<h3>3. Menu: Rombel (Rombongan Belajar) & Pegawai</h3>\n<p>Menu Rombel (Kelas) adalah titik relasi paling kuat di sistem ini.</p>\n<ul>\n    <li><strong>UI Tambah Rombel:</strong>\n        <ul>\n            <li><code>Nama Kelas (Input Text):</code> Contoh: "Kelas 1A" atau "Abu Bakar".</li>\n            <li><code>Tingkat Kelas (Dropdown):</code> Untuk menentukan level (Misal: SD Kelas 1).</li>\n            <li><code>Wali Kelas (Searchable Dropdown):</code> <strong>Krusial!</strong> Kolom ini menarik data dari menu <strong>Pegawai</strong>. UX form menggunakan kotak pencarian pintar (mengetikkan huruf "B", muncul nama "Budi").</li>\n        </ul>\n    </li>\n    <li><strong>Manajemen Anggota Rombel (Mapping UI):</strong> Saat Rombel berhasil dibuat, UX akan berubah menjadi <strong>Dual Listbox</strong> (Dua kolom bersebelahan). Sebelah kiri adalah "Daftar Murid yang Belum Punya Kelas", sebelah kanan adalah "Anggota Rombel Ini". Admin cukup memindahkan (<em>Move Arrow / Drag & Drop</em>) nama siswa ke kanan untuk mendaftarkannya ke kelas tersebut.</li>\n</ul>\n\n<h3>4. Menu: Akademik (Kenaikan Kelas & Kelulusan)</h3>\n<p>Ini adalah alat (<em>Tools</em>) pemrosesan massal tahunan.</p>\n<ul>\n    <li><strong>UI Layout (Kenaikan Kelas Massal):</strong>\n        <p>Bentuk form dirancang sangat aman untuk mencegah salah klik (*Human Error*).</p>\n        <ul>\n            <li><strong>Langkah 1:</strong> Memilih <code>Kelas Asal (Dropdown)</code> dan <code>Tahun Ajaran Asal</code>. Sistem memunculkan tabel berisi nama-nama siswa.</li>\n            <li><strong>Langkah 2:</strong> Memilih <code>Kelas Tujuan (Dropdown)</code> dan <code>Tahun Ajaran Baru</code>.</li>\n            <li><strong>Langkah 3 (Checklist):</strong> Terdapat kotak centang (<em>Checkbox</em>) masal. Admin mencentang semua siswa, lalu menekan tombol <strong>"Proses Naik Kelas"</strong>.</li>\n        </ul>\n    </li>\n    <li><strong>UX Kelulusan:</strong> Tombol kelulusan biasanya diamankan dengan kotak dialog (<em>Modal Confirmation</em>) berwarna merah yang meminta Admin mengetik ulang kata "LULUS" (<em>Hard Confirmation</em>) untuk memastikan siswa tersebut benar-benar dikeluarkan dari daftar Siswa Aktif dan dipindahkan ke Tabel Alumni.</li>\n</ul>\n\n<hr>\n<p><em>Baca kelanjutannya pada <strong>Seri 4: Analisa Menu Administrasi Biaya & PMB</strong> (Paling Detail!).</em></p>', '1', '2', '83', '2026-07-15 02:23:50', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('129', '31', 'Seri 4: Anatomi UI/UX Administrasi Biaya (Daftar Ulang)', 'seri-4-ui-ux-administrasi-biaya-dan-pmb', '<p>Artikel ini adalah <strong>Seri 4 dari 5</strong> panduan bedah UI/UX Backoffice ALAZHARAPPS. Ini adalah artikel terpenting karena membahas Dapur Utama Operasional (Kelompok Menu <strong>Administrasi</strong>), terutama membedah <em>Form</em> Biaya Daftar Ulang.</p>\n\n<h3>1. Sub-Menu Administrasi &rarr; PMB (Penerimaan Murid Baru)</h3>\n<p>Kumpulan form ini mengatur logika (<em>Business Logic</em>) penerimaan awal siswa.</p>\n<ul>\n    <li><strong>Gelombang Pendaftaran:</strong> Form untuk membuat batas waktu. (Kolom: <code>Nama Gelombang</code>, <code>Tanggal Mulai</code>, <code>Tanggal Berakhir</code>, <code>Biaya Formulir</code>).</li>\n    <li><strong>Jadwal Ujian & Peserta Ujian:</strong> Form (UI Grid) untuk menentukan tanggal tes (<em>Entrance Test</em>) dan mendaftarkan ID Calon Siswa (Animo) ke dalam ruangan ujian.</li>\n</ul>\n\n<h3>2. Sub-Menu Administrasi &rarr; Biaya (Penggerak Keuangan)</h3>\n<p>Di sinilah seluruh tagihan sistem bermula. UX didesain agar Admin bisa mengatur tagihan yang rumit menjadi fleksibel.</p>\n\n<h4>Bedah Tuntas UX Form "Tambah Biaya Daftar Ulang" (Berdasarkan Layar Utama)</h4>\n<p>Tagihan Daftar Ulang dieksekusi secara periodik (Tahunan) setiap kali murid akan naik kelas. Tata letak form ini sangat bersih (<em>Clean Design</em>) menggunakan form yang dibingkai (<em>Card Layout</em>).</p>\n<ul>\n    <li><strong>Kolom Atribut Penentu (Sisi Kiri & Kanan Atas):</strong>\n        <ul>\n            <li><code>Tahun Ajaran (Dropdown)*:</code> Menentukan untuk periode akademik kapan tagihan ini berlaku. Bersifat Wajib (Bintang Merah).</li>\n            <li><code>Tingkat Kelas (Dropdown)*:</code> Filter spesifik agar biaya ini hanya mengikat murid di kelas tertentu.</li>\n            <li><code>Program (Dropdown)*:</code> (Misal: Reguler, Bilingual, Tahfidz). Menentukan pembedaan harga antar program.</li>\n            <li><code>Tanggal Jatuh Tempo (Date Picker)*:</code> Sangat krusial (UX). Format kalender <code>dd/mm/yyyy</code>. Di balik layar, tanggal ini akan dibaca oleh <em>Worker Scheduler</em> untuk menembakkan notifikasi peringatan (<em>Push Notification</em>) ke HP orang tua jika melewati batas waktu.</li>\n        </ul>\n    </li>\n    \n    <li><strong>Fitur Dynamic Form (Penambahan Komponen Dinamis):</strong>\n        <p>Inilah letak fleksibilitas sistem. Alih-alih membuat satu form kaku "Biaya Total", UX menggunakan teknik <em>Dynamic Input Fields</em>.</p>\n        <ul>\n            <li><code>Komponen Biaya (Dropdown):</code> Admin memilih elemen penyusun tagihan (Misal: Uang Buku).</li>\n            <li><code>Nominal (Input Number):</code> Mengisi harga, biasanya dilengkapi dengan format *masking* otomatis (titik/koma mata uang).</li>\n            <li><strong>Tombol Biru [+ Tambah Komponen Biaya]:</strong> UX yang brilian. Admin dapat mengeklik tombol ini berulang kali untuk memunculkan baris *inputan* baru di bawahnya. Sehingga 1 tagihan Daftar Ulang bisa berisi rincian (Uang Buku, Uang Seragam, Uang Kegiatan) yang terpisah.</li>\n        </ul>\n    </li>\n\n    <li><strong>Indikator Real-time (Total Banner):</strong>\n        <p>Di bagian bawah terdapat kotak berwarna biru muda (<em>Light Blue Banner</em>) bertuliskan <strong>"Total Biaya Daftar Ulang: Rp 0"</strong>. Ini adalah fitur perhitungan otomatis (*Auto-Calculate JS*). Saat Admin mengetik Nominal, angka ini akan berubah secara langsung (*real-time*). Mencegah Admin salah hitung sebelum menekan tombol Simpan.</p>\n    </li>\n</ul>\n\n<h4>Menu Lain di Administrasi Biaya</h4>\n<ul>\n    <li><strong>Uang Sekolah (SPP):</strong> Secara UX hampir mirip, namun biasanya tidak menggunakan tombol penambahan komponen dinamis yang terlalu banyak karena sifatnya <em>flat rate</em> bulanan.</li>\n    <li><strong>Pengajuan Diskon:</strong> Menampilkan tabel *Approval*. Admin harus memilih jenis diskon (Saudara Kandung/Prestasi), mengunggah berkas persetujuan, lalu status tagihan siswa tersebut akan berubah.</li>\n</ul>\n\n<hr>\n<p><em>Baca penutup seri ini pada <strong>Seri 5: Analisa Manajemen User & Jurnal E-Rapot</strong>.</em></p><hr>\n<h3>Arsitektur Sistem Sebenarnya (Backend Logic)</h3>\n<p>Halaman Administrasi Biaya (seperti Uang Daftar Ulang dan Uang SPP) telah menerapkan <strong>Pengetatan Hak Akses Sentralistis (Role-Based Restriction)</strong> tingkat tinggi pada sisi *Frontend* (NextJS):</p>\n<ul>\n    <li><strong>Tombol Aksi Disembunyikan (Hidden UX):</strong> Jika Anda <em>login</em> sebagai Admin Sekolah/Unit, Anda tidak akan menemukan tombol <strong>Edit (Pensil)</strong>, <strong>Hapus (Tempat Sampah)</strong>, atau tombol <strong>Eksekusi Tagihan (Ceklis Generate)</strong> di layar Anda. Layar Anda hanya bersifat *Read-Only* (Hanya bisa melihat/Zoom).</li>\n    <li><strong>Kekuasaan Superadmin:</strong> Semua tombol krusial pembuat tagihan tersebut kini dirancang untuk <strong>hanya muncul (di-*render*)</strong> jika pengguna memiliki hak akses tertinggi, yaitu <code>role_id = 1</code> (Admin Pusat Yayasan). Ini mencegah Admin Unit secara sepihak memodifikasi besaran tagihan tanpa izin Pusat.</li>\n</ul>', '1', '2', '84', '2026-07-15 02:23:50', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('130', '31', 'Seri 5: Anatomi UI/UX Manajemen User dan E-Rapot', 'seri-5-ui-ux-manajemen-user-dan-e-rapot', '<p>Artikel ini adalah <strong>Seri 5 (Penutup)</strong> dari panduan bedah UI/UX Backoffice ALAZHARAPPS. Membahas dua kelompok menu terbawah pada Sidebar: <strong>Manajemen User</strong> (Otorisasi) dan <strong>Jurnal & E-Rapot</strong> (Akademik Lanjutan).</p>\n\n<h3>1. Kelompok Menu: Manajemen User</h3>\n<p>Ini adalah pusat keamanan (<em>Security Center</em>) dari operasional web Backoffice.</p>\n<ul>\n    <li><strong>User Sekolah:</strong>\n        <ul>\n            <li><strong>Fungsi UI:</strong> Menampilkan daftar (Tabel) seluruh akun staf yang memiliki hak akses (*login*) ke Backoffice khusus sekolah tersebut.</li>\n            <li><strong>Kolom Isian (Form Tambah User):</strong> \n                <ul>\n                    <li><code>Email & Password (Text Input):</code> Kredensial dasar.</li>\n                    <li><code>Role (Dropdown):</code> Inilah penentu <em>User Experience</em> staf. Jika Admin memilih "Wali Kelas" (Level 10), maka saat user tersebut *login*, *Sidebar* di sebelah kiri akan menyusut secara otomatis, menyembunyikan menu Keuangan dan PMB (Konsep <em>Role-Based Access Control / RBAC UI</em>).</li>\n                </ul>\n            </li>\n        </ul>\n    </li>\n    <li><strong>Log Activity (Jejak Audit):</strong>\n        <ul>\n            <li><strong>Fungsi UI:</strong> Menampilkan tabel <em>Read-Only</em> yang berisi jejak kaki digital. Terdapat kolom "Waktu", "User", "Aksi", dan "Target".</li>\n            <li><strong>UX Keamanan:</strong> Berguna untuk melacak insiden (<em>Forensic UX</em>). Misalnya, jika nominal "Uang Pangkal" tiba-tiba berubah menjadi 0 rupiah, Kepala Sekolah bisa melihat di menu ini nama Staf yang menekan tombol Edit tersebut pada jam berapa.</li>\n        </ul>\n    </li>\n</ul>\n\n<h3>2. Kelompok Menu: Jurnal & E-Rapot</h3>\n<p>Menu ini menjadi penghubung (*Bridge*) antara aktivitas harian guru dengan hasil akhir pencetakan ijazah.</p>\n<ul>\n    <li><strong>E-Rapot (Rapor Digital):</strong>\n        <ul>\n            <li><strong>UI Input Nilai Guru (Grid Input):</strong> Berbentuk tabel yang bisa diedit di tempat (*Inline Editing*). Guru tidak perlu menekan tombol \'Edit\' di halaman baru, melainkan bisa langsung mengetik nilai (angka 0-100) di dalam kotak-kotak tabel layaknya Microsoft Excel (menggunakan pustaka *Handsontable* atau antarmuka serupa).</li>\n            <li><strong>UI Peringatan KKM (Conditional Formatting):</strong> Jika guru mengetik angka "60" (di bawah KKM), UX sistem secara seketika (*OnBlur*) akan mengubah warna kotak tersebut menjadi warna merah (<em>Danger</em>) agar guru sadar tanpa perlu membaca instruksi tertulis.</li>\n            <li><strong>Validasi & Penguncian (Locking UX):</strong> Terdapat tombol berlogo "Gembok". Jika Kepala Sekolah menekan tombol ini, seluruh kotak isian nilai tadi akan *Disabled* (Abu-abu, tidak bisa diklik lagi). Tujuannya agar Rapor yang sudah dicetak ke PDF tidak berubah nilainya di masa depan.</li>\n        </ul>\n    </li>\n    <li><strong>Ijazah:</strong>\n        <ul>\n            <li><strong>UI Eksekusi (Generation):</strong> Berisi daftar siswa tingkat akhir (Kelas 6/9/12) dengan status "Lulus". Tersedia tombol "Generate Batch Ijazah" yang akan memproses pembuatan dokumen PDF masal di latar belakang (<em>Background Job / Worker</em>) dan menampilkan *progress bar* agar UI tidak terkesan <em>hang</em> atau <em>lag</em>.</li>\n        </ul>\n    </li>\n</ul>\n\n<hr>\n<p><strong>Kesimpulan Proyek Serial UI/UX:</strong><br>\nKeseluruhan desain <em>Sidebar</em> Admin Sekolah di ALAZHARAPPS membuktikan bahwa sistem ini dibuat bukan hanya untuk menyimpan data, tetapi dirancang memandu (<em>Guiding UX</em>) pegawai sekolah agar bekerja sesuai urutan standar operasional yang tepat (Dimulai dari pendaftaran murid, pengaturan biaya, hingga kelulusan di E-Rapot).</p><hr>\n<h3>Arsitektur Sistem Sebenarnya (Backend Logic)</h3>\n<p>Untuk formulir yang melibatkan pengunggahan (*upload*) dokumen fisik, sistem kini menerapkan batasan efisiensi dan keamanan jaringan yang sangat ketat:</p>\n<ul>\n    <li><strong>Penyusutan Kapasitas (1MB Limit):</strong> Pada halaman pengisian <strong>Jurnal Mengajar Guru</strong> dan <strong>Pengajuan Diskon Prestasi</strong>, *Frontend* membatasi ukuran maksimal *file* (foto/PDF) dari yang sebelumnya 2MB kini menjadi <strong>maksimal 1MB</strong>. Langkah ini menghemat ruang server penyimpanan AWS S3 secara drastis.</li>\n    <li><strong>Pencegahan Server Hang (Auto-Timeout):</strong> Di balik layar *Backend* pengunggahan dokumen (*student-discount-usecase*), diterapkan konteks *Timeout 30 Detik*. Artinya, jika internet pengguna sedang lambat dan proses unggah berjalan terlalu lama, sistem akan memutus (membatalkan) koneksi pada detik ke-30 secara rapi, mencegah aplikasi mengalami <em>loading</em> abadi (<em>Hang</em>).</li>\n    <li><strong>Arsitektur Error Pembayaran:</strong> Jika terjadi masalah pada pembayaran <em>Virtual Account</em> DOKU, sistem *Backend* kini menggunakan pola <em>Error Builder</em> mutakhir yang merekam jejak (*Stack Trace*) kegagalan langkah demi langkah (Misal: Kode Error "01", "02") sehingga proses <em>Debugging</em> sangat akurat.</li>\n</ul>', '1', '2', '85', '2026-07-15 02:23:50', '2026-07-15 06:15:41');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('131', '29', 'Panduan Proses Bisnis: Siklus Administratif & Finansial ALAZHARAPPS', 'panduan-proses-bisnis-inti-alazharapps', '<p>Dokumen ini memetakan alur kerja (<em>Business Process</em>) dari ujung ke ujung (*end-to-end*) khusus untuk ekosistem <strong>ALAZHARAPPS</strong>. Ekosistem ini berfokus pada dua tulang punggung utama yayasan: <strong>Administrasi Siswa (PMB)</strong> dan <strong>Mesin Keuangan (Financial Engine)</strong>.</p>\n\n<h3>Diagram Alur Proses Bisnis ALAZHARAPPS</h3>\n<pre><code class="language-mermaid">\nflowchart TD\n    A[Masyarakat / Orang Tua] -->|Melihat Info| B(Animo PMB)\n    B -->|Membeli Formulir| C(Calon Murid)\n    C -->|Ikut Tes Seleksi| D{Ujian Masuk}\n    D -->|Lulus| E[Diterima / Data Calon Murid]\n    D -->|Gagal| Z[Ditolak]\n    \n    E -->|Tagihan Muncul| F(Uang Pangkal)\n    F -->|Bayar via DOKU| G{Payment Gateway}\n    G -->|Webhook Sukses| H[Murid Aktif]\n    \n    H -->|Siklus Bulanan| I(Tagihan SPP)\n    H -->|Siklus Tahunan| J(Naik Kelas & Tagihan Daftar Ulang)\n    J -->|Akhir Jenjang| K(Kelulusan / Alumni)\n</code></pre>\n\n<h3>1. Proses Hulu: Penerimaan Murid Baru (PMB)</h3>\n<p>Proses ini mengubah masyarakat umum menjadi siswa resmi sekolah.</p>\n<ul>\n    <li><strong>Tahap 1 (Setup Gelombang):</strong> Admin Pusat / Sekolah membuka "Keran" pendaftaran dengan mengatur nama gelombang, rentang tanggal pendaftaran, dan biaya formulir masuk.</li>\n    <li><strong>Tahap 2 (Animo/Peminat):</strong> Orang tua mendaftar di portal web/mobile. Mereka baru sebatas membuat akun. Status anaknya di sistem disebut sebagai <strong>Animo</strong> (Peminat).</li>\n    <li><strong>Tahap 3 (Pembelian Formulir):</strong> Orang tua melakukan pembayaran biaya formulir (biasanya via <em>Virtual Account</em>). Setelah lunas, status anak naik level menjadi <strong>Calon Murid</strong>. Di titik ini, mereka mendapatkan nomor ujian.</li>\n    <li><strong>Tahap 4 (Seleksi & Ujian):</strong> Sekolah mengatur <em>Jadwal Ujian</em>. Calon murid datang untuk tes (tertulis/wawancara). Setelah tes selesai, Panitia PMB merapatkan hasil ujian.</li>\n    <li><strong>Tahap 5 (Yudisium Kelulusan):</strong> Admin menekan tombol "Lulus" di sistem. Selamat! Anak tersebut kini siap menjadi warga sekolah, <strong>NAMUN</strong> statusnya belum aktif sepenuhnya sebelum ia menyelesaikan administrasi keuangan tahap awal.</li>\n</ul>\n\n<h3>2. Proses Inti: Mesin Keuangan & Payment Gateway</h3>\n<p>Ini adalah siklus perputaran uang (*Cashflow*) yang diotomasikan oleh sistem.</p>\n<ul>\n    <li><strong>Tahap 1 (Kewajiban Uang Pangkal):</strong> Segera setelah siswa dinyatakan lulus PMB, sistem secara otomatis me-<em>generate</em> (menerbitkan) tagihan raksasa bernama <strong>Uang Pangkal</strong> (terdiri dari Uang Gedung, Seragam, Buku, dll).</li>\n    <li><strong>Tahap 2 (Proses Pembayaran DOKU):</strong> Orang tua membuka Aplikasi Mobile, melihat tagihan Uang Pangkal (berwarna merah). Mereka memilih bank (Misal: Mandiri VA) lalu mentransfer uangnya.</li>\n    <li><strong>Tahap 3 (Mekanisme Webhook):</strong> Server Bank memberi tahu server DOKU, lalu DOKU mengirim "Pesan Gaib" (*Webhook*) ke server <code>transaction-service</code> ALAZHARAPPS. Sistem memvalidasi *Signature* (Tanda tangan keamanan). Jika valid, status tagihan di *database* diubah menjadi Lunas (Hijau). <strong>Siswa tersebut kini resmi menjadi Murid Aktif.</strong></li>\n    <li><strong>Tahap 4 (Siklus Berulang / Recurring Billing):</strong>\n        <ul>\n            <li><strong>Bulanan (SPP):</strong> Pada tanggal 1 setiap bulannya, sistem keuangan (*Cron Job / Scheduler*) otomatis menembakkan tagihan SPP ke HP seluruh orang tua.</li>\n            <li><strong>Tunggakan & Notifikasi:</strong> Jika melewati batas Jatuh Tempo, sistem menembakkan notifikasi peringatan (*Push Notification*) ke HP penunggak secara berkala.</li>\n        </ul>\n    </li>\n</ul>\n\n<h3>3. Proses Hilir: Mutasi & Promosi (Akhir Tahun Ajaran)</h3>\n<p>Siklus ini terjadi setiap bulan Juni/Juli saat pergantian tahun ajaran baru.</p>\n<ul>\n    <li><strong>Tahap 1 (Pembuatan Tahun Ajaran Baru):</strong> Admin menonaktifkan Tahun Ajaran lama dan mengaktifkan yang baru di menu Master Data.</li>\n    <li><strong>Tahap 2 (Kenaikan Kelas Massal):</strong> Admin masuk ke menu "Kenaikan Kelas", memilih rombongan belajar lama (Misal: Kelas 1A) lalu memindahkan seluruh siswanya ke kelas baru (Misal: Kelas 2A).</li>\n    <li><strong>Tahap 3 (Tagihan Daftar Ulang):</strong> Bersamaan dengan naiknya kelas siswa, Admin Keuangan menerbitkan tagihan tahunan <strong>Uang Daftar Ulang</strong>.</li>\n    <li><strong>Tahap 4 (Kelulusan / Alumni):</strong> Untuk siswa tingkat akhir (Kelas 6, 9, 12), Admin mengeksekusi menu Kelulusan. Sistem memindahkan data mereka dari tabel "Siswa Aktif" menjadi "Alumni", sehingga mereka tidak akan pernah lagi ditagihkan SPP di bulan-bulan berikutnya.</li>\n</ul>', '1', '2', '17', '2026-07-15 02:35:19', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('132', '29', 'Panduan Proses Bisnis: Siklus Akademik & CBT LMSALAZHARAPPS', 'panduan-proses-bisnis-inti-lmsalazharapps', '<p>Dokumen ini memetakan alur kerja (<em>Business Process</em>) dari ujung ke ujung (*end-to-end*) khusus untuk ekosistem <strong>LMSALAZHARAPPS</strong>. Ekosistem ini berfokus pada denyut nadi harian sekolah: <strong>Kegiatan Belajar Mengajar (KBM)</strong>, <strong>Ujian (CBT)</strong>, dan <strong>Penilaian Akademik (E-Rapot)</strong>.</p>\n\n<h3>Diagram Alur Proses Bisnis LMSALAZHARAPPS</h3>\n<pre><code class="language-mermaid">\nflowchart TD\n    A[Awal Tahun Ajaran] --> B(Penyusunan RPP & Jadwal Pelajaran)\n    B --> C(KBM Harian & Jurnal Guru)\n    C --> D{Presensi Siswa}\n    D -->|Hadir/Izin| E[Notifikasi Mobile Orang Tua]\n    D -->|Alpa| F[Teguran Wali Kelas]\n    \n    C --> G(Tugas & Ujian CBT)\n    G --> H{Aplikasi SEB Mobile}\n    H -->|Ujian Selesai| I(Penilaian Otomatis)\n    \n    I --> J[Rekapitulasi Nilai]\n    D --> J\n    J --> K(E-Rapot & Penguncian)\n    K --> L[Cetak PDF / Ijazah]\n</code></pre>\n\n<h3>1. Proses Hulu: Perencanaan Akademik (Awal Tahun)</h3>\n<p>Proses ini terjadi sebelum siswa masuk ke dalam kelas pada hari pertama sekolah.</p>\n<ul>\n    <li><strong>Tahap 1 (Pemetaan Kelas & Wali):</strong> Kepala Sekolah atau Kurikulum membagi siswa ke dalam Rombongan Belajar (Rombel) dan menunjuk Wali Kelas.</li>\n    <li><strong>Tahap 2 (Pembuatan Jadwal Pelajaran):</strong> Admin Kurikulum menyusun matriks jadwal. Kapan Guru Matematika mengajar di Kelas 7A, dan kapan Guru Agama mengajar di 7B. Jadwal ini yang nantinya akan di-<em>consume</em> (dibaca) oleh Aplikasi Mobile Siswa dan Orang Tua.</li>\n    <li><strong>Tahap 3 (Rencana Pelajaran/RPP):</strong> Guru menyiapkan materi pembelajaran (Modul/PDF/Video) yang diunggah ke *course-service* agar bisa diakses siswa dari rumah.</li>\n</ul>\n\n<h3>2. Proses Inti: KBM Harian (Kegiatan Belajar Mengajar)</h3>\n<p>Ini adalah rutinitas yang terjadi setiap hari (Senin - Jumat).</p>\n<ul>\n    <li><strong>Tahap 1 (Jurnal Mengajar Guru):</strong> Saat bel masuk berbunyi, Guru membuka aplikasi/web, memilih jadwal kelasnya hari itu, dan mengisi "Jurnal Mengajar" (Materi apa yang diajarkan hari ini).</li>\n    <li><strong>Tahap 2 (Presensi Harian):</strong> Guru memanggil nama siswa satu per satu. Di dalam sistem (<em>jurnal-service</em>), Guru mencentang status kehadiran (Hadir, Sakit, Izin, Alpa).</li>\n    <li><strong>Tahap 3 (Notifikasi Real-time):</strong> Saat Guru menekan tombol "Simpan Presensi", sistem langsung menembakkan *Push Notification* ke HP Orang Tua yang memberitahukan bahwa anak mereka sudah berada di dalam kelas dengan selamat (atau sebaliknya, membolos).</li>\n</ul>\n\n<h3>3. Proses Evaluasi: E-Learning & CBT (Ujian)</h3>\n<p>Proses penilaian harian, UTS, hingga UAS.</p>\n<ul>\n    <li><strong>Tahap 1 (Pembuatan Bank Soal):</strong> Guru menyusun soal (Pilihan Ganda / Esai) di dalam Bank Soal sistem LMS.</li>\n    <li><strong>Tahap 2 (Penjadwalan CBT - Computer Based Test):</strong> Guru menerbitkan ujian dengan batas waktu (<em>Timer</em>) yang ketat (Misalnya: Mulai jam 08:00, selesai 09:30).</li>\n    <li><strong>Tahap 3 (Pelaksanaan Ujian Anti-Nyontek):</strong> Siswa membuka ujian tersebut menggunakan Aplikasi Mobile Android. Sistem memaksa mereka masuk ke <em>Safe Exam Browser (SEB) Mode</em> (Layar terkunci, tidak bisa buka Google, tidak bisa <em>Screenshot</em>, dan navigasi HP dimatikan). Jika ketahuan mencoba keluar aplikasi, ujian akan tertutup otomatis.</li>\n    <li><strong>Tahap 4 (Kalkulasi Nilai Otomatis):</strong> Segera setelah waktu habis, sistem otomatis memeriksa jawaban pilihan ganda dan memunculkan skor. Menghemat waktu koreksi guru hingga 90%.</li>\n</ul>\n\n<h3>4. Proses Hilir: E-Rapot & Pencetakan Kelulusan</h3>\n<p>Siklus administratif yang terjadi di akhir Semester atau akhir Tahun Ajaran.</p>\n<ul>\n    <li><strong>Tahap 1 (Input Nilai Akhir):</strong> Guru mata pelajaran menggabungkan nilai tugas harian, nilai UTS, dan UAS (dari CBT di atas) ke dalam tabel (<em>Grid</em>) E-Rapot di Backoffice. Jika nilai di bawah KKM, sistem memberikan indikator peringatan visual.</li>\n    <li><strong>Tahap 2 (Validasi Wali Kelas):</strong> Wali kelas memeriksa kembali seluruh nilai dari semua guru mata pelajaran untuk anak walinya, lalu menambahkan catatan/deskripsi sikap (Karakter).</li>\n    <li><strong>Tahap 3 (Penguncian / Locking):</strong> Kepala Sekolah mengecek rekapitulasi. Jika sudah benar, Kepala Sekolah menekan tombol "Gembok" (<em>Lock</em>). Artinya, guru tidak bisa lagi diam-diam mengubah nilai siswanya.</li>\n    <li><strong>Tahap 4 (Pencetakan Massal):</strong> Sistem me-<em>generate</em> (membuat) ratusan file PDF (Buku Rapor atau Ijazah kelulusan) sekaligus. File PDF ini bisa langsung diakses oleh Orang Tua dari Aplikasi Mobile tanpa harus menunggu pembagian rapor fisik di sekolah.</li>\n</ul>', '1', '2', '18', '2026-07-15 02:35:19', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('135', '30', 'Panduan Spesifik: Alur Pengajuan Diskon (Potongan)', 'panduan-spesifik-alur-pengajuan-diskon', '<p>Dokumen ini adalah Panduan Spesifik (<em>Deep-Dive</em>) mengenai tata cara dan alur kerja (*Workflow*) fitur <strong>Pengajuan Diskon (Potongan Biaya)</strong> di sistem ALAZHARAPPS.</p>\n\n<h3>Konteks Bisnis</h3>\n<p>Dalam operasional sekolah, tidak semua siswa membayar penuh (<em>Full Payment</em>). Ada kondisi khusus di mana siswa berhak mendapat keringanan (Diskon Saudara Kandung, Anak Pegawai, Prestasi, atau Yatim Piatu). Sistem dirancang agar pemberian diskon tidak bisa dilakukan sembarangan oleh Kasir, melainkan harus melalui proses Validasi (<em>Approval</em>) bertingkat demi menghindari kecurangan (*Fraud*).</p>\n\n<h3>Alur Kerja (SOP) Pengajuan Diskon</h3>\n\n<ol>\n    <li>\n        <strong>Inisiasi oleh Tata Usaha (TU)</strong>\n        <ul>\n            <li><strong>Skenario:</strong> Orang tua siswa datang ke TU membawa berkas persyaratan (Kartu Keluarga untuk bukti Saudara Kandung, atau Piagam Lomba untuk bukti Prestasi).</li>\n            <li><strong>Jejak UI:</strong> TU membuka Web Backoffice &rarr; Sidebar <code>Administrasi</code> &rarr; <code>Biaya</code> &rarr; <code>Pengajuan Diskon</code>.</li>\n            <li><strong>Aksi UX:</strong> TU menekan tombol <strong>Tambah Pengajuan</strong>. TU memilih nama siswa, memilih <em>Jenis Diskon</em> (Misal: Saudara Kandung = 10%), lalu sistem akan meminta TU mengunggah (*upload*) dokumen pendukung berupa file PDF/Foto.</li>\n            <li><strong>Syarat Teknis Sistem (Validasi Upload):</strong> \n                <ul>\n                    <li>Batas maksimal ukuran *file* yang diizinkan adalah **1MB**. Jika ukuran melebihi limit, UI akan memberikan peringatan dan *Upload* ditolak.</li>\n                    <li>Sistem *Backend* menerapkan teknologi **Auto-Timeout 30 Detik** ke *Cloud Server* (AWS S3). Jika koneksi internet TU lambat atau terputus di tengah jalan, sistem tidak akan *hang/loading* selamanya, melainkan langsung membatalkan proses dengan rapi.</li>\n                </ul>\n            </li>\n            <li><strong>Status:</strong> Tagihan siswa saat ini masih utuh (Belum terpotong), dan status pengajuan menjadi <strong>Menunggu Persetujuan (Pending)</strong>.</li>\n        </ul>\n    </li>\n    <li>\n        <strong>Validasi (Approval) oleh Kepala Sekolah / Pimpinan</strong>\n        <ul>\n            <li><strong>Skenario:</strong> Kepala Sekolah masuk ke sistem untuk memverifikasi keabsahan dokumen.</li>\n            <li><strong>Jejak UI:</strong> Sama seperti di atas, namun Kepala Sekolah melihat tabel daftar antrean pengajuan diskon.</li>\n            <li><strong>Aksi UX:</strong> Kepala Sekolah mengklik ikon <strong>Mata (View)</strong> untuk memeriksa foto Kartu Keluarga. Jika datanya valid, Kepala Sekolah menekan ikon <strong>Ceklis Hijau (Approve)</strong>.</li>\n            <li><strong>Reaksi Sistem (Otomatis):</strong> Begitu tombol *Approve* ditekan, <em>Backend System</em> akan bekerja. Sistem otomatis mengurangi <em>Grand Total</em> tagihan siswa (Misal: dari Rp10.000.000 menjadi Rp9.000.000). </li>\n        </ul>\n    </li>\n    <li>\n        <strong>Notifikasi ke Aplikasi Mobile Orang Tua</strong>\n        <ul>\n            <li><strong>Reaksi UX Orang Tua:</strong> Sesaat setelah di-<em>approve</em>, tagihan di Aplikasi Mobile HP orang tua akan berkedip dan nominalnya berubah otomatis. Jika orang tua menekan detail tagihan, akan muncul keterangan rincian: "Potongan Saudara Kandung: -Rp1.000.000". Orang tua kemudian bisa melunasinya via DOKU <em>Virtual Account</em>.</li>\n        </ul>\n    </li>\n</ol>\n\n<blockquote>\n<p><strong>Catatan Keamanan (Audit Trail):</strong> Semua proses siapa yang mengajukan, dan siapa Kepala Sekolah yang menyetujui, terekam secara abadi di dalam <strong>Log Activity</strong> beserta stempel waktu (*Timestamp*)-nya. Hal ini mencegah adanya staf yang bermain mata ("Diskon Bodong").</p>\n</blockquote>', '1', '2', '19', '2026-07-15 02:45:06', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('136', '30', 'Panduan Spesifik: Alur Pengajuan Angsuran (Cicilan)', 'panduan-spesifik-alur-pengajuan-angsuran', '<p>Dokumen ini adalah Panduan Spesifik (<em>Deep-Dive</em>) mengenai tata cara dan alur kerja (*Workflow*) fitur <strong>Pengajuan Angsuran (Cicilan Biaya)</strong> di sistem ALAZHARAPPS.</p>\n\n<h3>Konteks Bisnis</h3>\n<p>Komponen biaya besar seperti <strong>Uang Pangkal</strong> (yang bisa mencapai belasan juta rupiah) seringkali menjadi beban berat jika harus dibayar lunas sekaligus (<em>Lump Sum</em>) oleh orang tua di awal tahun. Oleh karena itu, sistem menyediakan fitur Angsuran/Cicilan agar tagihan raksasa tersebut bisa dipecah menjadi beberapa termin tagihan yang lebih kecil.</p>\n\n<h3>Alur Kerja (SOP) Pengajuan Angsuran</h3>\n\n<ol>\n    <li>\n        <strong>Tatap Muka & Negosiasi dengan Tata Usaha</strong>\n        <ul>\n            <li><strong>Skenario:</strong> Orang tua siswa menghadap bagian Keuangan/TU untuk meminta keringanan pembayaran secara bertahap (Misal: Uang Pangkal Rp12.000.000 ingin dicicil 3 kali).</li>\n            <li><strong>Jejak UI (Admin TU):</strong> Membuka Web Backoffice &rarr; Sidebar <code>Administrasi</code> &rarr; <code>Biaya</code> &rarr; <code>Pengajuan Angsuran</code>.</li>\n            <li><strong>Aksi UX:</strong> \n                <p>Admin menekan <strong>Tambah Angsuran</strong> dan memilih nama siswa. Sistem akan menampilkan UX <em>Dynamic Form</em> (Formulir Dinamis) di mana Admin bisa menekan tombol "+ Tambah Termin" berkali-kali.</p>\n                <p>Admin mengisinya menjadi:</p>\n                <ul>\n                    <li>Termin 1: Rp5.000.000 (Jatuh Tempo: 1 Juli)</li>\n                    <li>Termin 2: Rp4.000.000 (Jatuh Tempo: 1 Agustus)</li>\n                    <li>Termin 3: Rp3.000.000 (Jatuh Tempo: 1 September)</li>\n                </ul>\n            </li>\n            <li><strong>Auto-Calculate Validation:</strong> Secara UX, sistem tidak akan mau menyimpan (<em>Save button disabled</em>) jika total penjumlahan ketiga termin tersebut kurang atau lebih dari Rp12.000.000. Ini menjaga agar tidak ada selisih uang.</li>\n        </ul>\n    </li>\n    <li>\n        <strong>Validasi & Eksekusi Pemecahan Tagihan</strong>\n        <ul>\n            <li><strong>Skenario:</strong> Sama seperti mekanisme Diskon, pengajuan cicilan ini biasanya butuh persetujuan (<em>Approval</em>) Kepala Sekolah/Bendahara Utama.</li>\n            <li><strong>Aksi UX:</strong> Kepala Sekolah menekan <strong>Approve</strong>.</li>\n            <li><strong>Reaksi Sistem (Database Split):</strong> Begitu di-<em>approve</em>, keajaiban sistem terjadi di belakang layar. Tagihan raksasa Uang Pangkal yang awalnya hanya 1 baris *database*, akan <strong>dipecah (di-split)</strong> menjadi 3 baris tagihan baru yang terpisah.</li>\n        </ul>\n    </li>\n    <li>\n        <strong>Tampilan di Aplikasi Mobile Orang Tua</strong>\n        <ul>\n            <li><strong>Skenario (Bulan Juli):</strong> Orang tua membuka HP dan hanya akan melihat 1 tagihan berwarna merah yaitu "Uang Pangkal Termin 1". Mereka membayarnya via DOKU.</li>\n            <li><strong>Skenario (Bulan Agustus):</strong> Saat tanggal 1 Agustus tiba (<em>Cron Job Scheduler</em> membaca Jatuh Tempo), sistem otomatis memunculkan tagihan "Uang Pangkal Termin 2" ke layar HP orang tua, disertai bunyi <em>Push Notification</em>.</li>\n        </ul>\n    </li>\n</ol>\n\n<blockquote>\n<p><strong>Kenapa harus dipecah termin?</strong><br>\nHal ini memudahkan sistem Payment Gateway (DOKU) yang membutuhkan 1 Nomor Virtual Account spesifik untuk 1 tagihan pasti. Jika tidak dipecah, sistem akan bingung ketika orang tua mentransfer Rp5 juta padahal tagihan aslinya Rp12 juta (Status akan menggantung / <em>Partial Paid</em>).</p>\n</blockquote>', '1', '2', '20', '2026-07-15 02:45:06', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('137', '30', 'Panduan Spesifik: Alur Pembatalan & Mutasi Keluar', 'panduan-spesifik-alur-pembatalan-siswa', '<p>Dokumen ini adalah Panduan Spesifik (<em>Deep-Dive</em>) mengenai tata cara dan alur kerja (*Workflow*) fitur <strong>Pembatalan Pendaftaran & Mutasi Keluar (Dropout / Pengunduran Diri)</strong> di sistem ALAZHARAPPS.</p>\n\n<h3>Konteks Bisnis (Pembatalan Siswa)</h3>\n<p>Ada kalanya calon siswa yang sudah membayar lunas Uang Pangkal tiba-tiba mengundurkan diri (karena pindah kota, diterima di sekolah negeri, dll). Proses membatalkan siswa tidak semudah sekadar menghapus namanya dari *database*, karena ini menyangkut uang yang sudah terekam di sistem (*Refund*) dan kuota bangku kosong yang harus dibuka kembali untuk siswa lain.</p>\n\n<h3>Alur Kerja (SOP) Pembatalan & Pengunduran Diri</h3>\n\n<ol>\n    <li>\n        <strong>Pembatalan Calon Siswa Baru (Refund Uang Pangkal)</strong>\n        <ul>\n            <li><strong>Skenario:</strong> Siswa X sudah lunas Uang Pangkal, tapi batal masuk.</li>\n            <li><strong>Jejak UI:</strong> Admin masuk ke Sidebar <code>Administrasi</code> &rarr; <code>PMB</code> &rarr; <code>Data Calon Murid</code>.</li>\n            <li><strong>Aksi UX & Sistem:</strong> Admin menekan tombol <strong>Batalkan Siswa</strong>. UX akan memunculkan *Pop-up Warning* berwarna merah untuk memastikan tindakan ini. Ketika dieksekusi:\n                <ol type="a">\n                    <li>Status anak tersebut diubah dari "Calon Murid" menjadi "Dibatalkan" (<em>Soft Delete</em>, data tidak dihapus permanen untuk keperluan audit).</li>\n                    <li>Sistem Keuangan akan memberikan tanda (<em>Flagging</em>) pada tagihan lunasnya untuk diteruskan ke menu <em>Refund / Pengembalian Dana</em> (yang akan dieksekusi manual oleh Yayasan).</li>\n                    <li><strong>Efek Samping (Side-effect):</strong> Kuota penerimaan di gelombang PMB tersebut akan otomatis bertambah +1 secara *real-time*, sehingga pendaftar *waiting list* bisa langsung masuk.</li>\n                </ol>\n            </li>\n        </ul>\n    </li>\n    <li>\n        <strong>Mutasi Keluar / Drop Out (Siswa Aktif)</strong>\n        <ul>\n            <li><strong>Skenario:</strong> Siswa Y pindah sekolah di tengah semester.</li>\n            <li><strong>Jejak UI:</strong> Admin masuk ke Sidebar <code>Sekolah</code> &rarr; <code>Data Murid</code>.</li>\n            <li><strong>Aksi UX & Sistem:</strong> Admin menekan menu Edit lalu mengganti Status Siswa menjadi <strong>Mutasi Keluar</strong>, diwajibkan mengisi kolom teks <code>Alasan Mutasi</code>. Reaksi sistem:\n                <ol type="a">\n                    <li>Siswa Y akan dihapus hubungannya dari <strong>Rombel (Kelas)</strong> dan tidak akan muncul lagi di E-Rapot milik Guru.</li>\n                    <li><em>Cron Job</em> tagihan SPP bulanan untuk siswa Y akan dihentikan seketika itu juga (<strong>Terminated</strong>).</li>\n                    <li>Aplikasi Mobile milik orang tua akan langsung ter-<em>log-out</em> (Akses dicabut) atau masuk ke mode *Read-Only* (Hanya bisa melihat riwayat, tidak bisa melakukan aksi).</li>\n                </ol>\n            </li>\n        </ul>\n    </li>\n</ol>\n\n<blockquote>\n<p><strong>Kenapa tidak menggunakan fitur "Hapus" (Delete) biasa?</strong><br>\nSistem berskala *Enterprise* tidak pernah menggunakan penghapusan permanen (*Hard Delete*) pada data transaksi dan manusia. Semua penghapusan bersifat merubah status (Aktif menjadi Non-Aktif / *Soft Delete*). Jika data dihapus fisik, seluruh laporan keuangan tahunan dan riwayat nilai E-Rapot di masa lalu akan berantakan (*Data Integrity Failure*).</p>\n</blockquote>', '1', '2', '21', '2026-07-15 04:05:13', '2026-07-15 06:15:40');
INSERT INTO `documents` (`id`, `category_id`, `title`, `slug`, `content`, `is_published`, `created_by`, `order`, `created_at`, `updated_at`) VALUES ('138', '30', 'Panduan Spesifik: Alur Penanganan Tunggakan Kronis', 'panduan-spesifik-alur-penanganan-tunggakan', '<p>Dokumen ini adalah Panduan Spesifik (<em>Deep-Dive</em>) mengenai tata cara dan alur kerja (*Workflow*) sistem dalam melakukan <strong>Penanganan Tunggakan Kronis (Chronic Arrears)</strong> di ALAZHARAPPS.</p>\n\n<h3>Konteks Bisnis (Tunggakan Finansial)</h3>\n<p>Tunggakan SPP atau tagihan lainnya adalah ancaman terbesar bagi <em>Cashflow</em> yayasan. Oleh karena itu, ALAZHARAPPS dilengkapi dengan mesin "Debt Collector Digital" (Penagih Hutang Otomatis) yang bertingkat, mulai dari peringatan halus hingga pemberian sanksi di dalam sistem aplikasi akademik.</p>\n\n<h3>Alur Kerja (SOP) Penanganan Tunggakan Kronis</h3>\n\n<ol>\n    <li>\n        <strong>Eskalasi Peringatan Otomatis (Auto-Reminder)</strong>\n        <ul>\n            <li><strong>Skenario:</strong> SPP jatuh tempo tanggal 10. Jika sampai tanggal 11 belum lunas, mesin akan bergerak.</li>\n            <li><strong>Tahap 1 (Notifikasi Halus):</strong> <em>Cron Job Scheduler</em> (Robot server yang berjalan tiap tengah malam) akan mengecek tabel <em>database</em>. Jika menemukan tagihan berstatus "Belum Lunas" dan melewati tanggal Jatuh Tempo, ia akan menembakkan <strong>Push Notification</strong> ke layar HP Orang Tua (Misal: <em>"Ayah/Bunda, tagihan SPP bulan ini belum dilunasi."</em>). UI di Aplikasi Mobile juga akan memunculkan <strong>Notification Badge</strong> (Titik Merah) di ikon tagihan.</li>\n            <li><strong>Tahap 2 (Notifikasi Keras):</strong> Jika tunggakan berlanjut hingga H+14, sistem bisa diprogram untuk menembakkan notifikasi peringatan yang lebih intens (dikirim berulang setiap 3 hari sekali). Admin juga bisa mengekspor laporan <strong>Arrears (Tunggakan)</strong> di menu Laporan untuk mulai menelepon orang tua.</li>\n        </ul>\n    </li>\n    <li>\n        <strong>Sanksi Sistemik (Block Access / Restriction)</strong>\n        <p>Jika tunggakan menumpuk hingga berbulan-bulan (Tunggakan Kronis) dan orang tua tidak merespons panggilan sekolah, Admin bisa mengeksekusi sanksi sistemik langsung dari Backoffice.</p>\n        <ul>\n            <li><strong>Jejak UI (Blokir E-Rapot):</strong> Admin masuk ke Sidebar <code>Jurnal & E-Rapot</code> &rarr; <code>E-Rapot</code> atau <code>Ijazah</code>.</li>\n            <li><strong>Aksi UX & Sistem:</strong> Sistem E-Rapot memiliki pengaturan *Interceptor* (Penghalang). Jika tagihan siswa masih berstatus "Tunggakan", maka di Aplikasi Mobile, fitur <strong>"Lihat/Unduh Rapor"</strong> milik orang tua tersebut akan <strong>Dinonaktifkan (Disabled)</strong> atau terkunci secara otomatis. UX akan memunculkan pesan *Pop-up*: <em>"Maaf, rapor anak Anda terkunci karena masih memiliki administrasi yang belum diselesaikan."</em></li>\n            <li><strong>Pembatasan Ujian (CBT):</strong> Demikian pula pada modul Ujian. Siswa yang menunggak secara kronis tidak akan bisa masuk ke dalam <em>Safe Exam Browser</em> untuk mengikuti UTS/UAS sampai tagihannya dilunasi (Status berubah Lunas/Hijau via DOKU).</li>\n        </ul>\n    </li>\n</ol>\n\n<blockquote>\n<p><strong>Efisiensi Psikologis UX:</strong><br>\nPendekatan "mengunci fasilitas digital" (seperti mengunci E-Rapot atau melarang akses Ujian CBT) di Aplikasi Mobile sangat efektif secara psikologis untuk memaksa penyelesaian tunggakan tanpa staf Tata Usaha harus selalu berdebat secara fisik dengan orang tua.</p>\n</blockquote>', '1', '2', '22', '2026-07-15 04:05:13', '2026-07-15 06:15:40');
